PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE Users (     user_id TEXT PRIMARY KEY NOT NULL,     line_display_name TEXT NOT NULL,     line_picture_url TEXT,     class TEXT DEFAULT '無' NOT NULL,     level INTEGER DEFAULT 1 NOT NULL,     current_exp INTEGER DEFAULT 0 NOT NULL,     created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL , nickname TEXT, phone TEXT, preferred_games TEXT, tag TEXT, email TEXT, perk TEXT DEFAULT '無特殊優惠', real_name TEXT, password TEXT, role TEXT DEFAULT 'member', username TEXT, notes TEXT, perk_claimed_level INTEGER DEFAULT 0, skill TEXT, skill_description TEXT, equipment TEXT, equipment_description TEXT);
CREATE TABLE IF NOT EXISTS "_BoardGames_old" (     game_id INTEGER PRIMARY KEY NOT NULL,     name TEXT NOT NULL,     description TEXT,     image_url TEXT,     tags TEXT,     min_players INTEGER,     max_players INTEGER,     difficulty INTEGER,     total_stock INTEGER,     for_sale_stock INTEGER,     for_rent_stock INTEGER,     is_visible BOOLEAN DEFAULT TRUE , sale_price INTEGER, rent_price INTEGER, deposit INTEGER DEFAULT 0, late_fee_per_day INTEGER DEFAULT 50, display_order INTEGER DEFAULT 999, image_url_2 TEXT, image_url_3 TEXT, supplementary_info TEXT);
CREATE TABLE ExpHistory (     history_id INTEGER PRIMARY KEY AUTOINCREMENT,     user_id TEXT NOT NULL,     exp_added INTEGER NOT NULL,     reason TEXT,     staff_id TEXT,     created_at DATETIME DEFAULT (datetime('now', 'localtime')) );
CREATE TABLE News (     id INTEGER PRIMARY KEY AUTOINCREMENT,     title TEXT NOT NULL,     category TEXT NOT NULL,     published_date TEXT NOT NULL,     image_url TEXT,     content TEXT,     is_published INTEGER DEFAULT 1,     created_at DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE StoreInfo (     id INTEGER PRIMARY KEY,     name TEXT,     address TEXT,     phone TEXT,     opening_hours TEXT,     description TEXT , booking_button_text TEXT, booking_promo_text TEXT, booking_announcement_text TEXT, booking_notify_user_id TEXT);
CREATE TABLE BookingSettings (     setting_id INTEGER PRIMARY KEY AUTOINCREMENT,     disabled_date TEXT NOT NULL UNIQUE );
CREATE TABLE MessageDrafts (     draft_id INTEGER PRIMARY KEY AUTOINCREMENT,     title TEXT NOT NULL,     content TEXT NOT NULL,     created_at DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE Bookings (     booking_id INTEGER PRIMARY KEY AUTOINCREMENT,     user_id TEXT,     contact_name TEXT NOT NULL,     contact_phone TEXT NOT NULL,     booking_date TEXT NOT NULL,     time_slot TEXT NOT NULL,     num_of_people INTEGER NOT NULL,     tables_occupied INTEGER,     booking_preference TEXT,     status TEXT DEFAULT 'confirmed',     created_at DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE Activities (     activity_id INTEGER PRIMARY KEY AUTOINCREMENT,     message TEXT NOT NULL,     is_read INTEGER DEFAULT 0,     created_at DATETIME DEFAULT (datetime('now', 'localtime')) );
CREATE TABLE IF NOT EXISTS "BoardGames" (     game_id INTEGER PRIMARY KEY,     name TEXT NOT NULL,     description TEXT,     image_url TEXT,     image_url_2 TEXT,     image_url_3 TEXT,     tags TEXT,     min_players INTEGER DEFAULT 1,     max_players INTEGER DEFAULT 4,     difficulty TEXT DEFAULT '普通',     total_stock INTEGER DEFAULT 0,     for_rent_stock INTEGER DEFAULT 0,     for_sale_stock INTEGER DEFAULT 0,     sale_price INTEGER DEFAULT 0,     rent_price INTEGER DEFAULT 0,     deposit INTEGER DEFAULT 0,     late_fee_per_day INTEGER DEFAULT 50,     is_visible INTEGER DEFAULT 0,     supplementary_info TEXT,     display_order INTEGER DEFAULT 999 , play_time TEXT);
CREATE TABLE IF NOT EXISTS "Rentals" (     rental_id INTEGER PRIMARY KEY AUTOINCREMENT,     user_id TEXT,     game_id INTEGER NOT NULL,     rental_date TEXT DEFAULT (date('now', 'localtime')),     due_date TEXT NOT NULL,     return_date TEXT,     name TEXT,     phone TEXT,     rent_price INTEGER,     deposit INTEGER,     late_fee_per_day INTEGER,     late_fee_override INTEGER,     status TEXT DEFAULT 'rented',     created_at TEXT DEFAULT (datetime('now', 'localtime')),     FOREIGN KEY (game_id) REFERENCES BoardGames(game_id) ON DELETE SET NULL );
CREATE TABLE GameAssets (      id INTEGER PRIMARY KEY AUTOINCREMENT,      type TEXT NOT NULL,       name TEXT NOT NULL,      description TEXT,         display_order INTEGER DEFAULT 999,      created_at DATETIME DEFAULT CURRENT_TIMESTAMP  , icon_url TEXT DEFAULT NULL);
CREATE TABLE UserAssets (     id INTEGER PRIMARY KEY AUTOINCREMENT,     user_id TEXT NOT NULL,     asset_id INTEGER NOT NULL,     acquired_at DATETIME DEFAULT CURRENT_TIMESTAMP , custom_description TEXT DEFAULT NULL);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_boardgames_difficulty ON "_BoardGames_old"(difficulty);
CREATE INDEX idx_boardgames_is_visible ON "_BoardGames_old"(is_visible);
