INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(102,'璀璨寶石：漫威版',replace('經典遊戲《璀璨寶石》的主題變體，玩家收集無限寶石，招募英雄、反派和經典場景。\n\n機制略有調整，變得更加有挑戰。','\n',char(10)),'https://i.postimg.cc/HkH7bq7s/image.png','販售,策略,家庭',2,4,'普通',3,3,0,1,1590,0,1500,50,2,'https://i.postimg.cc/KYh95x49/16473343459567776090.jpg','https://i.postimg.cc/KYh95x49/16473343459567776090.jpg','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(103,'估估劃劃','一款超級歡樂的派對遊戲，用盡方法讓隊友猜到答案，讓人笑到肚子痛。','https://i.postimg.cc/KjP8zYf7/image.png','租借,派對,家庭,兒童,比手畫腳,肢體語言',4,99,'簡單',2,1,1,1,890,100,800,50,1,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(104,'推倒堤基','想辦法讓自己的三尊堤基雕像排到最頂端，要小心壞心眼的對手移除你要的堤基們哦。','https://i.postimg.cc/DwbYbbLK/image.png','租借,家庭,輕快,小品,心機',2,4,'簡單',1,0,1,1,880,100,800,50,3,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(105,'鐮刀戰爭',replace('*此款僅提供現場遊玩*\n《鐮刀之戰》講述的是1920年代一戰後的歐洲，工業與農業激烈碰撞下的蒸汽朋克架空背景。\n英文原名的Scythe(鐮刀) ——即指「農耕發展」，也指戰備後的「收割」。','\n',char(10)),'https://i.postimg.cc/RVWgjnPn/image.png','僅供現場玩,策略,區域控制,資源控管',1,5,'專家',1,1,0,1,0,0,0,50,4,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(106,'星期五',replace('你是住在荒島上的星期五，魯濱遜來到你的小島，一開始他並沒有太多求生技巧，你要幫助他去面對各種冒險。每次戰鬥的勝利，都會增強他的能力，失敗則會讓他擺脫一些惡習。\n\n然而，在孤島上的生活是很磨人的，所以魯濱遜也會老化而且變得笨拙。在本遊戲中，魯濱遜牌庫代表他的各種行為，你要收集更好的卡牌來改善這組牌庫，以幫助魯濱遜在遊戲最後對抗難纏的海盜，重歸文明世界！在這款單人冒險遊戲中，只有你才能贏得最後勝利！','\n',char(10)),'https://i.postimg.cc/2Sw2sRpV/image.png','販售,策略,卡牌,小品',1,1,'普通',1,1,0,1,690,0,0,50,5,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(107,'七大奇蹟','一款經典的卡牌輪抽文明發展遊戲，玩家在三個世代中，透過打出建築、軍事、科技等卡牌來發展自己的文明，爭取最高的總分。描述內含『領袖』、『艦隊』擴充。','https://i.postimg.cc/ncxKpRG7/image.png','租借,策略,家庭,卡牌,',2,7,'困難',1,0,1,1,1500,1800,440,50,7,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(108,'土狼在笑你',replace('12歲以上｜3-6人｜30分鐘\n一款心機破表的派對遊戲，玩家扮演印地安人，透過觀察他人的羽毛數量（自己看不到自己的）來判斷是否吹牛。','\n',char(10)),'https://i.postimg.cc/T1JDKxJb/image.png','租借,派對,心機,吹牛',3,10,'簡單',1,0,1,1,890,100,800,50,8,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(109,'叔叔的遺囑',replace('*此款僅提供現場遊玩*\n遊戲時間:75分鐘  建議年齡:14歲以上\n「叔叔的遺產」是一款涉及經濟的遊戲，但你的目的卻非賺取最多的金錢。\n相反，你需要花光自己的全部家當，比其他玩家更快破產，聽起來是不是很不可思議？\n遊戲中，你將扮演維多利亞時期一位百萬富豪的姪子(姪女)。\n他臨終前寫下了一份遺囑，宣布將自己所有的遺產轉交給最會享受金錢的親戚。\n為此，你需要和其他玩家進行一場敗家的比拚，\n無論是騎馬、看戲、舉辦晚宴，還是購置房產或遊艇出海等。\n總之，你的目的只有一個，趕在其他玩家之前，花光你初始獲得的所有錢。\n當然，從本質上來講「叔叔的遺產」仍是一款工人擺放遊戲，\n玩家輪流差使自己的僕人去執行相應的敗家行動。\n執行順位和行動選擇是整局遊戲的關鍵。','\n',char(10)),'https://i.postimg.cc/Vk6Ck3rS/image.png','僅供現場玩,策略,行動分配,工人擺放,卡牌效果',2,5,'困難',1,1,0,1,0,0,0,50,9,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(110,'翠嶼秘境 Inis',replace('*此款僅提供現場遊玩*\n遊戲時間	90分鐘\n建議年齡	14歲以上\n\n翠嶼秘境(Inis)是關於凱爾特人歷史和傳奇的領地佔領遊戲。\n\n善用機謀與策略，策動攻擊，擴張領土，佔領敵對部落，或掌控神廟，成為最有實力的酋長。\n除了迷人的遊戲性，典雅富有特色的美術風格，更讓遊戲獲得2016 Golden Geek Best Board Game Artwork & Presentation提名，\n與精緻的模型配件相互輝映，是值得玩家珍藏的精品桌遊。\n以手牌管理、區域控制、區域移動、牌庫構築等為主要遊戲機制。','\n',char(10)),'https://i.postimg.cc/rwKDkx3x/image.png','僅供現場玩,策略,區域控制,區域移動,手牌管理,牌庫構築',2,4,'困難',1,0,1,1,0,0,0,50,10,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(111,'毒逗魔藥師',replace('遊戲時間	30分鐘\n建議年齡	14歲以上\n一款節奏快速的弄爆別人遊戲，玩家扮演魔藥師，要將不同成分的藥材放入鍋中，同時要想辦法讓別人的鍋子爆炸，但同時要處理自己鍋子裡的素材，遊戲投過卡牌效果來做出藥材轉換的方式，有點燒腦又有點好笑的輕策略選擇。','\n',char(10)),'https://i.postimg.cc/Df604xK1/image.png','租借,策略,家庭,行動選擇,資源轉換',2,5,'普通',1,0,1,1,1800,200,1800,50,11,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(112,'詭鎮奇談 卡牌版',replace('*此款僅提供現場遊玩*\n一款克蘇魯神話主題的合作式成長卡牌遊戲（LCG），相當有帶入感的劇本型遊戲，玩家可以在遊戲內跟不同的角色對話，甚至一些選擇會影響未來的劇本走向，同時角色也會隨著玩家的冒險持續成長，連同創傷也可能跟在玩家身上哦。','\n',char(10)),'https://i.postimg.cc/C1FYFV5X/image.png','僅供現場玩,策略,合作,牌庫構築,劇情',1,2,'專家',1,1,0,1,1850,0,0,50,12,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(113,'水瓶座',replace('如何瞞過對手，讓手中任務牌指定的元素七張相互連結？\n\n3歲以上｜10-30分鐘\n孩子們喜歡顏色豐富的設計、輕快的節奏及尋找相似配對的遊戲策略；大人們則酷愛遊戲過程中激烈的競爭。\n這是一款老少咸宜的家庭紙牌遊戲，發完牌後悄悄計劃如何移動你的元素牌，千萬別以為自己快贏了⋯⋯恐怕任務牌就要被調包囉！','\n',char(10)),'https://i.postimg.cc/d0FcBK23/image.png','租借,家庭,小品,兒童,心機,拚放',2,5,'簡單',1,0,1,1,490,50,400,50,13,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(114,'化妝舞會',replace('*僅供現場遊玩*\n一款角色扮演與推理遊戲，每位玩家持有一個隱藏的角色，可以透過交換角色、宣告角色能力來賺取金錢，但因為會交換身分，所以整個過程混亂歡樂，考驗所有人的記憶和吹牛，先賺到13元的玩家獲勝。','\n',char(10)),'https://i.postimg.cc/y8qM1zrj/image.png','僅供現場玩,記憶,心機,角色能力,吹牛',2,13,'普通',1,0,1,1,0,0,0,50,14,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(115,'神靈大對決',replace('一場關於窺探人心、秘密競標和區域控制的遊戲\n明朝末年連綿的大災難，人間化為煉獄，沒人會再次體驗的！\n\n \n\n遊戲背景\n昏庸的皇帝和無止境的黨爭導致連年戰亂不已，水災、大旱和暴雪都無人管理。\n無助的人們紛紛祈求上蒼庇護，於是乎上蒼派了五路神仙下凡，普度眾生！\n \n\n遊戲目標\n\n在這款遊戲中你會扮演一位神靈，通過出其不意、神鬼莫測的操作，\n完成祈禱，爭取更多的信徒支持，獲得主宰神壇的統治地位！','\n',char(10)),'https://i.postimg.cc/qBxwhHRQ/image.png','租借,策略,區域控制',2,5,'普通',1,0,1,1,600,100,600,50,15,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(116,'一知半解骨董市',replace('德川家在江戶建立幕府之後,江戶的商業更活躍了。\n\n\n有一天,在一個倉庫裡發現了一大堆奇珍異寶,這些寶物即將被拿到古物市集\n\n\n有幾個商人聽到這個消息便決定一起去看看,但其實他們都不太懂古董的價格。\n\n\n實際上，他們就是一群笨蛋而已。買太多相同的古董(等一下要轉賣掉)會讓其他買家失去興趣而跌價。\n\n在這種價格變來變去的情況下,哪個商人能賺走最多利潤呢?\n\n','\n',char(10)),'https://i.postimg.cc/kGTWj9Rm/image.png','租借,家庭,收集',3,6,'普通',1,0,1,1,590,100,500,50,16,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(117,'偶像發掘','在這個世界上，還埋藏著許多不為人知的偶像候補生。請您化身為精明幹練的製作人，努力發掘出未來的偶像吧！將大量的偶像送到世人面前，讓更多的觀眾感到熱血沸騰──這項任務就只有您才能辦到！ 本遊戲是一款簡單易懂的卡牌遊戲。每位玩家要做的事情，就是從疊放的卡牌裡發掘偶像卡，爭取儘可能多的觀眾（得分），由此來贏得遊戲的最終勝利。','https://i.postimg.cc/yYWRVMSD/image.png','販售,派對,家庭',2,6,'簡單',1,1,0,1,450,0,0,50,17,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(118,'瞎掰王',replace(' \n⭐️熱銷亞洲的派對桌遊!這是款專為講幹話設計的遊戲！到底誰在講真話，誰在瞎掰？⭐️\n\n來一場『瞎掰王』讓你塵封已久的幹話小宇宙爆發！胡謅無罪，瞎掰有理，達到吹牛最高境界。這遊戲的最終目的，就是要你成為『瞎掰王』。\n2023年度完全不能錯過的超爆笑桌遊，讓大家一起笑到肚子痛吧!\n','\n',char(10)),'https://i.postimg.cc/jqD81Fdh/image.png','販售,派對,吹牛,說話',3,10,'簡單',1,1,0,1,1080,0,0,50,18,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(119,'SDGS瞎掰王',replace('桌遊與教育題材的完美結合，推薦教育用\n\n\n\n🌎SDGs(2030永續發展目標)包含了17項核心\n\n包含消除貧窮、氣候變遷、性別平權等...議題\n\n看似無關的目標，其實都跟生活息息相關！\n\n\n\n\n\n在有款桌遊跟SDGs合體了，就是《瞎掰王SDGs教育版》‼\n\n題目都變成SDGs系列相關的題目，大家可以看題說故事，一起學習新知識，分享議題看法，玩著玩著就又學到了新知識','\n',char(10)),'https://i.postimg.cc/L5SnjWyM/SDGS.png','販售,派對,說話',3,8,'簡單',1,1,0,1,690,0,0,50,19,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(120,'花見小路',replace('歡迎來到古都最負盛名的花見小路通。在這條街上的料亭內，具有多樣專長的女性表演工作者─藝者─在筵席上為客人表演，展現她們高貴穩重的氣質。夜幕低垂，燈火從石板路兩側那些古色古香的木造格子戶中透出，照映出裡頭人們若隱若現的模樣，引起無限的想像空間。\n你是知名高級料亭的老闆，為了爭取七名最好的藝者來到你的店裡服務，你與其他老闆競爭，藉由蒐集她們最擅於使用的表演物品來吸引她們，在你的店裡發揚古都傳統文化的丰采','\n',char(10)),'https://i.postimg.cc/vTw3fQFH/image.png','租借,雙人,小品',2,2,'簡單',1,0,1,1,450,50,400,50,20,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(121,'農家樂',replace('★最經典的工人擺放遊戲\n★模擬中世紀農家，種植田地、畜牧，建造房屋\n★中重度策略，耐玩度極高','\n',char(10)),'','租借,策略,工人擺放,卡牌',1,4,'困難',1,0,1,1,2090,250,2000,50,21,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(122,'上洛',replace('《上洛》(Joraku) 是一款結合這兩種機制的遊戲，透過吃墩的過程贏得各區影響力，怎麼出牌要仔細考量。\n\n遊戲中有三種花色，和大部分吃墩遊戲一樣，接下來出牌的玩家一定要跟引牌大出相同花色的卡片，\n\n除非缺門 (手牌缺該色卡片) 才能打出不同花色的卡片。遊戲贏墩的方式是看數字大小 (忽略花色)，\n\n數字 6 基本上贏得任何一墩 (最大的王牌)，不過場上如果有玩家出忍者，則忍者會剋數字 6 (但比其它數字小)。\n每張打出的卡片會有些功能讓玩家移動自己的大名和忍者，是一款透過各區域影響力比玩家誰分數最高的遊戲。','\n',char(10)),'https://i.postimg.cc/pLrY99hJ/image.png','租借,區域控制,卡牌,吃墩',3,4,'普通',1,0,1,1,850,100,800,50,22,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(123,'印加寶藏',replace('你和你富有冒險精神的夥伴們，前往古老的印加神廟中，尋找稀有的綠松石、黑曜石與黃金。\n\n遊戲中的每個回合，你都必須決定是要進一步地深入探索神廟，或者是要安全地返回營地，將已經到手的寶物好好收藏保管。\n越往神廟的深處探索，就表示已經到手的寶物有可能因為神廟內發生的種種危機，而被迫拋棄，例如：巨型蜘蛛、甦醒的木乃伊、地底竄出的烈火與擁有劇毒的蛇⋯⋯都將讓你只能丟下一切逃命。\n但是傳聞中無價的古印加神器就在這裡，只有能克服心理恐懼的人才有機會得到它！\n\n你究竟有多勇敢？要有多少的寶物才能夠滿足你？玩過印加寶藏後你才會知道！','\n',char(10)),'https://i.postimg.cc/j2RyRCYN/image.png','租借,派對,家庭,小品,風險管理',3,8,'簡單',2,0,2,1,1090,150,1000,50,23,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(124,'黃牌2022 18+','黃牌(Yellow cards)是一款很間單的文字填空桌遊。【紫卡】裡面有挖空的句子，玩家要用【黃卡】上的字做填空。由裁判決定哪個玩家組合出來的句子最不合胃口，並給該玩家一張黃牌。桌遊黃牌要填的字詞大部分都是18禁或是亂七八糟的字眼，因此一本正經的句子也變得非常不正經。算是一款簡單又勁爆的Party Game，建議和熟悉的朋友玩會比較放得開？黃牌是一款老少不宜，只適合跟熟人玩的桌遊。想知道朋友的尺度在哪，這款桌遊倒是很好拿來用。','https://i.postimg.cc/3x00520V/2022.png','租借,派對,卡牌,說話',4,10,'簡單',1,1,0,0,990,100,900,50,24,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(125,'字字轉機',replace('你曾有過想到某個事物，卻一時答不上到底是什麼的經驗嗎？平常的常識，在遊戲中變得困難十足，歡樂就此誕生！\n一款隨機對手、隨機題目的快答遊戲，考驗你的圖案識別能力、反應力以及聯想力。遊戲中玩家必須聚精會神尋找自己的對手，找到後迅速講出對方卡牌上的題材答案，最快答對的玩家獲得分數，成為天下第一的「嘴遁王」！','\n',char(10)),'https://i.postimg.cc/FKjf1mZx/image.png','租借,家庭,派對,說話',3,6,'簡單',1,0,1,1,490,50,400,50,25,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(126,'逃離亞特蘭蒂斯',replace('*此款僅提供現場遊玩*\n"十世紀早期"一個屬於冒險和探索的時代。\n探險者們在大洋的中心發現了神秘的亞特蘭提斯島，\n傳說島嶼上藏有無價的寶物！\n在抵達亞特蘭提斯後，探險者們發現了大量的奇珍異寶。\n正當他們滿載而歸之時，亞特蘭提斯島卻開始沉沒！\n誰能最終安全返航呢？\n   \n這是一場刺激的生存遊戲，\n一個由40個六邊形組成的島嶼正在慢慢沉入海洋，\n玩家們需要在主島最終爆炸之前，\n向周圍島嶼安全轉移。\n你既可以游泳也可以用船去逃離，\n但必須避開海蛇、鯨魚和鯊魚前往安全地帶，\n並竭盡所能保護自己的財產，獲得更多的得分。','\n',char(10)),'https://i.postimg.cc/76w52ctr/image.png','僅供現場玩,家庭,派對,骰子',2,4,'普通',1,0,1,1,0,0,0,50,26,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(127,'石器時代',replace('在浩瀚的人類歷史當中，在不同的時期，人們面臨著不同的挑戰。\n在石器時代，農業誕生了﹔人類開始採集更多的自然資源，並且出現簡單的房舍。\n人與人間漸漸有了交易行為，文明也逐漸萌發、擴展。\n人口的成長，也導致了對高效率狩獵的強烈需求。\n玩家在遊戲中，要試圖去達成所有的挑戰。有許多種策略可以完成這些挑戰，因此每個玩家可以選擇自己擅長的策略，走上不同的路。\n找出你自己的策略模式，並看看它是不是能帶你走向勝利的最佳策略﹗','\n',char(10)),'https://i.postimg.cc/PJMXWsBr/image.png','租借,策略,家庭,骰子,卡牌',2,4,'普通',1,0,1,1,1890,200,1800,50,27,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(128,'卡卡頌：非洲之旅',replace('熱帶氣候的高溫籠罩著非洲草原，薰風徐徐，我們來到這片一望無際的草原，希望能看到這裡最受歡迎的大型動物。猴子在樹枝上擺盪，獅子在樹蔭下休憩，大象緩慢的步伐震動著大地，水池邊總是聚集了多種不同的動物，非常值得在一旁靜靜等待，捕捉更多的曼妙身影。\n這款合作即競爭的策略性版圖遊戲，每次玩都會激盪出不同的策略或同盟關係，除了對圖像的敏感外，開放的合作態度更是致勝的關鍵！','\n',char(10)),'https://i.postimg.cc/MHXK08yN/image.png','販售,家庭,策略,板塊拼接',2,5,'普通',3,3,0,1,1290,0,0,50,28,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(129,'駱駝大賽',replace('快來見識有史以來最瘋狂的駱駝大賽！\n\n身為埃及上流社會的你，來到這裡試試手氣，對自己看好的駱駝下注，以期在分段賽及賽終時贏得最多獎金。\n然而，互相揹負的駱駝，讓賽況變得更難預測。抓住比賽的節奏，精準掌握下注時機，才是讓你贏錢的關鍵。\n令人傻眼的是，來了兩名新的選手 —— 逆向奔馳的瘋狂駱駝，儘管立刻喪失了參賽資格，但仍嚴重驚擾了整場賽事⋯⋯\n讓我們拭目以待這場精彩的比賽！','\n',char(10)),'https://i.postimg.cc/kX0XSzDY/image.png','租借,派對,家庭,骰子',3,8,'普通',1,0,1,1,1490,150,1400,50,29,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(130,'伐木達人',replace('用斧頭小心地敲擊樹塔，並收集掉落的樹皮來得分，如果不慎讓樹心也掉下來，就要扣分囉！遊戲結束時，得分最高的玩家獲勝！\n\n這是一款簡單易學又充滿歡樂的遊戲，不管人數多寡，都能炒熱氣氛，絕對是派對必備！','\n',char(10)),'https://i.postimg.cc/63p9wN1q/image.png','租借,派對,家庭,兒童,動作',2,7,'簡單',1,0,1,1,790,100,700,50,30,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(131,'影子陣',replace('準備好迎接緊張的３Ｄ拼圖遊戲，這將令你絞盡腦汁。\n\n在這遊戲中你必須安排方塊以配合挑戰卡上描述的「影子」，影子陣包含三個難度和最多四位玩家使用的充足方塊。','\n',char(10)),'https://i.postimg.cc/2jJzpMdj/image.png','租借,競速,拚放',2,2,'簡單',1,0,1,1,880,100,800,50,31,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(132,'柯爾特快車','2015 Spiel des Jahres Winner 榮獲 2015 德國桌遊家庭類大獎一場驚險刺激的火車搶劫即將開始！你扮演著強盜的一員，雖然你們打劫了乘客身上的財物，但其實你們真正的目的是位於火車頭，由警長重重看守的保險箱！你必須在同夥中搶先一步，奪得保險箱，成為西部最富有的逃犯！','https://i.postimg.cc/GhybbKzF/image.png','租借,派對,家庭,卡牌,角色能力',2,6,'普通',1,0,1,1,1260,150,1200,50,32,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(133,'煤礦大亨紙牌版',replace('20世紀時，德國的艾森市是歐洲的煤礦中心，獻身在採煤的黑暗世界中，你從礦坑中開採煤礦，將它們裝上火車，經由遍布的鐵路網，將煤礦運送至各地以獲取財富。\n「煤礦大亨．超乎紙牌的紙牌遊戲」是依據2013年發行的「煤礦大亨桌上遊戲」所設計的一款獨立紙牌遊戲，本遊戲有創新的遊戲機制以及近達240張的紙牌。除了與基本版遊戲一樣的刺激，「煤礦大亨．超乎紙牌的紙牌遊戲」將帶給你獨一無二的遊戲體驗。','\n',char(10)),'https://i.postimg.cc/xjkXbKtC/image.png','販售,策略',2,4,'普通',2,2,0,1,1090,0,0,50,33,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(134,'勃根地城堡',replace('勃根地城堡建設於中古世紀的法國，\n玩家們即是扮演當代的貴族，統治一塊屬於自己的小領地，\n為了發展自家領土，必須開拓據點與建設城堡、藉由河運貿易、開墾銀礦、以及善用旅行者的寶貴知識。','\n',char(10)),'https://i.postimg.cc/N0J0KMXm/image.png','租借,策略,板塊拼接,骰子',2,4,'困難',1,0,1,1,1360,150,1300,50,34,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(135,'跑跑龜','期待已久的中文版跑跑龜終於出版了，百分之百台灣製造的中文版，可愛的木製烏龜及超有趣的賽跑機制，讓玩家們之間互動頻繁，雖然只有短短10~12步，隨著出現的行動牌烏龜們的先後順序可說是變化莫測，如果可以常常踏上別隻烏龜的背也能夠後來居上哦，快和孩子試試看此款輕鬆又有趣的遊戲吧！','https://i.postimg.cc/L5f4Q3b3/image.png','租借,家庭,兒童,競速',2,5,'簡單',1,1,0,1,980,100,900,50,35,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(136,'拉密:變臉版',replace('▲世界上最受歡迎的遊戲之一\n\n▲新增變化規則，適合升級版玩家\n\n\n\n★經過時間考驗的遊戲：由以色列人Ephraim Hertzano 於1930年初於羅馬尼亞所研發設計。 因遊戲與眾不同的遊戲規則和娛樂性，靠著口耳相傳，拉密遊戲就在穩健中不斷的成長。\n\n★最受玩家歡迎的遊戲：成為全世界第三大最佳銷售遊戲和全世界第一大最佳銷售的數字磚塊牌。\n\n★打破語言隔閡的遊戲：超過50,000,000個拉密遊戲，用28種不同的語言發行，橫跨五大洲，風行於全世界70多個國家和地區。但是此遊戲所包含的106個磚塊牌所代表的意義是全球共同了解的\n\n★激發思考神經的遊戲：因為它不太靠運氣，卻需要您運用很多的策略。\n\n◎排列組合能力 — 學習數字和顏色的最佳排列組合\n\n◎創新規劃能力 — 培養能不受限於所面對的現有牌局，重新規劃新的牌局組合\n\n◎決斷分析能力 — 訓練在短時間內，做出正確的出牌和操作牌的能力。','\n',char(10)),'https://i.postimg.cc/kg53ByvY/image.png','販售,租借,家庭,策略',2,4,'普通',2,1,1,1,950,100,900,50,36,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(137,'猜心俱樂部',replace('★ 遊戲簡介\n\n接近港口的位置，讓它匯集許多來自世界各國的旅行家前來較勁，\n\n但是知識豐富的你，也絕對不能讓他們小看。\n\n這群好勝的旅行者不懷好意地要求你加入他們的遊戲，從牌縫間透出的銳利眼神看來，\n\n不但要回答他們的問題，還要贏走你帶來的所有籌碼。\n\n \n\n每一道問題都是一個密室。在遊戲裏頭，像是躲貓貓一樣，猜測彼此的答案。\n遊戲過程中，每個人都必須回答問題，把六個不同的答案分別寫在六張卡牌上(用畫的也可以！)。\n然後輪流打出手牌或者進行預測。\n答案相同，可以獲得碟中所有的籌碼；\n如果不同，就支付一枚十元籌碼，相當簡單。','\n',char(10)),'https://i.postimg.cc/MHYNGcM8/image.png','租借,派對,家庭',2,8,'簡單',1,0,1,1,990,100,900,50,37,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(138,'復仇女神號',replace('*此款僅提供現場遊玩*\n星辰離我們不再遙遠。小行星開採已遍地開花。火星和金星上的定居點已經可以自給自足。然後，一個來自宇宙深處的遊蕩者以1/2的光速沖我們而來。它擦過月球，把這顆衛星撞擊成碎片，月球脫離軌道，對地表造成了災難性的破壞。\n\n\n\n但很多人卻抓住了這個可能性開始謀利，因為有人發現撞擊後留下的殘餘雜質和奇異的物質，人們不再滿足於傳統的小行星收穫。太空船被重新改造，狂熱的人們不惜在浩瀚的太空中花費數年，他們在群星之間穿梭，只為釣到下一條大魚。他們就像一條條捕鯨船，流星，小行星，死亡的原行星和其他來自宇宙深處的奇怪物體都成了他們的拾荒場。\n許多人一去不返。而是也澆不滅人的熱情。儘管有人明知攔截極速運行下的不明物體非常危險。這時，傳言有人發現了不可思議的東西……','\n',char(10)),'https://i.postimg.cc/BbJ7Rqh7/image.png','僅供現場玩,策略,合作,卡牌,角色能力',1,5,'專家',1,1,0,1,0,0,0,50,38,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(139,'犯人在跳舞','救命啊！這裡發生命案了！封鎖現場！所有人不准動！犯人一定還藏匿在我們當中，是你？還是他？犯人究竟是誰？想辦法揪出他吧！','https://i.postimg.cc/MpgPq0PQ/image.png','販售,租借,派對,家庭,小品,推理',3,9,'簡單',2,1,1,1,400,50,400,50,39,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(140,'聖石之路旅行版',replace('*僅供現場遊玩*\n遊戲規則簡單，新玩家也可以立即上手，然而遊戲的過程由始至終都變幻不斷、樂趣無窮。','\n',char(10)),'https://i.postimg.cc/J42K5cW2/image.png','僅供現場玩,家庭,小品',2,4,'簡單',1,0,1,1,400,0,0,50,40,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(141,'數字火車',replace('簡單有趣的數學賓果遊戲，將每回合隨機抽出的數字寫下來，盡可能完成最長的升序排列。考驗玩家對機率的掌握，當然也需要一點好運囉！\n2013 美國家長之選優選獎推薦','\n',char(10)),'https://i.postimg.cc/50bm2sw6/image.png','租借,家庭,兒童',1,6,'簡單',1,0,1,1,790,100,700,50,41,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(142,'吹牛骰BLUFF',replace('*此款僅提供現場遊玩*\n一款經典的骰子吹牛遊戲，玩家搖動自己的骰盅，然後根據所有玩家的骰子（只能看自己的）來叫喊某個點數的骰子總共有多少顆，考驗大家的表情控管，好好的吹牛吹爆別人吧','\n',char(10)),'https://i.postimg.cc/KzpghfQX/BLUFF.png','僅供現場玩,派對,家庭,吹牛',2,6,'簡單',1,0,1,1,0,0,0,50,42,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(143,'大魔術師:魔幻傳奇',replace('*此款僅供現場遊玩*\n數十年前，這裡曾是一座被譽為魔幻之都的繁華城市，而現在卻只徒留著昔日輝煌的殘影。\n\n這座城市無私的贊助人，史上最偉大的魔術師達爾高，在一次表演的最後一刻神秘消失，\n他最後的表演，也宣告了黃金時代在這一天結束，此後再也未出現過有關達爾高的消息，直到現在…\n \n一天夜裡，四位來自不同魔術領域，才華洋溢的魔術師，都收到了一份神祕的邀請。\n那位偉大的達爾高從未知之地歸來，親自召集他們，來揭示自己隱瞞終生的秘密：他那閃耀的琥珀聖物，魔幻之石的真相。\n儘管許多人以為，這不過只是他的護身符罷了。\n但根據他的透露，這塊石頭會賦予其擁有者超常的智慧、速度，以及感知力：一位完美的魔術師應具備的素質。\n \n達爾高的秘密只是他偉大計劃的一部分：\n他希望挑選出一位值得託付之人，繼承他的這塊石頭和全部遺產，在他死後重振魔格利亞，讓這裡重新成為魔幻之都。\n而繼承者的人選，將在這四位天才魔術師中產生，他必須在為期七週的名利競爭中脫穎而出。\n成敗在此一舉，這四位魔術師必將不惜一切得勝利。\n究竟誰能夠成為下一個魔幻傳奇?','\n',char(10)),'https://i.postimg.cc/BZ1xG9WM/image.png','僅供現場玩,策略,工人擺放',2,4,'專家',1,1,0,1,0,0,0,50,43,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(144,'情書6人版','皇宮裡的每一個人，千方百計想要靠近公主，贏的芳心，希望能收到公主的情書。在眾多的競爭對手中，如何收到這珍貴的情書，快點想想辦法吧！','https://i.postimg.cc/KYzMqCr7/image.png','租借,派對,小品,推理',2,6,'簡單',1,0,1,1,450,50,400,50,44,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(145,'椰子猴王',replace('利用猴子將椰子發射出去，若投進杯子中，就可贏得該杯子，第一個以杯子建好金字塔的猴子，便會成為王者！\n\n椰子猴王在遊戲中可以練習到手指分離性動作、雙手協調、視覺動作整合、心像演練、視覺認知、動作計畫能力等，還能促進小朋友的挫折忍受度及情緒控制能力！\n\n可愛又討喜的猴子配件，絕對可以馬上抓住小朋友的心～\n非常適合親朋好友一同遊玩，大小朋友都會喜歡的！','\n',char(10)),'https://i.postimg.cc/j5nJKN1L/image.png','租借,派對,家庭,兒童',2,4,'簡單',1,0,1,1,750,100,700,50,45,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(146,'十三道線索',replace('數起兇殘的犯罪案件震驚了1899年的倫敦，謎樣的案情掩蓋了真相，蘇格蘭警場在黑暗中摸索，號召一群優秀的偵探前來協助破案。\n每位偵探必須利用敏銳的直覺，從13道線索中找出蛛絲馬跡，負責解開自己的謎題，比其他人更快偵破自己的案件！','\n',char(10)),'https://i.postimg.cc/jSqw2B9V/13.png','租借,家庭,推理,小品',2,6,'普通',1,0,1,1,1190,150,1100,50,46,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(147,'吾王塔羅之戰',replace('塔羅眾神世世代代各司其職、盡忠職守，引領著眾生萬物。不知何時，從渾沌之中誕生了一股神祕力量－「科技神」。新神的崛起打亂了長久以來的平衡，破壞了牽制著塔羅們的枷鎖，塔羅眾神因此受到污染與影響，世界開始動亂不安⋯⋯ \n\n\n 《瘋狂島MaddishIsland》2022年全新鉅獻，第七款原創桌遊《吾王：塔羅之戰》登場啦！這次玩家們將化身成一位隱匿身分的塔羅使者，借用其他塔羅的能力，依循目前已知的線索，抽絲剝繭、推理猜測，才能輔佐神諭淨化所有被汙染的塔羅眾神。','\n',char(10)),'https://i.postimg.cc/FK7Yg3ND/image.png','租借,卡牌,小品',2,4,'普通',1,0,1,1,605,100,600,50,47,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(148,'牛頭王老五',replace('一個類似「誰是牛頭王？」（6 nimmt [Take 6]）的姊妹品遊戲，\n設計多了一些變體，但是同樣刺激、耐玩，推薦最適合帶動全家或朋友們火熱氣氛的遊戲之一！\n在這個遊戲你儘可能地收集綠色的牛頭，在桌上有許多列的卡片，\n當你放置卡片是第五張時，你須將整組的片卡收走，\n整組卡片中綠色是正分，紅色是負分，收集最多分數的玩家為優勝者。\n\n','\n',char(10)),'https://i.postimg.cc/X7sNHq2h/image.png','租借,家庭,小品,卡牌',2,6,'簡單',1,0,1,1,500,50,500,50,48,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(149,'狼來了',replace('大野狼偷偷潛入農舍！\n\n可能偽裝成綿羊、獵人或是獵犬，\n\n而為了混淆大野狼，農舍裡的大家也進行偽裝大作戰，\n\n結果最後都搞不清楚誰是誰了！\n\n放羊的小孩還趁機惡作劇，大喊「狼來了～！」。\n\n每個人得要小心翼翼找出彼此真正的身分，\n\n究竟是大野狼會抓到綿羊、還是農舍的夥伴們能成功戰勝大野狼呢？','\n',char(10)),'https://i.postimg.cc/ZqdT5cTt/image.png','販售,派對,推理,身分猜測',4,8,'普通',2,2,0,1,500,0,0,50,49,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(150,'字母風火輪',replace('在十秒內，想出你的解答吧！\n字母瘋火輪是一款挑戰反應，訓練思考的遊戲。\n玩家要在十秒內，依據題目的規定，想出具有可使用注音（字母）開頭的答案。\n能撐到最後的玩家，就是獲勝者！\n\n★獲獎★2014 Mensa Select門薩推薦','\n',char(10)),'https://i.postimg.cc/90WV1HyC/image.png','租借,派對,家庭,反應',2,8,'簡單',1,0,1,1,890,100,800,50,50,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(151,'煉金術士',replace('*此款僅提供現場遊玩*\n一款中度偏重的推理策略遊戲，玩家扮演煉金術士，透過實驗來測試不同藥材的組合，推理出八種藥材的鍊金方程式，並發表論文來獲得聲望。','\n',char(10)),'https://i.postimg.cc/05f9jrqQ/image.png','僅供現場玩,策略,推理',2,4,'專家',1,0,1,1,0,0,0,50,51,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(152,'地產大亨台灣版','經典的房地產交易遊戲《大富翁》的台灣主題版本，玩家在圖版上移動，購買台灣各地的地產並向過路的對手收取租金，目標是讓所有對手破產。','https://i.postimg.cc/xdy45J5N/image.png','租借,家庭',2,6,'簡單',1,0,1,1,699,100,600,50,52,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(153,'哆寶/嗒寶',replace('由法國 Asmodee發行、Dobble (Spot It)，就是你能訓練小朋友的反應力及對圖案的辨識力。圓型鐵盒輕巧好攜帶，讓你一路玩著走! 比心臟病更刺激，更好玩。 試試看，小心大家都上癮喔!\n\n就是它、發現它，你贏了！ 遊戲中任2張卡，總有且只有一個一樣符號。 多人參加4種玩法，要銳利眼睛和敏捷反應喔!','\n',char(10)),'https://i.postimg.cc/Bbt7Jh02/image.png','租借,家庭,兒童,反應',2,8,'簡單',2,1,1,1,500,50,500,50,53,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(154,'環遊世界80天',replace('改編自知名小說與桌遊"龜兔賽跑"，\n榮獲第一屆德國年度最佳遊戲(Spiel des Jahres)！\n西元1872年10月2日，斐利亞福克自誇可在80天內完成環遊世界一周，\n同是革新俱樂部的成員們向他下了一場賭注，不相信這位個性古怪的紈绔子弟可以成功，\n於是他和忠心的僕人路路通旋即啟程，不過艱鉅的挑戰隨之而來...\n英格蘭 50,000英鎊劫案不幸同時發生，讓斐利亞福克背上 大盜的首要罪嫌！\n你能在世人面前成功地證明你的清白，並實現環遊世界80天的壯舉嗎？','\n',char(10)),'https://i.postimg.cc/SQwHyhns/80.png','販售,家庭',2,6,'普通',1,1,0,1,1300,0,0,50,54,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(155,'仙境幽谷',replace('*僅供現場遊玩*\n在迷人的永恆幽谷裡面，下面是如高塔矗立的樹木枝葉，\n在蜿蜒的河流和苔癬遍布的洞穴之間，一個森林動物的文明世界正在繁衍擴張。\n從長寒地到鈴歌地，一年年過去永恆不變，但是現在，尋找新領土來建立新城市的時候到了。\n你會是一隊動物的領袖來執行這個任務。有建築物要建造，和其他角色見面，事件要處理 - 你將要面對忙碌的一年。\n你能夠在寒冬之月升起前，讓明亮的陽光照耀在你的城市上嗎？','\n',char(10)),'https://i.postimg.cc/RF2pV7V8/image.png','僅供現場玩,策略,卡牌',1,4,'困難',1,1,0,1,0,0,0,50,55,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(156,'殭屍貓的試膽大會',replace('日本正式授權人氣商品全球首發\n可愛又恐怖的試膽大會正式展開!\n派對遊戲熱門首選！','\n',char(10)),'https://i.postimg.cc/c1YXB8Jx/image.png','販售,租借,派對,家庭,小品',2,6,'簡單',2,1,1,1,590,100,500,50,56,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(157,'鍛骰物語 ',replace('你是被諸神選上的勇士之一。\n在鍛骰物語中依照自己的喜好自由組裝骰子，收集黃金跟日月碎片，獻給諸神並邁向榮耀之路！','\n',char(10)),'https://i.postimg.cc/ZRNFH147/image.png','販售,租借,策略,骰子,卡牌',2,4,'普通',2,1,1,1,1550,200,1500,50,57,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(158,'驚滔駭浪RIFF RAFF',replace('這是一款平衡遊戲，玩家將裝載的木製指示物轉向搖擺不定的木船。\n瓶子、水手、老鼠和其他貨物被放置在船體和從桅杆伸出的三個碼臂上。\n第一個將所有物品擺完的玩家贏得遊戲','\n',char(10)),'https://i.postimg.cc/GhXYFcv3/image.png','租借,平衡,家庭',2,4,'簡單',1,0,1,1,2650,300,2600,50,58,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(159,'妙筆神猜',replace('你知道斑馬長什麼樣子嗎？你畫得出來嗎？\n不會？！那這個遊戲就是專為你設計的！\n只要能讓其他玩家看出你畫的斑馬不是車子就夠了！\n\n玩妙筆神猜時每個人畫一個謎題，同時也猜別人所畫的謎底，遊戲時間不足以讓你畫一幅傑作，你最好能用簡單的筆觸畫個簡圖來表達你的謎題，這樣你就有更多時間來猜測其它玩家的謎底。\n計分方式簡單而精彩，讓猜對的人和畫得正確的人都得分，動作快的人也有額外加分喔！\n\n','\n',char(10)),'https://i.postimg.cc/bw2JZ8TB/image.png','租借,派對,家庭,繪畫',3,6,'簡單',1,0,1,1,1490,150,1400,50,59,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(160,'馬拉開波',replace('*僅供現場遊玩*\n馬拉開波是款由Alexander Pfister設計，可1~4人遊玩的全新策略遊戲。背景是17世紀的加勒比海。\n在約莫為玩家人數乘以40分鐘的遊戲時間中，玩家要在4輪內盡可能增加他們在三個國家中的影響力。\n玩家要揚帆航行周遊加勒比海，過程中你將擁有城市板塊來讓你執行各種行動、或供你運送販賣貨物。\n比較特殊的地方是遊戲中的任務模式，讓玩家在隨著過程遊歷諸城的同時能夠體會到其中的小故事。\n移動的同時也會需要玩家調度及使用卡片，有玩過該設計師其他遊戲的玩家對這部分一定不陌生。','\n',char(10)),'https://i.postimg.cc/K8yX52bV/image.png','僅供現場玩,策略,卡牌',1,4,'困難',1,0,1,1,0,0,0,50,60,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(161,'實話實說','認識別人眼中的你！「實話實說」系列佳評如潮，援引周哈理窗，帶你認識「公開我」、「未知我」、「盲目我」、「隱藏我」等四大面向。聯誼、派對、輔導等，遊戲體驗好玩又好用！','https://i.postimg.cc/Pfpr3dGr/image.png','租借,派對,家庭',3,5,'簡單',2,0,2,1,250,50,200,50,61,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(162,'找找醜比頭','眼力與記憶力的大考驗！16隻醜比頭分別在畫面中出現，請正確找出目標醜比頭目前的所在位置吧！ 爬到樹上的粉屁桃、出現在古埃及壁畫上的黃金寶、愛打架的小花頭..... 誰能依據不同任務，累積找到最多醜比頭，成為醜比頭專家呢？','https://i.postimg.cc/tg49hjtb/image.png','販售,兒童,家庭,記憶',2,6,'簡單',1,1,0,1,590,0,0,50,62,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(163,'水下城市',replace('*此款僅提供現場遊玩*\n遊戲的核心觀念是卡片放置。三種色卡要沿著主要圖板邊緣放在3 x 5的格子裡面，格子也有顏色。\n\n玩家可以把卡片放入同色的格子，那麼他們就可以同時進行行動和優勢：行動和卡片優勢在主要圖板的格子上都有說明。','\n',char(10)),'https://i.postimg.cc/j5WKF4Fk/image.png','僅供現場玩,策略,卡牌,建設',1,4,'困難',1,0,1,1,0,0,0,50,63,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(164,'靈跡島 Spirit Island',replace('*此款僅提供現場遊玩*\n在世界最遙遠的邊境，魔法仍舊存在，透過大地、天空和所有自然事物的精靈來施展。當歐洲殖民帝國的勢力持續擴張，他們將無可避免地將觸手伸到精靈之地 - 這時，大地本身和島民將猛烈抵抗。\n\n            \n精靈島是一款複雜的主題式合作遊戲，關於保護你的島嶼家園抵抗殖民入侵者。玩家是島上不同的精靈，各有自己的元素力量。每一個回合，玩家同時選擇要使用哪一張力量卡，接著支付能量來打出。使用符合精靈元素屬性的力量卡組合可以獲得免費的加成效果。較快的力量可以在入侵者擴張之前立刻發生效果，但是其他的魔法就比較慢，需要有遠見地計畫來發揮影響力。在精靈階段，精靈會獲得能量，並且選擇如何/是否成長：收回力量卡、尋找新力量或散播到島嶼的新區域。\n           \n入侵者透過一種半預測性的方式在島上擴張。每個回合他們會探索一些土地(島嶼的一部份)；而在下一回合他們就會在土地上建造殖民地和城市。在下一個回合他們就會蹂躪該處，給土地帶來荒蕪並攻擊島民。\n           \n島民被攻擊時會反擊，同時給予精靈支援，但是無法總是在你需要時出現。有些力量要透過島民發揮作用，幫助他們驅逐入侵者或清除荒蕪的土地。\n           \n遊戲的規模會逐步擴大：精靈散播他們的存在到島上新的區域，並且尋找更多新的強大力量，而入侵者則建立他們的殖民地。每個回合代表架空歷史的1到3年。\n             ','\n',char(10)),'https://i.postimg.cc/2yFtcqrK/image.png','僅供現場玩,策略,合作,卡牌,角色能力',1,4,'專家',1,1,0,1,0,0,0,50,64,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(165,'蜥蓋','蜥蓋遊戲人數:2-6人遊戲時間:20分鐘推薦年齡:6歲以上遊戲背景：這是一個競爭激烈的蜥蜴世界，當繁殖季節來到，雄性「側斑猶他蜥」為了爭奪生存的土地與繁衍後代，展開一場大戰，要怎麼讓自己所屬的品種能夠獨霸一方，就看你如何有技巧的阻斷其他蜥蜴進行繁殖，只要能讓自己的族群繁衍昌盛，就能成為該島嶼的王者。遊戲目的:最快完成所屬蜥蜴的連線。','https://i.postimg.cc/y8Wf9pg5/image.png','租借,家庭,兒童,小品',2,6,'簡單',2,1,1,1,260,50,200,50,65,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(166,'王國製圖師',replace('女王吉娜下令開拓北方的土地。作為一位王國製圖師，你被派往北方繪製地圖以宣稱這片領土屬於納洛斯王國。女王將透過正式的法令宣告她最重視哪些土地，如果你能滿足她的要求，你的聲望將會提高。\n\n在這片荒野之中並非沒有任何人存在。在此定居的德拉古人將派出他們的前哨部隊與你爭奪領土的所有權，所以你必須盡可能地與他們劃清界線，以降低他們對王國的影響力。如果你能圈起最多女王想要的土地，那麼你將成為王國裡最偉大的製圖師。','\n',char(10)),'https://i.postimg.cc/Y9N8kJZ4/image.png','租借,策略,家庭,繪畫',1,99,'普通',1,0,1,1,850,100,900,50,66,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(167,'天生絕配',replace('想知道誰跟你的想法最像嗎？這款遊戲幫你立刻找到同溫層！\n這是一款可以確認彼此想法的派對遊戲，遊戲設計了300條主題，以及一套都是圖片的聯想牌，玩家們透過聯想牌表達對主題的想法，在眾多卡牌中，誰跟你十分有默契的選擇了相同的卡牌，或許你們就是命中注定的天生絕配哦！','\n',char(10)),'https://i.postimg.cc/8P7Wm24h/image.png','租借,派對',3,8,'簡單',1,0,1,1,990,100,900,50,67,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(168,'禪道 Zendo',replace('*僅提供現場遊玩*\n邏輯推理遊戲，比想像的難哦!!\n遊戲由一位玩家扮演禪宗大師, 向其他求道者出題. 大家利用遊戲配件拼砌出不同的作品, 大師會告訴該作品是否「有道」(是否遵循特定的規則). 最先「得道」(看出特定規則)的人...就可以下山了.','\n',char(10)),'https://i.postimg.cc/B6wb8vdR/ZENDO.png','僅供現場玩,派對,推理',2,6,'普通',1,1,0,1,1200,0,0,50,68,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(169,'HINT 限時快猜',replace('你會 模仿 雞尾酒嗎？\n你會 哼唱 經典電影配樂嗎？\n在《限時快猜》派對遊戲中，你的隊友必須試著猜出你費盡心思給出的提示\n\n而你可以根據題目採用模仿、哼唱、繪圖、說話等方式\n但千萬小心，每道題目都有一個不能讓隊友答出的禁語\n如果不慎答出，將立即讓你們那隊遭受扣分懲罰。','\n',char(10)),'https://i.postimg.cc/Nj706D36/HINT.png','租借,派對,家庭,說話',4,99,'簡單',1,1,0,1,650,0,0,50,69,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(170,'蟹霸王','作為一個經驗老道的捕蟹達人，迅速的帶上你的裝備，加入這次的盛會吧！技術嫻熟地從各個角落找出一隻隻看似美味的螃蟹。不斷有補蟹人從各地慕名而來，再次迎來了螃蟹的季節！這個平靜的海岸，','https://i.postimg.cc/kM6KQrfW/image.png','租借,家庭,小品',3,5,'簡單',2,1,1,1,450,50,400,50,70,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(171,'文明繪卷',replace('*此款僅提供現場遊玩*\n文明繪卷是由Jamey Stegmaier設計，1~5人遊玩，時間約2小時的文明遊戲。\n\n從史前文明直至未來時代，創造一個擁有最多淵源歷史的文明，而你選擇的發展途徑會對這個世界及人民產生巨大的影響 - 你的文明是獨一無二的！\n\n在文明繪卷中，你將從零開始，推進4種發展軌(科學、工業、探索、軍事)來獲得發展的優勢，要專精於單項或是平衡發展皆取決於你。\n\n同時你也會提升國家的收入，建設首都，在眾多能力中抉擇，並獲得勝利點數。\n\n而在過程中獲得的文明繪卷卡將會鉅細靡遺的述說著你的國家文明史詩。','\n',char(10)),'https://i.postimg.cc/0yfwk9y1/image.png','僅供現場玩,策略,卡牌,角色能力,區域佔領',1,5,'困難',1,1,0,1,0,0,0,50,71,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(172,'繽紛夜光蟲','美麗繽紛的夜光蟲，在夜晚的水池邊嬉戲，快來用瓶子將牠們蒐集起來。遊戲最大的特色就是有超多美美的骰子，蒐集起來的時候非常賞心悅目。','https://i.postimg.cc/76Th24w6/image.png','販售,家庭',2,4,'簡單',1,1,0,1,1200,0,0,50,72,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(173,'路易斯與克拉克',replace('*此款僅提供現場遊玩*\n一款結合牌庫構築與工人擺放的競速遊戲，遊戲機制放到現在還是相當特別，獨特的機制再加上歷史背景，相當推薦此款策略遊戲。','\n',char(10)),'https://i.postimg.cc/59S1ky7J/image.png','僅供現場玩,策略,競速,卡牌構築',1,5,'普通',1,1,0,1,0,0,0,50,73,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(174,'獨家專輯',replace('★會是五音不全還是完美和聲呢？嘗試為播放清單找到完美的封面\n★將樂曲的音量調高，並和你的朋友與家人沉浸在音樂中！','\n',char(10)),'https://i.postimg.cc/XNLSkhq7/image.png','販售,小品,說話,投票',3,8,'簡單',1,1,0,1,750,0,0,50,74,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(175,'陰間條例：夜巡篇',replace('七爺八爺牛頭馬面，全員出動!! — 陰間條例 夜巡篇\n\n\n\n鬼門關，還沒離開的好兄弟誰來收？就靠你在全新登場「夜巡篇」裡降妖除魔囉！\n\n\n\n座落在生死交界的夜神旅店，有著無數的房間，每個房間都是來訪旅客生前最後的記憶。旅店的盡頭有一間特殊房間，房內雜揉著旅客們的善惡因果，前往陰間前的亡靈最終都會在這間房間經歷一場審判，而房間的主人正是城隍。某天旅店內突然發生一場騷動，原本安分徘徊於旅店內等待審判的亡靈們突然躁動喧鬧、大肆破壞，吵鬧的聲響驚動到旅館內的陰間執法者 — 『七爺』與『八爺』試圖盡快找出騷動的源頭，生怕驚動到城隍，但為時已晚...\n『夜巡...開始!』夜神旅店深處傳來城隍指令與讓人恐懼的威壓。','\n',char(10)),'https://i.postimg.cc/c1X2nnkv/image.png','租借,小品',3,6,'普通',1,0,1,1,540,100,500,50,75,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(176,'展翅翱翔 (Wingspan)',replace('*此款僅提供現場遊玩*\n展翅翱翔（Wingspan）是款由Stonemaier Games出品的競爭類、中量級、卡牌驅動、引擎搭建桌遊。\n你們扮演著鳥類愛好者－研究員、鳥類觀察家、鳥類學者，以及收藏家¬－藉由搜查進而發現並吸引最好的鳥兒到你的鳥園。\n\n每隻鳥都會對於你的其中一座棲息地（行動）延伸出連鎖的強力組合。每座棲息地都有著幾項獨特的關鍵發展方向。\n\n在鳥類餵食器骰塔中，透過自訂骰子取得食物標記\n使用鳥蛋模型誕生不同顏色的蛋\n抽取上百張獨特的鳥卡而後打出它們\n四局後最高分的玩家為贏家\n此款遊戲好玩到我們認為這款遊戲會在你的桌上起飛','\n',char(10)),'https://i.postimg.cc/xCgxMwRw/image.png','僅供現場玩,策略,家庭,卡牌',1,5,'普通',1,1,0,1,0,0,0,50,76,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(177,'密語幸運草',replace('抽取關鍵字卡牌，在四葉草圖版上秘密地寫下它們的共同特徵；這些共同特徵是\n您的線索。然後齊心協力，設法猜出每一名玩家寫下的關鍵字。遊戲結束時，根據\n你們猜出的關鍵字數量，相加得出你們的總分，寫在「傳奇記錄」榜單中。\n努力在每一局遊戲中刷新高分記錄吧！','\n',char(10)),'https://i.postimg.cc/dtgW2m2V/image.png','販售,派對,家庭,合作',3,6,'簡單',1,1,0,1,790,0,0,50,77,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(178,'眨眨眼',replace('眨眨眼，誰是我的夥伴呢？ 這是個適合在派對時遊玩的遊戲,玩家需要靠著眨眼的暗示來找到跟他有同張卡片的夥伴！\n但說者有意、聽著無心，要想辦法讓在天涯一方的夥伴接收到你的暗號，玩起來其實沒那麼簡單喲！ 但要小心，其他玩家也可以抓到你的暗示喔，所以要小心不要讓別人發現，偷偷地傳送暗示給你的夥伴吧！ ','\n',char(10)),'https://i.postimg.cc/QC9QCwnk/image.png','販售,派對,家庭',4,8,'簡單',1,1,0,1,690,0,0,50,78,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(179,'蟲蟲拍拍','蟲蟲拍拍遊戲人數:2-4人遊戲時間:15分鐘推薦年齡:5歲以上遊戲背景：拍拍草原」裡資源豐富，有各式各樣色彩繽紛的昆蟲藏身其中，不同的昆蟲要用不同的工具來捕捉才不會傷到牠們喔！快來「拍拍」發現昆蟲。別忘了觀察完畢，要把昆蟲放回家喔！遊戲目的:使用正確的工具抓到最多隻昆蟲。','https://i.postimg.cc/263v9gmR/image.png','兒童,家庭,反應',2,6,'簡單',2,1,1,1,250,50,200,50,79,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(180,'西國聖騎士',replace('*此款僅提供現場遊玩*\n《西方王國聖騎士》設定在西法國騷亂時刻的故事，大約在公元900年。\n縱然近來努力發展城市，偏遠城鎮仍持續處於外邦的威脅中。\n\n薩拉森人在邊界偵查，同時維京人掠奪財富漢聲口，甚至東方的拜占庭人也展露其黑暗面。\n\n玩家扮演貴族男女，必須從城市徵集工人以抵禦敵人、建設要塞並在領地中散播信仰。\n幸運的是你並不孤單，在這座偉大王國中，國王派出他最優秀的騎士以提供各位幫手，所以準備好馬匹、磨利寶劍，聖騎士正在接近。','\n',char(10)),'https://i.postimg.cc/28WFwMFL/image.png','僅供現場玩,策略,工人擺放',1,4,'困難',1,1,0,1,0,0,0,50,80,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(181,'一網打盡',replace('在德國漢堡港口的魚市拍賣中，大盤商叫賣著：「來來來，來買上好的新鮮魚貨啊！首先是兩隻龍蝦⋯⋯再來是兩條鰻魚⋯⋯只賣10元喔！沒有人要？那我再加上一隻龍蝦⋯⋯來了個「偷魚賊」⋯⋯再猶豫就買不到囉！⋯⋯好吧，賠本大放送，加三條比目魚⋯⋯」\n「叮！」鈴聲響起「成交！」\n「感謝戴藍色帽子的老闆，一共是10歐元，謝謝您的惠顧。」\n\n這是一筆好買賣嗎？\n只有眼光獨到且下標快狠準的玩家，才能成為賺大錢的魚販喔！','\n',char(10)),'https://i.postimg.cc/pdsDrHx4/image.png','販售,家庭',3,5,'簡單',1,1,0,1,890,0,0,50,81,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(182,'迷霧島',replace('傳說中，奧克拉科克島是海盜的天堂，也是黑鬍子最神祕的巢穴。\n\n為了慶祝劫掠的豐收，黑鬍子在這裡舉辦了盛大的派對，邀請了許多海上的亡命之徒，\n\n一起慶祝。但是，派對來到高潮時，海軍的砲火打斷了所有人的興致。大家紛紛拿取僅存的財物，\n\n趕緊開溜。不過，黑鬍子最心愛的一艘船：安妮皇后復仇號上，載滿了搶奪而來的寶藏，\n\n為了避免被海軍沒收，黑鬍子此時只能帶領部下奮力一搏了！若你是海軍，為了海軍的榮耀，\n\n努力將黑鬍子逮捕歸案！不然，就趕緊拾起地上的金幣開溜！','\n',char(10)),'https://i.postimg.cc/nhZ71zhN/image.png','租借,小品',2,4,'簡單',1,0,1,1,320,50,300,50,82,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(183,'方舟動物園 (Ark Nova)',replace('*此款僅提供現場遊玩*\n在《方舟動物園》中，你將規劃並設計一座充滿現代化、科學化管理的動物園。\n你將建造飼養區、安置動物，並在全球各地支持各種動物保護項目，以求努力打造出最成功的動物學機構。\n各類專家以及獨特的建築都將協助你實現這一目標。\n\n\n《方舟動物園》的核心由255張卡牌構成，涉及動物、專家、獨特建築以及保護項目，每張卡牌都具有特定的能力。\n使用它們來增加你動物園的魅力以及科研聲望，並收穫保護點數。\n每位玩家均有一套行動卡牌，你將通過使用並升級它們來實現你的計劃。\n\n','\n',char(10)),'https://i.postimg.cc/0Q6JNKVK/image.png','僅供現場玩,策略,卡牌,板塊拼放',1,4,'專家',1,1,0,1,0,0,0,50,83,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(184,'地城對決',replace('《地城對決》是一款兩人對戰的卡牌遊戲，不同於《魔法風雲會》或是《鍛鑰者》這類抽象空間中的卡片效果攻防，玩家在《地城對決》中會在有地城空間深度的牌池上輪流選擇一張卡片來使用。\n\n卡片可以用來招募夥伴、撿拾寶物、打倒魔物、學習魔法、成長職業、發動陷阱、挑戰魔王等等，有更豐富的情境體驗！','\n',char(10)),'https://i.postimg.cc/cCwgRyys/image.png','販售,雙人',2,2,'普通',1,1,0,1,800,0,0,50,84,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(185,'深淵密謀 (Conspiracy)',replace('爾虞我詐，權力鬥爭  — 深淵密謀\n\n\n\n此款有5種封面外盒，採隨機出貨\n\n如果有想要指定外觀歡迎私訊詢問庫存喔QQ\n\n\n\n與深淵之王(Abyss)同樣背景與美術的策略小品遊戲。\n\n\n\n在深海之處的深淵之國，陰謀與腐敗乃是日常生活中的主旋律。而深海會議則正是這種永恆的權力鬥爭的核心舞台，各方勢力都密謀著打擊對手，獲取更多的影響力。\n你必須搶在你對手之前匯聚最具威望的深海領主們，並且確保你的會議內閣井然有序。','\n',char(10)),'https://i.postimg.cc/90d04dZ0/image.png','租借,小品',2,4,'簡單',1,0,1,1,490,50,400,50,85,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(186,'骰子街','骰子街是款快節奏，運用點小心機的刺激歡樂遊戲。憑藉著夢想，以及我們所信賴的骰子，您必須把骰子街建設成這片土地上最大的城市，只是沒有錢萬萬不能，您必須靠城市的發展與公共建設來賺取資金，當然，從鄰居身上撈點好處也是不錯的作法。不過小心，你的鄰居也瞄準好你的口袋了。','https://i.postimg.cc/SKHxDTGj/image.png','租借,家庭,骰子',2,4,'普通',2,0,2,1,750,100,700,50,86,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(187,'王都布拉格',replace('查理四世被加冕為波西米亞國王並統治著神聖羅馬帝國。從他的布拉格城堡，可以俯視這新城寨的各個建設：橫跨伏爾塔瓦河的橋樑、大學、以及在城牆內緩緩升起的大教堂。布拉格已為歐洲著名的大城市，而查理王則更進一步，將其建設為帝國的首都！\n\n在"王都布拉格"中，玩家扮演在中古世紀的布拉格中要規劃城市建築的富有市民，\n\n藉著參與城市建設以及增加自身的財產，你將獲得國王的敬重與名聲。\n\n玩家在遊戲圖板"行動地基"上的六種行動中選擇，這些行動永遠可以執行，但費用和收益則是會持續變動。\n\n藉由這些行動，你可以增加你的資源，強化你選擇的行動，以及建造查理橋、城牆與"新布拉格市"。\n\n你也可能會獲得額外的行動，甚至參與聖維特大教堂的建設。\n\n聰明的玩家將會發現仔細規劃時機的行動與自建設城市計畫網中獲得的收益，兩者之間微妙的關聯。\n\n在遊戲結束時，讓查理王印象最深刻的玩家獲勝','\n',char(10)),'https://i.postimg.cc/8z8wgNPb/image.png','租借,策略',2,4,'困難',1,0,1,1,2800,300,2800,50,87,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(188,'來杯兔兔',replace('「來杯兔兔」咖啡廳熱鬧開張！快來喝一杯兔兔店長的特調飲品!!\n每杯飲料上都有特製的兔兔奶泡與美味配料，多種變化讓人眼花撩亂。\n\n今天你與朋友們想喝哪種飲料呢?\n\n趕緊「來杯兔兔」吧! 如果沒有看到合適的飲料，代表兔兔店長又忘記了~趕快提醒兔兔店長，晚了就喝不到了!','\n',char(10)),'https://i.postimg.cc/6Q8d8P3Q/image.png','租借,反應,小品,家庭',2,6,'簡單',1,0,1,1,390,50,300,50,88,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(189,'台灣愛玩客',replace('「台灣愛玩客(Taiwan Walker)」遊戲的原型為韓國的「濟州島(Jeju Island)」，為2015年由Yeon-Min Jung、Gary Kim及Jun-Hyup Kim所設計，遊戲過程益智趣味。栢龍玩具與胖胖熊將此遊戲代理後，為了更貼近台灣人的生活喜好，將其重製成「台灣愛玩客」，所有插畫皆已本土化，並於2017年發行。遊戲中玩家們扮演著愛玩客，在台灣寶島上到處遊覽，沿途收集觀光板塊，並換取擁有特殊效能的分數卡。遊戲進行時，玩家可選擇遊覽及收集觀光板塊，或是使用觀光板塊換取分數卡。當遊戲圖板上已無觀光板塊，或分數卡牌列無法補齊時，遊戲即告結束。玩家們分別計算自家最後所獲得的分數，分數最高者即為遊戲贏家。\n\n','\n',char(10)),'https://i.postimg.cc/jSw5PYzB/image.png','租借,家庭',2,4,'簡單',1,0,1,1,790,100,700,50,89,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(190,'吸爆鬆餅',replace('超ㄎ一ㄤ的隨機派對遊戲「吸爆鬆餅」出爐啦！\n★國外KS募資超過三千萬，創新概念派對遊戲\n★超胡鬧的派對遊戲，帶給你歡樂的小聚時光','\n',char(10)),'https://i.postimg.cc/52Sxw9X7/image.png','租借,派對,卡牌',2,8,'簡單',2,1,1,1,790,100,700,50,90,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(191,'OPEN!賓果派對','療癒系桌遊，5隻萌萌滴 OPEN 家族公仔! 釋放你的療癒fu ~ OPEN PARTY 賓果派對是由 7-11 與 KIDDY KIDDO 合作的最新親子產品，簡單易懂的遊戲方式，不管大朋友或小朋友，絕對是適合全家一起玩的 OPEN系列桌遊，可愛的小公仔在轉盤上跑跳著，考驗著小朋友的觀察力、反應力與運氣呢，看最先把公仔們排列正確，大聲地喊出 OPEN 賓果吧!','https://i.postimg.cc/rFSckyNV/open.png','販售,兒童,家庭',2,5,'簡單',1,1,0,1,469,0,0,50,91,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(192,'馬尼拉',replace('現在是西元1821年，西班牙人控制菲律賓島嶼已經250年了。但是，直到目前為止，西班牙人並未實際控制一切。\n在殖民地的權力背後，一些固執己見的本地人已經建立起與鄰近島嶼以及亞洲大陸的秘密的海洋貿易管道。\n這些黑市商人使用看起來非常奇特的平底船以及脆弱的竹筏，將肉豆蔻，絲綢，玉，以及人蔘填滿他們的船，並且將它們走私運進馬尼拉。\n每一次投機活動的勝算並不明確，船長與船在海中的適航性也相當貧乏。\n海盜在旁伺機劫掠那些無法從他們手中逃脫的船，為這些船增添幾些不幸。\n\n想要親身體驗馬尼拉黑市交易的過程嗎？\n快來瞧瞧吧！','\n',char(10)),'https://i.postimg.cc/m2NxnXTh/image.png','租借,家庭,骰子',3,5,'普通',1,0,1,1,1690,200,1600,50,92,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(193,'積木式 西洋棋','一款經典的雙人抽象戰略棋盤遊戲，雙方各有16枚棋子，目標是透過不同的兵種移動規則，將死對方的國王。','https://i.postimg.cc/j5N3725C/image.png','租借,下棋,雙人',2,2,'普通',1,0,1,1,240,50,200,50,93,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(194,'拾貓鍋',replace('可愛的貓咪萌系桌遊第二彈！輕鬆簡單的規則玩法，熱鬧有趣的遊戲\n\n機制，快跟朋友一起做出最完美的貓鍋！','\n',char(10)),'https://i.postimg.cc/76xJgQP7/image.png','租借,家庭,兒童,小品,骰子',2,6,'簡單',1,0,1,1,450,50,400,50,94,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(195,'天恩湖',replace('你遠離文明來到了這蠻荒之地。身為拓荒者的一員，你在天恩湖荒廢的湖畔安頓了下來。這個地區沒有被開發過，但顯然有人在這裡生活，這些聚落吸引著你！融入人群並對公眾事務做出貢獻。探索地區、建造房屋與聚落、飼養牲畜、蒐集建材來完成更多建設，並改革這些過程讓一切更現代化。抓住機會，親手打造你在天恩湖的完美新生活。\n\n\n\n在這款由Alexander Pfister設計的的遊戲中，你的目標是改善你自己與你的跟隨者們的生活，而要如何達成全部操之在你。如同說故事般的行動過程會讓每場遊戲都與眾不同。你會是專注在擴張呢？或是致力於建造各種設施？還是你有屬於自己的其他追求？謹慎思考你的每個行動：不只是因為它們之間會互相影響，也影響了你的帆船能航行多遠，越快、越遠就越好，因為只有最老練的水手才能得到最棒的獎勵......。','\n',char(10)),'https://i.postimg.cc/sfHGhckQ/image.png','販售,策略,卡牌',2,4,'困難',4,4,0,1,2400,0,0,50,95,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(196,'太公望',replace('記得小時候總是會在夏天午後跟著大哥哥一起到溪邊釣魚的美好時光嗎？\n如果你沒有經歷過這樣充滿活力與期待魚兒上鉤的童年，千萬不要難過，今天就讓我們一起在桌上來一場釣魚大賽吧！\n不過今天要用的釣竿和魚餌非常非常特殊，我們要用骰子來釣魚喔～','\n',char(10)),'https://i.postimg.cc/8CwzVkDJ/image.png','租借,骰子,小品',2,4,'簡單',2,0,2,1,600,100,600,50,96,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(197,'跳跳骰',replace('這款遊戲已經不需多做介紹，當你們想要家人團聚、朋友狂歡，這款遊戲絕對最適合！\n簡單到不行的遊戲規則，卻能帶來最爆笑歡樂的氣氛！\n\n《跳跳骰》新版CP值更高！價格減少、質感卻一點也沒少，聚會就差這一盒～～～','\n',char(10)),'https://i.postimg.cc/HnCCfpYP/IMG-20251014-205415.jpg','販售,租借,家庭,兒童,骰子',2,4,'簡單',2,1,1,1,1250,150,1200,50,97,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(198,'拉長島',replace('「拉長島」由熱門經典數字牌遊戲改編，即使是小小孩，也可以自行學會這款沒有數字的遊戲。\n只要1張頭部牌和1張尾部牌便能組合成一隻動物，腹部牌能讓你創造來自拉長島的特有動物，為孩童帶給無限歡樂。\n\n率先出清手牌的玩家獲勝！','\n',char(10)),'https://i.postimg.cc/P55tQs1d/image.png','租借,家庭,兒童,小品',2,5,'簡單',1,0,1,1,490,50,400,50,98,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(199,'賽馬大亨',replace('《賽馬大亨》以四場賽馬為一局的即時賽馬遊戲，玩家會在每場賽事進行期間下注，並在賽後結算投注結果。玩家不僅可贏取貴賓獎勵，還可以通過在特別彩池中下注來增加遊戲體驗。經過四場賽事之後，贏得最多彩金的玩家獲勝！\n\n \n\n《賽馬大亨》除了可用傳統的擲骰子決定賽馬結果外，也可使用內置的apps感受即時買馬的快感。當中更有廣東話配音讓你感受賽馬直擊。當中也可以自由選擇遊戲速度，要每秒都有馬在前進的分秒必爭賽局還是一步一驚心的賭局式賽局，全由你去安排。快來下注與好友享受賽馬的快感。','\n',char(10)),'https://i.postimg.cc/tJbb1LXQ/image.png','租借,策略,家庭,',2,9,'簡單',1,0,1,1,1190,150,1100,50,99,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(200,'帽子大風吹/魔法帽',replace('小姐戴上維京帽？船長頂著王冠？就像一陣大風吹，把大家的帽子都吹亂了！快幫他們找到正確的帽子戴上，不然會變成光頭喔！\n別怕！找到魔法帽便能解救光頭！\n\n','\n',char(10)),'https://i.postimg.cc/VsFQGZfv/image.png','租借,兒童,家庭,記憶',2,4,'簡單',1,0,1,1,390,50,300,50,100,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(201,'熱力狂飆 HEAT',replace('*此款僅提供現場遊玩*\n★埃森桌遊展話題之作，體驗最Hot的賽車遊戲！\n★簡單而直覺的手牌管理遊戲，各式模組增加遊玩樂趣','\n',char(10)),'https://i.postimg.cc/mDRp7RFw/HEAT.png','僅供現場玩,策略,家庭,卡牌,競速',1,6,'普通',1,0,1,1,0,0,0,50,101,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(202,'小小工廠',replace('★【小小村莊】系列續作\n★資源管理－輕度策略的卡牌遊戲\n★ 給你強烈的“創業”感：用很少的錢起家，成為競爭對手中成長最快的那位','\n',char(10)),'https://i.postimg.cc/W4mXNKfJ/image.png','販售,租借,家庭,小品',2,4,'普通',2,1,1,1,700,100,700,50,102,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(203,'給我餅乾','你是一個有超大胃口的怪獸，急著想吃到被藏起來的甜點。你能搶在別人之前，循著線索，找到美味的點心嗎？','https://i.postimg.cc/q7rx5wMB/image.png','租借,兒童',2,5,'簡單',1,0,1,1,550,100,500,50,103,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(204,'奧地利大飯店',replace('*此款僅提供現場遊玩*\n二十世紀初，維也納是歐洲的主要城市之一。\n城市的街道上人流如織，藝術家，政治家，貴族，市民和觀光遊客隨處可見，\n\n而皇帝統治著整個帝國的一切。\n\n你正身處當時維也納的動盪時代，作為旅店老闆一直小心經營。\n\n為此，你必須擴張你的旅店並及時準備好新房間。\n\n同時，你的客人需要精心烹製的餐飲。\n\n為確保每一位客人都能享用到適合口味的美食，你可能還需要僱傭額外的員工。\n\n儘管如此，也別忘記經常向皇帝致以敬意，否則你很快就會受到懲罰。\n\n迎接各項挑戰，最終將你的飯店打造成名副其實的奧地利大飯店！\n\n','\n',char(10)),'https://i.postimg.cc/wMnhccGp/image.png','僅供現場玩,策略,卡牌,骰子',2,4,'困難',1,1,0,1,0,0,0,50,104,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(205,'地產大亨/愛台客走跳台灣電子版','首度與台灣最知名的媒體之一"三立"合作,共同推出三立"愛台客地產大亨",22個台灣私房景點,配搭配電子刷卡機,大家一起來體驗玩桌遊的樂趣!','https://i.postimg.cc/mrVC6G5V/image.png','租借,家庭,派對,經典,',2,6,'簡單',1,0,1,1,1399,150,1300,50,105,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(206,'友善魔物與酒館英雄',replace('冒險者充滿好奇心地踏入祭壇深處，眼前浮現出供奉著的祭器。就在這一刻，一股聲音在他的腦海中響起：\n\n『聰明的冒險者啊，如果你渴望了解時間的真相，請碰觸那個祭器！ 你將能夠進入遙遠回憶中，那個已被遺忘的人類與魔物共存的最後世界.....』\n\n『友善的魔物與酒館英雄』是一款工人擺放策略遊戲。 作為領主的玩家們，在四輪遊戲中必須巧妙運用行動，如擴展領地、建設都市、招募人才，以獲得聲望。 每一輪遊戲，你可以選擇「方針」以增加收入，或執行特定行動以獲得聲望獎勵。 方針的選擇與行動順序息息相關，必須根據你的目標來巧妙搭配運用。 此外，遊戲中還能夠與魔物互動，透過不同的行動（如交易、探索、討伐），獲得各種不同的獎勵，以追求更高的聲望。 遊戲結束時，擁有最高聲望的玩家將成為勝利者。','\n',char(10)),'https://i.postimg.cc/VkWK1ph0/image.png','工人擺放,策略',2,4,'普通',1,0,1,1,1380,150,1300,50,106,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(207,'天下無雙小紅帽與貝武夫',replace('★準備好你的牌庫，誰才是天下無雙？\n★節奏明快的微縮模型決鬥遊戲','\n',char(10)),'https://i.postimg.cc/Fzvf9W81/image.png','策略,雙人',2,2,'普通',2,2,0,1,850,0,0,50,107,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(208,'達爾文的旅程','一款重量級的工人擺放策略遊戲，玩家扮演科學家，跟隨達爾文的腳步在加拉巴哥群島進行研究，派遣工人學習、探索、收集標本並發表理論。','https://i.postimg.cc/zXcJ727W/image.png','租借,策略,工人擺放',1,4,'困難',1,0,1,1,2700,300,2700,50,108,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(209,'太空基地',replace('在太空基地中，玩家們是指揮一小支太空艦隊的隊長。你們可把停泊在太空站裏的船艦，而玩家必須贏得最多影響力，從而攀升到艦隊司令一職並勝出遊戲！\n\n每到你的回合時，擲2顆六面骰，所有玩家都會按擲骰結果從自己的卡牌領取獎勵。範例：你擲出了5和6，那麼可選擇根據你版圖上分區5和6的卡牌，領取相應獎勵、或把5加6以領取分區11的卡牌獎勵。須注意，對手回合的擲骰結果不會讓你領取在自己版圖的卡牌的獎勵，改為領取插在玩家版圖上方卡牌的獎勵。當前玩家領取獎勵後，可以購買新牌放在自己玩家版圖，並派遣原本在該分區的牌，把它放到玩家版圖上方。最終獲得最高分的玩家獲勝。','\n',char(10)),'https://i.postimg.cc/qMzrNXr7/image.png','租借,家庭,骰子,combo',2,5,'普通',1,0,1,1,1190,150,1100,50,109,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(210,'招5玩酒',replace('*此款僅提供現場遊玩*\n把團康遊戲從戶外搬到了室內\n我們還貼心的替不喝酒的玩家\n設計了虛擬喝醉系統\n讓不喝酒的玩家們能夠感受那種\n再輸下去就醉了的感覺。','\n',char(10)),'https://i.postimg.cc/9fBK8r2S/5.png','僅供現場玩,派對,小品,反應',4,20,'簡單',1,1,0,1,0,0,0,50,110,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(211,'璀璨都市Cities','簡單的規則，但因為輪流選的規則造就滿滿的互動,不管是搶東西還是搶快，整個遊戲輕快目標也明確，很適合家庭、朋友間快速來一場的輕鬆小策略遊戲。','https://i.postimg.cc/4nCWNgZV/Cities.png','租借,家庭,工人擺放',2,4,'普通',1,0,1,1,1400,150,1400,50,111,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(212,'翻翻海盜 Captain Flip',replace('*此款僅提供現場遊玩*\n一款輕鬆有趣的家庭遊戲，玩家從袋中抽取角色板塊，可以選擇喜歡的一面或另一面（翻面）放置到自己的船上，湊成排或列來得分。','\n',char(10)),'https://i.postimg.cc/SKTFQJP9/image.png','僅供現場玩,家庭,派對,小品',2,4,'簡單',1,1,0,1,0,0,0,50,112,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(213,'蜜蜂物語','嗡嗡嗡！蜜蜂飛到花叢中！玩家們化身蜜蜂，競相採集花蜜。為此你們必須明智地規劃飛行路線，趕在別人之前採集到所需的花蜜，以求符合共用以及秘密的不同目標，爭取最高分數。來機智地規劃路線和儲藏花蜜，在花間展現巧妙的舞步吧！','https://i.postimg.cc/YqfPqvGS/image.png','租借,家庭',2,4,'普通',1,0,1,1,1290,150,1200,50,113,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(214,'夢幻小隊','一款合作遊戲，玩家扮演進入夢境的探險家，要合力對抗夢魘，保護夢境之主。','https://i.postimg.cc/Xqgg3yHS/image.png','租借,派對,家庭,卡牌,牌庫構築',1,8,'普通',1,0,1,1,1200,150,1200,50,114,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(215,'同感悄悄話16+',replace('從感受出發，正經的談「不正經」話題\n\n適合16歲+ (準)成年人的溝通遊戲\n\n情侶、夫妻、密友團暢談悄悄話的好機會\n\n導師們跟年青人探討現代性文化的導入工具\n\n「浪漫的燭光晚餐...... 你的伴侶赤裸裸從廚房走出來。」\n\n你會覺得「有趣」、「恐懼」、「驚奇」、「懷疑」？\n\n318條全新情況題\n\n每張情況牌均有一條性/俏皮話題可選\n玩法依舊簡潔，計分改以團體分為目標以及情緒掛臉的全新畫風。','\n',char(10)),'https://i.postimg.cc/d1PRy9gc/image.png','租借,派對,合作,說話',2,8,'簡單',1,0,1,1,960,100,900,50,115,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(216,'電車難題',replace('陣營攻防 × 道德選擇 × 黑色幽默的極限對決！\n國外知名IP快樂氰化物，惡搞極致的桌遊來啦！\n歡迎搭乘這班「無法停下的電車」，在兩條鐵軌之間，你能做出「正確」的選擇嗎？\n是無辜小狗？還是世界末日的開關？\n\n你要如何說服列車長不要來你這裡，列車長又要如何抉擇才能展示自己的公平道義？\n發揮你們的口才及想像力，一起來解這道世界級的電車難題！\n\n*遊戲內容僅供娛樂，切勿認真看待。','\n',char(10)),'https://i.postimg.cc/FHw3MZrk/image.png','租借,派對,說話',3,13,'簡單',1,0,1,1,1100,150,1100,50,116,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(217,'搖滾巫奇','咻！丟三落四的女巫如閃電般地在魔法黑森林中穿梭，她總是忘東忘西，無論是魔法書、大釜或是掃帚！好在有小精靈，他們非常樂意幫她尋找寶物……和女巫一起滾動，尋找她丟失的魔法寶物。如果你夠靈巧並能和其他玩家巧妙合作，便能在這款快速滾動的遊戲中，找到最多的魔法寶物，獲得最多女巫的獎賞。','https://i.postimg.cc/SR7p4wRG/IMG-20251014-205402.jpg','販售,派對,家庭,兒童',2,5,'簡單',1,1,0,1,1390,0,0,50,117,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(218,'皮諾丘',replace('*此款僅提供現場遊玩*\n玩家一起協助小木偶在探險的旅程中學習分辨是非。\n\n回合玩家先抽出題目卡，然後決定之後說故事的是真實的或虛構的，跟著便開始講出他動人的故事來。\n\n聽故事的人在判斷故事的真實性的同時，亦可認識身邊說故事的人。\n\n','\n',char(10)),'https://i.postimg.cc/NfzHX4rC/image.png','僅供現場玩,派對,說話',4,10,'簡單',1,0,1,1,0,0,0,50,118,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(219,'巴薩利市集',replace('高超的談判技巧讓你叱咤商場！\n每位玩家為了獲得珍貴的寶石，秘密地挑選一項行動，若你是唯一選擇該種行動的玩家，立刻執行吧！若有兩位玩家選擇同一項行動，必須進行競價來決定由誰執行。在巴撒利市集，體驗刺激、緊湊、高度互動，但又簡單易學的談判交易遊戲！','\n',char(10)),'https://i.postimg.cc/1tsnS7LX/image.png','販售,小品',3,5,'簡單',1,1,0,1,590,0,0,50,119,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(220,'杯子蛋糕學院',replace('大家同心協力，一起爭奪杯子蛋糕學院獎項吧！\n1. 將沙漏倒置並展示第一張任務卡。\n2. 依照指示移動杯子蛋糕的位置。\n3. 完成你們的任務卡，接著繼續完成下一張。\n你們能在時間耗盡前完成所有任務嗎？','\n',char(10)),'https://i.postimg.cc/NF0K99Gw/image.png','販售,租借,兒童,家庭,反應,合作',2,4,'簡單',1,0,1,1,900,100,900,50,120,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(221,'ERA中世紀：時代紀元',replace('*此款僅提供現場遊玩*\n《中世紀：時代紀元》作為《骰越世紀》的精神續作而推出。\n若說《骰越世紀》是「擲骰畫紙」類遊戲的先鋒，《中世紀》就是「擲骰構築」的先鋒！\n\n在《紀元》中，你的骰子表示中世紀社會不同階層的玩家，而玩家試圖建造最繁榮的城市。\n透過玩家確實在自己的圖板上興建建築，「構築」要素進入場中。你將使用美麗的3D模型元件，如牆壁、堡壘、農田和其他建築。\n遊戲結束時，每位玩家將有各自獨特的城市！\n\n《中世紀：時代紀元》被設計得更具挑戰性，因為玩家透過諸如敲詐、焦土，還有，理所當然的，疾病，彼此互動！\n嘿，這是中世紀，對吧？說到這個，《紀元》被視為新系列的第一款獨立「擲骰構築」遊戲，\n由麥特．李考克（Matt Leacock）和eggertspiele所推出！','\n',char(10)),'https://i.postimg.cc/Yqh4tWy6/ERA.png','僅供現場玩,策略,骰子,拚放',1,4,'普通',1,0,1,1,0,0,0,50,121,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(222,'秀才遇到幾個兵',replace('在一群天兵中，誰才是出類拔萃的秀才呢?\n這是一款視覺觀察 X 量詞聯想的遊戲，包含四種創意要素，「左右」X「種類」X「數量」X「造詞」\n快來挑戰你的聯想力與反射神經 !','\n',char(10)),'https://i.postimg.cc/W46z56hv/image.png','租借,反應,說話',2,6,'簡單',1,0,1,1,350,50,300,50,122,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(223,'搗蛋王國',replace('《搗蛋王國》是一款別出心裁的排庫構築類遊戲—你的卡牌不僅能讓你在自己的回合執行行動，還能讓你在其他玩家的回合跟隨他們執行行動。\n\n你是會專心致志按照自己的想法獨樹一幟呢?還是會跟隨其他孩子們亦步亦趨呢?\n\n當你還是個孩子時，你的想法大概就是:多交幾個好朋友，左手玩具右手披薩，然後搭造出最壯觀的王國。\n\n想要玩具，想要披薩，想和小夥伴們出去玩，想建兒童樂園......\n\n這些酷斃的事情會給你帶來分數，在遊戲結束時，得分最高的玩家就是遊戲的勝利者!\n\n你要時刻注意—如果你沒法把手上的卡牌全部打完，其他搗蛋鬼們就會把你的牌搶走!\n\n畢竟，如果你不肯陪朋友們玩，那誰又會願意陪在您身邊呢?','\n',char(10)),'https://i.postimg.cc/gj52xgBv/image.png','租借,牌庫構築,建設,combo',2,4,'困難',1,0,1,1,1200,150,1200,50,123,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(224,'火線任務',replace('在《火線任務》中，玩家化身為英勇的消防員\n與夥伴制定消防計畫，果斷的衝進火場\n面對吞噬一切的火舌，小心通過被破壞的環境\n克服內心恐懼 並救出更多的受困者\n#完成一次又一次驚險的任務\n遊戲還有進階的專家規則\n\n消防員將會區分出不同 #專業能力\n駕駛救護車以及消防車更快的救援受困者\n撲滅火勢，噴出空氣泡沫\n擔任消防隊長指揮任務\n但也加入了危險物品以及高熱系統\n讓火勢更加難以捉摸','\n',char(10)),'https://i.postimg.cc/66SWL1YZ/image.png','租借,合作,角色能力,行動分配',2,6,'普通',1,0,1,1,1280,150,1200,50,124,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(225,'我要上太空',replace('一場精彩的太空冒險！\n扮演一隻星際探險隊，不斷招募隊員並前往各種星球探索。\n在遊戲中你需要嘗試找出一套COMBO公式，管理好你的手牌，秀一波操作打造出最強的探險隊陣容。\n\n遊戲僅有少少的10動，但卻會隨著陣容的龐大，一次動作所引發的連鎖效應越來越長。\n當遊戲即將結束時，你才會意識到『啊！如果再多1動就可以做出完美COMBO了，可惡！只好再來一場！』。','\n',char(10)),'https://i.postimg.cc/2SYVhKSw/image.png','租借,卡牌,combo',1,5,'普通',1,0,1,1,890,100,800,50,125,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(226,'雙胞胎',replace('你一定可以看得出來，仙人掌和刺蝟有什麼關係，對了，沒有錯，\n他們都有刺。遊戲裡的300種圖案，隨機抽出11種來湊成5對時，你\n和你的家人及朋友們能夠有一樣的想法來配成對嗎？兩個看似不太\n相關的配成同一對了，說出你們的邏輯也會一樣嗎？一起來在遊戲\n裡製造歡笑吧！','\n',char(10)),'https://i.postimg.cc/PxvtBWqJ/image.png','租借,派對',3,8,'簡單',1,0,1,1,1080,150,1000,50,126,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(227,'Project L',replace('*此款僅提供現場遊玩*\n《Project L》是一款抽象策略遊戲，遊戲會有各式各樣的謎題與方塊，\n玩家要做的事情是以最有效率的方式，盡可能完成越多謎題越好\n\n是一款非常考驗玩家空間能力與規劃能力的遊戲！','\n',char(10)),'https://i.postimg.cc/52Pby7Yj/L-project-L.png','僅供現場玩,策略,家庭',2,4,'普通',1,1,0,1,0,0,0,50,127,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(228,'殺手賽局',replace('這是款變換同盟的「社交勾結」遊戲，玩家為了利益互相背叛與謀害，\n6~12個玩家每回合共謀決定將誰殺死，所有人努力成為最後一個存活者並收集金條。\n\n你必須有默契地投票，成為最大票群才能存活。\n有趣的是你可以做任何的方式來傳遞你的訊息，\n但確保你不會成為目標或者他們可能改為埋伏你！\n你們可能在任何時機跟其他人結盟甚至背叛，選擇你的良機，別相信任何人。','\n',char(10)),'https://i.postimg.cc/3RmsXnRX/2.png','租借,派對,心機,投票',6,12,'簡單',1,0,1,1,790,100,700,50,128,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(229,'噤聲尋寶記：地下墓穴',replace('讓你在摸黑找寶的同時，一邊製造聲響、一邊擔心吵醒沉睡在墓穴的巨龍！\n每一步都得盤算，每抽一張牌都是生死賭注：發出的聲響太多，龍就來敲門；走太快，各種墓穴怪物還會上前阻攔！\n探索地圖、營救囚犯、擊倒怪物，過程腦力全開、心跳狂飆，還得時刻提防身邊“隊友”的背刺操作。\n\n這是一款牌庫構築遊戲，隨著遊戲進行，你的牌庫將會越來越強，能不能在適當的時機抽到自己想要的牌，就要看你運氣。\n每一場遊戲的地圖都是隨機抽取，每次的地下墓穴都不一樣，重玩性極高！\n\n這絕對不是冒險尋寶遊戲，這是聲控地獄。\n誰能靜悄悄地把寶帶回家？誰又會被自己吵到出局？一起下墓穴，一起大吼“我就這麼點聲音你也來打我？！"\n\n','\n',char(10)),'https://i.postimg.cc/Pr9MHhKq/image.png','租借,策略,牌庫構築,卡牌,板塊拼放',2,4,'困難',1,1,0,1,1990,150,1900,50,129,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(230,'我們不一樣','喝酒遊戲，派對起來~','https://i.postimg.cc/2j4YnBGZ/IMG-20251014-205517.jpg','販售,派對',2,6,'簡單',1,1,0,1,1080,0,0,50,130,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(231,'璀璨寶石',replace('榮獲 2014 年度最佳遊戲 2014 Golden Geek Board Game of the Year Winner，榮獲 2014 Spiel des Jahres Nominee 德國桌遊年度大獎，家庭桌遊獎項提名殊榮，本遊戲適合10歲以上，2~4人遊玩。\n(中文版) 璀璨寶石 桌上遊戲，擁有優雅華麗的美術風格，引領玩家進入文藝復興的歐洲地區，擁有最多的寶石將會吸引貴族前往投資。利用手上的資源獲取礦脈、運輸方式以及工匠，工匠將會把你手上的原石冶煉成完美無瑕的寶石！','\n',char(10)),'https://i.postimg.cc/8CDMkCvT/image.png','租借,家庭,收集',2,4,'普通',1,0,1,1,1400,150,1400,50,131,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(232,'多拉A夢疊疊樂',replace('*僅供現場玩*\n一款需要穩定性與技巧的平衡遊戲，將可愛的哆啦A夢放到時光機上吧!!','\n',char(10)),'https://i.postimg.cc/904qgR6Y/A.png','僅供現場玩,兒童,平衡',1,2,'簡單',1,1,0,1,0,0,0,50,132,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(233,'複製貓貓','日本設計師作品，規則簡單好上手，還有可愛貓咪插畫!','https://i.postimg.cc/Pq2ptQhM/copy-cat-meow.png','租借,小品',2,5,'簡單',1,0,1,1,490,50,400,50,133,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(234,'神廟密契',replace('在《神廟密契》中，你將扮演考古學家和冒險家。\n你要尋找的無價之寶就藏在一座神殿中。\n為了得到寶藏，你必須要找到一組雕像，才能解除藏寶室的門鎖。','\n',char(10)),'https://i.postimg.cc/jqWXFLQ1/image.png','租借,家庭,推理',1,4,'簡單',1,0,1,1,690,100,600,50,134,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(235,'璀璨寶石：雙人版',replace('回到文藝復興時代，作為首屈一指珠寶公會首領，為了鞏固你的名聲與財富，你需要善用你的技巧與獨到的眼光，為各個王侯貴族打造最莊嚴華美的手飾。\n璀璨寶石推出全新雙人版了！由設計師Marc André、出版社SPACE Cowboys原班人馬，並特別與《七大奇蹟：對決》設計師Bruno Cathala合作，在原版璀璨寶石中加入新機制，讓雙人版中更添競爭與互動的趣味。','\n',char(10)),'https://i.postimg.cc/13Kcq6s8/image.png','販售,策略,雙人,收集',2,2,'普通',2,2,0,1,850,0,0,50,135,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(236,'獵巫鎮',replace('《獵巫鎮 1692》是一款社交演繹、輕策略遊戲，適合4-12位玩家。一場女巫審判活動正在逐漸升溫。每位玩家將扮演塞林鎮的一位鎮民，試圖相互指控，並將對手送上審判法庭，以保住自己的性命。當所有女巫都被發現，平民才能獲勝！而女巫可以在夜晚殺死其他玩家。在傳染階段中，平民玩家可能也會成為一名女巫！ 你會把親人送上法庭，還是被無辜冤死？或者是拋開所有世俗，成為一名女巫，將罪惡的塞林鎮推入地獄的深淵。\n\n','\n',char(10)),'https://i.postimg.cc/1zCGWQgP/1692.png','租借,陣營,推理,心機,身分猜測,說話',4,12,'普通',1,0,1,1,850,100,800,50,136,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(237,'可可亞','《可可亞》讓所有玩家沈浸在「神之果國度」的異國情調當中！玩家將扮演部落的酋長，領導你的族人種植與交易可可果來創造榮耀與財富。簡單的規則，卻包裹著不簡單的策略性，又巧妙地與主題結合，讓《可可亞》成為全家大小都愛不釋手的刺激遊戲！','https://i.postimg.cc/4djzgQbS/image.png','租借,販售,家庭,板塊拼接',2,4,'普通',2,1,1,1,1050,150,1000,50,137,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(238,'動物園大亨輕便版',replace('遊戲介紹\nReviews\n\n動物園大亨輕便版是動物園大亨的方便攜帶版本，動物園大亨獲得2007 年德國年度遊戲獎。簡單的規則和快速的遊戲時間，讓動物園大亨輕便版成為孩子們完美的入門遊戲！在這遊戲中，玩家必須妥善利用園區空間，引進並管理各種可愛動物，豐富自己的動物園。 園區與動物們規劃最好、得到最多分的玩家獲勝！','\n',char(10)),'https://i.postimg.cc/hjQdp7Wb/image.png','販售,家庭',2,5,'簡單',1,1,0,1,514,0,0,50,138,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(239,'七隻貓咪','一款規則簡單的卡牌遊戲，玩家透過打牌來湊對，目標是收集七隻不同種類的貓咪。','https://i.postimg.cc/3NBJBKRF/image.png','販售,小品,吹牛',2,5,'簡單',1,1,0,1,300,0,0,50,139,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(240,'風聲再臨','《風聲再臨》中，玩家透過傳遞情報的方式、內容來推測各玩家的陣營，同時想辦法達成獲勝條件：獲得藍色或紅色情報。同時，隱藏在兩隊之中的特工也會為了自己的獲勝，而擾亂戰局......','https://i.postimg.cc/YSWrPN09/image.png','租借,陣營,心機,卡牌,身分猜測,角色能力',3,7,'普通',1,0,1,1,590,100,500,50,140,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(241,'忍者魂',replace('遊戲簡介:\n扮演一位忍者,試著奪取藏在城堡內的藏寶圖.\n每局的開始會公開拿著藏寶圖的玩家,玩家們要在換牌,看牌,開牌三個動作選擇一個,\n試著將藏寶圖換到你的手上並順利打開,\n但要小心,一旦打開了錯誤的動作,你將立刻被敵人發現並死在場上','\n',char(10)),'https://i.postimg.cc/4dPr2n6y/image.png','販售,推理,心機',5,8,'簡單',1,0,1,1,300,0,0,50,141,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(242,'天堂與美酒',replace('*此款僅提供現場遊玩*\n你被派去領導一座古老的修道院和它的釀酒廠。\n現在是你在上帝的藍天下釀出最好的麥酒的時刻！\n釀酒的藝術要求你找出最好的時機。\n為了獲得最好的產品，你必須提供你修道院的花園最肥沃的資源和正確數量的僧侶來收獲—\n但是請記住你的釀酒大師，他已經摩拳擦掌要來裝滿你的每一具酒桶！\n在天堂與酒裡面，你必須克服與其他玩家激烈的競爭。\n你要在升級花園和收割資源之間取得平衡來裝滿你的酒桶。\n只有能夠保持冷靜的頭腦可以贏得這場最佳麥酒的競賽！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','僅供現場玩,策略,板塊拼放',2,4,'困難',1,1,0,1,0,0,0,50,142,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(243,'偉人的猜拳策略',replace('這是一場攸關世界未來命運的大戰。 \n \n世界偉人將加入你的麾下，與你一同發展文明、建設國土；\n \n和雄才大略的軍武家一齊征服天下、獨霸世界。\n \n究竟你會成為名留青史的統治者，還是亡國敗君？\n \n就用「剪刀、石頭、布」分出勝負！\n \n \n遊戲中，玩家可以運用偉人獨一無二的特殊能力，\n \n強化武力擴展帝國的領土、發展科技與文化建設地方繁榮。\n \n攻打你的對手！並且使用詭譎的猜拳能力贏得每一場戰役。\n \n誰能率先征服六大洲、或者建設出昌盛的帝國將成為遊戲最終的勝利者！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,小品,卡牌',3,6,'普通',1,0,1,1,600,100,600,50,143,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(244,'王國軼聞錄',replace('簡單上手的遊戲機制！\n極具特色的卡牌插畫。\n快速的遊戲時間，讓你和好友連開數局。\n形成自己獨特的戰術風格，體驗爽快的卡牌Combo。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,家庭,卡牌,輪抽',2,5,'普通',1,0,1,1,1190,150,1100,50,144,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(245,'動物日報',replace('玩家扮演報紙頭版的決定者\n\n在連續的三回合拼湊出當日報紙頭條。\n\n\n\n遊戲採實時制\n\n每個人在回合開始時進入採訪階段\n\n在不知道板塊正面為何的情形下盲選板塊\n\n當玩家各自覺得選夠了就可以進入各自的排版階段\n\n也就是把先前拿的哩哩扣扣拼貼到頭版\n\n\n\n考驗玩家的空間能力\n\n怎麼擺才能最大化滿足各種板塊囉嗦的得分條件也是遊戲樂趣之一\n\n而遊戲中最最最殘酷的事情是\n\n打最少廣告的人會直接出局\n\n很幽默的諷刺當今新聞的窘境\n\n主題非常具像化，帶入感堪稱一絕。\n\n\n\n很好理解之外，每一回合也非常緊張刺激\n\n譏諷對手廣告滿版的同時\n\n你抓著手中認真老實的報導卻不知道為什麼汗流浹背\n\n什麼？你說小時不讀書長大當記者？\n\n你一定要來試試 號外！動物日報！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,反應,板塊拼放',1,6,'普通',1,0,1,1,1600,200,1600,50,145,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(246,'驚爆倫敦','莫里亞蒂在倫敦的大笨鐘安裝了定時炸彈！遊戲中玩家分成正反兩方，除了要找出隊友外，還要處理炸彈！機智的福爾摩斯一行人是否能在時間內解除炸彈？或是莫里亞蒂會與他的同夥笑著離開大笨鐘的廢墟呢？','https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,推理,陣營,說話',4,6,'普通',1,0,1,1,650,100,600,50,146,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(247,'德國心臟病',replace('玩家依序翻開一張卡片置於自己面前，只要桌面上翻開的紙牌中，一共出現5個同樣的水果時，玩家就要搶按桌面中央的鈴，最快按鈴的玩家贏得桌面上所有的卡片，手牌用盡的玩家便出局了！\n堅持到最後的玩家獲勝！\n\n這是一款挑戰你心臟極限的刺激遊戲。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,兒童,反應',2,6,'簡單',1,0,1,1,790,100,700,50,147,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(248,'七大奇蹟：對決',replace('本商品為「七大奇蹟：對決」系列，與「七大奇蹟」、「七大奇蹟新版」系列不相容！\n發展你的科技和軍事，建造雄偉的建築，領導你的文明走向勝利！\n《七大奇蹟：對決》是一款獨立遊戲適用於兩人競技。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','販售,策略,雙人,卡牌',2,2,'普通',1,1,0,1,950,100,900,50,148,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(249,'卡卡頌',replace('熱銷逾1200萬套的《卡卡頌》全球風靡\n簡單規則帶來深刻遊戲體驗\n是當代經典桌遊，不容錯過！\n兩人玩也很讚喔！\n是經典的板塊拼接遊戲，玩家輪流抽取板塊，拼接出一個共享的地圖，並派遣自己的手下（米寶）到城堡、道路或草原上佔地得分。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,家庭,板塊拼放',2,5,'普通',1,0,1,1,1290,150,1200,50,149,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(250,'三國殺',' 相信"三國"是一個家域戶曉名詞，三國殺是一個以三國時代為背景，集角色扮演、戰鬥、偽裝等要素于一體的多人卡片遊戲。玩家可以通過在遊戲裡扮演不同身份的角色，隱藏自己，尋找同伴，並運用各是不同的技能擊敗敵對勢力，得到最後的勝利，創造一個屬於自己的三國傳奇。','https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,陣營,卡牌,身分猜測',2,10,'普通',1,0,1,1,600,100,600,50,150,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(251,'皇家港',replace('在皇家港的碼頭上，生活總是繁華忙碌，而你也想在這裡混一口飯吃，但別太冒險，不然你的存貨會耗盡。\n別忘記撥出你的部分收益給總督及海軍上將以獲得他們的庇護，並僱用各行各業的人物來幫助你往目標前進。\n\n試著擴展你的影響力，讓你成為名垂青史的遠征軍。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,家庭,策略,卡牌',2,5,'普通',1,0,1,1,590,100,500,50,151,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(252,'拼布藝術',replace('拼布在歐洲中世紀是一種針線活，需要將幾片碎布片拼湊出一個較大的刺繡品。在過去，拼布是一種利用剩下的碎布塊來製造衣服和被子的方法。今天，拼布是一種藝術，設計師使用珍貴的織物來創造出美麗的紡織品。特別是使用參差不齊的各種織物，更能創造出真正的大師傑作。\n\n要創造出一個美麗的被子，需要花費很多的精力和時間，但也需要有可用的補丁配合。所以要仔細選擇你的補丁，並確保有足夠的鈕扣來完成你的被子，好向你的對手展現你的美麗作品。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,雙人,拚放',2,2,'簡單',1,0,1,1,880,100,800,50,152,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(253,'小王子：給我一個星球',replace('曾經清澈的眼睛都已長大，被工作與責任模糊，走向過度強調嚴肅與成熟的大人世界，問問自己，有多久沒有停下腳步去欣賞一朵你愛的花？\n\n小王子70週年了，一雙仍然清澈的眼睛，為多少迷失在現實的大人們，重新安裝上想像力，世界一樣在轉，但我們不再為自己的不夠成熟感到悲哀。\n\n慶祝小王子70週年，玩樂小子獨家代理法國 the little prince 小王子桌遊 (中文版)，重新邂逅和小王子初識的溫暖。 遊戲中，透過卡牌熟悉小王子的故事以及處事哲學，拼成一個完整的星球。\n\n由桌遊界兩大設計師 Antoine Bauza (設計 7 Wonders 等桌遊)，Bruno Cathala (設計 MOW, Dice Town 等桌遊)聯手設計，內附中文及英文遊戲說明書，適合2~5人， 七歲以上的孩子及成人，遊戲規則簡單易上手，却難以精通，2~5位玩家之間積分計算，欲擒故縱的全盤策略思考過程中，透過觀察指定下一位玩者抽牌，透過資源的分配，轉變為對自己有利的局勢以獲得勝利，遊戲極富重複可玩性。 是一款適合全家共同玩樂的遊戲。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,家庭,拚放',2,5,'普通',1,0,1,1,980,100,900,50,153,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(254,'妙語說書人奧德賽',replace('妙語說書人：奧德賽是款挑戰你想像力與推理能力的說書人遊戲。\n遊戲所附的84張精美圖卡都有不同的故事，而且每個人每一次說出的故事都不一樣，讓每場遊戲都充滿全新驚奇。\n奧德賽是款獨立遊戲，不需要妙語說書人基本版即可進行遊戲。更棒的是，你可以最多12人同時進行遊戲，還可以進行團隊賽！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,兒童,說話',3,12,'簡單',1,0,1,1,1190,150,1100,50,154,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(255,'快手疊杯','在「快手疊杯」裡，每個人用五個不同顏色的杯子，試著比別人更快完成任務。每張題卡會以各種有趣的方式，提示你要將五個杯子以什麼順序疊起來或排成一列：可能是樹上的五隻鳥，或是牆上掛的五件外套。趕快看懂提示，速速排好，馬上按鈴！','https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,兒童,家庭,反應',2,4,'簡單',1,0,1,1,790,100,700,50,155,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(256,'出包魔法師',replace('這是一個用魔法互相傷害的遊戲，玩家扮演一群想第一個登上大魔法師之塔的魔法師，但是不知道為什麼，大家的咒語頻頻出包，必須透過觀察判斷、邏輯推測以及一點點冒險的勇氣，來召喚正確的魔法石。\n來吧！一場咒語大亂鬥已經開始了！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭',2,5,'普通',1,0,1,1,1290,150,1200,50,156,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(257,'目擊者之夜',replace('疑神疑鬼的密室推理陣營遊戲\n\n山中作客的夜晚，主人慘遭殺害！\n殺人魔就在受邀的賓客中，為了避免殺戮繼續蔓延，賓客們交換目擊情報，討論兇手的去向。在有限的時間內，賓客能否藉由各自職業上的優勢，識破殺人魔與其共犯羅織的謊言，並經由投票將嫌疑人關進鍋爐室裡，確保自身的安全？','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,陣營,推理,身分猜測',3,6,'普通',1,0,1,1,490,50,400,50,157,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(258,'草泥馬',replace('草泥馬最高原則：擺脫所有負分！\n出清你的手牌，否則會扣分。如果你無法出牌，便要決定：現在就退出，或抽牌賭一下，以期之後能順利打出手牌。\n扣分時拿取扣分指示物，當你出清所有的手牌時，返還1個扣分指示物（可能是扣1分或扣10分）。\n遊戲結束時，扣分最少的玩家獲勝。\nL.A.M.A = Lege Alle Minuspunkte Ab!\n草泥馬＝棄掉所有負分（德文）的縮寫','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,小品,卡牌',2,6,'簡單',1,0,1,1,290,50,200,50,158,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(259,'卡魯巴紙牌版','在充滿傳說的卡魯巴島上，有幾座巨大的寺廟，還有深藏在叢林中的寶藏。你是探險隊隊長，必須運用你的經驗為隊員規劃路徑，不要讓隊員阻擋彼此的去路，還要比其他競爭隊伍做得更好，你才能獲得叢林中所有的寶藏，並且讓你所有的隊員到達寺廟。','https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,家庭,小品,板塊拼接,路徑規劃',2,6,'簡單',1,0,1,1,490,50,50,50,159,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(260,'血契獵殺',replace('血族戰爭已經結束，只有少數幸運者幸存，你可以聚集起自己的信徒並找出敵對氏族的族長嗎？\n在兩個血族的人口與領土都急速擴張的情況下，衝突是不可避免的結果，隨之而來的戰爭讓無以數計的永生者隕落。\n只有氏族族長及少數精英得以倖免。\n在低調躲藏數月之後，這兩位血族的族長開始熱切地搜尋倖存者，不只是自己的族人，也包括敵對的血族成員。\n現在是兩位族長聚集自己忠實的部下並與敵人進行最終決戰的時刻！\n血契獵殺是一款可供六至十二名玩家一同進行的推理遊戲，但遊戲中充滿騙局。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,陣營,身分猜測,角色效果',6,12,'普通',1,1,0,1,790,100,700,50,160,'','','缺中文規則書');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(261,'牙買加','1678年二月，在多年的海盜生涯之後， 亨利·摩根靠著小聰明謀得牙買加總督一職， 從此不再是人人喊打的那個海上惡霸。 不僅如此，他還把以前的那幫狐朋狗友都邀請至此居住， 這樣一來，他們就能一起享用海上掠奪的勝利果實。 30年之後，海盜為了紀念他的大名，舉辦了一場比賽： 這就是環島海上競速！ 獲勝的隊伍， 將獲得數不盡的黃金。 水手們，出發啦！','https://upload.cc/i1/2025/09/11/RFZOYL.jpg','販售,家庭,派對,骰子,手牌管理',2,6,'普通',1,1,0,1,1200,0,0,50,161,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(262,'血與刃的白薔薇',replace('白薔薇的復活祭典開始了🌹\n司教統領信者們獻出生命，來復活偉大的母親\n但因為魔法而掌握權力的人們🧙\n不願意償還生命與力量，來到此處將花苞殘殺殆盡🥀','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,陣營,身分猜測',5,10,'普通',1,0,1,1,690,100,600,50,162,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(263,'閃靈快手',replace('幽靈巴頓在城堡的地下室發現一台老相機。\n他立刻拿起相機四處拍他想要變不見的東西，當然也包括他自己囉！\n奇怪的是，魔法相機照出來的顏色時常出錯，有時綠色的瓶子照成白色，有時又照成藍色。\n巴頓看著這些顏色奇怪的照片，記不起來他到底要把什麼變不見？\n‍\n你能幫他說出正確的名稱、或甚至親手把東西變不見嗎？\n如果你快速地抓到正確的物品，你就有機會獲勝！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','販售,兒童,家庭,反應',2,8,'簡單',1,0,1,1,790,100,700,50,163,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(264,'奇雞連連',replace('給孩子的第一款策略遊戲。\n只要會玩圈圈叉叉，便能享受「奇雞連連」帶來的無窮樂趣。\n貪吃的公雞會吃掉（套住）比自己小的公雞，你能首先讓自己的三隻公雞排成一直線嗎？\n\n這款易學易懂的策略遊戲挑戰你的記憶力，看看你的記性是否和公雞的胃口一樣好！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,兒童,家庭,雙人',2,2,'簡單',2,1,1,1,890,100,800,50,164,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(265,'多米諾王國',replace('身為國王，你正在尋找新土地來擴張王國的勢力並提高聲望，必須探索所有的土地、麥田、湖泊以及山脈，來找到最棒的領地。但是要小心，其他的國王也在覬覦這些土地唷！\n選擇適當的多米諾板塊，妥善地將相同的地形拼放在一起，形成最大的領土，並透過事前的規劃，讓你王國中的每一寸土地都得到完善的利用，以獲得最高的聲望分數！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,拚放,家庭',2,4,'簡單',1,0,1,1,790,100,700,50,165,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(266,'動物疊疊樂',replace('4歲以上｜15分鐘\n動物們想來場特技表演，牠們要堆疊成一座巨大的金字塔，這需要高超的技巧與過人的勇氣！\n誰能將企鵝放在鱷魚上面，把綿羊放在企鵝上面，再把蛇放在綿羊身上呢？大熊想要站上這金字塔頂端，但是這高度著實使牠頭暈目眩！\n\n一款搖搖晃晃的堆疊遊戲，也可以一個人玩喔！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,兒童,家庭,平衡,骰子',2,4,'簡單',1,0,1,1,1290,150,1200,50,166,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(267,'豆腐王國',replace('這是一場精采的推理遊戲。\n遊戲中輪流扮演找尋豆腐公主的麻糬王子。把握線索，思考線索中的邏輯，來破解謎題。而其他人則會扮演給予線索的角色，因為有人可能說謊，而有些人則必須說實話，所以善用你的演技給予線索，為自己在這場宮廷鬥爭贏得勝利吧！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,小品,派對,推理,身分猜測',3,8,'簡單',1,0,1,1,490,50,400,50,167,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(268,'蛙蛙闖蓮池',replace('5歲以上｜10-20分鐘\n青蛙在蓮葉間跳躍，獵捕咔嗞咔嗞的美味蒼蠅。小心！送子鳥就躲在池塘邊，等待小胖胖青蛙自己送上門來。\n青蛙必須依擲骰結果，至少跳到顏色相符的蓮花牌上，才能將發現的蒼蠅吃下肚。\n然而，小小的蒼蠅難以填滿青蛙大大的胃，牠得繼續往前跳到下一朵同色的蓮花，試試看能否捕獲更多的蒼蠅。\n當心，別撞見送子鳥，否則就會前功盡棄，餓肚子啦！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,兒童,家庭,記憶',2,4,'簡單',1,1,0,1,390,0,0,50,168,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(269,'腦霧證人',replace('最瞎目擊者！\n\n1.起始玩家隨機抽6張牌，重新排列後講述一個犯罪故事。將這些牌依序疊放，形成故事牌堆。\n2.擲骰決定要從故事牌堆中移除哪一張牌。\n3.下一名證人用剩餘的牌與兩張新增的牌，重新陳述案情，必須對應紙牌順序，並且合情合理。\n\n到底誰的腦子比較有霧？','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','販售,記憶,說話',2,5,'普通',1,1,0,1,690,0,0,50,169,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(270,'超級犀牛',replace('那是什麼？有隻犀牛在爬牆？是的！超級犀牛又出動了。\n來自動物世界的超級英雄，不畏大樓有多高，不斷搜捕小偷和強盜。他和獅子一樣強壯，和狐狸一樣聰明，但也和犀牛一樣重。所以即使超級犀牛出現在最堅固的大樓，還是會讓大樓搖晃。你可以幫超級犀牛在會搖晃的建築物上完成任務嗎？','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,兒童,家庭,平衡,派對',2,5,'簡單',1,0,1,1,790,100,700,50,170,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(271,'幕後交易',replace('什麼？你要用2隻羊來換1隻牛？門都沒有！\n\n拍賣會開始囉！\n你可以經由拍賣或幕後交易來購得動物。\n但是在幕後交易時，得小心對方騙人！\n看看到底是誰比較會吹牛，能以低價購得對方的動物。\n\n遊戲結束時必須以4張相同的動物（四重奏）來算分，由總分最高的玩家獲勝。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,競標,說話',3,5,'簡單',1,0,1,1,490,50,400,50,171,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(272,'嗒寶/哆寶',replace('你能訓練小朋友的反應力及對圖案的辨識力。圓型鐵盒輕巧好攜帶，讓你一路玩著走! 比心臟病更刺激，更好玩。 試試看，小心大家都上癮喔!\n就是它、發現它，你贏了！ 遊戲中任2張卡，總有且只有一個一樣符號。 多人參加4種玩法，要銳利眼睛和敏捷反應喔!','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,兒童,反應',2,8,'簡單',1,0,1,1,500,50,500,50,172,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(273,'侃侃而猜','「侃侃而猜」是一款運用推理，來猜測其他玩家生活體驗的遊戲。過程中的提問與作答，將讓你窺見，生活中習以為常的平凡小事，在其他玩家的生活中，竟然有與你迥異的歷程。與新朋友快速熱絡及與老朋友加深情誼的絕妙遊戲！','https://upload.cc/i1/2025/09/11/RFZOYL.jpg','販售,租借,派對,家庭',3,6,'簡單',1,1,0,1,490,50,400,50,173,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(274,'誰是牛頭王',replace('每位玩家同時從10張手牌中打出一張，並依規則將牌接到桌面上4列牌陣中的一列，若你的牌成為一列中的第6張，就必須將前面的5張牌拿起，每張牌上有數量不等的牛頭。\n遊戲目標是：不要得到任何紙牌，因為牌上的每個牛頭都是負分。\n遊戲結束時，得到最少牛頭的玩家獲勝。\n\n這是一個經常讓你有出乎意料之感的瘋狂聚會遊戲，人越多越好玩喔！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,小品',2,10,'簡單',1,0,1,1,490,50,400,50,174,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(275,'倉庫城(無擴充版)',replace('在1900年代，漢堡市是世界的門戶，港口的中心有一棟特別且複雜的倉儲大樓，稱為『倉庫城』。\n\n你是一名住在漢堡的貿易公司老闆，生長在倉庫城最繁華的時代，從貨輪上購買貨物並提供給客戶以完成合約，賺取白花花的銀子。記得雇用消防員來保護你的貨物和辦公大樓，以免在不時發生的火災中蒙受損失。一年中生意最好的玩家將贏得勝利。\n\n倉庫城運用超級簡約卻極度原創的精神所開發，絕對令您印象深刻！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,策略,卡牌,工人擺放',2,5,'困難',1,0,1,1,1490,150,1400,50,175,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(276,'花磚物語.花磚密語',replace('★在《花磚密語》中，你們將扮演瓷磚畫藝術家，裝潢埃武拉皇宮的\n牆壁。\n★由摩爾人所引進的「阿茲勒赫瓷磚畫」(azulejos)，原為帶有白色與藍色的瓷磚，深受葡萄牙人喜愛。葡萄牙國王曼紐一世某次造訪西班牙南部的阿爾罕布拉宮時，深深著迷於這些奪目的摩爾裝飾。這令國王魂牽夢縈，並立即下令要在自己的皇宮中如法炮製。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','販售,策略,家庭',2,4,'普通',1,1,0,1,1250,0,0,50,176,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(277,'東京之王','東京之王是款極受歡迎的狂歡大亂鬥Party Game與家庭遊戲，玩家扮演突變怪獸，暴走機器人，甚至是異種外星人，以投擲骰子，獲得最佳骰子組合來選擇自己的策略。是要進攻對手嗎？還是治癒慘重的傷害？或是準備更多的能量方塊以增強怪獸的超能力？邁步向前為您的勝利之路奮鬥吧！','https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,卡牌,骰子',2,6,'普通',1,0,1,1,1250,150,1200,50,177,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(278,'砰！骰子版',replace('在西部荒野中，執法人員與不法之徒之間永不停息的戰鬥持續加溫，突然，一陣遮空蔽日的箭雨襲來：印地安人來襲！你夠膽量跟上這些印地安人的腳步嗎？你有勇氣去挑戰自己的命運嗎？你可以擊敗圍繞你的兇狠槍手並揭露他們的身份嗎？\n\n砰! 的所有樂趣在骰子版中重現！\n‍','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,陣營,心機,骰子,角色能力',3,8,'普通',1,0,1,1,790,100,700,50,178,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(279,'終極密碼',replace('10歲以上｜15分鐘\n每位玩家要在自己的數字牌被對手完全猜出前，搶先猜出對手所有的數字牌！但是面對空白的牌背，如何能猜到對手的數字牌呢？玩家雖然只知道自己擁有哪些數字，在遊戲過程中，藉由分析逐漸增加的資訊：其它玩家的猜測、及陸續攤開的牌，慢慢推敲出每張牌正確的數字！\n你能搶先猜出對手的牌嗎？','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,家庭,小品,推理',2,4,'簡單',1,0,1,1,790,100,700,50,179,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(280,'矮人礦坑',replace('在遊戲中玩家們將會扮演矮人族。其中一種矮人是淘金矮人，他們開拓礦坑坑道向山脈深處尋找寶藏；另一種則是試著在淘金矮人的路上放置障礙的搗蛋鬼。雖然你只能猜測其他玩家的角色，兩組矮人還是要想辦法支援自己的同伴。如果淘金矮人成功地建造出通往寶藏的路徑，他們將得到金塊作為獎賞，而搗蛋鬼將一無所獲；不過萬一淘金矮人失敗了，則搗蛋鬼將會得到獎賞。每位玩家所扮演的角色，只有在分金塊的時候才會揭露。遊戲進行三回合後結束，金塊最多的玩家獲勝。\n\n這是個可以10人同樂的派對遊戲，規則簡單好上手，但過程變化多端，可以趁機耍耍心機喔！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,陣營,心機,身分猜測,拚放,卡片',3,10,'普通',2,1,0,1,690,100,600,50,180,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(281,'獴鷲派對','在正確的時刻打出正確的牌，讓狐獴和你一起歡慶。遊戲中，得到越多的加分狐獴牌越好，但要小心，禿鷲正盯著獵物，隨時準備奪走分數，唯有緊扣好牌在手上，才能讓你免於禿鷲的肆虐！ ','https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,卡牌,心機',2,5,'簡單',1,0,1,1,290,50,200,50,181,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(282,'格格不入 (Blokus) 大格鬥',replace('遊玩時間約20分鐘，適合7歲以上。\n一人各佔一邊，努力把自己所有的幾何板塊拓展出自己的新天地！\n記住！鞏固自己的地盤，並同時觀察對手的一舉一動，才是上上策。\n一個可以靈活動腦的抽象遊戲，一個看似簡單，但卻可發揮無窮潛力，最適合朋友及家庭聚會，一起同樂！\n格格不入(正式名稱是"阻擋我們")是一款抽象的策略遊戲，玩家要試著把各色透明的俄羅斯方塊放到圖板上。\n唯一的限制是不能和你其他的方塊相鄰，並且要碰到你已經在圖板上的方塊至少一個角。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,家庭,下棋,區域佔領',2,4,'簡單',1,0,0,1,1099,150,1000,50,182,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(283,'蹦蹦蛙',replace('5歲以上｜20分鐘\n讓青蛙歡快的跳躍，幫助你將面前的牌由小到大排列整齊。\n每當池塘裡出現垃圾，就會擋住去路，妨礙你整理紙牌。巧妙地換牌，並善用青蛙的大跳躍，讓你成功達陣！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,兒童,家庭,小品',2,4,'簡單',1,0,1,1,390,50,300,50,183,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(284,'政變',replace('消滅所有對手的影響力，成為最後倖存的玩家。\n\n每次到你的回合，你都可以宣稱自己擁有某些角色(可以吹牛)從而使用角色能力，又或是獲得基本收入。\n\n但要注意，其他玩家可以向你提出質疑，如果你被發現吹牛，又或是質疑失敗，即損失一點影響力。而你只有兩點影響力，沒有影響力即時退場。\n\n而部份角色能力也可以被某些角色阻礙，當然你也可以吹牛擁有那些角色，而理所當然，對方也可以質疑。\n\n儘全力成為最後倖存的玩家。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,小品,心機,吹牛,身分猜測',2,6,'普通',3,0,3,1,450,50,400,50,184,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(285,'金金樂盜',replace('海盗們，揚帆掠奪吧！\n\n在金金樂盜中，玩家將以擲骰的方式奪取寶藏，努力成為加勒比海群島中最富有的海盜！回合中，你將投擲5顆骰子，最多3次，依你的擲骰結果組成的骰面組合，搜刮當地商船、其他海盜或是國王本尊！慎選你的骰子，用最聰明的方式去搶奪金幣，成為這片海域中最富有的海盜！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,小品,骰子',2,6,'簡單',2,0,2,1,490,50,400,50,185,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(286,'烏邦果',replace('快速！簡單！迷人！\n\n烏邦果是一款節奏明快、讓人上癮的簡單幾何拼放遊戲，玩家必須和時間賽跑並和對手競爭，完成環環相扣的板塊拼放。\n\n越快完成就能得到越多寶石，九回合後，寶石價值最高的玩家獲勝！遊戲進行方式：每位玩家拿取一套共12片的幾何板塊，每片形狀不同的板塊都由多個大小相同的正方形所組成。回合開始時，每位玩家拿取一張新的拼圖板，一位玩家擲骰決定必須用哪些板塊填滿拼圖板上的空格，在時限內完成的人大喊「烏邦果」，接著從袋子裡隨機拿取一顆寶石。最快完成的人可以額外獲得一顆藍寶石，次快完成的人可以額外獲得一顆黃寶石。不同顏色寶石帶來不同分數，九回合後，得分最高的玩家獲勝。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,家庭,競速',1,4,'簡單',1,0,1,1,1490,150,1400,50,186,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(287,'卡坦島',replace('歡迎來到卡坦島！\n\n你們是勇敢的拓荒者，首先來到這座資源豐沛但未經開發的島嶼，並命名為卡坦島。你們創建的第一批村莊發展迅速，透過收集資源、鋪設道路和興建城市讓聚落逐漸壯大，並且透過交易解決資源不均的問題。\n\n然而，土地與資源有限，誰能迅速擴張自己的聚落並搶佔最佳地段？制定明智且有彈性的策略，偶爾還需命運之神的眷顧，才能率先實現目標，從群雄中脫穎而出，稱霸卡坦島！\n\n自1995年榮獲德國年度遊戲冠軍以來，卡坦島激勵著全世界數百萬人，投身這款鬥智且充滿樂趣的遊戲。\n現在就加入！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,販售,策略,家庭,收集,建設,區域佔領,說話',3,4,'普通',2,1,1,1,1690,200,1600,50,187,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(288,'機密代號','一款分組競賽的派對陣營遊戲。在一組加密情報之中，領袖必須想出絕妙的暗號，如：「一個名詞+數量」，讓隊員們以最少回合找出最多特務，率先找出我方所有特務的隊伍獲得勝利。不過得小心潛伏在情報背後的殺手，找到他的人必死無疑！這款遊戲擁有簡潔的遊戲機制，以及難以重複的題庫組合，讓它百玩不膩。','https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,陣營,猜詞',2,8,'簡單',1,0,1,1,780,100,700,50,188,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(289,'恐龍電車',replace('這是一款排列電車和恐龍的卡牌遊戲。\n由山田空太 設計，日本人氣遊戲「鯨魚電車」的續作！\n遊戲目的是玩家要將9張手牌拼湊成不同的組合，肉食恐龍由 2 張卡牌組成，而草食恐龍則由3張卡牌組成。\n但是，電車、蒸汽火車、新幹線則可以由3張或更多的車卡組成。遊戲以簡單麻雀規則包裝，卻是一款需動動腦筋的派對遊戲。\n與前作相比，此作新增了「寶牌」及更多的計分方法，戰略性UP！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','販售,派對,',2,4,'簡單',1,1,0,1,650,0,0,50,189,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(290,'傻傻玩',replace('傻傻玩是一款具速度感的歡樂桌遊，即時換牌、節奏明快，讓您成為團康與破冰高手！\n當有人收集到4張相同動物就要大喊：「喝水！」盡快奪取一枚水滴，水總是不夠給所有的動物喝，勝利終將屬於反應最快或頭腦清楚的玩家。\n馬上行動！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,兒童,反應',4,12,'簡單',1,0,1,1,390,50,300,50,190,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(291,'搶地毯',replace('市場上人們熙來攘往，這是地毯市集的大日子！最佳的銷售人員即將誕生！\n每個玩家都是銷售人員，試圖智取他人。每個玩家輪流擲骰子，\n然後移動市場經理阿三。如果阿三停在對手的地毯上，\n銷售人員必須付錢給地毯主人之後，才可以在相鄰空間放一張自己的地毯。\n當最後一張地毯鋪上時，每位玩家加總自己在市集上可看見的地毯總數和金錢，\n最富有的玩家獲勝！\n家庭遊戲好玩耐玩，全年齡層皆適合。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','販售,策略,家庭,區域控制,',2,4,'簡單',1,1,0,1,1190,0,0,50,191,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(292,'沉睡皇后',replace('深受大家上癮的沉睡皇后來囉！\n你會發現這個遊戲有助於記憶的發展、策略及基本的算術技巧！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,兒童,家庭,小品,卡牌',2,5,'簡單',1,0,1,1,450,50,400,50,192,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(293,'傳情畫意-歡樂今宵18+',replace('請注意題目為18禁內容，不適合兒童遊玩。\n\n大熱的派對遊戲—傳情畫意系列，為大家帶來新意，\n加入了許多可能讓人羞於啟齒的內容，適合各位成人散發平日積存的各種…軟實力！\n畫出看到的詞語，或猜出圖畫的內容，結果到最後通常跟答案相去十萬九千里，讓人笑破肚皮！\n遊戲時間 : 30分鐘\n\n','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,繪畫,寫字',4,8,'簡單',1,1,1,1,1350,150,1300,50,193,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(294,'輕鬆放',replace('10歲以上｜20分鐘\n呼牌員隨機挑選他的一片板塊並把它翻開，其他的玩家從自己的板塊中找出數字相同的板塊，接著，每位玩家將這片板塊放到自己的圖板上。\n持續以此方式進行遊戲，直到圖板上都放滿板塊為止，玩家為自己圖板上三個方向的每一條單色線計分。\n你會有幾條得分線？\n離滿分307分還有多遠？\n一款讓1-6人享受的大腦運動，放輕鬆！輕鬆放！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,小品,拚放',1,6,'簡單',2,0,2,1,1090,150,1000,50,194,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(295,'腦洞量表','一款換位思考的猜謎遊戲。每回遊戲推派一位玩家擔任評量員，其他人隨機抽取一張數字牌，根據題材指示，輪流形容一段符合數字強弱的事件，讓評量員嘗試將數字由小至大排序出來，任務成敗就看你們熟不熟了！','https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭',4,9,'簡單',1,0,1,1,750,100,700,50,195,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(296,'狼人真言',replace('這款遊戲可以結合手機APP呦，APP會擔任主持人，讓遊戲流程更順暢。\n狼人的嚎叫近在咫尺，只有4分鐘的時間尋找魔法咒語，保護先知，拯救你們的小鎮吧！\n遊戲適合8歲以上，時間10分鐘。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,陣營,推理,心機',4,10,'普通',1,0,1,1,590,100,500,50,196,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(297,'狼人殺',replace('■遊戲人數：8-18人\n■適合年齡：14歲以上\n■遊戲時間：約45分\n《Werewolves 狼人殺》是一款可供多人參與的推理策略類遊戲，考驗玩家的語言表述能力及邏輯分析，通常的版本需要12人參與。\n本套卡牌結合了面殺和網殺的遊戲規則，設計了更加貼合玩家需求的卡牌樣式及配置說明，角色更加豐富，玩法更加歡樂，喜歡派對遊戲的您不容錯過！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,陣營,推理,心機,說話,投票',8,18,'普通',1,0,1,1,690,100,600,50,197,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(298,'瀑布淘金客','玩家讓他們的獨木舟在尼加拉河中來回穿梭以採集寶石。但是河流的變化總是超乎人們的想像，該如何適切地運用行進卡，在險象環生的瀑布邊緣採集珍貴的寶石並安全運回岸上？在河水湍急、奔流快速的尼加拉河，無所畏懼的獨木舟勇者對抗著河水，沿著河岸採集寶石。當然，只有在河流的深處，接近瀑布的地方才能發現最有價值的寶石。雖然獨木舟勇者當然並不害怕，可是，仍要小心以對，否則就會船毀人亡。第一位取得五個都不同顏色、或四個都相同顏色、或任何七個寶石的玩家，將贏得這場遊戲。最先採集到整組寶石的玩家獲勝。','https://upload.cc/i1/2025/09/11/RFZOYL.jpg','販售,家庭,派對',2,5,'普通',1,1,0,1,1650,0,0,50,198,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(299,'截碼戰',replace('遊戲時間	45分鐘\n建議年齡	12歲以上\n小心！對手好像快破解妳的密碼了！\n第二次世界大戰，同盟國破解了納粹的密碼，大幅縮短了戰爭。\n現在，你和你的解碼小組要想辦法破解對手的加密訊息，\n同時傳遞加密訊息給其他隊友！\n截碼戰考驗語言表達能力、聯想能力以及邏輯思考，\n簡單好學又挑戰彼此的團隊默契。\n內附中、英文雙語題目卡！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,陣營,推理,心機',3,8,'普通',1,0,1,1,850,100,800,50,199,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(300,'你刺我殺他',replace('9歲以上｜30-45分鐘\n\n在香蕉共和國裡，高壓獨裁的政權引發百姓的憤怒與不滿，許多人投身刺殺總理的行列，進而集結成一個刺客組織。然而多金的總理並不在乎，身旁伴隨職業級保鑣，依然無惡不做。\n到底是總理會先除掉一名刺客，讓刺客集團潰不成軍，還是刺客會先暗殺成功，推翻政權？\n保鑣能否在關鍵時刻營救總理，維繫政權？','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,陣營,卡牌,心機',4,8,'普通',1,0,1,1,490,100,400,50,200,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(301,'巫術學院',replace('8歲以上｜30-45分鐘\n各位親愛的同學：又到了期末考試的時刻，考試規則一如往常：從成分供應機內取用所需的成分彈珠並注意其變化。如果相同顏色的成分彈珠相互碰撞，就會引發爆炸...... 你可以拿走它們！使用你收集的成分彈珠來完成藥水，並飲用藥水來釋放其魔法的神奇威力。\n請記住，為了奪得年度風雲學生的榮耀，光靠迅捷是不夠的，你必須研製難度最高且價值非凡的藥水！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,家庭,收集,combo',2,4,'普通',1,0,1,1,1390,150,1300,50,201,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(302,'糟了個糕！(這就是人生)',replace('▲讓人一刻都無法放鬆的緊張骰子遊戲！\n■如同真實生活般變幻莫測\n■時而洋溢幸福、時而處處陷阱。\n■不過別緊張，遊戲尚未結束，你還有機會！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,骰子',2,6,'簡單',1,0,1,1,990,100,900,50,202,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(303,'G同鴨搶',replace('適合年齡：8歲以上\n遊戲時間：約20分\n一場為2-6位大小玩家、各種家禽與狐狸而設計的農場饗宴！\n\n「給我玉米，其餘免談！」\n不知為何禽舍裡的 家禽最近胃口大開，土雞、珠雞、火雞、雉雞、鴨子和鵝整天都在爭食。\n但務必小心！ 一旁的狐狸虎視眈眈，牠們想吃的可不是玉米……\n雞鴨鵝等家禽們只要三餐吃得飽飽飽，便能心滿意足，對狐狸而言，又何嘗不是如此？\n遊戲結束時，獲取最多養分（包括家禽和飼料）的玩家獲勝！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,兒童,家庭,嘴砲,骰子',2,6,'簡單',1,0,1,1,890,100,800,50,203,'','','綠色token-1。藍色+黃色token-2');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(304,'詐賭巫師',replace('10歲以上｜30分鐘\n在這個遊戲裡，玩家們是懂得各種咒語的魔法師。\n在怪物競技賭場裡，只要自己押注的怪物鬥士獲勝，就能得到一大筆賞金。\n玩家們秘密地使用咒語，想盡辦法讓自己押注的怪物鬥士獲勝。\n但是競技場的裁判可不會放任不管，在某些情況下強大的咒語反而無法使用。\n遊戲結束時，由賺到最多錢的玩家獲勝。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,卡牌,心機',3,6,'普通',1,0,1,1,590,100,500,50,204,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(305,'從前從前…',replace('8歲以上｜20-40分鐘\n壯烈的冒險？浪漫的愛情？惡毒的詛咒？說個獨屬於你的奇幻冒險故事！\n\n這款說故事紙牌遊戲中提供許多童話故事中常見的元素，例如：王子、森林或仙女。一名玩家擔任說書人開始說故事，故事中要包含他的故事卡上的關鍵字，並將故事合理地導向他手中結局卡上的結局。\n其它玩家則要使用手牌打斷說書人，並成為新的說書人。\n最後的贏家是先把手上故事卡用完、並將故事帶到自己結局上的玩家。\n但本遊戲的樂趣不是在於獲勝，而是在一起說故事中獲得樂趣！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,說話',2,6,'簡單',1,0,1,1,990,100,900,50,205,'','','少6張故事卡');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(306,'5秒定律好棒棒',replace('五秒定律科技大升級！這次推出了聲光特效絕佳的接力棒，玩家只要喊出答案，然後將棒子交給下一位玩家，棒子就會自動感應開始５秒倒數，說出答案交棒或者使用功能卡躲避，誰會是腦力枯竭的最後一棒呢？\n2024 波蘭年度遊戲獎最佳派對遊戲提名\n2024 丹麥年度遊戲獎最佳家庭遊戲','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,反應,說話',2,99,'簡單',1,0,1,1,890,100,800,50,206,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(307,'德國蟑螂',replace('遊戲年齡： 8\n遊戲時間： 少於 30 分鐘\n德國蟑螂是一款非常有趣的遊戲，在遊戲中要不斷的騙人來或得遊戲的勝利。遊戲就好像吹牛一樣，什麼時候是真，什麼時候是假你永遠不清楚。但你可以望穿他的眼神，瞭解他騙人的跡象。\n\n此遊戲適合在歡樂派對中進行，考驗玩家撒謊的功力喔！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,派對,家庭,小品,吹牛,心機',2,6,'簡單',1,0,1,1,590,100,500,50,207,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(308,'炸彈競技場2',replace('適合年齡：8歲以上\n遊玩時間：20-30分鐘\n西元3012，地球經數次戰爭及汙染，已破壞殆盡。\n玩家將扮演"世界政府軍"與"人民聯軍"，兩大陣營，\n展開搶奪搶奪僅存資源的基地戰爭，最先達成基地連線一方，\n便能稱霸地球！\n而科學之子-米翁，需在激烈戰火下將通往生存的最後希望，\n太空飛船ZERO注滿能量。在分秒必爭的末世戰爭中，誰能成為最存活的一方？','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','租借,陣營,派對,卡牌',2,9,'普通',1,0,1,1,650,100,600,50,208,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(309,'龍龍公園',replace('你在經營一座龍龍公園！你將如何設置？\n\n你會把某些恐龍放在一起還是分開？根據你所擁有的種類和放置條件，決定該怎麼做能吸引最多遊客的目光。\n\n遊戲規則非常簡單，擲骰子決定放恐龍的條件＞從手中選一隻恐龍放進去＞把恐龍傳給左手邊玩家，然後重新開始！\n\n簡易的規則、超可愛吸睛的恐龍米寶，一款不論大小朋友都喜歡的遊戲，快一起來體驗看看吧～～～','\n',char(10)),'https://i.postimg.cc/9XGnDhk3/image.png','租借,家庭,輪抽',2,5,'普通',1,0,1,1,750,100,700,50,209,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(310,'忍者之夜',replace('忍者之夜 Night of The Ninja 夜幕降臨...一場新的風暴，即將展開!\n咻咻我來了~ 咻咻我背刺你~~! — 忍者之夜\n『揉合了諜戰、詭計、暗殺的陣營推理遊戲！』\n這是一款超快節奏的遊戲，在簡短的對話中你要找到敵人，想出與自己隊友配合的方法，精準的打擊對手，在這邊收集訊息與暗殺另個敵人一樣重要！\n一局忍者之夜可能在電光石火中就結束了，但爭雄尚未完結，所以趕緊將牌洗勻，再投入下一場挑戰吧。\n忍者的進攻需要快狠準，太陽西下，忍者之夜即將來臨，為了流派的榮譽，你必須找到敵人，且先發制人幹掉他們。發揮忍者優越的隱蔽和狡猾來混淆視聽，克敵制勝。','\n',char(10)),'https://i.postimg.cc/vBPtpGHR/IMG-20251004-162454.jpg','販售,陣營,派對',4,11,'普通',1,1,0,1,750,0,0,50,210,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(311,'傳情畫意',replace('風靡各間桌遊店的派對遊戲。\n玩家必須手腦並用，手負責畫畫、腦袋負責開洞；畫技與猜技並用，畫給別人猜、猜給別人畫，當答案揭曉時，才發現大家是否都搞錯了什麼！\n\n輸贏不是重點，笑果最重要。','\n',char(10)),'https://i.postimg.cc/L8fvndvz/IMG-20251004-162444.jpg','販售,派對,畫圖',4,8,'簡單',1,1,0,1,1390,0,0,50,211,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(312,'地產大亨-七龍珠Z版',replace('在本集《七龍珠Z》當中，Z戰士加入買賣房地產的戰爭，透過擲骰子掀起一場史詩式混戰！\n\n招攬悟空、達爾和悟飯等傳奇戰士，一同在《Monopoly:七龍珠Z特別版》展開冒險吧！\n你遇上紅帶軍和膠囊集團時，記得把握機會成為世界上最富有的戰士。\n布瑪和龜先人等盟友，僵住你取得偉大成就！你能收集所有地契，成為天下第一嗎？\n\n內含精緻特殊造型配件！讓遊戲體驗更上層樓！','\n',char(10)),'https://i.postimg.cc/Xqzxy4TT/IMG-20251004-162410.jpg','販售,家庭',2,6,'簡單',1,1,0,1,1299,0,0,50,212,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(313,'爆炸貓桌遊','歡慶爆炸貓10 週年！出版社隆重鉅獻《 爆炸貓桌遊》 ☆承襲爆炸貓的簡單有趣及陷害元素，絕對熟悉的爆炸貓卡牌和超有趣的圖板翻面設計','https://i.postimg.cc/V6whYs8J/IMG-20251004-162345.jpg','販賣,派對,小品',2,6,'簡單',1,1,0,1,950,0,0,50,213,'','','');
INSERT INTO "_BoardGames_old" ("game_id","name","description","image_url","tags","min_players","max_players","difficulty","total_stock","for_sale_stock","for_rent_stock","is_visible","sale_price","rent_price","deposit","late_fee_per_day","display_order","image_url_2","image_url_3","supplementary_info") VALUES(314,'古墓謎蹤',replace('一款探險家 vs. 僵屍，驚險追逐遊戲，潛入詭異古墓，尋找珍貴寶藏！\n\n玩家分為探險家與僵屍，探險家要躲避僵屍的追擊，也要與其他探險家互相競爭，成為最先收集完寶物的勝利者。\n而僵屍則是要阻止入侵者，將他們逐一消滅！\n\n遊戲進行時，探險家及僵屍分別坐在遊戲版圖兩側，角色棋子內含磁鐵可吸在版圖上，\n僵屍看不到探險家的所在位置，因此探險家移動時千萬要小心，不要被僵屍看出端倪唷～～\n探險家回合可以投擲數顆骰子，並從中選一顆當作此回合移動步數，但是！如果骰到僵屍面，此顆骰子將會被僵屍沒收\n若想贖回骰子，僵屍會馬上移動與骰子顆數相同的步數，何時贖回也是關鍵之一！\n這是一款獨特的不對稱競爭遊戲，僵屍會根據你找到的寶藏、移動的格數，來推敲探險家的位置。\n看著僵屍的棋子一步步朝自己接近....那種緊張的感覺，體驗一次就知道！\n驚險刺激、充滿變數，每一回合都是腦力與運氣的較量，與家人、朋友們玩一場吧！','\n',char(10)),'https://i.postimg.cc/pXS1mJvM/IMG-20251004-162358.jpg','販賣,兒童,家庭',2,5,'簡單',1,1,0,1,1250,0,0,50,214,'','','');
