INSERT INTO "News" ("id","title","category","published_date","image_url","content","is_published","created_at") VALUES(7,'會員優惠懶人包','公告','2025-10-26','',replace('詳細的會員優惠請詢問店員哦\n以下為簡單介紹的優惠懶人包：\nｷﾀ━━━━(ﾟ∀ﾟ)━━━━!!\n1.升等優惠：每升一個等級，即送優惠券(可折抵入場、買桌遊、租桌遊都可以!)\n2.職業優惠：LV.5 時，可以選擇獨特的職業，每種職業都有自己的能力(優惠)\n3.外食機會：有機會探索日和附近美食，當然也還是歡迎吃吃看日和的餐點哦!\n4.團主優惠：可報名團主優惠，擔任日和團主一職!\n5.月月抽獎：每月至少來日和現場遊玩一次，即可以參加抽獎哦!','\n',char(10)),1,'2025-10-03 08:14:44');
INSERT INTO "News" ("id","title","category","published_date","image_url","content","is_published","created_at") VALUES(9,'現在預約享優惠，加入會員升經驗','公告','2025-10-26','',replace('現在用此平台訂位，有優惠哦~請至"場地預約"看有甚麼特殊優惠哦~\n─=≡Σ((( つ•̀ω•́)つ\n現在加入會員立即增加5經驗值，馬上升等不是夢!\n加入會費只要$300，各種福利馬上給您~\n<<會員優惠請看會員優惠懶人包的貼文>>','\n',char(10)),1,'2025-10-26 10:40:37');
INSERT INTO "News" ("id","title","category","published_date","image_url","content","is_published","created_at") VALUES(12,'~日和下午茶~悠閒打桌遊','促銷活動','2026-01-04','https://i.postimg.cc/NGZHz3fP/zhuo-you-xia-wu-cha.png',replace('【1月每周三：日和下午茶】\n還在煩惱下午要去哪嗎？桌遊x茶點 玩桌遊輕鬆無負擔\n活動很簡單：只要點選一份「餐點 ＋ 飲料」， 即享 免入場費 玩桌遊！\n\n【有吃有玩，就是這麼簡單】\n【簡單點個飲料+小點心，不用100元就能玩桌遊~】\n\n由店員挑選1-3款適合的小遊戲，配上簡單的飲料點心\n一起度過輕鬆愉快的下午吧~(*´∀`)~♥\n\n活動時間：2026年1月的每個星期三下午1點~下午6點\n參加方式：一桌四人，桌數有限，請先私訊粉專告知想參加活動哦~','\n',char(10)),0,'2026-01-04 12:01:57');
INSERT INTO "News" ("id","title","category","published_date","image_url","content","is_published","created_at") VALUES(14,'【日和方舟杯 ! 開賽啦 ! 】','比賽活動','2026-03-19','https://i.postimg.cc/SQMVxhjj/4-October-2025-(1).png',replace('【日和方舟杯 ! 開賽啦 ! 】\nლ( • ̀ω•́ )っ\n許多玩家敲碗許久，日和也絞盡腦汁思考怎麼比這個\n有興趣的玩家歡迎往下看看\n首先要先確認的是決賽日能不能參賽!\n【2026/4/19(日)決賽日】\n【如何能參加決賽呢?】\n首先要在 2026/3/21-2026/4/17 這之間來日和打資格賽\n【 懶人包：湊滿四人 ➔ 贏得第一 ➔ 晉級決賽圈！】\n不限平假日，只要湊滿 4 位玩家，繳交當日一般入場費，並向店員宣告這是一場「資格賽」即可\n當天取得該桌第 1 名即可進4/19的決賽日比賽\n【每人每天限打一場資格賽，比完仍可以在日和繼續遊玩哦~】\n【 限量 8 席，其餘候補 】\n能進決賽圈的人員只有8位！先打先有機會！\n後面的人只能安排候補囉～\n【決賽獎勵 】\n決賽辦在週末假日，晉級決賽圈的高手需先繳交報名費 $350\n(賽後依然可以在日和玩桌遊哦)\n🥇 冠軍：購物金 $1,500 元\n🥈 亞軍：購物金 $1,000 元\n🥉 季軍：購物金 $500 元\n🎖️ 第4~8名：入場抵用金\n【 其餘規定 】\n已取得決賽圈資格的玩家不能再進行任何資格賽呦!\n其相關規定和細則請私訊或來電詢問哦\n【  找不到人湊桌】\n可以加入日和社群或是請我們幫忙湊桌\n平常打桌遊，日和這邊也都天天開團，歡迎來加團和大家一起玩哦~','\n',char(10)),1,'2026-03-19 12:18:13');
INSERT INTO "News" ("id","title","category","published_date","image_url","content","is_published","created_at") VALUES(15,'新遊戲推廣周：熱帶椰林雞尾酒','促銷活動','2026-03-26','https://i.postimg.cc/nrf1Hs0P/ni-de-duan-luo-wen-zi.png',replace('🍹 《熱門新遊戲推廣周》 來囉！\n節奏輕快! 精緻配件 ! 骰子歡樂 ! \n《熱帶椰林雞尾酒》來啦~\n٩(｡・ω・｡)﻿و\n結合運氣與小策略的骰子遊戲\n在接下來的連假中可千萬不能錯過它\n有興趣的朋友歡迎來現場體驗看看\n📅 活動期間\n3/28 ～ 4/5\n✨ 只要在活動期間內來店擇一即可享優惠：\n1.試玩體驗： 入場點名遊玩《熱帶椰林雞尾酒》\n2.拍照打卡： 拍下桌遊畫面，發布 IG 或 臉書動態\n🎁 獲得優惠： 完成一項，結帳時即有熱帶椰林雞尾酒的優惠！\n詳細優惠與活動內容以現場與粉專公告為主\n有任何問題都歡迎私訊或詢問店員唷！','\n',char(10)),1,'2026-03-26 05:11:34');
INSERT INTO "News" ("id","title","category","published_date","image_url","content","is_published","created_at") VALUES(16,'4月活動及公休日懶人包!','公告','2026-03-30','https://i.postimg.cc/cHMGrBvF/2026nian04yue-(2).png',replace('日和桌遊｜2026年4月月曆出爐啦 📅\n四月公休之外也是天天開團哦\n月底還有新品體驗會等著你\n也有活動與賽事等你來挑戰！趕快把時間空下來吧～\n\n🛑 營業調整提醒\n4/1（三）、4/2（四） 調整為 下午 4:00 至 晚上 10:00 營業 (16:00~22:00)\n\n【 四月活動重點整理】\n🍹 熱帶椰林雞尾酒周（最後倒數）\n只到 4/5（日）即將圓滿結束！\n還沒體驗這款歡樂派對遊戲的朋友，快把握機會擲出自己的調酒\n\n4/24新品體驗會\n除了有大量新品可以玩之外，當天還會抽桌遊送給大家哦!!!\n千萬不要錯過這天了\n\n🌟 會員經驗加倍週\n4/6（一）～ 4/12（日）\n會員經驗賽為常駐活動~但這週來店遊玩\n經驗賽時，日和提供的經驗值加倍！趕快揪團來快速升級 🆙(前提要第一名R)\n٩(๑•̀ω•́๑)۶\n\n🏆 方舟杯賽事\n4/17（五）：方舟杯資格賽最後衝刺日！在這之前還沒拿到決賽門票的玩家千萬別錯過。\n4/19（日）：方舟杯決賽日 👑 準備見證最終贏家的誕生！\n日和第一場重策略賽事即將結束，敬請期待下次的方舟杯及其他桌遊賽事\n\n🔸 活動內容與時間以現場與粉專公告為主\n有任何問題都歡迎私訊或詢問店員唷！我們四月見 💛','\n',char(10)),1,'2026-03-30 05:41:18');
INSERT INTO "StoreInfo" ("id","name","address","phone","opening_hours","description","booking_button_text","booking_promo_text","booking_announcement_text","booking_notify_user_id") VALUES(1,'日和桌遊','404 台中市北區青島路二段12號','(04)-36099900',replace('週一至週五: 12:00 - 22:00<br>週六至週日及國定假日: 12:00 - 22:00<br>公休日：不定時公休日請參考最新情報或臉書貼文\n','\n',char(10)),replace('今天是個適合桌遊的好日子!!!歡迎來到「日和桌遊」，一個屬於你的桌遊空間！<br>我們位於熱鬧的北平商圈和天津商圈......<br>的隔壁青島路，提供上百款熱門及經典桌遊，無論是策略高手還是派對玩家，都能在此找到樂趣。店內提供舒適且明亮的遊戲空間及專業的遊戲教學。冒險之餘，也別忘了品嚐我們飲料及餐點！<br>都打那麼多介紹了\n<br>還不快來玩玩看٩(๑`^´๑)۶','\n',char(10)),replace('點擊我即可開啟你的冒險預約\n下面可以查看您的預約紀錄哦','\n',char(10)),'用此系統"提前三日"全團可享飲料暢飲折扣20元哦~',replace('若人數較多(8人以上)，或是有特殊需求\n還請來訊或電話告知哦~!','\n',char(10)),'U43e4e5c607aa74a030f61505ebd5e888');
