INSERT INTO "MessageDrafts" ("draft_id","title","content","created_at") VALUES(1,'租借到期提醒','親愛的顧客您好，提醒您租借的桌遊將於明天到期哦~','2025-09-20 17:22:28');
INSERT INTO "MessageDrafts" ("draft_id","title","content","created_at") VALUES(2,'未如期報到','您好，因已超過您訂位的時間，日和這邊將先取消您的訂位。','2025-09-20 18:58:54');
INSERT INTO "MessageDrafts" ("draft_id","title","content","created_at") VALUES(3,'取消訂位','您好，已收到您取消訂位的需求，這邊將取消您的預約，感謝告知。','2025-09-21 22:48:09');
INSERT INTO "MessageDrafts" ("draft_id","title","content","created_at") VALUES(4,'更改訂位','您好，已收到您更改訂位的訊息，這邊將更改您的訂位資訊，請再麻煩核對一次，以免發生錯誤。','2025-10-01 10:53:35');
INSERT INTO "MessageDrafts" ("draft_id","title","content","created_at") VALUES(5,'租借資訊',replace('🎉 租借資訊確認\n\n姓名：\n電話：\n日期：\n租借時間：3天\n歸還日期：\n租借遊戲：\n-\n\n本次租金：\n收取押金：\n\n租借規則：\n1. 收取遊戲押金，於歸還桌遊、確認內容物無誤後退還。\n2. 內容物需現場清點，若歸還時有缺少或損毀，將不退還押金。\n3. 最短租期為3天，租借當日即算第一天。\n4. 逾期歸還，每逾期一天將從押金扣除 50 元。\n\n如上面資訊沒有問題，並已確認租借的桌遊配件齊全，請回覆「ok」或「貼圖」視為同意租借規則。\n感謝您的租借！','\n',char(10)),'2025-10-05 09:56:47');
INSERT INTO "MessageDrafts" ("draft_id","title","content","created_at") VALUES(6,'成功歸還桌遊',replace('您好，已收到您租借的遊戲，已歸還押金給您，請回覆「ok」或「貼圖」視為確認。\n感謝您的租借！歡迎下次再來租遊戲哦~','\n',char(10)),'2025-10-06 11:54:48');
