INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(101,'阿瓦隆','經典陣營推理遊戲，玩家扮演正邪兩陣營，透過任務成功或失敗來找出彼此的身份，投票、推理、嘴砲於一身的經典遊戲!','https://i.postimg.cc/vm9qC5ch/LINE_ALBUM_販售區桌遊_251023_41.jpg','','','販售,租借,陣營,策略燒腦',5,10,'普通',2,1,1,550,100,500,50,1,'阿瓦隆補充說明',8,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(102,'璀璨寶石：漫威版',replace('經典遊戲《璀璨寶石》的主題變體，玩家收集無限寶石，招募英雄、反派和經典場景。\n\n機制略有調整，變得更加有挑戰。','\n',char(10)),'https://i.postimg.cc/R0krHMnL/IMG-20251014-211047.jpg','','','販售,策略燒腦,家庭',2,4,'普通',2,0,2,1590,0,1500,50,1,'',3,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(103,'估估劃劃','一款超級歡樂的派對遊戲，用盡方法讓隊友猜到答案，讓人笑到肚子痛。','https://i.postimg.cc/Prr7NLRJ/LINE_ALBUM_販售區桌遊_251023_11.jpg','','','租借,派對,家庭,兒童',4,99,'簡單',1,1,0,890,100,800,50,1,'',1,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(104,'推倒堤基','想辦法讓自己的三尊堤基雕像排到最頂端，要小心壞心眼的對手移除你要的堤基們哦。','https://i.postimg.cc/Y0sRzg3d/IMG-20260105-093201.jpg','','','販售,租借,家庭,輕鬆小品',2,4,'簡單',2,1,1,880,100,800,50,1,'',5,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(105,'鐮刀戰爭',replace('*此款僅提供現場遊玩*\n《鐮刀之戰》講述的是1920年代一戰後的歐洲，工業與農業激烈碰撞下的蒸汽朋克架空背景。\n英文原名的Scythe(鐮刀) ——即指「農耕發展」，也指戰備後的「收割」。','\n',char(10)),'','','','僅供現場玩,策略燒腦',1,5,'專家',1,0,1,2800,0,0,50,1,'',6,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(106,'星期五',replace('你是住在荒島上的星期五，魯濱遜來到你的小島，一開始他並沒有太多求生技巧，你要幫助他去面對各種冒險。每次戰鬥的勝利，都會增強他的能力，失敗則會讓他擺脫一些惡習。\n\n然而，在孤島上的生活是很磨人的，所以魯濱遜也會老化而且變得笨拙。在本遊戲中，魯濱遜牌庫代表他的各種行為，你要收集更好的卡牌來改善這組牌庫，以幫助魯濱遜在遊戲最後對抗難纏的海盜，重歸文明世界！在這款單人冒險遊戲中，只有你才能贏得最後勝利！','\n',char(10)),'https://i.postimg.cc/sD6NWVkn/LINE_ALBUM_販售區桌遊_251023_20.jpg','','','販售,策略,合作闖關',1,1,'普通',2,0,2,690,0,0,50,1,'',7,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(107,'七大奇蹟','一款經典的卡牌輪抽文明發展遊戲，玩家在三個世代中，透過打出建築、軍事、科技等卡牌來發展自己的文明，爭取最高的總分。另有『領袖』、『艦隊』擴充。','https://i.postimg.cc/xTyMJ68b/IMG_20260106_201910.jpg','','','租借,策略燒腦,家庭',2,7,'普通',1,1,0,1500,1800,440,50,1,'',9,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(108,'土狼在笑你',replace('12歲以上｜3-6人｜30分鐘\n一款心機破表的派對遊戲，玩家扮演印地安人，透過觀察他人的羽毛數量（自己看不到自己的）來判斷是否吹牛。','\n',char(10)),'https://i.postimg.cc/GhJG8Xt4/IMG_20260106_201932.jpg','','','租借,派對,輕鬆小品,家庭',3,10,'簡單',1,1,0,890,100,800,50,1,'',10,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(109,'叔叔的遺囑',replace('*此款僅提供現場遊玩*\n遊戲時間:75分鐘  建議年齡:14歲以上\n「叔叔的遺產」是一款涉及經濟的遊戲，但你的目的卻非賺取最多的金錢。\n相反，你需要花光自己的全部家當，比其他玩家更快破產，聽起來是不是很不可思議？\n遊戲中，你將扮演維多利亞時期一位百萬富豪的姪子(姪女)。\n他臨終前寫下了一份遺囑，宣布將自己所有的遺產轉交給最會享受金錢的親戚。\n為此，你需要和其他玩家進行一場敗家的比拚，\n無論是騎馬、看戲、舉辦晚宴，還是購置房產或遊艇出海等。\n總之，你的目的只有一個，趕在其他玩家之前，花光你初始獲得的所有錢。\n當然，從本質上來講「叔叔的遺產」仍是一款工人擺放遊戲，\n玩家輪流差使自己的僕人去執行相應的敗家行動。\n執行順位和行動選擇是整局遊戲的關鍵。','\n',char(10)),'https://i.postimg.cc/9FtZRL07/IMG_20260106_201956.jpg','','','僅供現場玩,策略燒腦',2,5,'困難',1,0,1,2400,0,0,50,1,'',11,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(110,'翠嶼秘境 Inis',replace('*此款僅提供現場遊玩*\n遊戲時間	90分鐘\n建議年齡	14歲以上\n\n翠嶼秘境(Inis)是關於凱爾特人歷史和傳奇的領地佔領遊戲。\n\n善用機謀與策略，策動攻擊，擴張領土，佔領敵對部落，或掌控神廟，成為最有實力的酋長。\n除了迷人的遊戲性，典雅富有特色的美術風格，更讓遊戲獲得2016 Golden Geek Best Board Game Artwork & Presentation提名，\n與精緻的模型配件相互輝映，是值得玩家珍藏的精品桌遊。\n以手牌管理、區域控制、區域移動、牌庫構築等為主要遊戲機制。','\n',char(10)),'https://i.postimg.cc/FK1L6mZs/IMG_20260106_202054.jpg','','','僅供現場玩,策略燒腦',2,4,'困難',1,1,0,2100,0,0,50,1,'',12,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(111,'毒逗魔藥師',replace('遊戲時間	30分鐘\n建議年齡	14歲以上\n一款節奏快速的弄爆別人遊戲，玩家扮演魔藥師，要將不同成分的藥材放入鍋中，同時要想辦法讓別人的鍋子爆炸，但同時要處理自己鍋子裡的素材，遊戲投過卡牌效果來做出藥材轉換的方式，有點燒腦又有點好笑的輕策略選擇。','\n',char(10)),'https://i.postimg.cc/Mp6Ry1f3/IMG_20260106_202017.jpg','','','租借,策略燒腦,家庭',2,5,'普通',1,1,0,1800,200,1800,50,1,'',13,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(112,'詭鎮奇談 卡牌版',replace('*此款僅提供現場遊玩*\n一款克蘇魯神話主題的合作式成長卡牌遊戲（LCG），相當有帶入感的劇本型遊戲，玩家可以在遊戲內跟不同的角色對話，甚至一些選擇會影響未來的劇本走向，同時角色也會隨著玩家的冒險持續成長，連同創傷也可能跟在玩家身上哦。','\n',char(10)),'https://i.postimg.cc/qBb1rVTJ/IMG-20260105-115049.jpg','','','僅供現場玩,策略燒腦,合作闖關',1,2,'專家',1,0,1,1850,0,0,50,1,'',14,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(113,'水瓶座',replace('如何瞞過對手，讓手中任務牌指定的元素七張相互連結？\n\n3歲以上｜10-30分鐘\n孩子們喜歡顏色豐富的設計、輕快的節奏及尋找相似配對的遊戲策略；大人們則酷愛遊戲過程中激烈的競爭。\n這是一款老少咸宜的家庭紙牌遊戲，發完牌後悄悄計劃如何移動你的元素牌，千萬別以為自己快贏了⋯⋯恐怕任務牌就要被調包囉！','\n',char(10)),'https://i.postimg.cc/d0DyfvBk/IMG_20260106_202146.jpg','','','租借,家庭,輕鬆小品,兒童',2,5,'簡單',1,1,0,490,50,400,50,1,'',15,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(114,'化妝舞會',replace('*僅供現場遊玩*\n一款角色扮演與推理遊戲，每位玩家持有一個隱藏的角色，可以透過交換角色、宣告角色能力來賺取金錢，但因為會交換身分，所以整個過程混亂歡樂，考驗所有人的記憶和吹牛，先賺到13元的玩家獲勝。','\n',char(10)),'https://i.postimg.cc/tg7xcy5R/IMG_20260106_202132.jpg','','','僅供現場玩,輕鬆小品,策略燒腦,派對',2,13,'普通',1,1,0,890,0,0,50,1,'',16,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(115,'神靈大對決',replace('一場關於窺探人心、秘密競標和區域控制的遊戲\n明朝末年連綿的大災難，人間化為煉獄，沒人會再次體驗的！\n\n \n\n遊戲背景\n昏庸的皇帝和無止境的黨爭導致連年戰亂不已，水災、大旱和暴雪都無人管理。\n無助的人們紛紛祈求上蒼庇護，於是乎上蒼派了五路神仙下凡，普度眾生！\n \n\n遊戲目標\n\n在這款遊戲中你會扮演一位神靈，通過出其不意、神鬼莫測的操作，\n完成祈禱，爭取更多的信徒支持，獲得主宰神壇的統治地位！','\n',char(10)),'https://i.postimg.cc/8C36Q3Ky/IMG_20260106_202306.jpg','','','租借,策略燒腦',2,5,'普通',1,1,0,600,100,600,50,1,'',17,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(116,'一知半解骨董市',replace('德川家在江戶建立幕府之後,江戶的商業更活躍了。\n有一天,在一個倉庫裡發現了一大堆奇珍異寶,這些寶物即將被拿到古物市集\n有幾個商人聽到這個消息便決定一起去看看,但其實他們都不太懂古董的價格。\n實際上，他們就是一群笨蛋而已。買太多相同的古董(等一下要轉賣掉)會讓其他買家失去興趣而跌價。\n在這種價格變來變去的情況下,哪個商人能賺走最多利潤呢?','\n',char(10)),'https://i.postimg.cc/R0qHY9R7/IMG_20260106_202202.jpg','','','租借,家庭,輕鬆小品,派對',3,6,'簡單',1,1,0,590,100,500,50,1,'',18,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(117,'偶像發掘','在這個世界上，還埋藏著許多不為人知的偶像候補生。請您化身為精明幹練的製作人，努力發掘出未來的偶像吧！將大量的偶像送到世人面前，讓更多的觀眾感到熱血沸騰──這項任務就只有您才能辦到！ 本遊戲是一款簡單易懂的卡牌遊戲。每位玩家要做的事情，就是從疊放的卡牌裡發掘偶像卡，爭取儘可能多的觀眾（得分），由此來贏得遊戲的最終勝利。','https://i.postimg.cc/yYWRVMSD/image.png','','','販售,派對,家庭',2,6,'簡單',0,0,0,450,0,0,50,1,'',19,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(118,'瞎掰王',replace(' ⭐️熱銷亞洲的派對桌遊!這是款專為講幹話設計的遊戲！到底誰在講真話，誰在瞎掰？⭐️\n\n來一場『瞎掰王』讓你塵封已久的幹話小宇宙爆發！胡謅無罪，瞎掰有理，達到吹牛最高境界。這遊戲的最終目的，就是要你成為『瞎掰王』。\n2023年度完全不能錯過的超爆笑桌遊，讓大家一起笑到肚子痛吧!\n','\n',char(10)),'https://i.postimg.cc/YS4JSq5J/IMG_20260326_150228.jpg','','','販售,租借,派對',3,10,'簡單',2,1,1,1080,150,1000,50,1,'',20,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(119,'SDGS瞎掰王',replace('桌遊與教育題材的完美結合，推薦教育用\n🌎SDGs(2030永續發展目標)包含了17項核心\n包含消除貧窮、氣候變遷、性別平權等...議題\n\n看似無關的目標，其實都跟生活息息相關！\n在有款桌遊跟SDGs合體了，就是《瞎掰王SDGs教育版》‼\n題目都變成SDGs系列相關的題目，大家可以看題說故事，一起學習新知識，分享議題看法，玩著玩著就又學到了新知識','\n',char(10)),'https://i.postimg.cc/L5SnjWyM/SDGS.png','','','販售,派對',3,8,'簡單',1,0,1,690,0,0,50,1,'',21,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(120,'花見小路',replace('歡迎來到古都最負盛名的花見小路通。在這條街上的料亭內，具有多樣專長的女性表演工作者─藝者─在筵席上為客人表演，展現她們高貴穩重的氣質。夜幕低垂，燈火從石板路兩側那些古色古香的木造格子戶中透出，照映出裡頭人們若隱若現的模樣，引起無限的想像空間。\n你是知名高級料亭的老闆，為了爭取七名最好的藝者來到你的店裡服務，你與其他老闆競爭，藉由蒐集她們最擅於使用的表演物品來吸引她們，在你的店裡發揚古都傳統文化的丰采','\n',char(10)),'https://i.postimg.cc/5N1FV8gM/IMG_20260106_202742.jpg','','','租借,輕鬆小品',2,2,'簡單',1,1,0,450,50,400,50,1,'',22,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(121,'農家樂',replace('★最經典的工人擺放遊戲\n★模擬中世紀農家，種植田地、畜牧，建造房屋\n★中重度策略，耐玩度極高','\n',char(10)),'https://i.postimg.cc/XNhrxYQV/IMG-20260106-202400.jpg','','','租借,策略燒腦',1,4,'困難',1,1,0,2090,250,2000,50,1,'',23,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(122,'上洛',replace('《上洛》(Joraku) 是一款結合這兩種機制的遊戲，透過吃墩的過程贏得各區影響力，怎麼出牌要仔細考量。\n\n遊戲中有三種花色，和大部分吃墩遊戲一樣，接下來出牌的玩家一定要跟引牌大出相同花色的卡片，\n\n除非缺門 (手牌缺該色卡片) 才能打出不同花色的卡片。遊戲贏墩的方式是看數字大小 (忽略花色)，\n\n數字 6 基本上贏得任何一墩 (最大的王牌)，不過場上如果有玩家出忍者，則忍者會剋數字 6 (但比其它數字小)。\n每張打出的卡片會有些功能讓玩家移動自己的大名和忍者，是一款透過各區域影響力比玩家誰分數最高的遊戲。','\n',char(10)),'https://i.postimg.cc/0N3wR3WV/IMG_20260106_202255.jpg','','','租借,策略燒腦',3,4,'普通',1,1,0,850,100,800,50,1,'',24,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(123,'印加寶藏',replace('你和你富有冒險精神的夥伴們，前往古老的印加神廟中，尋找稀有的綠松石、黑曜石與黃金。\n\n遊戲中的每個回合，你都必須決定是要進一步地深入探索神廟，或者是要安全地返回營地，將已經到手的寶物好好收藏保管。\n越往神廟的深處探索，就表示已經到手的寶物有可能因為神廟內發生的種種危機，而被迫拋棄，例如：巨型蜘蛛、甦醒的木乃伊、地底竄出的烈火與擁有劇毒的蛇⋯⋯都將讓你只能丟下一切逃命。\n但是傳聞中無價的古印加神器就在這裡，只有能克服心理恐懼的人才有機會得到它！\n\n你究竟有多勇敢？要有多少的寶物才能夠滿足你？玩過印加寶藏後你才會知道！','\n',char(10)),'https://i.postimg.cc/J7jBvpbp/IMG_20260106_202700.jpg','','','租借,派對,家庭,輕鬆小品',3,8,'簡單',3,3,0,1090,150,1000,50,1,'',25,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(124,'黃牌2022 18+',replace('此遊戲不適合18歲以下遊玩哦。\n黃牌(Yellow cards)是一款很間單的文字填空桌遊。\n【紫卡】裡面有挖空的句子，玩家要用【黃卡】上的字做填空。由裁判決定哪個玩家組合出來的句子最不合胃口，並給該玩家一張黃牌。桌遊黃牌要填的字詞大部分都是18禁或是亂七八糟的字眼，因此一本正經的句子也變得非常不正經。算是一款簡單又勁爆的Party Game，建議和熟悉的朋友玩會比較放得開？黃牌是一款老少不宜，只適合跟熟人玩的桌遊。想知道朋友的尺度在哪，這款桌遊倒是很好拿來用。','\n',char(10)),'https://i.postimg.cc/3x00520V/2022.png','','','租借,派對,輕鬆小品',4,10,'簡單',1,1,0,990,100,900,50,1,'1197g',26,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(125,'字字轉機',replace('你曾有過想到某個事物，卻一時答不上到底是什麼的經驗嗎？平常的常識，在遊戲中變得困難十足，歡樂就此誕生！\n一款隨機對手、隨機題目的快答遊戲，考驗你的圖案識別能力、反應力以及聯想力。遊戲中玩家必須聚精會神尋找自己的對手，找到後迅速講出對方卡牌上的題材答案，最快答對的玩家獲得分數，成為天下第一的「嘴遁王」！','\n',char(10)),'https://i.postimg.cc/W1yCB2Sk/IMG-20251015-112102.jpg','','','租借,家庭,派對,輕鬆小品',3,6,'簡單',1,1,0,490,50,400,50,1,'',27,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(126,'逃離亞特蘭蒂斯',replace('*此款僅提供現場遊玩*\n"十世紀早期"一個屬於冒險和探索的時代。\n探險者們在大洋的中心發現了神秘的亞特蘭提斯島，\n傳說島嶼上藏有無價的寶物！\n在抵達亞特蘭提斯後，探險者們發現了大量的奇珍異寶。\n正當他們滿載而歸之時，亞特蘭提斯島卻開始沉沒！\n誰能最終安全返航呢？\n   \n這是一場刺激的生存遊戲，\n一個由40個六邊形組成的島嶼正在慢慢沉入海洋，\n玩家們需要在主島最終爆炸之前，\n向周圍島嶼安全轉移。\n你既可以游泳也可以用船去逃離，\n但必須避開海蛇、鯨魚和鯊魚前往安全地帶，\n並竭盡所能保護自己的財產，獲得更多的得分。','\n',char(10)),'https://i.postimg.cc/JnkB1qSD/IMG_20260106_202457.jpg','','','僅供現場玩,家庭,派對',2,4,'普通',1,1,0,1750,0,0,50,1,'',28,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(127,'石器時代',replace('在浩瀚的人類歷史當中，在不同的時期，人們面臨著不同的挑戰。\n在石器時代，農業誕生了﹔人類開始採集更多的自然資源，並且出現簡單的房舍。\n人與人間漸漸有了交易行為，文明也逐漸萌發、擴展。\n人口的成長，也導致了對高效率狩獵的強烈需求。\n玩家在遊戲中，要試圖去達成所有的挑戰。有許多種策略可以完成這些挑戰，因此每個玩家可以選擇自己擅長的策略，走上不同的路。\n找出你自己的策略模式，並看看它是不是能帶你走向勝利的最佳策略﹗','\n',char(10)),'https://i.postimg.cc/PJMXWsBr/image.png','','','租借,策略燒腦,家庭',2,4,'普通',1,1,0,1890,200,1800,50,1,'',29,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(128,'卡卡頌：非洲之旅',replace('熱帶氣候的高溫籠罩著非洲草原，薰風徐徐，我們來到這片一望無際的草原，希望能看到這裡最受歡迎的大型動物。猴子在樹枝上擺盪，獅子在樹蔭下休憩，大象緩慢的步伐震動著大地，水池邊總是聚集了多種不同的動物，非常值得在一旁靜靜等待，捕捉更多的曼妙身影。\n這款合作即競爭的策略性版圖遊戲，每次玩都會激盪出不同的策略或同盟關係，除了對圖像的敏感外，開放的合作態度更是致勝的關鍵！','\n',char(10)),'https://i.postimg.cc/qvZHpcJ9/IMG-20251014-211017.jpg','','','販售,家庭,策略燒腦',2,5,'普通',3,0,3,1290,0,0,50,1,'',30,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(129,'駱駝大賽',replace('快來見識有史以來最瘋狂的駱駝大賽！\n\n身為埃及上流社會的你，來到這裡試試手氣，對自己看好的駱駝下注，以期在分段賽及賽終時贏得最多獎金。\n然而，互相揹負的駱駝，讓賽況變得更難預測。抓住比賽的節奏，精準掌握下注時機，才是讓你贏錢的關鍵。\n令人傻眼的是，來了兩名新的選手 —— 逆向奔馳的瘋狂駱駝，儘管立刻喪失了參賽資格，但仍嚴重驚擾了整場賽事⋯⋯\n讓我們拭目以待這場精彩的比賽！','\n',char(10)),'https://i.postimg.cc/SNC3X2wB/IMG_20260106_202650.jpg','','','租借,派對,家庭',3,8,'普通',1,1,0,1490,150,1400,50,1,'',31,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(130,'伐木達人',replace('用斧頭小心地敲擊樹塔，並收集掉落的樹皮來得分，如果不慎讓樹心也掉下來，就要扣分囉！遊戲結束時，得分最高的玩家獲勝！\n\n這是一款簡單易學又充滿歡樂的遊戲，不管人數多寡，都能炒熱氣氛，絕對是派對必備！','\n',char(10)),'https://i.postimg.cc/tCyVjF5c/IMG_20260106_202729.jpg','','','租借,派對,家庭,兒童',2,7,'簡單',1,1,0,790,100,700,50,1,'',32,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(131,'影子陣',replace('準備好迎接緊張的３Ｄ拼圖遊戲，這將令你絞盡腦汁。\n\n在這遊戲中你必須安排方塊以配合挑戰卡上描述的「影子」，影子陣包含三個難度和最多四位玩家使用的充足方塊。','\n',char(10)),'https://i.postimg.cc/J4mBLjxG/IMG_20260106_202753.jpg','','','租借,家庭,輕鬆小品',1,4,'簡單',1,1,0,880,100,800,50,1,'',33,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(132,'柯爾特快車','2015 Spiel des Jahres Winner 榮獲 2015 德國桌遊家庭類大獎一場驚險刺激的火車搶劫即將開始！你扮演著強盜的一員，雖然你們打劫了乘客身上的財物，但其實你們真正的目的是位於火車頭，由警長重重看守的保險箱！你必須在同夥中搶先一步，奪得保險箱，成為西部最富有的逃犯！','https://i.postimg.cc/GhybbKzF/image.png','','','租借,派對,家庭',2,6,'普通',1,1,0,1260,150,1200,50,1,'',34,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(133,'煤礦大亨紙牌版',replace('20世紀時，德國的艾森市是歐洲的煤礦中心，獻身在採煤的黑暗世界中，你從礦坑中開採煤礦，將它們裝上火車，經由遍布的鐵路網，將煤礦運送至各地以獲取財富。\n「煤礦大亨．超乎紙牌的紙牌遊戲」是依據2013年發行的「煤礦大亨桌上遊戲」所設計的一款獨立紙牌遊戲，本遊戲有創新的遊戲機制以及近達240張的紙牌。除了與基本版遊戲一樣的刺激，「煤礦大亨．超乎紙牌的紙牌遊戲」將帶給你獨一無二的遊戲體驗。','\n',char(10)),'https://i.postimg.cc/13Y1y0RP/IMG-20251014-211027.jpg','','','販售,策略燒腦',2,4,'普通',2,0,2,1090,0,0,50,1,'',35,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(134,'勃根地城堡',replace('勃根地城堡建設於中古世紀的法國，\n玩家們即是扮演當代的貴族，統治一塊屬於自己的小領地，\n為了發展自家領土，必須開拓據點與建設城堡、藉由河運貿易、開墾銀礦、以及善用旅行者的寶貴知識。','\n',char(10)),'https://i.postimg.cc/NMHrg4Zq/IMG_20260106_202409.jpg','','','租借,策略燒腦,家庭',2,4,'困難',1,1,0,1360,150,1300,50,1,'',36,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(135,'跑跑龜','期待已久的中文版跑跑龜終於出版了，百分之百台灣製造的中文版，可愛的木製烏龜及超有趣的賽跑機制，讓玩家們之間互動頻繁，雖然只有短短10~12步，隨著出現的行動牌烏龜們的先後順序可說是變化莫測，如果可以常常踏上別隻烏龜的背也能夠後來居上哦，快和孩子試試看此款輕鬆又有趣的遊戲吧！','https://i.postimg.cc/L5f4Q3b3/image.png','','','租借,家庭,兒童,輕鬆小品',2,5,'簡單',1,0,1,980,100,900,50,1,'',37,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(136,'拉密:變臉版',replace('▲世界上最受歡迎的遊戲之一\n\n▲新增變化規則，適合升級版玩家\n\n\n\n★經過時間考驗的遊戲：由以色列人Ephraim Hertzano 於1930年初於羅馬尼亞所研發設計。 因遊戲與眾不同的遊戲規則和娛樂性，靠著口耳相傳，拉密遊戲就在穩健中不斷的成長。\n\n★最受玩家歡迎的遊戲：成為全世界第三大最佳銷售遊戲和全世界第一大最佳銷售的數字磚塊牌。\n\n★打破語言隔閡的遊戲：超過50,000,000個拉密遊戲，用28種不同的語言發行，橫跨五大洲，風行於全世界70多個國家和地區。但是此遊戲所包含的106個磚塊牌所代表的意義是全球共同了解的\n\n★激發思考神經的遊戲：因為它不太靠運氣，卻需要您運用很多的策略。\n\n◎排列組合能力 — 學習數字和顏色的最佳排列組合\n\n◎創新規劃能力 — 培養能不受限於所面對的現有牌局，重新規劃新的牌局組合\n\n◎決斷分析能力 — 訓練在短時間內，做出正確的出牌和操作牌的能力。','\n',char(10)),'https://i.postimg.cc/wTgp2Tb7/IMG-20251014-205552.jpg','','','販售,租借,家庭,策略燒腦',2,4,'普通',1,1,0,950,100,900,50,1,'',38,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(137,'猜心俱樂部',replace('★ 遊戲簡介\n\n接近港口的位置，讓它匯集許多來自世界各國的旅行家前來較勁，\n\n但是知識豐富的你，也絕對不能讓他們小看。\n\n這群好勝的旅行者不懷好意地要求你加入他們的遊戲，從牌縫間透出的銳利眼神看來，\n\n不但要回答他們的問題，還要贏走你帶來的所有籌碼。\n\n \n\n每一道問題都是一個密室。在遊戲裏頭，像是躲貓貓一樣，猜測彼此的答案。\n遊戲過程中，每個人都必須回答問題，把六個不同的答案分別寫在六張卡牌上(用畫的也可以！)。\n然後輪流打出手牌或者進行預測。\n答案相同，可以獲得碟中所有的籌碼；\n如果不同，就支付一枚十元籌碼，相當簡單。','\n',char(10)),'https://i.postimg.cc/0yyM6xhV/IMG_20260106_202928.jpg','','','租借,派對,家庭',2,8,'簡單',1,1,0,990,100,900,50,1,'',39,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(138,'復仇女神號',replace('*此款僅提供現場遊玩*\n星辰離我們不再遙遠。小行星開採已遍地開花。火星和金星上的定居點已經可以自給自足。然後，一個來自宇宙深處的遊蕩者以1/2的光速沖我們而來。它擦過月球，把這顆衛星撞擊成碎片，月球脫離軌道，對地表造成了災難性的破壞。\n\n\n\n但很多人卻抓住了這個可能性開始謀利，因為有人發現撞擊後留下的殘餘雜質和奇異的物質，人們不再滿足於傳統的小行星收穫。太空船被重新改造，狂熱的人們不惜在浩瀚的太空中花費數年，他們在群星之間穿梭，只為釣到下一條大魚。他們就像一條條捕鯨船，流星，小行星，死亡的原行星和其他來自宇宙深處的奇怪物體都成了他們的拾荒場。\n許多人一去不返。而是也澆不滅人的熱情。儘管有人明知攔截極速運行下的不明物體非常危險。這時，傳言有人發現了不可思議的東西……','\n',char(10)),'https://i.postimg.cc/BbJ7Rqh7/image.png','','','僅供現場玩,策略燒腦,合作闖關',1,5,'專家',1,0,1,4800,0,0,50,1,'',40,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(139,'犯人在跳舞','救命啊！這裡發生命案了！封鎖現場！所有人不准動！犯人一定還藏匿在我們當中，是你？還是他？犯人究竟是誰？想辦法揪出他吧！','https://i.postimg.cc/dVhSmbFW/LINE_ALBUM_販售區桌遊_251023_24.jpg','','','販售,租借,派對,家庭,輕鬆小品',3,9,'簡單',1,1,0,400,50,400,50,1,'',41,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(140,'聖石之路旅行版',replace('*僅供現場遊玩*\n遊戲規則簡單，新玩家也可以立即上手，然而遊戲的過程由始至終都變幻不斷、樂趣無窮。','\n',char(10)),'https://i.postimg.cc/J42K5cW2/image.png','','','僅供現場玩,家庭,輕鬆小品',2,4,'簡單',1,1,0,400,0,0,50,1,'',42,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(141,'數字火車',replace('只要計分紙夠多，想要幾人玩都可以!!\n簡單有趣的數學賓果遊戲，將每回合隨機抽出的數字寫下來，盡可能完成最長的升序排列。考驗玩家對機率的掌握，當然也需要一點好運囉！\n2013 美國家長之選優選獎推薦','\n',char(10)),'https://i.postimg.cc/HsZhMpq3/LINE_ALBUM_販售區桌遊_251023_19.jpg','','','租借,家庭,兒童,輕鬆小品',1,99,'簡單',2,2,0,790,100,700,50,1,'',43,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(142,'吹牛骰BLUFF',replace('*此款僅提供現場遊玩*\n一款經典的骰子吹牛遊戲，玩家搖動自己的骰盅，然後根據所有玩家的骰子（只能看自己的）來叫喊某個點數的骰子總共有多少顆，考驗大家的表情控管，好好的吹牛吹爆別人吧','\n',char(10)),'https://i.postimg.cc/KzpghfQX/BLUFF.png','','','僅供現場玩,派對,家庭,輕鬆小品',2,6,'簡單',1,1,0,1700,0,0,50,1,'',44,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(143,'大魔術師:魔幻傳奇',replace('*此款僅供現場遊玩*\n數十年前，這裡曾是一座被譽為魔幻之都的繁華城市，而現在卻只徒留著昔日輝煌的殘影。\n\n這座城市無私的贊助人，史上最偉大的魔術師達爾高，在一次表演的最後一刻神秘消失，\n他最後的表演，也宣告了黃金時代在這一天結束，此後再也未出現過有關達爾高的消息，直到現在…\n \n一天夜裡，四位來自不同魔術領域，才華洋溢的魔術師，都收到了一份神祕的邀請。\n那位偉大的達爾高從未知之地歸來，親自召集他們，來揭示自己隱瞞終生的秘密：他那閃耀的琥珀聖物，魔幻之石的真相。\n儘管許多人以為，這不過只是他的護身符罷了。\n但根據他的透露，這塊石頭會賦予其擁有者超常的智慧、速度，以及感知力：一位完美的魔術師應具備的素質。\n \n達爾高的秘密只是他偉大計劃的一部分：\n他希望挑選出一位值得託付之人，繼承他的這塊石頭和全部遺產，在他死後重振魔格利亞，讓這裡重新成為魔幻之都。\n而繼承者的人選，將在這四位天才魔術師中產生，他必須在為期七週的名利競爭中脫穎而出。\n成敗在此一舉，這四位魔術師必將不惜一切得勝利。\n究竟誰能夠成為下一個魔幻傳奇?','\n',char(10)),'https://i.postimg.cc/BZ1xG9WM/image.png','','','僅供現場玩,策略燒腦',2,4,'專家',1,0,1,6000,0,0,50,1,'',45,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(144,'情書6人版','皇宮裡的每一個人，千方百計想要靠近公主，贏的芳心，希望能收到公主的情書。在眾多的競爭對手中，如何收到這珍貴的情書，快點想想辦法吧！','https://i.postimg.cc/KYzMqCr7/image.png','','','租借,派對,輕鬆小品,家庭',2,6,'簡單',1,1,0,450,50,400,50,1,'',46,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(145,'椰子猴王',replace('利用猴子將椰子發射出去，若投進杯子中，就可贏得該杯子，第一個以杯子建好金字塔的猴子，便會成為王者！\n\n椰子猴王在遊戲中可以練習到手指分離性動作、雙手協調、視覺動作整合、心像演練、視覺認知、動作計畫能力等，還能促進小朋友的挫折忍受度及情緒控制能力！\n\n可愛又討喜的猴子配件，絕對可以馬上抓住小朋友的心～\n非常適合親朋好友一同遊玩，大小朋友都會喜歡的！','\n',char(10)),'https://i.postimg.cc/j5nJKN1L/image.png','','','租借,派對,家庭,兒童,輕鬆小品',2,4,'簡單',1,1,0,750,100,700,50,1,'',47,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(146,'十三道線索',replace('數起兇殘的犯罪案件震驚了1899年的倫敦，謎樣的案情掩蓋了真相，蘇格蘭警場在黑暗中摸索，號召一群優秀的偵探前來協助破案。\n每位偵探必須利用敏銳的直覺，從13道線索中找出蛛絲馬跡，負責解開自己的謎題，比其他人更快偵破自己的案件！','\n',char(10)),'https://i.postimg.cc/8cgfsvV4/IMG_20260106_202532.jpg','','','租借,家庭,策略燒腦',2,6,'普通',1,1,0,1190,150,1100,50,1,'',48,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(147,'吾王塔羅之戰',replace('塔羅眾神世世代代各司其職、盡忠職守，引領著眾生萬物。不知何時，從渾沌之中誕生了一股神祕力量－「科技神」。新神的崛起打亂了長久以來的平衡，破壞了牽制著塔羅們的枷鎖，塔羅眾神因此受到污染與影響，世界開始動亂不安⋯⋯ \n\n\n 《瘋狂島MaddishIsland》2022年全新鉅獻，第七款原創桌遊《吾王：塔羅之戰》登場啦！這次玩家們將化身成一位隱匿身分的塔羅使者，借用其他塔羅的能力，依循目前已知的線索，抽絲剝繭、推理猜測，才能輔佐神諭淨化所有被汙染的塔羅眾神。','\n',char(10)),'https://i.postimg.cc/FK7Yg3ND/image.png','','','租借,輕鬆小品',2,4,'普通',1,1,0,605,100,600,50,1,'',49,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(148,'牛頭王老五',replace('一個類似「誰是牛頭王？」（6 nimmt [Take 6]）的姊妹品遊戲，\n設計多了一些變體，但是同樣刺激、耐玩，推薦最適合帶動全家或朋友們火熱氣氛的遊戲之一！\n在這個遊戲你儘可能地收集綠色的牛頭，在桌上有許多列的卡片，\n當你放置卡片是第五張時，你須將整組的片卡收走，\n整組卡片中綠色是正分，紅色是負分，收集最多分數的玩家為優勝者。\n\n','\n',char(10)),'https://i.postimg.cc/X7sNHq2h/image.png','','','租借,家庭,輕鬆小品,策略燒腦',2,6,'簡單',1,1,0,500,50,500,50,1,'',50,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(149,'狼來了',replace('大野狼偷偷潛入農舍！\n可能偽裝成綿羊、獵人或是獵犬，\n而為了混淆大野狼，農舍裡的大家也進行偽裝大作戰，\n結果最後都搞不清楚誰是誰了！\n放羊的小孩還趁機惡作劇，大喊「狼來了～！」。\n每個人得要小心翼翼找出彼此真正的身分，\n究竟是大野狼會抓到綿羊、還是農舍的夥伴們能成功戰勝大野狼呢？','\n',char(10)),'https://i.postimg.cc/fWvFw7Bh/LINE_ALBUM_販售區桌遊_251023_2.jpg','','','販售,派對,策略燒腦',4,8,'普通',2,0,2,790,0,0,50,1,'',51,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(150,'字母風火輪',replace('在十秒內，想出你的解答吧！\n字母瘋火輪是一款挑戰反應，訓練思考的遊戲。\n玩家要在十秒內，依據題目的規定，想出具有可使用注音（字母）開頭的答案。\n能撐到最後的玩家，就是獲勝者！\n\n★獲獎★2014 Mensa Select門薩推薦','\n',char(10)),'https://i.postimg.cc/pTFn2Z3P/IMG_20260106_202448.jpg','','','租借,派對,家庭,輕鬆小品,兒童',2,8,'簡單',1,1,0,890,100,800,50,1,'',52,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(151,'煉金術士',replace('*此款僅提供現場遊玩*\n一款中度偏重的推理策略遊戲，玩家扮演煉金術士，透過實驗來測試不同藥材的組合，推理出八種藥材的鍊金方程式，並發表論文來獲得聲望。','\n',char(10)),'https://i.postimg.cc/05f9jrqQ/image.png','','','僅供現場玩,策略燒腦',2,4,'專家',1,1,0,2400,0,0,50,1,'',53,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(152,'地產大亨台灣版','經典的房地產交易遊戲《大富翁》的台灣主題版本，玩家在圖版上移動，購買台灣各地的地產並向過路的對手收取租金，目標是讓所有對手破產。','https://i.postimg.cc/xdy45J5N/image.png','','','租借,家庭,兒童,派對',2,6,'簡單',1,1,0,699,100,600,50,1,'',54,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(153,'哆寶/嗒寶',replace('由法國 Asmodee發行、Dobble (Spot It)，就是你能訓練小朋友的反應力及對圖案的辨識力。圓型鐵盒輕巧好攜帶，讓你一路玩著走! 比心臟病更刺激，更好玩。 試試看，小心大家都上癮喔!\n\n就是它、發現它，你贏了！ 遊戲中任2張卡，總有且只有一個一樣符號。 多人參加4種玩法，要銳利眼睛和敏捷反應喔!','\n',char(10)),'https://i.postimg.cc/KvZwMNSy/IMG_20260326_151023.jpg','','','租借,家庭,兒童,輕鬆小品',2,8,'簡單',2,1,1,500,50,500,50,1,'',55,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(154,'環遊世界80天',replace('改編自知名小說與桌遊"龜兔賽跑"，\n榮獲第一屆德國年度最佳遊戲(Spiel des Jahres)！\n西元1872年10月2日，斐利亞福克自誇可在80天內完成環遊世界一周，\n同是革新俱樂部的成員們向他下了一場賭注，不相信這位個性古怪的紈绔子弟可以成功，\n於是他和忠心的僕人路路通旋即啟程，不過艱鉅的挑戰隨之而來...\n英格蘭 50,000英鎊劫案不幸同時發生，讓斐利亞福克背上 大盜的首要罪嫌！\n你能在世人面前成功地證明你的清白，並實現環遊世界80天的壯舉嗎？','\n',char(10)),'https://i.postimg.cc/bNN5dGBQ/LINE_ALBUM_販售區桌遊_251023_15.jpg','','','販售,家庭',2,6,'普通',1,0,1,1300,0,0,50,1,'',56,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(155,'仙境幽谷',replace('*僅供現場遊玩*\n在迷人的永恆幽谷裡面，下面是如高塔矗立的樹木枝葉，\n在蜿蜒的河流和苔癬遍布的洞穴之間，一個森林動物的文明世界正在繁衍擴張。\n從長寒地到鈴歌地，一年年過去永恆不變，但是現在，尋找新領土來建立新城市的時候到了。\n你會是一隊動物的領袖來執行這個任務。有建築物要建造，和其他角色見面，事件要處理 - 你將要面對忙碌的一年。\n你能夠在寒冬之月升起前，讓明亮的陽光照耀在你的城市上嗎？','\n',char(10)),'https://i.postimg.cc/RF2pV7V8/image.png','','','僅供現場玩,策略燒腦',1,4,'普通',1,0,1,3000,0,0,50,1,'',57,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(156,'殭屍貓的試膽大會',replace('日本正式授權人氣商品全球首發\n可愛又恐怖的試膽大會正式展開!\n派對遊戲熱門首選！','\n',char(10)),'https://i.postimg.cc/FHwCPTsg/LINE_ALBUM_販售區桌遊_251023_36.jpg','','','販售,租借,派對,家庭,輕鬆小品',2,6,'簡單',2,1,1,590,100,500,50,1,'',58,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(157,'鍛骰物語 ',replace('你是被諸神選上的勇士之一。\n在鍛骰物語中依照自己的喜好自由組裝骰子，收集黃金跟日月碎片，獻給諸神並邁向榮耀之路！','\n',char(10)),'https://i.postimg.cc/ZRNFH147/image.png','','','販售,租借,策略燒腦,家庭',2,4,'普通',2,1,1,1550,200,1500,50,1,'',59,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(158,'驚滔駭浪RIFF RAFF',replace('這是一款平衡遊戲，玩家將裝載的木製指示物轉向搖擺不定的木船。\n瓶子、水手、老鼠和其他貨物被放置在船體和從桅杆伸出的三個碼臂上。\n第一個將所有物品擺完的玩家贏得遊戲','\n',char(10)),'https://i.postimg.cc/GhXYFcv3/image.png','','','租借,家庭,兒童,輕鬆小品',2,4,'簡單',1,1,0,2650,300,2600,50,1,'',60,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(159,'妙筆神猜',replace('你知道斑馬長什麼樣子嗎？你畫得出來嗎？\n不會？！那這個遊戲就是專為你設計的！\n只要能讓其他玩家看出你畫的斑馬不是車子就夠了！\n\n玩妙筆神猜時每個人畫一個謎題，同時也猜別人所畫的謎底，遊戲時間不足以讓你畫一幅傑作，你最好能用簡單的筆觸畫個簡圖來表達你的謎題，這樣你就有更多時間來猜測其它玩家的謎底。\n計分方式簡單而精彩，讓猜對的人和畫得正確的人都得分，動作快的人也有額外加分喔！\n\n','\n',char(10)),'https://i.postimg.cc/bw2JZ8TB/image.png','','','租借,派對,家庭,兒童',3,6,'簡單',1,1,0,1490,150,1400,50,1,'',61,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(160,'馬拉開波',replace('*僅供現場遊玩*\n馬拉開波是款由Alexander Pfister設計，可1~4人遊玩的全新策略遊戲。背景是17世紀的加勒比海。\n在約莫為玩家人數乘以40分鐘的遊戲時間中，玩家要在4輪內盡可能增加他們在三個國家中的影響力。\n玩家要揚帆航行周遊加勒比海，過程中你將擁有城市板塊來讓你執行各種行動、或供你運送販賣貨物。\n比較特殊的地方是遊戲中的任務模式，讓玩家在隨著過程遊歷諸城的同時能夠體會到其中的小故事。\n移動的同時也會需要玩家調度及使用卡片，有玩過該設計師其他遊戲的玩家對這部分一定不陌生。','\n',char(10)),'https://i.postimg.cc/K8yX52bV/image.png','','','僅供現場玩,策略燒腦',1,4,'困難',1,1,0,2400,0,0,50,1,'',62,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(161,'實話實說','認識別人眼中的你！「實話實說」系列佳評如潮，援引周哈理窗，帶你認識「公開我」、「未知我」、「盲目我」、「隱藏我」等四大面向。聯誼、派對、輔導等，遊戲體驗好玩又好用！','https://i.postimg.cc/Pfpr3dGr/image.png','','','租借,派對,家庭',3,5,'簡單',2,2,0,390,50,300,50,1,'',63,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(162,'找找醜比頭','眼力與記憶力的大考驗！16隻醜比頭分別在畫面中出現，請正確找出目標醜比頭目前的所在位置吧！ 爬到樹上的粉屁桃、出現在古埃及壁畫上的黃金寶、愛打架的小花頭..... 誰能依據不同任務，累積找到最多醜比頭，成為醜比頭專家呢？','https://i.postimg.cc/Mpg3s9K1/LINE_ALBUM_販售區桌遊_251023_35.jpg','','','販售,兒童,家庭',2,6,'簡單',1,0,1,590,0,0,50,1,'',64,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(163,'水下城市',replace('*此款僅提供現場遊玩*\n遊戲的核心觀念是卡片放置。三種色卡要沿著主要圖板邊緣放在3 x 5的格子裡面，格子也有顏色。\n\n玩家可以把卡片放入同色的格子，那麼他們就可以同時進行行動和優勢：行動和卡片優勢在主要圖板的格子上都有說明。','\n',char(10)),'https://i.postimg.cc/j5WKF4Fk/image.png','','','僅供現場玩,策略燒腦',1,4,'困難',1,1,0,2450,0,0,50,1,'',65,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(164,'靈跡島 Spirit Island',replace('*此款僅提供現場遊玩*\n在世界最遙遠的邊境，魔法仍舊存在，透過大地、天空和所有自然事物的精靈來施展。當歐洲殖民帝國的勢力持續擴張，他們將無可避免地將觸手伸到精靈之地 - 這時，大地本身和島民將猛烈抵抗。\n\n            \n精靈島是一款複雜的主題式合作遊戲，關於保護你的島嶼家園抵抗殖民入侵者。玩家是島上不同的精靈，各有自己的元素力量。每一個回合，玩家同時選擇要使用哪一張力量卡，接著支付能量來打出。使用符合精靈元素屬性的力量卡組合可以獲得免費的加成效果。較快的力量可以在入侵者擴張之前立刻發生效果，但是其他的魔法就比較慢，需要有遠見地計畫來發揮影響力。在精靈階段，精靈會獲得能量，並且選擇如何/是否成長：收回力量卡、尋找新力量或散播到島嶼的新區域。\n           \n入侵者透過一種半預測性的方式在島上擴張。每個回合他們會探索一些土地(島嶼的一部份)；而在下一回合他們就會在土地上建造殖民地和城市。在下一個回合他們就會蹂躪該處，給土地帶來荒蕪並攻擊島民。\n           \n島民被攻擊時會反擊，同時給予精靈支援，但是無法總是在你需要時出現。有些力量要透過島民發揮作用，幫助他們驅逐入侵者或清除荒蕪的土地。\n           \n遊戲的規模會逐步擴大：精靈散播他們的存在到島上新的區域，並且尋找更多新的強大力量，而入侵者則建立他們的殖民地。每個回合代表架空歷史的1到3年。\n             ','\n',char(10)),'https://i.postimg.cc/2yFtcqrK/image.png','','','僅供現場玩,策略燒腦,合作闖關',1,4,'專家',1,0,1,3200,0,0,50,1,'',66,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(165,'蜥蓋','蜥蓋遊戲人數:2-6人遊戲時間:20分鐘推薦年齡:6歲以上遊戲背景：這是一個競爭激烈的蜥蜴世界，當繁殖季節來到，雄性「側斑猶他蜥」為了爭奪生存的土地與繁衍後代，展開一場大戰，要怎麼讓自己所屬的品種能夠獨霸一方，就看你如何有技巧的阻斷其他蜥蜴進行繁殖，只要能讓自己的族群繁衍昌盛，就能成為該島嶼的王者。遊戲目的:最快完成所屬蜥蜴的連線。','https://i.postimg.cc/y8Wf9pg5/image.png','','','租借,家庭,兒童,輕鬆小品',2,6,'簡單',2,1,1,250,50,200,50,1,'',67,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(166,'王國製圖師',replace('女王吉娜下令開拓北方的土地。作為一位王國製圖師，你被派往北方繪製地圖以宣稱這片領土屬於納洛斯王國。女王將透過正式的法令宣告她最重視哪些土地，如果你能滿足她的要求，你的聲望將會提高。\n\n在這片荒野之中並非沒有任何人存在。在此定居的德拉古人將派出他們的前哨部隊與你爭奪領土的所有權，所以你必須盡可能地與他們劃清界線，以降低他們對王國的影響力。如果你能圈起最多女王想要的土地，那麼你將成為王國裡最偉大的製圖師。','\n',char(10)),'https://i.postimg.cc/Y9N8kJZ4/image.png','','','租借,策略燒腦,家庭,輕鬆小品',1,99,'普通',1,1,0,850,100,900,50,1,'',68,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(167,'天生絕配',replace('想知道誰跟你的想法最像嗎？這款遊戲幫你立刻找到同溫層！\n這是一款可以確認彼此想法的派對遊戲，遊戲設計了300條主題，以及一套都是圖片的聯想牌，玩家們透過聯想牌表達對主題的想法，在眾多卡牌中，誰跟你十分有默契的選擇了相同的卡牌，或許你們就是命中注定的天生絕配哦！','\n',char(10)),'https://i.postimg.cc/Sxx2Xqwq/IMG_20260106_202953.jpg','','','租借,派對,家庭,兒童',3,8,'簡單',1,1,0,990,100,900,50,1,'',69,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(168,'禪道 Zendo',replace('*僅提供現場遊玩*\n邏輯推理遊戲，比想像的難哦!!\n遊戲由一位玩家扮演禪宗大師, 向其他求道者出題. 大家利用遊戲配件拼砌出不同的作品, 大師會告訴該作品是否「有道」(是否遵循特定的規則). 最先「得道」(看出特定規則)的人...就可以下山了.','\n',char(10)),'https://i.postimg.cc/7Y0dCGpX/IMG_20260106_202904.jpg','','','僅供現場玩,家庭,策略燒腦',2,6,'普通',1,0,1,1200,0,0,50,1,'',70,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(169,'HINT 限時快猜',replace('你會 模仿 雞尾酒嗎？\n你會 哼唱 經典電影配樂嗎？\n在《限時快猜》派對遊戲中，你的隊友必須試著猜出你費盡心思給出的提示\n\n而你可以根據題目採用模仿、哼唱、繪圖、說話等方式\n但千萬小心，每道題目都有一個不能讓隊友答出的禁語\n如果不慎答出，將立即讓你們那隊遭受扣分懲罰。','\n',char(10)),'https://i.postimg.cc/yYjzb4w6/IMG-20251014-205605.jpg','','','租借,派對,家庭',4,99,'簡單',1,0,1,650,0,0,50,1,'',71,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(170,'蟹霸王','作為一個經驗老道的捕蟹達人，迅速的帶上你的裝備，加入這次的盛會吧！技術嫻熟地從各個角落找出一隻隻看似美味的螃蟹。不斷有補蟹人從各地慕名而來，再次迎來了螃蟹的季節！這個平靜的海岸，','https://i.postimg.cc/kM6KQrfW/image.png','','','租借,家庭,輕鬆小品,兒童',3,5,'簡單',2,1,1,450,50,400,50,1,'',72,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(171,'文明繪卷',replace('*此款僅提供現場遊玩*\n文明繪卷是由Jamey Stegmaier設計，1~5人遊玩，時間約2小時的文明遊戲。\n\n從史前文明直至未來時代，創造一個擁有最多淵源歷史的文明，而你選擇的發展途徑會對這個世界及人民產生巨大的影響 - 你的文明是獨一無二的！\n\n在文明繪卷中，你將從零開始，推進4種發展軌(科學、工業、探索、軍事)來獲得發展的優勢，要專精於單項或是平衡發展皆取決於你。\n\n同時你也會提升國家的收入，建設首都，在眾多能力中抉擇，並獲得勝利點數。\n\n而在過程中獲得的文明繪卷卡將會鉅細靡遺的述說著你的國家文明史詩。','\n',char(10)),'https://i.postimg.cc/0yfwk9y1/image.png','','','僅供現場玩,策略燒腦',1,5,'困難',1,0,1,3450,0,0,50,1,'',73,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(172,'繽紛夜光蟲','美麗繽紛的夜光蟲，在夜晚的水池邊嬉戲，快來用瓶子將牠們蒐集起來。遊戲最大的特色就是有超多美美的骰子，蒐集起來的時候非常賞心悅目。','https://i.postimg.cc/63XjKTZJ/LINE_ALBUM_販售區桌遊_251023_51.jpg','','','販售,家庭,兒童',2,4,'簡單',1,0,1,1200,0,0,50,1,'',74,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(173,'路易斯與克拉克',replace('*此款僅提供現場遊玩*\n一款結合牌庫構築與工人擺放的競速遊戲，遊戲機制放到現在還是相當特別，獨特的機制再加上歷史背景，相當推薦此款策略遊戲。','\n',char(10)),'https://i.postimg.cc/59S1ky7J/image.png','','','僅供現場玩,策略燒腦',1,5,'困難',1,0,1,2000,0,0,50,1,'',75,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(174,'獨家專輯',replace('★會是五音不全還是完美和聲呢？嘗試為播放清單找到完美的封面\n★將樂曲的音量調高，並和你的朋友與家人沉浸在音樂中！','\n',char(10)),'https://i.postimg.cc/pLdtNcH4/IMG-20251014-205641.jpg','','','販售,輕鬆小品,派對',3,8,'簡單',0,0,0,750,0,0,50,1,'',76,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(175,'陰間條例：夜巡篇',replace('七爺八爺牛頭馬面，全員出動!! — 陰間條例 夜巡篇\n\n\n\n鬼門關，還沒離開的好兄弟誰來收？就靠你在全新登場「夜巡篇」裡降妖除魔囉！\n\n\n\n座落在生死交界的夜神旅店，有著無數的房間，每個房間都是來訪旅客生前最後的記憶。旅店的盡頭有一間特殊房間，房內雜揉著旅客們的善惡因果，前往陰間前的亡靈最終都會在這間房間經歷一場審判，而房間的主人正是城隍。某天旅店內突然發生一場騷動，原本安分徘徊於旅店內等待審判的亡靈們突然躁動喧鬧、大肆破壞，吵鬧的聲響驚動到旅館內的陰間執法者 — 『七爺』與『八爺』試圖盡快找出騷動的源頭，生怕驚動到城隍，但為時已晚...\n『夜巡...開始!』夜神旅店深處傳來城隍指令與讓人恐懼的威壓。','\n',char(10)),'https://i.postimg.cc/c1X2nnkv/image.png','','','租借,輕鬆小品',3,6,'普通',1,1,0,540,100,500,50,1,'',77,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(176,'展翅翱翔 (Wingspan)',replace('*此款僅提供現場遊玩*\n展翅翱翔（Wingspan）是款由Stonemaier Games出品的競爭類、中量級、卡牌驅動、引擎搭建桌遊。\n你們扮演著鳥類愛好者－研究員、鳥類觀察家、鳥類學者，以及收藏家¬－藉由搜查進而發現並吸引最好的鳥兒到你的鳥園。\n\n每隻鳥都會對於你的其中一座棲息地（行動）延伸出連鎖的強力組合。每座棲息地都有著幾項獨特的關鍵發展方向。\n\n在鳥類餵食器骰塔中，透過自訂骰子取得食物標記\n使用鳥蛋模型誕生不同顏色的蛋\n抽取上百張獨特的鳥卡而後打出它們\n四局後最高分的玩家為贏家\n此款遊戲好玩到我們認為這款遊戲會在你的桌上起飛','\n',char(10)),'https://i.postimg.cc/xCgxMwRw/image.png','','','僅供現場玩,策略燒腦,家庭',1,5,'普通',1,0,1,1950,0,0,50,1,'',78,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(177,'密語幸運草',replace('抽取關鍵字卡牌，在四葉草圖版上秘密地寫下它們的共同特徵；這些共同特徵是\n您的線索。然後齊心協力，設法猜出每一名玩家寫下的關鍵字。遊戲結束時，根據\n你們猜出的關鍵字數量，相加得出你們的總分，寫在「傳奇記錄」榜單中。\n努力在每一局遊戲中刷新高分記錄吧！','\n',char(10)),'https://i.postimg.cc/Ghhf9B5C/LINE_ALBUM_販售區桌遊_251023_5.jpg','','','販售,派對,家庭,合作闖關',3,6,'簡單',2,0,2,790,0,0,50,1,'',79,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(178,'眨眨眼',replace('眨眨眼，誰是我的夥伴呢？ 這是個適合在派對時遊玩的遊戲,玩家需要靠著眨眼的暗示來找到跟他有同張卡片的夥伴！\n但說者有意、聽著無心，要想辦法讓在天涯一方的夥伴接收到你的暗號，玩起來其實沒那麼簡單喲！ 但要小心，其他玩家也可以抓到你的暗示喔，所以要小心不要讓別人發現，偷偷地傳送暗示給你的夥伴吧！ ','\n',char(10)),'https://i.postimg.cc/y8DrXMBD/LINE_ALBUM_販售區桌遊_251023_31.jpg','','','販售,派對,家庭,輕鬆小品',4,8,'簡單',1,0,1,690,0,0,50,1,'',80,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(179,'蟲蟲拍拍','蟲蟲拍拍遊戲人數:2-4人遊戲時間:15分鐘推薦年齡:5歲以上遊戲背景：拍拍草原」裡資源豐富，有各式各樣色彩繽紛的昆蟲藏身其中，不同的昆蟲要用不同的工具來捕捉才不會傷到牠們喔！快來「拍拍」發現昆蟲。別忘了觀察完畢，要把昆蟲放回家喔！遊戲目的:使用正確的工具抓到最多隻昆蟲。','https://i.postimg.cc/263v9gmR/image.png','','','租借,兒童,家庭,輕鬆小品',2,6,'簡單',2,1,1,250,50,200,50,1,'',81,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(180,'西國聖騎士',replace('《西方王國聖騎士》設定在西法國騷亂時刻的故事，大約在公元900年。\n縱然近來努力發展城市，偏遠城鎮仍持續處於外邦的威脅中。\n\n薩拉森人在邊界偵查，同時維京人掠奪財富漢聲口，甚至東方的拜占庭人也展露其黑暗面。\n\n玩家扮演貴族男女，必須從城市徵集工人以抵禦敵人、建設要塞並在領地中散播信仰。\n幸運的是你並不孤單，在這座偉大王國中，國王派出他最優秀的騎士以提供各位幫手，所以準備好馬匹、磨利寶劍，聖騎士正在接近。','\n',char(10)),'https://i.postimg.cc/28WFwMFL/image.png','','','租借,策略燒腦',1,4,'困難',1,0,1,1850,200,1800,50,1,'',82,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(181,'一網打盡',replace('在德國漢堡港口的魚市拍賣中，大盤商叫賣著：「來來來，來買上好的新鮮魚貨啊！首先是兩隻龍蝦⋯⋯再來是兩條鰻魚⋯⋯只賣10元喔！沒有人要？那我再加上一隻龍蝦⋯⋯來了個「偷魚賊」⋯⋯再猶豫就買不到囉！⋯⋯好吧，賠本大放送，加三條比目魚⋯⋯」\n「叮！」鈴聲響起「成交！」\n「感謝戴藍色帽子的老闆，一共是10歐元，謝謝您的惠顧。」\n\n這是一筆好買賣嗎？\n只有眼光獨到且下標快狠準的玩家，才能成為賺大錢的魚販喔！','\n',char(10)),'https://i.postimg.cc/HWtKp0BH/IMG_20251015_112221.jpg','','','販售,家庭,派對',3,5,'簡單',1,0,1,890,0,0,50,1,'',83,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(182,'迷霧島',replace('傳說中，奧克拉科克島是海盜的天堂，也是黑鬍子最神祕的巢穴。\n\n為了慶祝劫掠的豐收，黑鬍子在這裡舉辦了盛大的派對，邀請了許多海上的亡命之徒，\n\n一起慶祝。但是，派對來到高潮時，海軍的砲火打斷了所有人的興致。大家紛紛拿取僅存的財物，\n\n趕緊開溜。不過，黑鬍子最心愛的一艘船：安妮皇后復仇號上，載滿了搶奪而來的寶藏，\n\n為了避免被海軍沒收，黑鬍子此時只能帶領部下奮力一搏了！若你是海軍，為了海軍的榮耀，\n\n努力將黑鬍子逮捕歸案！不然，就趕緊拾起地上的金幣開溜！','\n',char(10)),'https://i.postimg.cc/nhZ71zhN/image.png','','','租借,輕鬆小品,家庭',2,4,'簡單',1,1,0,320,50,300,50,1,'',84,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(183,'方舟動物園 (Ark Nova)',replace('*此款僅提供現場遊玩*\n在《方舟動物園》中，你將規劃並設計一座充滿現代化、科學化管理的動物園。\n你將建造飼養區、安置動物，並在全球各地支持各種動物保護項目，以求努力打造出最成功的動物學機構。\n各類專家以及獨特的建築都將協助你實現這一目標。\n\n\n《方舟動物園》的核心由255張卡牌構成，涉及動物、專家、獨特建築以及保護項目，每張卡牌都具有特定的能力。\n使用它們來增加你動物園的魅力以及科研聲望，並收穫保護點數。\n每位玩家均有一套行動卡牌，你將通過使用並升級它們來實現你的計劃。\n\n','\n',char(10)),'https://i.postimg.cc/0Q6JNKVK/image.png','','','僅供現場玩,策略燒腦',1,4,'專家',1,0,1,2400,0,0,50,1,'',85,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(184,'地城對決',replace('《地城對決》是一款兩人對戰的卡牌遊戲，不同於《魔法風雲會》或是《鍛鑰者》這類抽象空間中的卡片效果攻防，玩家在《地城對決》中會在有地城空間深度的牌池上輪流選擇一張卡片來使用。\n\n卡片可以用來招募夥伴、撿拾寶物、打倒魔物、學習魔法、成長職業、發動陷阱、挑戰魔王等等，有更豐富的情境體驗！','\n',char(10)),'https://i.postimg.cc/5tv7D8XW/LINE_ALBUM_販售區桌遊_251023_45.jpg','','','販售,策略燒腦',2,2,'普通',1,0,1,800,0,0,50,1,'',86,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(185,'深淵密謀 (Conspiracy)',replace('爾虞我詐，權力鬥爭  — 深淵密謀\n與深淵之王(Abyss)同樣背景與美術的策略小品遊戲。\n在深海之處的深淵之國，陰謀與腐敗乃是日常生活中的主旋律。而深海會議則正是這種永恆的權力鬥爭的核心舞台，各方勢力都密謀著打擊對手，獲取更多的影響力。\n你必須搶在你對手之前匯聚最具威望的深海領主們，並且確保你的會議內閣井然有序。','\n',char(10)),'https://i.postimg.cc/dtBZtDN3/IMG_20260106_202818.jpg','','','租借,輕鬆小品',2,4,'簡單',1,1,0,490,50,400,50,1,'',87,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(186,'骰子街','骰子街是款快節奏，運用點小心機的刺激歡樂遊戲。憑藉著夢想，以及我們所信賴的骰子，您必須把骰子街建設成這片土地上最大的城市，只是沒有錢萬萬不能，您必須靠城市的發展與公共建設來賺取資金，當然，從鄰居身上撈點好處也是不錯的作法。不過小心，你的鄰居也瞄準好你的口袋了。','https://i.postimg.cc/LX3y8Rk8/LINE_ALBUM_販售區桌遊_251023_61.jpg','','','租借,家庭',2,4,'普通',2,2,0,750,100,700,50,1,'',88,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(187,'王都布拉格',replace('查理四世被加冕為波西米亞國王並統治著神聖羅馬帝國。從他的布拉格城堡，可以俯視這新城寨的各個建設：橫跨伏爾塔瓦河的橋樑、大學、以及在城牆內緩緩升起的大教堂。布拉格已為歐洲著名的大城市，而查理王則更進一步，將其建設為帝國的首都！\n\n在"王都布拉格"中，玩家扮演在中古世紀的布拉格中要規劃城市建築的富有市民，\n\n藉著參與城市建設以及增加自身的財產，你將獲得國王的敬重與名聲。\n\n玩家在遊戲圖板"行動地基"上的六種行動中選擇，這些行動永遠可以執行，但費用和收益則是會持續變動。\n\n藉由這些行動，你可以增加你的資源，強化你選擇的行動，以及建造查理橋、城牆與"新布拉格市"。\n\n你也可能會獲得額外的行動，甚至參與聖維特大教堂的建設。\n\n聰明的玩家將會發現仔細規劃時機的行動與自建設城市計畫網中獲得的收益，兩者之間微妙的關聯。\n\n在遊戲結束時，讓查理王印象最深刻的玩家獲勝','\n',char(10)),'https://i.postimg.cc/8z8wgNPb/image.png','','','租借,策略燒腦',2,4,'困難',1,1,0,2800,300,2800,50,1,'',89,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(188,'來杯兔兔',replace('「來杯兔兔」咖啡廳熱鬧開張！快來喝一杯兔兔店長的特調飲品!!\n每杯飲料上都有特製的兔兔奶泡與美味配料，多種變化讓人眼花撩亂。\n\n今天你與朋友們想喝哪種飲料呢?\n\n趕緊「來杯兔兔」吧! 如果沒有看到合適的飲料，代表兔兔店長又忘記了~趕快提醒兔兔店長，晚了就喝不到了!','\n',char(10)),'https://i.postimg.cc/6Q8d8P3Q/image.png','','','租借,輕鬆小品,兒童,家庭',2,6,'簡單',1,1,0,390,50,300,50,1,'',90,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(189,'台灣愛玩客',replace('「台灣愛玩客(Taiwan Walker)」遊戲的原型為韓國的「濟州島(Jeju Island)」，為2015年由Yeon-Min Jung、Gary Kim及Jun-Hyup Kim所設計，遊戲過程益智趣味。栢龍玩具與胖胖熊將此遊戲代理後，為了更貼近台灣人的生活喜好，將其重製成「台灣愛玩客」，所有插畫皆已本土化，並於2017年發行。遊戲中玩家們扮演著愛玩客，在台灣寶島上到處遊覽，沿途收集觀光板塊，並換取擁有特殊效能的分數卡。遊戲進行時，玩家可選擇遊覽及收集觀光板塊，或是使用觀光板塊換取分數卡。當遊戲圖板上已無觀光板塊，或分數卡牌列無法補齊時，遊戲即告結束。玩家們分別計算自家最後所獲得的分數，分數最高者即為遊戲贏家。\n\n','\n',char(10)),'https://i.postimg.cc/DydLJx0Z/IMG_20260106_203132.jpg','','','租借,家庭,策略燒腦',2,4,'簡單',1,1,0,790,100,700,50,1,'',91,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(190,'吸爆鬆餅',replace('超ㄎ一ㄤ的隨機派對遊戲「吸爆鬆餅」出爐啦！\n★國外KS募資超過三千萬，創新概念派對遊戲\n★超胡鬧的派對遊戲，帶給你歡樂的小聚時光','\n',char(10)),'https://i.postimg.cc/52Sxw9X7/image.png','','','販售,租借,派對',2,8,'簡單',1,1,0,790,100,700,50,1,'752克',92,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(191,'OPEN!賓果派對','療癒系桌遊，5隻萌萌滴 OPEN 家族公仔! 釋放你的療癒fu ~ OPEN PARTY 賓果派對是由 7-11 與 KIDDY KIDDO 合作的最新親子產品，簡單易懂的遊戲方式，不管大朋友或小朋友，絕對是適合全家一起玩的 OPEN系列桌遊，可愛的小公仔在轉盤上跑跳著，考驗著小朋友的觀察力、反應力與運氣呢，看最先把公仔們排列正確，大聲地喊出 OPEN 賓果吧!','https://i.postimg.cc/ZYFkWzYF/IMG-20251015-111852.jpg','','','販售,兒童,家庭',2,5,'簡單',1,0,1,469,0,0,50,1,'',93,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(192,'馬尼拉',replace('現在是西元1821年，西班牙人控制菲律賓島嶼已經250年了。但是，直到目前為止，西班牙人並未實際控制一切。\n在殖民地的權力背後，一些固執己見的本地人已經建立起與鄰近島嶼以及亞洲大陸的秘密的海洋貿易管道。\n這些黑市商人使用看起來非常奇特的平底船以及脆弱的竹筏，將肉豆蔻，絲綢，玉，以及人蔘填滿他們的船，並且將它們走私運進馬尼拉。\n每一次投機活動的勝算並不明確，船長與船在海中的適航性也相當貧乏。\n海盜在旁伺機劫掠那些無法從他們手中逃脫的船，為這些船增添幾些不幸。\n\n想要親身體驗馬尼拉黑市交易的過程嗎？\n快來瞧瞧吧！','\n',char(10)),'https://i.postimg.cc/Pxj3HNDw/LINE_ALBUM_販售區桌遊_251023_58.jpg','','','租借,家庭,派對,策略燒腦',3,5,'普通',1,1,0,1690,200,1600,50,1,'',94,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(193,'積木式 西洋棋','一款經典的雙人抽象戰略棋盤遊戲，雙方各有16枚棋子，目標是透過不同的兵種移動規則，將死對方的國王。','https://i.postimg.cc/j5N3725C/image.png','','','租借,策略燒腦,家庭',2,2,'普通',1,1,0,240,50,200,50,1,'',95,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(194,'拾貓鍋',replace('可愛的貓咪萌系桌遊第二彈！輕鬆簡單的規則玩法，熱鬧有趣的遊戲\n\n機制，快跟朋友一起做出最完美的貓鍋！','\n',char(10)),'https://i.postimg.cc/76xJgQP7/image.png','','','租借,家庭,兒童,輕鬆小品',2,6,'簡單',1,1,0,450,50,400,50,1,'',96,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(195,'天恩湖',replace('你遠離文明來到了這蠻荒之地。身為拓荒者的一員，你在天恩湖荒廢的湖畔安頓了下來。這個地區沒有被開發過，但顯然有人在這裡生活，這些聚落吸引著你！融入人群並對公眾事務做出貢獻。探索地區、建造房屋與聚落、飼養牲畜、蒐集建材來完成更多建設，並改革這些過程讓一切更現代化。抓住機會，親手打造你在天恩湖的完美新生活。\n\n\n\n在這款由Alexander Pfister設計的的遊戲中，你的目標是改善你自己與你的跟隨者們的生活，而要如何達成全部操之在你。如同說故事般的行動過程會讓每場遊戲都與眾不同。你會是專注在擴張呢？或是致力於建造各種設施？還是你有屬於自己的其他追求？謹慎思考你的每個行動：不只是因為它們之間會互相影響，也影響了你的帆船能航行多遠，越快、越遠就越好，因為只有最老練的水手才能得到最棒的獎勵......。','\n',char(10)),'https://i.postimg.cc/cHS9W63G/LINE_ALBUM_販售區桌遊_251023_52.jpg','','','販售,租借,策略燒腦',2,4,'困難',3,0,3,2400,250,2400,50,1,'',97,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(196,'太公望',replace('記得小時候總是會在夏天午後跟著大哥哥一起到溪邊釣魚的美好時光嗎？\n如果你沒有經歷過這樣充滿活力與期待魚兒上鉤的童年，千萬不要難過，今天就讓我們一起在桌上來一場釣魚大賽吧！\n不過今天要用的釣竿和魚餌非常非常特殊，我們要用骰子來釣魚喔～','\n',char(10)),'https://i.postimg.cc/8CwzVkDJ/image.png','','','租借,輕鬆小品,家庭',2,5,'簡單',2,2,0,600,100,600,50,1,'',98,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(197,'跳跳骰',replace('這款遊戲已經不需多做介紹，當你們想要家人團聚、朋友狂歡，這款遊戲絕對最適合！\n簡單到不行的遊戲規則，卻能帶來最爆笑歡樂的氣氛！\n\n《跳跳骰》新版CP值更高！價格減少、質感卻一點也沒少，聚會就差這一盒～～～','\n',char(10)),'https://i.postimg.cc/HnCCfpYP/IMG-20251014-205415.jpg','','','販售,租借,家庭,兒童,輕鬆小品',2,4,'簡單',1,1,0,1250,150,1200,50,1,'',99,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(198,'拉長島',replace('「拉長島」由熱門經典數字牌遊戲改編，即使是小小孩，也可以自行學會這款沒有數字的遊戲。\n只要1張頭部牌和1張尾部牌便能組合成一隻動物，腹部牌能讓你創造來自拉長島的特有動物，為孩童帶給無限歡樂。\n\n率先出清手牌的玩家獲勝！','\n',char(10)),'https://i.postimg.cc/P55tQs1d/image.png','','','租借,家庭,兒童,輕鬆小品',2,5,'簡單',1,1,0,490,50,400,50,1,'',100,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(199,'賽馬大亨',replace('《賽馬大亨》以四場賽馬為一局的即時賽馬遊戲，玩家會在每場賽事進行期間下注，並在賽後結算投注結果。玩家不僅可贏取貴賓獎勵，還可以通過在特別彩池中下注來增加遊戲體驗。經過四場賽事之後，贏得最多彩金的玩家獲勝！\n\n \n\n《賽馬大亨》除了可用傳統的擲骰子決定賽馬結果外，也可使用內置的apps感受即時買馬的快感。當中更有廣東話配音讓你感受賽馬直擊。當中也可以自由選擇遊戲速度，要每秒都有馬在前進的分秒必爭賽局還是一步一驚心的賭局式賽局，全由你去安排。快來下注與好友享受賽馬的快感。','\n',char(10)),'https://i.postimg.cc/tJbb1LXQ/image.png','','','租借,家庭,派對',2,9,'簡單',1,1,0,1190,150,1100,50,1,'',101,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(200,'帽子大風吹/魔法帽',replace('小姐戴上維京帽？船長頂著王冠？就像一陣大風吹，把大家的帽子都吹亂了！快幫他們找到正確的帽子戴上，不然會變成光頭喔！\n別怕！找到魔法帽便能解救光頭！\n\n','\n',char(10)),'https://i.postimg.cc/VsFQGZfv/image.png','','','租借,兒童,家庭',2,4,'簡單',1,1,0,390,50,300,50,1,'',102,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(201,'熱力狂飆 HEAT',replace('*此款僅提供現場遊玩*\n★埃森桌遊展話題之作，體驗最Hot的賽車遊戲！\n★簡單而直覺的手牌管理遊戲，各式模組增加遊玩樂趣','\n',char(10)),'https://i.postimg.cc/mDRp7RFw/HEAT.png','','','僅供現場玩,策略燒腦,家庭,派對',1,6,'普通',1,1,0,2400,0,0,50,1,'',103,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(202,'小小工廠',replace('★【小小村莊】系列續作\n★資源管理－輕度策略的卡牌遊戲\n★ 給你強烈的“創業”感：用很少的錢起家，成為競爭對手中成長最快的那位','\n',char(10)),'https://i.postimg.cc/mgKpdm2r/LINE_ALBUM_販售區桌遊_251023_33.jpg','','','販售,家庭,輕鬆小品,策略燒腦',2,4,'普通',2,0,2,700,100,700,50,1,'',104,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(203,'給我餅乾','你是一個有超大胃口的怪獸，急著想吃到被藏起來的甜點。你能搶在別人之前，循著線索，找到美味的點心嗎？','https://i.postimg.cc/XvTpD5Xn/IMG_20260106_203126.jpg','','','租借,兒童',2,5,'簡單',1,1,0,550,100,500,50,1,'',105,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(204,'奧地利大飯店',replace('*此款僅提供現場遊玩*\n二十世紀初，維也納是歐洲的主要城市之一。\n城市的街道上人流如織，藝術家，政治家，貴族，市民和觀光遊客隨處可見，\n\n而皇帝統治著整個帝國的一切。\n\n你正身處當時維也納的動盪時代，作為旅店老闆一直小心經營。\n\n為此，你必須擴張你的旅店並及時準備好新房間。\n\n同時，你的客人需要精心烹製的餐飲。\n\n為確保每一位客人都能享用到適合口味的美食，你可能還需要僱傭額外的員工。\n\n儘管如此，也別忘記經常向皇帝致以敬意，否則你很快就會受到懲罰。\n\n迎接各項挑戰，最終將你的飯店打造成名副其實的奧地利大飯店！\n\n','\n',char(10)),'https://i.postimg.cc/wMnhccGp/image.png','','','僅供現場玩,策略燒腦',2,4,'困難',1,0,1,1800,0,0,50,1,'',106,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(205,'地產大亨/愛台客走跳台灣電子版','首度與台灣最知名的媒體之一"三立"合作,共同推出三立"愛台客地產大亨",22個台灣私房景點,配搭配電子刷卡機,大家一起來體驗玩桌遊的樂趣!','https://i.postimg.cc/mrVC6G5V/image.png','','','租借,家庭,派對,兒童',2,6,'簡單',1,1,0,1399,150,1300,50,1,'',107,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(206,'友善魔物與酒館英雄',replace('冒險者充滿好奇心地踏入祭壇深處，眼前浮現出供奉著的祭器。就在這一刻，一股聲音在他的腦海中響起：\n\n『聰明的冒險者啊，如果你渴望了解時間的真相，請碰觸那個祭器！ 你將能夠進入遙遠回憶中，那個已被遺忘的人類與魔物共存的最後世界.....』\n\n『友善的魔物與酒館英雄』是一款工人擺放策略遊戲。 作為領主的玩家們，在四輪遊戲中必須巧妙運用行動，如擴展領地、建設都市、招募人才，以獲得聲望。 每一輪遊戲，你可以選擇「方針」以增加收入，或執行特定行動以獲得聲望獎勵。 方針的選擇與行動順序息息相關，必須根據你的目標來巧妙搭配運用。 此外，遊戲中還能夠與魔物互動，透過不同的行動（如交易、探索、討伐），獲得各種不同的獎勵，以追求更高的聲望。 遊戲結束時，擁有最高聲望的玩家將成為勝利者。','\n',char(10)),'https://i.postimg.cc/VkWK1ph0/image.png','','','租借,策略燒腦',2,4,'困難',1,1,0,1380,150,1300,50,1,'',108,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(207,'天下無雙小紅帽與貝武夫',replace('★準備好你的牌庫，誰才是天下無雙？\n★節奏明快的微縮模型決鬥遊戲','\n',char(10)),'https://i.postimg.cc/L66WhqbX/LINE_ALBUM_販售區桌遊_251023_10.jpg','','','販售,策略燒腦',2,2,'普通',2,0,2,850,0,0,50,1,'',109,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(208,'達爾文的旅程','一款重量級的工人擺放策略遊戲，玩家扮演科學家，跟隨達爾文的腳步在加拉巴哥群島進行研究，派遣工人學習、探索、收集標本並發表理論。','https://i.postimg.cc/zXcJ727W/image.png','','','租借,策略燒腦',1,4,'困難',1,1,0,2700,300,2700,50,1,'',110,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(209,'太空基地',replace('在太空基地中，玩家們是指揮一小支太空艦隊的隊長。你們可把停泊在太空站裏的船艦，而玩家必須贏得最多影響力，從而攀升到艦隊司令一職並勝出遊戲！\n\n每到你的回合時，擲2顆六面骰，所有玩家都會按擲骰結果從自己的卡牌領取獎勵。範例：你擲出了5和6，那麼可選擇根據你版圖上分區5和6的卡牌，領取相應獎勵、或把5加6以領取分區11的卡牌獎勵。須注意，對手回合的擲骰結果不會讓你領取在自己版圖的卡牌的獎勵，改為領取插在玩家版圖上方卡牌的獎勵。當前玩家領取獎勵後，可以購買新牌放在自己玩家版圖，並派遣原本在該分區的牌，把它放到玩家版圖上方。最終獲得最高分的玩家獲勝。','\n',char(10)),'https://i.postimg.cc/qMzrNXr7/image.png','','','租借,家庭,派對',2,5,'簡單',1,1,0,1190,150,1100,50,1,'',111,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(210,'招5玩酒',replace('*此款僅提供現場遊玩*\n把團康遊戲從戶外搬到了室內\n我們還貼心的替不喝酒的玩家\n設計了虛擬喝醉系統\n讓不喝酒的玩家們能夠感受那種\n再輸下去就醉了的感覺。','\n',char(10)),'https://i.postimg.cc/N0yK4Dsy/IMG_20260106_203051.jpg','','','僅供現場玩,派對',4,20,'簡單',1,0,1,1800,0,0,50,1,'',112,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(211,'璀璨都市Cities','簡單的規則，但因為輪流選的規則造就滿滿的互動,不管是搶東西還是搶快，整個遊戲輕快目標也明確，很適合家庭、朋友間快速來一場的輕鬆小策略遊戲。','https://i.postimg.cc/GhQTh9gq/IMG_20260106_202843.jpg','','','租借,家庭',2,4,'簡單',1,1,0,1400,150,1400,50,1,'',113,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(212,'翻翻海盜 Captain Flip',replace('*此款僅提供現場遊玩*\n一款輕鬆有趣的家庭遊戲，玩家從袋中抽取角色板塊，可以選擇喜歡的一面或另一面（翻面）放置到自己的船上，湊成排或列來得分。','\n',char(10)),'https://i.postimg.cc/SKTFQJP9/image.png','','','僅供現場玩,家庭,輕鬆小品',2,4,'簡單',1,0,1,1400,0,0,50,1,'',114,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(213,'蜜蜂物語','嗡嗡嗡！蜜蜂飛到花叢中！玩家們化身蜜蜂，競相採集花蜜。為此你們必須明智地規劃飛行路線，趕在別人之前採集到所需的花蜜，以求符合共用以及秘密的不同目標，爭取最高分數。來機智地規劃路線和儲藏花蜜，在花間展現巧妙的舞步吧！','https://i.postimg.cc/kXKzV60C/IMG_20260106_202602.jpg','','','租借,家庭,輕鬆小品',2,4,'簡單',1,1,0,1290,150,1200,50,1,'',115,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(214,'夢幻小隊','一款合作遊戲，玩家扮演進入夢境的探險家，要合力對抗夢魘，保護夢境之主。','https://i.postimg.cc/Xqgg3yHS/image.png','','','租借,派對,家庭,策略燒腦',1,8,'普通',1,1,0,1200,150,1200,50,1,'',116,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(215,'同感悄悄話18+',replace('從感受出發，正經的談「不正經」話題\n適合18歲成年人的溝通遊戲\n情侶、夫妻、密友團暢談悄悄話的好機會\n導師們跟年青人探討現代性文化的導入工具\n「浪漫的燭光晚餐...... 你的伴侶赤裸裸從廚房走出來。」\n你會覺得「有趣」、「恐懼」、「驚奇」、「懷疑」？\n318條全新情況題\n每張情況牌均有一條性/俏皮話題可選\n玩法依舊簡潔，計分改以團體分為目標以及情緒掛臉的全新畫風。','\n',char(10)),'https://i.postimg.cc/d1PRy9gc/image.png','','','租借,派對,合作闖關',2,8,'簡單',1,1,0,960,100,900,50,1,'',117,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(216,'電車難題',replace('適合18歲以上人士遊玩~\n陣營攻防 × 道德選擇 × 黑色幽默的極限對決！\n國外知名IP快樂氰化物，惡搞極致的桌遊來啦！\n歡迎搭乘這班「無法停下的電車」，在兩條鐵軌之間，你能做出「正確」的選擇嗎？\n是無辜小狗？還是世界末日的開關？\n\n你要如何說服列車長不要來你這裡，列車長又要如何抉擇才能展示自己的公平道義？\n發揮你們的口才及想像力，一起來解這道世界級的電車難題！\n\n*遊戲內容僅供娛樂，切勿認真看待。','\n',char(10)),'https://i.postimg.cc/FHw3MZrk/image.png','','','租借,派對,陣營',3,13,'簡單',1,1,0,1100,150,1100,50,1,'',118,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(217,'搖滾巫奇','咻！丟三落四的女巫如閃電般地在魔法黑森林中穿梭，她總是忘東忘西，無論是魔法書、大釜或是掃帚！好在有小精靈，他們非常樂意幫她尋找寶物……和女巫一起滾動，尋找她丟失的魔法寶物。如果你夠靈巧並能和其他玩家巧妙合作，便能在這款快速滾動的遊戲中，找到最多的魔法寶物，獲得最多女巫的獎賞。','https://i.postimg.cc/SR7p4wRG/IMG-20251014-205402.jpg','','','販售,派對,家庭,兒童',2,5,'簡單',1,0,1,1390,0,0,50,1,'',119,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(218,'皮諾丘',replace('*此款僅提供現場遊玩*\n玩家一起協助小木偶在探險的旅程中學習分辨是非。\n\n回合玩家先抽出題目卡，然後決定之後說故事的是真實的或虛構的，跟著便開始講出他動人的故事來。\n\n聽故事的人在判斷故事的真實性的同時，亦可認識身邊說故事的人。\n\n','\n',char(10)),'https://i.postimg.cc/NfzHX4rC/image.png','','','僅供現場玩,派對',4,10,'簡單',1,1,0,990,0,0,50,1,'',120,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(219,'巴薩利市集',replace('高超的談判技巧讓你叱咤商場！\n每位玩家為了獲得珍貴的寶石，秘密地挑選一項行動，若你是唯一選擇該種行動的玩家，立刻執行吧！若有兩位玩家選擇同一項行動，必須進行競價來決定由誰執行。在巴撒利市集，體驗刺激、緊湊、高度互動，但又簡單易學的談判交易遊戲！','\n',char(10)),'https://i.postimg.cc/1tsnS7LX/image.png','','','販售,輕鬆小品',3,5,'簡單',1,0,1,590,0,0,50,1,'',121,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(220,'杯子蛋糕學院',replace('大家同心協力，一起爭奪杯子蛋糕學院獎項吧！\n1. 將沙漏倒置並展示第一張任務卡。\n2. 依照指示移動杯子蛋糕的位置。\n3. 完成你們的任務卡，接著繼續完成下一張。\n你們能在時間耗盡前完成所有任務嗎？','\n',char(10)),'https://i.postimg.cc/cHwp7VRC/IMG-20251014-211249.jpg','','','販售,租借,兒童,家庭,合作闖關',2,4,'簡單',2,1,1,900,100,900,50,1,'',122,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(221,'ERA中世紀：時代紀元',replace('*此款僅提供現場遊玩*\n《中世紀：時代紀元》作為《骰越世紀》的精神續作而推出。\n若說《骰越世紀》是「擲骰畫紙」類遊戲的先鋒，《中世紀》就是「擲骰構築」的先鋒！\n\n在《紀元》中，你的骰子表示中世紀社會不同階層的玩家，而玩家試圖建造最繁榮的城市。\n透過玩家確實在自己的圖板上興建建築，「構築」要素進入場中。你將使用美麗的3D模型元件，如牆壁、堡壘、農田和其他建築。\n遊戲結束時，每位玩家將有各自獨特的城市！\n\n《中世紀：時代紀元》被設計得更具挑戰性，因為玩家透過諸如敲詐、焦土，還有，理所當然的，疾病，彼此互動！\n嘿，這是中世紀，對吧？說到這個，《紀元》被視為新系列的第一款獨立「擲骰構築」遊戲，\n由麥特．李考克（Matt Leacock）和eggertspiele所推出！','\n',char(10)),'https://i.postimg.cc/Yqh4tWy6/ERA.png','','','僅供現場玩,家庭',1,4,'普通',1,1,0,2200,0,0,50,1,'',123,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(222,'秀才遇到幾個兵',replace('在一群天兵中，誰才是出類拔萃的秀才呢?\n這是一款視覺觀察 X 量詞聯想的遊戲，包含四種創意要素，「左右」X「種類」X「數量」X「造詞」\n快來挑戰你的聯想力與反射神經 !','\n',char(10)),'https://i.postimg.cc/W46z56hv/image.png','','','租借,輕鬆小品,兒童,家庭,派對',2,6,'簡單',1,1,0,350,50,300,50,1,'',124,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(223,'搗蛋王國',replace('《搗蛋王國》是一款別出心裁的排庫構築類遊戲—你的卡牌不僅能讓你在自己的回合執行行動，還能讓你在其他玩家的回合跟隨他們執行行動。\n\n你是會專心致志按照自己的想法獨樹一幟呢?還是會跟隨其他孩子們亦步亦趨呢?\n\n當你還是個孩子時，你的想法大概就是:多交幾個好朋友，左手玩具右手披薩，然後搭造出最壯觀的王國。\n\n想要玩具，想要披薩，想和小夥伴們出去玩，想建兒童樂園......\n\n這些酷斃的事情會給你帶來分數，在遊戲結束時，得分最高的玩家就是遊戲的勝利者!\n\n你要時刻注意—如果你沒法把手上的卡牌全部打完，其他搗蛋鬼們就會把你的牌搶走!\n\n畢竟，如果你不肯陪朋友們玩，那誰又會願意陪在您身邊呢?','\n',char(10)),'https://i.postimg.cc/gj52xgBv/image.png','','','租借,策略燒腦',2,4,'困難',1,1,0,1200,150,1200,50,1,'',125,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(224,'火線任務',replace('在《火線任務》中，玩家化身為英勇的消防員\n與夥伴制定消防計畫，果斷的衝進火場\n面對吞噬一切的火舌，小心通過被破壞的環境\n克服內心恐懼 並救出更多的受困者\n#完成一次又一次驚險的任務\n遊戲還有進階的專家規則\n\n消防員將會區分出不同 #專業能力\n駕駛救護車以及消防車更快的救援受困者\n撲滅火勢，噴出空氣泡沫\n擔任消防隊長指揮任務\n但也加入了危險物品以及高熱系統\n讓火勢更加難以捉摸','\n',char(10)),'https://i.postimg.cc/66SWL1YZ/image.png','','','租借,合作闖關,家庭',2,6,'普通',1,1,0,1280,150,1200,50,1,'',126,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(225,'我要上太空',replace('一場精彩的太空冒險！\n扮演一隻星際探險隊，不斷招募隊員並前往各種星球探索。\n在遊戲中你需要嘗試找出一套COMBO公式，管理好你的手牌，秀一波操作打造出最強的探險隊陣容。\n\n遊戲僅有少少的10動，但卻會隨著陣容的龐大，一次動作所引發的連鎖效應越來越長。\n當遊戲即將結束時，你才會意識到『啊！如果再多1動就可以做出完美COMBO了，可惡！只好再來一場！』。','\n',char(10)),'https://i.postimg.cc/2SYVhKSw/image.png','','','租借,輕鬆小品,策略燒腦',1,5,'普通',1,1,0,890,100,800,50,1,'',127,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(226,'雙胞胎',replace('你一定可以看得出來，仙人掌和刺蝟有什麼關係，對了，沒有錯，\n他們都有刺。遊戲裡的300種圖案，隨機抽出11種來湊成5對時，你\n和你的家人及朋友們能夠有一樣的想法來配成對嗎？兩個看似不太\n相關的配成同一對了，說出你們的邏輯也會一樣嗎？一起來在遊戲\n裡製造歡笑吧！','\n',char(10)),'https://i.postimg.cc/25PVXW3R/IMG_20260106_203121.jpg','','','租借,派對,家庭',3,8,'簡單',1,1,0,1080,150,1000,50,1,'',128,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(227,'Project L',replace('*此款僅提供現場遊玩*\n《Project L》是一款抽象策略遊戲，遊戲會有各式各樣的謎題與方塊，\n玩家要做的事情是以最有效率的方式，盡可能完成越多謎題越好\n\n是一款非常考驗玩家空間能力與規劃能力的遊戲！','\n',char(10)),'https://i.postimg.cc/zGGbL54k/IMG_20260106_202857.jpg','','','僅供現場玩,策略燒腦,家庭',2,4,'普通',1,0,1,1800,0,0,50,1,'',129,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(228,'殺手賽局',replace('這是款變換同盟的「社交勾結」遊戲，玩家為了利益互相背叛與謀害，\n6~12個玩家每回合共謀決定將誰殺死，所有人努力成為最後一個存活者並收集金條。\n\n你必須有默契地投票，成為最大票群才能存活。\n有趣的是你可以做任何的方式來傳遞你的訊息，\n但確保你不會成為目標或者他們可能改為埋伏你！\n你們可能在任何時機跟其他人結盟甚至背叛，選擇你的良機，別相信任何人。','\n',char(10)),'https://i.postimg.cc/3RmsXnRX/2.png','','','租借,派對',6,12,'簡單',1,1,0,790,100,700,50,1,'',130,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(229,'噤聲尋寶記：地下墓穴',replace('讓你在摸黑找寶的同時，一邊製造聲響、一邊擔心吵醒沉睡在墓穴的巨龍！\n每一步都得盤算，每抽一張牌都是生死賭注：發出的聲響太多，龍就來敲門；走太快，各種墓穴怪物還會上前阻攔！\n探索地圖、營救囚犯、擊倒怪物，過程腦力全開、心跳狂飆，還得時刻提防身邊“隊友”的背刺操作。\n\n這是一款牌庫構築遊戲，隨著遊戲進行，你的牌庫將會越來越強，能不能在適當的時機抽到自己想要的牌，就要看你運氣。\n每一場遊戲的地圖都是隨機抽取，每次的地下墓穴都不一樣，重玩性極高！\n\n這絕對不是冒險尋寶遊戲，這是聲控地獄。\n誰能靜悄悄地把寶帶回家？誰又會被自己吵到出局？一起下墓穴，一起大吼“我就這麼點聲音你也來打我？！"\n\n','\n',char(10)),'https://i.postimg.cc/Pr9MHhKq/image.png','','','租借,策略燒腦,派對',2,4,'困難',1,0,1,1990,150,1900,50,1,'',131,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(230,'我們不一樣',replace('18+遊戲，你是否和別人不一樣呢!超歡樂派對遊戲!\n喝酒必備遊戲，派對起來!!','\n',char(10)),'https://i.postimg.cc/2j4YnBGZ/IMG-20251014-205517.jpg','','','販售,派對',2,6,'簡單',1,0,1,1080,0,0,50,1,'',132,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(231,'璀璨寶石',replace('榮獲 2014 年度最佳遊戲 2014 Golden Geek Board Game of the Year Winner，榮獲 2014 Spiel des Jahres Nominee 德國桌遊年度大獎，家庭桌遊獎項提名殊榮，本遊戲適合10歲以上，2~4人遊玩。\n(中文版) 璀璨寶石 桌上遊戲，擁有優雅華麗的美術風格，引領玩家進入文藝復興的歐洲地區，擁有最多的寶石將會吸引貴族前往投資。利用手上的資源獲取礦脈、運輸方式以及工匠，工匠將會把你手上的原石冶煉成完美無瑕的寶石！','\n',char(10)),'https://i.postimg.cc/8CDMkCvT/image.png','','','租借,家庭,策略燒腦',2,4,'普通',1,1,0,1400,150,1400,50,1,'',133,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(232,'多拉A夢疊疊樂',replace('*僅供現場玩*\n一款需要穩定性與技巧的平衡遊戲，將可愛的哆啦A夢放到時光機上吧!!','\n',char(10)),'https://i.postimg.cc/904qgR6Y/A.png','','','僅供現場玩,兒童,輕鬆小品',1,2,'簡單',1,0,1,650,0,0,50,1,'',134,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(233,'複製貓貓','日本設計師作品，規則簡單好上手，還有可愛貓咪插畫!','https://i.postimg.cc/Pq2ptQhM/copy-cat-meow.png','','','租借,輕鬆小品,兒童,家庭',2,5,'簡單',1,1,0,490,50,400,50,1,'',135,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(234,'神廟密契',replace('在《神廟密契》中，你將扮演考古學家和冒險家。\n你要尋找的無價之寶就藏在一座神殿中。\n為了得到寶藏，你必須要找到一組雕像，才能解除藏寶室的門鎖。','\n',char(10)),'https://i.postimg.cc/jqWXFLQ1/image.png','','','租借,家庭,輕鬆小品',1,4,'簡單',1,1,0,690,100,600,50,1,'',136,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(235,'璀璨寶石：雙人版',replace('回到文藝復興時代，作為首屈一指珠寶公會首領，為了鞏固你的名聲與財富，你需要善用你的技巧與獨到的眼光，為各個王侯貴族打造最莊嚴華美的手飾。\n璀璨寶石推出全新雙人版了！由設計師Marc André、出版社SPACE Cowboys原班人馬，並特別與《七大奇蹟：對決》設計師Bruno Cathala合作，在原版璀璨寶石中加入新機制，讓雙人版中更添競爭與互動的趣味。','\n',char(10)),'https://i.postimg.cc/nL7RNqCY/LINE_ALBUM_販售區桌遊_251023_39.jpg','','','販售,策略燒腦',2,2,'普通',2,0,2,850,0,0,50,1,'',137,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(236,'獵巫鎮',replace('《獵巫鎮 1692》是一款社交演繹、輕策略遊戲，適合4-12位玩家。一場女巫審判活動正在逐漸升溫。每位玩家將扮演塞林鎮的一位鎮民，試圖相互指控，並將對手送上審判法庭，以保住自己的性命。當所有女巫都被發現，平民才能獲勝！而女巫可以在夜晚殺死其他玩家。在傳染階段中，平民玩家可能也會成為一名女巫！ 你會把親人送上法庭，還是被無辜冤死？或者是拋開所有世俗，成為一名女巫，將罪惡的塞林鎮推入地獄的深淵。\n\n','\n',char(10)),'https://i.postimg.cc/1zCGWQgP/1692.png','','','租借,陣營',4,12,'普通',1,1,0,850,100,800,50,1,'',138,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(237,'可可亞','《可可亞》讓所有玩家沈浸在「神之果國度」的異國情調當中！玩家將扮演部落的酋長，領導你的族人種植與交易可可果來創造榮耀與財富。簡單的規則，卻包裹著不簡單的策略性，又巧妙地與主題結合，讓《可可亞》成為全家大小都愛不釋手的刺激遊戲！','https://i.postimg.cc/4x3TC2GT/IMG-20251014-210951.jpg','','','租借,販售,家庭',2,4,'普通',2,1,1,1050,150,1000,50,1,'',139,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(238,'動物園大亨輕便版',replace('遊戲介紹\nReviews\n\n動物園大亨輕便版是動物園大亨的方便攜帶版本，動物園大亨獲得2007 年德國年度遊戲獎。簡單的規則和快速的遊戲時間，讓動物園大亨輕便版成為孩子們完美的入門遊戲！在這遊戲中，玩家必須妥善利用園區空間，引進並管理各種可愛動物，豐富自己的動物園。 園區與動物們規劃最好、得到最多分的玩家獲勝！','\n',char(10)),'https://i.postimg.cc/659kRbyv/IMG-20251015-112001.jpg','','','販售,家庭',2,5,'簡單',1,0,1,514,0,0,50,1,'',140,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(239,'七隻貓咪','一款規則簡單的卡牌遊戲，玩家透過打牌來湊對，目標是收集七隻不同種類的貓咪。','https://i.postimg.cc/3NBJBKRF/image.png','','','販售,輕鬆小品',2,5,'簡單',1,0,1,300,0,0,50,1,'',141,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(240,'風聲再臨','《風聲再臨》中，玩家透過傳遞情報的方式、內容來推測各玩家的陣營，同時想辦法達成獲勝條件：獲得藍色或紅色情報。同時，隱藏在兩隊之中的特工也會為了自己的獲勝，而擾亂戰局......','https://i.postimg.cc/YSWrPN09/image.png','','','租借,陣營,策略燒腦',3,7,'困難',1,1,0,590,100,500,50,1,'',142,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(241,'忍者魂',replace('遊戲簡介:\n扮演一位忍者,試著奪取藏在城堡內的藏寶圖.\n每局的開始會公開拿著藏寶圖的玩家,玩家們要在換牌,看牌,開牌三個動作選擇一個,\n試著將藏寶圖換到你的手上並順利打開,\n但要小心,一旦打開了錯誤的動作,你將立刻被敵人發現並死在場上','\n',char(10)),'https://i.postimg.cc/4dPr2n6y/image.png','','','販售,輕鬆小品',5,8,'簡單',1,1,0,300,0,0,50,1,'',143,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(242,'天堂與美酒',replace('*此款僅提供現場遊玩*\n你被派去領導一座古老的修道院和它的釀酒廠。\n現在是你在上帝的藍天下釀出最好的麥酒的時刻！\n釀酒的藝術要求你找出最好的時機。\n為了獲得最好的產品，你必須提供你修道院的花園最肥沃的資源和正確數量的僧侶來收獲—\n但是請記住你的釀酒大師，他已經摩拳擦掌要來裝滿你的每一具酒桶！\n在天堂與酒裡面，你必須克服與其他玩家激烈的競爭。\n你要在升級花園和收割資源之間取得平衡來裝滿你的酒桶。\n只有能夠保持冷靜的頭腦可以贏得這場最佳麥酒的競賽！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','','','僅供現場玩,策略燒腦',2,4,'困難',1,0,1,2400,0,0,50,1,'',144,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(243,'偉人的猜拳策略',replace('這是一場攸關世界未來命運的大戰。 \n \n世界偉人將加入你的麾下，與你一同發展文明、建設國土；\n \n和雄才大略的軍武家一齊征服天下、獨霸世界。\n \n究竟你會成為名留青史的統治者，還是亡國敗君？\n \n就用「剪刀、石頭、布」分出勝負！\n \n \n遊戲中，玩家可以運用偉人獨一無二的特殊能力，\n \n強化武力擴展帝國的領土、發展科技與文化建設地方繁榮。\n \n攻打你的對手！並且使用詭譎的猜拳能力贏得每一場戰役。\n \n誰能率先征服六大洲、或者建設出昌盛的帝國將成為遊戲最終的勝利者！','\n',char(10)),'https://i.postimg.cc/dVVbz94L/IMG_20260326_150052.jpg','','','租借,派對,輕鬆小品',3,6,'普通',1,1,0,600,100,600,50,1,'',145,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(244,'王國軼聞錄',replace('簡單上手的遊戲機制！\n極具特色的卡牌插畫。\n快速的遊戲時間，讓你和好友連開數局。\n形成自己獨特的戰術風格，體驗爽快的卡牌Combo。','\n',char(10)),'https://i.postimg.cc/vZZg1MCC/IMG_20260106_202936.jpg','','','租借,家庭',2,5,'普通',1,1,0,1190,150,1100,50,1,'',146,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(245,'動物日報',replace('玩家扮演報紙頭版的決定者\n\n在連續的三回合拼湊出當日報紙頭條。\n\n\n\n遊戲採實時制\n\n每個人在回合開始時進入採訪階段\n\n在不知道板塊正面為何的情形下盲選板塊\n\n當玩家各自覺得選夠了就可以進入各自的排版階段\n\n也就是把先前拿的哩哩扣扣拼貼到頭版\n\n\n\n考驗玩家的空間能力\n\n怎麼擺才能最大化滿足各種板塊囉嗦的得分條件也是遊戲樂趣之一\n\n而遊戲中最最最殘酷的事情是\n\n打最少廣告的人會直接出局\n\n很幽默的諷刺當今新聞的窘境\n\n主題非常具像化，帶入感堪稱一絕。\n\n\n\n很好理解之外，每一回合也非常緊張刺激\n\n譏諷對手廣告滿版的同時\n\n你抓著手中認真老實的報導卻不知道為什麼汗流浹背\n\n什麼？你說小時不讀書長大當記者？\n\n你一定要來試試 號外！動物日報！','\n',char(10)),'https://i.postimg.cc/T33zZcCn/IMG_20260326_145957.jpg','','','租借,派對,家庭',1,6,'普通',1,1,0,1600,200,1600,50,1,'',147,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(246,'驚爆倫敦','莫里亞蒂在倫敦的大笨鐘安裝了定時炸彈！遊戲中玩家分成正反兩方，除了要找出隊友外，還要處理炸彈！機智的福爾摩斯一行人是否能在時間內解除炸彈？或是莫里亞蒂會與他的同夥笑著離開大笨鐘的廢墟呢？','https://i.postimg.cc/FFxnNLff/IMG_20260326_151705.jpg','','','租借,陣營,派對',4,6,'簡單',1,1,0,650,100,600,50,1,'',148,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(247,'德國心臟病',replace('玩家依序翻開一張卡片置於自己面前，只要桌面上翻開的紙牌中，一共出現5個同樣的水果時，玩家就要搶按桌面中央的鈴，最快按鈴的玩家贏得桌面上所有的卡片，手牌用盡的玩家便出局了！\n堅持到最後的玩家獲勝！\n\n這是一款挑戰你心臟極限的刺激遊戲。','\n',char(10)),'https://i.postimg.cc/RFKycpZ4/IMG_20260326_150258.jpg','','','租借,派對,家庭,兒童,輕鬆小品',2,6,'簡單',1,1,0,790,100,700,50,1,'',149,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(248,'七大奇蹟：對決',replace('本商品為「七大奇蹟：對決」系列，與「七大奇蹟」、「七大奇蹟新版」系列不相容！\n發展你的科技和軍事，建造雄偉的建築，領導你的文明走向勝利！\n《七大奇蹟：對決》是一款獨立遊戲適用於兩人競技。','\n',char(10)),'https://i.postimg.cc/xjP70Gtf/LINE_ALBUM_販售區桌遊_251023_3.jpg','','','販售,策略燒腦',2,2,'困難',1,0,1,950,100,900,50,1,'',150,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(249,'卡卡頌',replace('熱銷逾1200萬套的《卡卡頌》全球風靡\n簡單規則帶來深刻遊戲體驗\n是當代經典桌遊，不容錯過！\n兩人玩也很讚喔！\n是經典的板塊拼接遊戲，玩家輪流抽取板塊，拼接出一個共享的地圖，並派遣自己的手下（米寶）到城堡、道路或草原上佔地得分。','\n',char(10)),'https://i.postimg.cc/nLVpHDpx/IMG_20260326_150146.jpg','','','租借,家庭',2,5,'簡單',1,1,0,1290,150,1200,50,1,'',151,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(250,'三國殺標準版',' 相信"三國"是一個家域戶曉名詞，三國殺是一個以三國時代為背景，集角色扮演、戰鬥、偽裝等要素于一體的多人卡片遊戲。玩家可以通過在遊戲裡扮演不同身份的角色，隱藏自己，尋找同伴，並運用各是不同的技能擊敗敵對勢力，得到最後的勝利，創造一個屬於自己的三國傳奇。','https://i.postimg.cc/Vv3BcBw4/IMG_20260107_211023.jpg','','','租借,陣營,策略燒腦',4,10,'普通',1,1,0,600,100,600,50,1,'',152,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(251,'皇家港',replace('在皇家港的碼頭上，生活總是繁華忙碌，而你也想在這裡混一口飯吃，但別太冒險，不然你的存貨會耗盡。\n別忘記撥出你的部分收益給總督及海軍上將以獲得他們的庇護，並僱用各行各業的人物來幫助你往目標前進。\n\n試著擴展你的影響力，讓你成為名垂青史的遠征軍。','\n',char(10)),'https://i.postimg.cc/x8WySyQG/IMG_20260107_211149.jpg','','','租借,策略燒腦,輕鬆小品',2,5,'普通',1,1,0,590,100,500,50,1,'',153,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(252,'拼布藝術',replace('拼布在歐洲中世紀是一種針線活，需要將幾片碎布片拼湊出一個較大的刺繡品。在過去，拼布是一種利用剩下的碎布塊來製造衣服和被子的方法。今天，拼布是一種藝術，設計師使用珍貴的織物來創造出美麗的紡織品。特別是使用參差不齊的各種織物，更能創造出真正的大師傑作。\n\n要創造出一個美麗的被子，需要花費很多的精力和時間，但也需要有可用的補丁配合。所以要仔細選擇你的補丁，並確保有足夠的鈕扣來完成你的被子，好向你的對手展現你的美麗作品。','\n',char(10)),'https://i.postimg.cc/CKvYdxLW/IMG_20260326_150143.jpg','','','租借,輕鬆小品',2,2,'簡單',1,1,0,880,100,800,50,1,'',154,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(253,'小王子：給我一個星球',replace('曾經清澈的眼睛都已長大，被工作與責任模糊，走向過度強調嚴肅與成熟的大人世界，問問自己，有多久沒有停下腳步去欣賞一朵你愛的花？\n\n小王子70週年了，一雙仍然清澈的眼睛，為多少迷失在現實的大人們，重新安裝上想像力，世界一樣在轉，但我們不再為自己的不夠成熟感到悲哀。\n\n慶祝小王子70週年，玩樂小子獨家代理法國 the little prince 小王子桌遊 (中文版)，重新邂逅和小王子初識的溫暖。 遊戲中，透過卡牌熟悉小王子的故事以及處事哲學，拼成一個完整的星球。\n\n由桌遊界兩大設計師 Antoine Bauza (設計 7 Wonders 等桌遊)，Bruno Cathala (設計 MOW, Dice Town 等桌遊)聯手設計，內附中文及英文遊戲說明書，適合2~5人， 七歲以上的孩子及成人，遊戲規則簡單易上手，却難以精通，2~5位玩家之間積分計算，欲擒故縱的全盤策略思考過程中，透過觀察指定下一位玩者抽牌，透過資源的分配，轉變為對自己有利的局勢以獲得勝利，遊戲極富重複可玩性。 是一款適合全家共同玩樂的遊戲。','\n',char(10)),'https://i.postimg.cc/nr6YtYxG/IMG_20260107_211133.jpg','','','租借,家庭,策略燒腦',2,5,'普通',1,1,0,980,100,900,50,1,'',155,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(254,'妙語說書人奧德賽',replace('妙語說書人：奧德賽是款挑戰你想像力與推理能力的說書人遊戲。\n遊戲所附的84張精美圖卡都有不同的故事，而且每個人每一次說出的故事都不一樣，讓每場遊戲都充滿全新驚奇。\n奧德賽是款獨立遊戲，不需要妙語說書人基本版即可進行遊戲。更棒的是，你可以最多12人同時進行遊戲，還可以進行團隊賽！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','','','租借,派對,家庭,兒童,輕鬆小品',3,12,'簡單',1,1,0,1190,150,1100,50,1,'',156,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(255,'快手疊杯','在「快手疊杯」裡，每個人用五個不同顏色的杯子，試著比別人更快完成任務。每張題卡會以各種有趣的方式，提示你要將五個杯子以什麼順序疊起來或排成一列：可能是樹上的五隻鳥，或是牆上掛的五件外套。趕快看懂提示，速速排好，馬上按鈴！','https://i.postimg.cc/4NJq95CB/IMG_20260326_150937.jpg','','','租借,兒童,家庭',2,4,'簡單',1,1,0,790,100,700,50,1,'',157,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(256,'出包魔法師',replace('這是一個用魔法互相傷害的遊戲，玩家扮演一群想第一個登上大魔法師之塔的魔法師，但是不知道為什麼，大家的咒語頻頻出包，必須透過觀察判斷、邏輯推測以及一點點冒險的勇氣，來召喚正確的魔法石。\n來吧！一場咒語大亂鬥已經開始了！','\n',char(10)),'https://i.postimg.cc/jj8KCSSd/IMG_20260326_151218.jpg','','','租借,派對,家庭',2,5,'簡單',1,1,0,1290,150,1200,50,1,'',158,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(257,'目擊者之夜',replace('疑神疑鬼的密室推理陣營遊戲\n\n山中作客的夜晚，主人慘遭殺害！\n殺人魔就在受邀的賓客中，為了避免殺戮繼續蔓延，賓客們交換目擊情報，討論兇手的去向。在有限的時間內，賓客能否藉由各自職業上的優勢，識破殺人魔與其共犯羅織的謊言，並經由投票將嫌疑人關進鍋爐室裡，確保自身的安全？','\n',char(10)),'https://i.postimg.cc/g0vHsC8r/IMG_20260326_152615.jpg','','','租借,派對,陣營',3,6,'簡單',1,1,0,490,50,400,50,1,'',159,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(258,'草泥馬',replace('草泥馬最高原則：擺脫所有負分！\n出清你的手牌，否則會扣分。如果你無法出牌，便要決定：現在就退出，或抽牌賭一下，以期之後能順利打出手牌。\n扣分時拿取扣分指示物，當你出清所有的手牌時，返還1個扣分指示物（可能是扣1分或扣10分）。\n遊戲結束時，扣分最少的玩家獲勝。\nL.A.M.A = Lege Alle Minuspunkte Ab!\n草泥馬＝棄掉所有負分（德文）的縮寫','\n',char(10)),'https://i.postimg.cc/vBbLN0vR/IMG_20260326_152706.jpg','','','租借,家庭,輕鬆小品',2,6,'簡單',2,1,1,290,50,200,50,1,'',160,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(259,'卡魯巴紙牌版','在充滿傳說的卡魯巴島上，有幾座巨大的寺廟，還有深藏在叢林中的寶藏。你是探險隊隊長，必須運用你的經驗為隊員規劃路徑，不要讓隊員阻擋彼此的去路，還要比其他競爭隊伍做得更好，你才能獲得叢林中所有的寶藏，並且讓你所有的隊員到達寺廟。','https://i.postimg.cc/T359LLwx/IMG_20260326_152550.jpg','','','租借,家庭,輕鬆小品',2,6,'簡單',1,1,0,490,50,50,50,1,'',161,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(260,'血契獵殺',replace('*僅供現場遊玩*\n血族戰爭已經結束，只有少數幸運者幸存，你可以聚集起自己的信徒並找出敵對氏族的族長嗎？\n在兩個血族的人口與領土都急速擴張的情況下，衝突是不可避免的結果，隨之而來的戰爭讓無以數計的永生者隕落。\n只有氏族族長及少數精英得以倖免。\n在低調躲藏數月之後，這兩位血族的族長開始熱切地搜尋倖存者，不只是自己的族人，也包括敵對的血族成員。\n現在是兩位族長聚集自己忠實的部下並與敵人進行最終決戰的時刻！\n血契獵殺是一款可供六至十二名玩家一同進行的推理遊戲，但遊戲中充滿騙局。','\n',char(10)),'https://i.postimg.cc/9FpwFzgT/IMG_20260106_202833.jpg','','','租借,陣營,策略燒腦',6,12,'困難',1,0,1,790,100,700,50,1,'缺中文規則書',162,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(261,'牙買加','1678年二月，在多年的海盜生涯之後， 亨利·摩根靠著小聰明謀得牙買加總督一職， 從此不再是人人喊打的那個海上惡霸。 不僅如此，他還把以前的那幫狐朋狗友都邀請至此居住， 這樣一來，他們就能一起享用海上掠奪的勝利果實。 30年之後，海盜為了紀念他的大名，舉辦了一場比賽： 這就是環島海上競速！ 獲勝的隊伍， 將獲得數不盡的黃金。 水手們，出發啦！','https://i.postimg.cc/7Z5QMFD4/LINE_ALBUM_販售區桌遊_251023_29.jpg','','','販售,家庭,派對',2,6,'普通',0,0,0,1200,0,0,50,0,'',163,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(262,'血與刃的白薔薇',replace('白薔薇的復活祭典開始了🌹\n司教統領信者們獻出生命，來復活偉大的母親\n但因為魔法而掌握權力的人們🧙\n不願意償還生命與力量，來到此處將花苞殘殺殆盡🥀','\n',char(10)),'https://i.postimg.cc/QMLqp898/IMG_20260326_152554.jpg','','','租借,陣營',5,10,'普通',1,1,0,690,100,600,50,1,'',164,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(263,'閃靈快手',replace('幽靈巴頓在城堡的地下室發現一台老相機。\n他立刻拿起相機四處拍他想要變不見的東西，當然也包括他自己囉！\n奇怪的是，魔法相機照出來的顏色時常出錯，有時綠色的瓶子照成白色，有時又照成藍色。\n巴頓看著這些顏色奇怪的照片，記不起來他到底要把什麼變不見？\n‍\n你能幫他說出正確的名稱、或甚至親手把東西變不見嗎？\n如果你快速地抓到正確的物品，你就有機會獲勝！','\n',char(10)),'https://i.postimg.cc/RVDdZQvT/IMG_20260326_152438.jpg','','','販售,兒童,家庭,輕鬆小品,派對',2,8,'簡單',1,1,0,790,100,700,50,1,'',165,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(264,'奇雞連連',replace('給孩子的第一款策略遊戲。\n只要會玩圈圈叉叉，便能享受「奇雞連連」帶來的無窮樂趣。\n貪吃的公雞會吃掉（套住）比自己小的公雞，你能首先讓自己的三隻公雞排成一直線嗎？\n\n這款易學易懂的策略遊戲挑戰你的記憶力，看看你的記性是否和公雞的胃口一樣好！','\n',char(10)),'https://i.postimg.cc/XYgPLMNs/IMG_20260106_202551.jpg','','','租借,兒童,家庭',2,2,'簡單',2,1,1,890,100,800,50,1,'',166,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(265,'多米諾王國',replace('身為國王，你正在尋找新土地來擴張王國的勢力並提高聲望，必須探索所有的土地、麥田、湖泊以及山脈，來找到最棒的領地。但是要小心，其他的國王也在覬覦這些土地唷！\n選擇適當的多米諾板塊，妥善地將相同的地形拼放在一起，形成最大的領土，並透過事前的規劃，讓你王國中的每一寸土地都得到完善的利用，以獲得最高的聲望分數！','\n',char(10)),'https://i.postimg.cc/c4HTW5yz/IMG_20260326_152359.jpg','','','租借,家庭,輕鬆小品',2,4,'簡單',1,1,0,790,100,700,50,1,'',167,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(266,'動物疊疊樂',replace('4歲以上｜15分鐘\n動物們想來場特技表演，牠們要堆疊成一座巨大的金字塔，這需要高超的技巧與過人的勇氣！\n誰能將企鵝放在鱷魚上面，把綿羊放在企鵝上面，再把蛇放在綿羊身上呢？大熊想要站上這金字塔頂端，但是這高度著實使牠頭暈目眩！\n\n一款搖搖晃晃的堆疊遊戲，也可以一個人玩喔！','\n',char(10)),'https://i.postimg.cc/Z5vcBBqM/IMG_20260326_152503.jpg','','','租借,兒童,家庭',2,4,'簡單',1,1,0,1290,150,1200,50,1,'',168,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(267,'豆腐王國',replace('這是一場精采的推理遊戲。\n遊戲中輪流扮演找尋豆腐公主的麻糬王子。把握線索，思考線索中的邏輯，來破解謎題。而其他人則會扮演給予線索的角色，因為有人可能說謊，而有些人則必須說實話，所以善用你的演技給予線索，為自己在這場宮廷鬥爭贏得勝利吧！','\n',char(10)),'https://i.postimg.cc/X7wbd8v4/IMG_20260326_152302.jpg','','','租借,陣營,輕鬆小品',3,8,'簡單',1,1,0,490,50,400,50,1,'',169,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(268,'蛙蛙闖蓮池',replace('5歲以上｜10-20分鐘\n青蛙在蓮葉間跳躍，獵捕咔嗞咔嗞的美味蒼蠅。小心！送子鳥就躲在池塘邊，等待小胖胖青蛙自己送上門來。\n青蛙必須依擲骰結果，至少跳到顏色相符的蓮花牌上，才能將發現的蒼蠅吃下肚。\n然而，小小的蒼蠅難以填滿青蛙大大的胃，牠得繼續往前跳到下一朵同色的蓮花，試試看能否捕獲更多的蒼蠅。\n當心，別撞見送子鳥，否則就會前功盡棄，餓肚子啦！','\n',char(10)),'https://i.postimg.cc/VNHQmZKR/IMG_20260326_152305.jpg','','','租借,兒童,家庭,派對',2,4,'簡單',1,1,0,390,50,300,50,1,'',170,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(269,'腦霧證人',replace('最瞎目擊者！\n\n1.起始玩家隨機抽6張牌，重新排列後講述一個犯罪故事。將這些牌依序疊放，形成故事牌堆。\n2.擲骰決定要從故事牌堆中移除哪一張牌。\n3.下一名證人用剩餘的牌與兩張新增的牌，重新陳述案情，必須對應紙牌順序，並且合情合理。\n\n到底誰的腦子比較有霧？','\n',char(10)),'https://i.postimg.cc/MHwh9d51/IMG-20251015-111726.jpg','','','販售,家庭,輕鬆小品',2,5,'簡單',1,0,1,690,0,0,50,1,'',171,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(270,'超級犀牛',replace('那是什麼？有隻犀牛在爬牆？是的！超級犀牛又出動了。\n來自動物世界的超級英雄，不畏大樓有多高，不斷搜捕小偷和強盜。他和獅子一樣強壯，和狐狸一樣聰明，但也和犀牛一樣重。所以即使超級犀牛出現在最堅固的大樓，還是會讓大樓搖晃。你可以幫超級犀牛在會搖晃的建築物上完成任務嗎？','\n',char(10)),'https://i.postimg.cc/LXrcZYKK/IMG_20260326_152404.jpg','','','租借,兒童,家庭',2,5,'簡單',1,1,0,790,100,700,50,1,'',172,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(271,'幕後交易',replace('什麼？你要用2隻羊來換1隻牛？門都沒有！\n\n拍賣會開始囉！\n你可以經由拍賣或幕後交易來購得動物。\n但是在幕後交易時，得小心對方騙人！\n看看到底是誰比較會吹牛，能以低價購得對方的動物。\n\n遊戲結束時必須以4張相同的動物（四重奏）來算分，由總分最高的玩家獲勝。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','','','租借,家庭',3,5,'簡單',1,1,0,490,50,400,50,1,'',173,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(272,'瑞士興國錄',replace('*僅供現場玩*\n特殊機制，絕版少見!蓋房子.生小孩.工作.結婚，把所有你能想到的包一起，然後還很策略!\n一個互動極高，又要比誰跑分跑得快，跟平常玩的策略遊戲大大的不同，試著挑戰這遊戲吧~','\n',char(10)),'https://i.postimg.cc/KvQJZ1gk/IMG_20260105_122904.jpg','','','僅供現場玩,策略燒腦',2,4,'困難',1,0,1,2500,0,0,50,1,'',174,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(273,'侃侃而猜','「侃侃而猜」是一款運用推理，來猜測其他玩家生活體驗的遊戲。過程中的提問與作答，將讓你窺見，生活中習以為常的平凡小事，在其他玩家的生活中，竟然有與你迥異的歷程。與新朋友快速熱絡及與老朋友加深情誼的絕妙遊戲！','https://i.postimg.cc/43tLjpmW/LINE_ALBUM_販售區桌遊_251023_42.jpg','','','販售,輕鬆小品,派對,家庭',3,6,'簡單',1,0,1,490,50,400,50,1,'',175,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(274,'誰是牛頭王',replace('每位玩家同時從10張手牌中打出一張，並依規則將牌接到桌面上4列牌陣中的一列，若你的牌成為一列中的第6張，就必須將前面的5張牌拿起，每張牌上有數量不等的牛頭。\n遊戲目標是：不要得到任何紙牌，因為牌上的每個牛頭都是負分。\n遊戲結束時，得到最少牛頭的玩家獲勝。\n\n這是一個經常讓你有出乎意料之感的瘋狂聚會遊戲，人越多越好玩喔！','\n',char(10)),'https://i.postimg.cc/PJfyPSLY/IMG_20260326_152217.jpg','','','租借,輕鬆小品,家庭,派對,兒童',2,10,'簡單',1,1,0,490,50,400,50,1,'',176,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(275,'倉庫城(無擴充版)',replace('在1900年代，漢堡市是世界的門戶，港口的中心有一棟特別且複雜的倉儲大樓，稱為『倉庫城』。\n\n你是一名住在漢堡的貿易公司老闆，生長在倉庫城最繁華的時代，從貨輪上購買貨物並提供給客戶以完成合約，賺取白花花的銀子。記得雇用消防員來保護你的貨物和辦公大樓，以免在不時發生的火災中蒙受損失。一年中生意最好的玩家將贏得勝利。\n\n倉庫城運用超級簡約卻極度原創的精神所開發，絕對令您印象深刻！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','','','租借,策略燒腦,派對,輕鬆小品',2,5,'普通',1,1,0,1490,150,1400,50,1,'',177,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(276,'花磚物語.花磚密語',replace('★在《花磚密語》中，你們將扮演瓷磚畫藝術家，裝潢埃武拉皇宮的\n牆壁。\n★由摩爾人所引進的「阿茲勒赫瓷磚畫」(azulejos)，原為帶有白色與藍色的瓷磚，深受葡萄牙人喜愛。葡萄牙國王曼紐一世某次造訪西班牙南部的阿爾罕布拉宮時，深深著迷於這些奪目的摩爾裝飾。這令國王魂牽夢縈，並立即下令要在自己的皇宮中如法炮製。','\n',char(10)),'https://i.postimg.cc/HssNjJhb/LINE_ALBUM_販售區桌遊_251023_13.jpg','','','販售,家庭,策略燒腦',2,4,'普通',1,0,1,1250,0,0,50,1,'',178,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(277,'東京之王','東京之王是款極受歡迎的狂歡大亂鬥Party Game與家庭遊戲，玩家扮演突變怪獸，暴走機器人，甚至是異種外星人，以投擲骰子，獲得最佳骰子組合來選擇自己的策略。是要進攻對手嗎？還是治癒慘重的傷害？或是準備更多的能量方塊以增強怪獸的超能力？邁步向前為您的勝利之路奮鬥吧！','https://i.postimg.cc/Znzv0NhF/IMG_20260106_202520.jpg','','','租借,派對,家庭,輕鬆小品',2,6,'簡單',1,1,0,1250,150,1200,50,1,'',179,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(278,'砰！骰子版',replace('在西部荒野中，執法人員與不法之徒之間永不停息的戰鬥持續加溫，突然，一陣遮空蔽日的箭雨襲來：印地安人來襲！你夠膽量跟上這些印地安人的腳步嗎？你有勇氣去挑戰自己的命運嗎？你可以擊敗圍繞你的兇狠槍手並揭露他們的身份嗎？\n\n砰! 的所有樂趣在骰子版中重現！\n‍','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','','','租借,陣營,輕鬆小品',3,8,'簡單',1,1,0,790,100,700,50,1,'',180,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(279,'終極密碼',replace('10歲以上｜15分鐘\n每位玩家要在自己的數字牌被對手完全猜出前，搶先猜出對手所有的數字牌！但是面對空白的牌背，如何能猜到對手的數字牌呢？玩家雖然只知道自己擁有哪些數字，在遊戲過程中，藉由分析逐漸增加的資訊：其它玩家的猜測、及陸續攤開的牌，慢慢推敲出每張牌正確的數字！\n你能搶先猜出對手的牌嗎？','\n',char(10)),'https://i.postimg.cc/g21gNy5n/IMG_20260326_152035.jpg','','','租借,家庭,輕鬆小品',2,4,'簡單',2,2,0,790,100,700,50,1,'',181,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(280,'矮人礦坑',replace('在遊戲中玩家們將會扮演矮人族。其中一種矮人是淘金矮人，他們開拓礦坑坑道向山脈深處尋找寶藏；另一種則是試著在淘金矮人的路上放置障礙的搗蛋鬼。雖然你只能猜測其他玩家的角色，兩組矮人還是要想辦法支援自己的同伴。如果淘金矮人成功地建造出通往寶藏的路徑，他們將得到金塊作為獎賞，而搗蛋鬼將一無所獲；不過萬一淘金矮人失敗了，則搗蛋鬼將會得到獎賞。每位玩家所扮演的角色，只有在分金塊的時候才會揭露。遊戲進行三回合後結束，金塊最多的玩家獲勝。\n\n這是個可以10人同樂的派對遊戲，規則簡單好上手，但過程變化多端，可以趁機耍耍心機喔！','\n',char(10)),'https://i.postimg.cc/pTJkWwdt/IMG_20260326_152110.jpg','','','租借,陣營,家庭,派對',3,10,'簡單',2,2,0,690,100,600,50,1,'',182,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(281,'獴鷲派對','在正確的時刻打出正確的牌，讓狐獴和你一起歡慶。遊戲中，得到越多的加分狐獴牌越好，但要小心，禿鷲正盯著獵物，隨時準備奪走分數，唯有緊扣好牌在手上，才能讓你免於禿鷲的肆虐！ ','https://i.postimg.cc/PxQKXg5g/IMG_20260326_152126.jpg','','','租借,輕鬆小品',2,5,'簡單',1,1,0,290,50,200,50,1,'',183,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(282,'格格不入 (Blokus) 大格鬥',replace('遊玩時間約20分鐘，適合7歲以上。\n一人各佔一邊，努力把自己所有的幾何板塊拓展出自己的新天地！\n記住！鞏固自己的地盤，並同時觀察對手的一舉一動，才是上上策。\n一個可以靈活動腦的抽象遊戲，一個看似簡單，但卻可發揮無窮潛力，最適合朋友及家庭聚會，一起同樂！\n格格不入(正式名稱是"阻擋我們")是一款抽象的策略遊戲，玩家要試著把各色透明的俄羅斯方塊放到圖板上。\n唯一的限制是不能和你其他的方塊相鄰，並且要碰到你已經在圖板上的方塊至少一個角。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','','','租借,家庭,輕鬆小品',2,4,'簡單',1,1,0,1099,150,1000,50,1,'',184,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(283,'蹦蹦蛙',replace('5歲以上｜20分鐘\n讓青蛙歡快的跳躍，幫助你將面前的牌由小到大排列整齊。\n每當池塘裡出現垃圾，就會擋住去路，妨礙你整理紙牌。巧妙地換牌，並善用青蛙的大跳躍，讓你成功達陣！','\n',char(10)),'https://i.postimg.cc/9fGYb6Z7/IMG_20260326_152641.jpg','','','租借,兒童',2,4,'簡單',1,1,0,390,50,300,50,1,'',185,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(284,'政變(政變疑雲)',replace('消滅所有對手的影響力，成為最後倖存的玩家。\n\n每次到你的回合，你都可以宣稱自己擁有某些角色(可以吹牛)從而使用角色能力，又或是獲得基本收入。\n\n但要注意，其他玩家可以向你提出質疑，如果你被發現吹牛，又或是質疑失敗，即損失一點影響力。而你只有兩點影響力，沒有影響力即時退場。\n\n而部份角色能力也可以被某些角色阻礙，當然你也可以吹牛擁有那些角色，而理所當然，對方也可以質疑。\n\n儘全力成為最後倖存的玩家。','\n',char(10)),'https://i.postimg.cc/y8DfmpLh/IMG_20260326_151956.jpg','','','租借,派對,輕鬆小品',2,6,'簡單',3,3,0,450,50,400,50,1,'',186,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(285,'金金樂盜',replace('海盗們，揚帆掠奪吧！\n\n在金金樂盜中，玩家將以擲骰的方式奪取寶藏，努力成為加勒比海群島中最富有的海盜！回合中，你將投擲5顆骰子，最多3次，依你的擲骰結果組成的骰面組合，搜刮當地商船、其他海盜或是國王本尊！慎選你的骰子，用最聰明的方式去搶奪金幣，成為這片海域中最富有的海盜！','\n',char(10)),'https://i.postimg.cc/nL7RNqC7/LINE_ALBUM_販售區桌遊_251023_38.jpg','','','租借,輕鬆小品',2,6,'簡單',2,2,0,490,50,400,50,1,'',187,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(286,'烏邦果',replace('快速！簡單！迷人！\n\n烏邦果是一款節奏明快、讓人上癮的簡單幾何拼放遊戲，玩家必須和時間賽跑並和對手競爭，完成環環相扣的板塊拼放。\n\n越快完成就能得到越多寶石，九回合後，寶石價值最高的玩家獲勝！遊戲進行方式：每位玩家拿取一套共12片的幾何板塊，每片形狀不同的板塊都由多個大小相同的正方形所組成。回合開始時，每位玩家拿取一張新的拼圖板，一位玩家擲骰決定必須用哪些板塊填滿拼圖板上的空格，在時限內完成的人大喊「烏邦果」，接著從袋子裡隨機拿取一顆寶石。最快完成的人可以額外獲得一顆藍寶石，次快完成的人可以額外獲得一顆黃寶石。不同顏色寶石帶來不同分數，九回合後，得分最高的玩家獲勝。','\n',char(10)),'https://i.postimg.cc/TYYNw3gd/IMG_20260326_151846.jpg','','','租借,家庭',1,4,'簡單',1,1,0,1490,150,1400,50,1,'',188,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(287,'卡坦島',replace('歡迎來到卡坦島！\n\n你們是勇敢的拓荒者，首先來到這座資源豐沛但未經開發的島嶼，並命名為卡坦島。你們創建的第一批村莊發展迅速，透過收集資源、鋪設道路和興建城市讓聚落逐漸壯大，並且透過交易解決資源不均的問題。\n\n然而，土地與資源有限，誰能迅速擴張自己的聚落並搶佔最佳地段？制定明智且有彈性的策略，偶爾還需命運之神的眷顧，才能率先實現目標，從群雄中脫穎而出，稱霸卡坦島！\n\n自1995年榮獲德國年度遊戲冠軍以來，卡坦島激勵著全世界數百萬人，投身這款鬥智且充滿樂趣的遊戲。\n現在就加入！','\n',char(10)),'https://i.postimg.cc/R0fs2wW9/LINE_ALBUM_販售區桌遊_251023_47.jpg','','','租借,家庭',3,4,'普通',1,1,0,1690,200,1600,50,1,'',189,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(288,'機密代號','一款分組競賽的派對陣營遊戲。在一組加密情報之中，領袖必須想出絕妙的暗號，如：「一個名詞+數量」，讓隊員們以最少回合找出最多特務，率先找出我方所有特務的隊伍獲得勝利。不過得小心潛伏在情報背後的殺手，找到他的人必死無疑！這款遊戲擁有簡潔的遊戲機制，以及難以重複的題庫組合，讓它百玩不膩。','https://i.postimg.cc/rmxK6ptV/IMG_20260106_203128.jpg','','','租借,派對,家庭,陣營',2,8,'簡單',1,1,0,780,100,700,50,1,'',190,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(289,'恐龍電車',replace('這是一款排列電車和恐龍的卡牌遊戲。\n由山田空太 設計，日本人氣遊戲「鯨魚電車」的續作！\n遊戲目的是玩家要將9張手牌拼湊成不同的組合，肉食恐龍由 2 張卡牌組成，而草食恐龍則由3張卡牌組成。\n但是，電車、蒸汽火車、新幹線則可以由3張或更多的車卡組成。遊戲以簡單麻雀規則包裝，卻是一款需動動腦筋的派對遊戲。\n與前作相比，此作新增了「寶牌」及更多的計分方法，戰略性UP！','\n',char(10)),'https://i.postimg.cc/Gm6gMXhz/LINE_ALBUM_販售區桌遊_251023_37.jpg','','','販售,輕鬆小品',2,4,'簡單',1,0,1,650,0,0,50,1,'',191,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(290,'傻傻玩',replace('傻傻玩是一款具速度感的歡樂桌遊，即時換牌、節奏明快，讓您成為團康與破冰高手！\n當有人收集到4張相同動物就要大喊：「喝水！」盡快奪取一枚水滴，水總是不夠給所有的動物喝，勝利終將屬於反應最快或頭腦清楚的玩家。\n馬上行動！','\n',char(10)),'https://i.postimg.cc/L66QX8fV/IMG_20260326_151739.jpg','','','租借,派對,家庭,兒童,輕鬆小品',4,12,'簡單',1,1,0,390,50,300,50,1,'',192,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(291,'搶地毯',replace('市場上人們熙來攘往，這是地毯市集的大日子！最佳的銷售人員即將誕生！\n每個玩家都是銷售人員，試圖智取他人。每個玩家輪流擲骰子，\n然後移動市場經理阿三。如果阿三停在對手的地毯上，\n銷售人員必須付錢給地毯主人之後，才可以在相鄰空間放一張自己的地毯。\n當最後一張地毯鋪上時，每位玩家加總自己在市集上可看見的地毯總數和金錢，\n最富有的玩家獲勝！\n家庭遊戲好玩耐玩，全年齡層皆適合。','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','','','販售,家庭',2,4,'簡單',0,0,0,1190,0,0,50,0,'',193,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(292,'沉睡皇后',replace('深受大家上癮的沉睡皇后來囉！\n你會發現這個遊戲有助於記憶的發展、策略及基本的算術技巧！','\n',char(10)),'https://i.postimg.cc/qMfrNY4s/IMG_20260326_151424.jpg','','','租借,兒童,家庭,輕鬆小品',2,5,'簡單',2,1,1,450,50,400,50,1,'',194,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(293,'傳情畫意-歡樂今宵18+',replace('請注意題目為18禁內容，不適合兒童遊玩。\n\n大熱的派對遊戲—傳情畫意系列，為大家帶來新意，\n加入了許多可能讓人羞於啟齒的內容，適合各位成人散發平日積存的各種…軟實力！\n畫出看到的詞語，或猜出圖畫的內容，結果到最後通常跟答案相去十萬九千里，讓人笑破肚皮！','\n',char(10)),'https://i.postimg.cc/kGpsv8cf/IMG-20260105-093138.jpg','','','租借,派對,家庭',4,8,'簡單',1,1,0,1350,150,1300,50,1,'',199,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(294,'輕鬆放',replace('10歲以上｜20分鐘\n呼牌員隨機挑選他的一片板塊並把它翻開，其他的玩家從自己的板塊中找出數字相同的板塊，接著，每位玩家將這片板塊放到自己的圖板上。\n持續以此方式進行遊戲，直到圖板上都放滿板塊為止，玩家為自己圖板上三個方向的每一條單色線計分。\n你會有幾條得分線？\n離滿分307分還有多遠？\n一款讓1-6人享受的大腦運動，放輕鬆！輕鬆放！','\n',char(10)),'https://i.postimg.cc/cJ8bSkYH/IMG_20260326_151312.jpg','','','租借,輕鬆小品',1,6,'簡單',2,2,0,1090,150,1000,50,1,'',195,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(295,'腦洞量表','一款換位思考的猜謎遊戲。每回遊戲推派一位玩家擔任評量員，其他人隨機抽取一張數字牌，根據題材指示，輪流形容一段符合數字強弱的事件，讓評量員嘗試將數字由小至大排序出來，任務成敗就看你們熟不熟了！','https://i.postimg.cc/TwMHYjqh/IMG_20260326_151335.jpg','','','租借,派對,合作闖關',4,9,'簡單',1,1,0,750,100,700,50,1,'',196,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(296,'狼人真言',replace('這款遊戲可以結合手機APP呦，APP會擔任主持人，讓遊戲流程更順暢。\n狼人的嚎叫近在咫尺，只有4分鐘的時間尋找魔法咒語，保護先知，拯救你們的小鎮吧！\n遊戲適合8歲以上，時間10分鐘。','\n',char(10)),'https://i.postimg.cc/C5JvN3y7/IMG_20260326_151633.jpg','','','租借,派對,陣營,輕鬆小品',4,10,'簡單',1,1,0,590,100,500,50,1,'',197,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(297,'狼人殺',replace('■遊戲人數：8-18人\n■適合年齡：14歲以上\n■遊戲時間：約45分\n《Werewolves 狼人殺》是一款可供多人參與的推理策略類遊戲，考驗玩家的語言表述能力及邏輯分析，通常的版本需要12人參與。\n本套卡牌結合了面殺和網殺的遊戲規則，設計了更加貼合玩家需求的卡牌樣式及配置說明，角色更加豐富，玩法更加歡樂，喜歡派對遊戲的您不容錯過！','\n',char(10)),'https://i.postimg.cc/bvGZTgyR/IMG_20260106_203114.jpg','','','租借,陣營,策略燒腦,派對',8,18,'普通',1,1,0,690,100,600,50,1,'',198,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(298,'瀑布淘金客','玩家讓他們的獨木舟在尼加拉河中來回穿梭以採集寶石。但是河流的變化總是超乎人們的想像，該如何適切地運用行進卡，在險象環生的瀑布邊緣採集珍貴的寶石並安全運回岸上？在河水湍急、奔流快速的尼加拉河，無所畏懼的獨木舟勇者對抗著河水，沿著河岸採集寶石。當然，只有在河流的深處，接近瀑布的地方才能發現最有價值的寶石。雖然獨木舟勇者當然並不害怕，可是，仍要小心以對，否則就會船毀人亡。第一位取得五個都不同顏色、或四個都相同顏色、或任何七個寶石的玩家，將贏得這場遊戲。最先採集到整組寶石的玩家獲勝。','https://i.postimg.cc/pd8G3KmH/LINE_ALBUM_販售區桌遊_251023_46.jpg','','','販售,家庭',2,5,'簡單',1,0,1,1650,0,0,50,1,'',200,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(299,'截碼戰',replace('遊戲時間	45分鐘\n建議年齡	12歲以上\n小心！對手好像快破解妳的密碼了！\n第二次世界大戰，同盟國破解了納粹的密碼，大幅縮短了戰爭。\n現在，你和你的解碼小組要想辦法破解對手的加密訊息，\n同時傳遞加密訊息給其他隊友！\n截碼戰考驗語言表達能力、聯想能力以及邏輯思考，\n簡單好學又挑戰彼此的團隊默契。\n內附中、英文雙語題目卡！','\n',char(10)),'https://i.postimg.cc/FHGnhkBN/cb1ec7e0_33a3_474f_9456_a893021818cb.jpg','','','租借,陣營,輕鬆小品',3,8,'簡單',1,1,0,880,100,800,50,1,'',201,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(300,'你刺我殺他',replace('9歲以上｜30-45分鐘\n\n在香蕉共和國裡，高壓獨裁的政權引發百姓的憤怒與不滿，許多人投身刺殺總理的行列，進而集結成一個刺客組織。然而多金的總理並不在乎，身旁伴隨職業級保鑣，依然無惡不做。\n到底是總理會先除掉一名刺客，讓刺客集團潰不成軍，還是刺客會先暗殺成功，推翻政權？\n保鑣能否在關鍵時刻營救總理，維繫政權？','\n',char(10)),'https://i.postimg.cc/XvFHt9pm/LINE_ALBUM_販售區桌遊_251023_43.jpg','','','租借,陣營,輕鬆小品',4,8,'簡單',1,1,0,490,100,400,50,1,'',202,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(301,'巫術學院',replace('8歲以上｜30-45分鐘\n各位親愛的同學：又到了期末考試的時刻，考試規則一如往常：從成分供應機內取用所需的成分彈珠並注意其變化。如果相同顏色的成分彈珠相互碰撞，就會引發爆炸...... 你可以拿走它們！使用你收集的成分彈珠來完成藥水，並飲用藥水來釋放其魔法的神奇威力。\n請記住，為了奪得年度風雲學生的榮耀，光靠迅捷是不夠的，你必須研製難度最高且價值非凡的藥水！','\n',char(10)),'https://upload.cc/i1/2025/09/11/RFZOYL.jpg','','','租借,家庭',2,4,'簡單',1,1,0,1390,150,1300,50,1,'',203,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(302,'糟了個糕！(這就是人生)',replace('▲讓人一刻都無法放鬆的緊張骰子遊戲！\n■如同真實生活般變幻莫測\n■時而洋溢幸福、時而處處陷阱。\n■不過別緊張，遊戲尚未結束，你還有機會！','\n',char(10)),'https://i.postimg.cc/nLdZMhhB/IMG_20260326_151145.jpg','','','租借,家庭,派對,輕鬆小品',2,6,'簡單',1,1,0,990,100,900,50,1,'',204,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(303,'G同鴨搶',replace('適合年齡：8歲以上\n遊戲時間：約20分\n一場為2-6位大小玩家、各種家禽與狐狸而設計的農場饗宴！\n\n「給我玉米，其餘免談！」\n不知為何禽舍裡的 家禽最近胃口大開，土雞、珠雞、火雞、雉雞、鴨子和鵝整天都在爭食。\n但務必小心！ 一旁的狐狸虎視眈眈，牠們想吃的可不是玉米……\n雞鴨鵝等家禽們只要三餐吃得飽飽飽，便能心滿意足，對狐狸而言，又何嘗不是如此？\n遊戲結束時，獲取最多養分（包括家禽和飼料）的玩家獲勝！','\n',char(10)),'https://i.postimg.cc/RhTYY3th/IMG_20260326_150830.jpg','','','租借,派對,兒童,家庭,輕鬆小品',2,6,'簡單',1,1,0,890,100,800,50,1,'綠色token-1。藍色+黃色token-2',205,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(304,'詐賭巫師',replace('10歲以上｜30分鐘\n在這個遊戲裡，玩家們是懂得各種咒語的魔法師。\n在怪物競技賭場裡，只要自己押注的怪物鬥士獲勝，就能得到一大筆賞金。\n玩家們秘密地使用咒語，想盡辦法讓自己押注的怪物鬥士獲勝。\n但是競技場的裁判可不會放任不管，在某些情況下強大的咒語反而無法使用。\n遊戲結束時，由賺到最多錢的玩家獲勝。','\n',char(10)),'https://i.postimg.cc/J09cWc8q/IMG_20260107_211145.jpg','','','租借,派對,策略燒腦',3,6,'普通',1,1,0,590,100,500,50,1,'',206,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(305,'從前從前…',replace('8歲以上｜20-40分鐘\n壯烈的冒險？浪漫的愛情？惡毒的詛咒？說個獨屬於你的奇幻冒險故事！\n\n這款說故事紙牌遊戲中提供許多童話故事中常見的元素，例如：王子、森林或仙女。一名玩家擔任說書人開始說故事，故事中要包含他的故事卡上的關鍵字，並將故事合理地導向他手中結局卡上的結局。\n其它玩家則要使用手牌打斷說書人，並成為新的說書人。\n最後的贏家是先把手上故事卡用完、並將故事帶到自己結局上的玩家。\n但本遊戲的樂趣不是在於獲勝，而是在一起說故事中獲得樂趣！','\n',char(10)),'https://i.postimg.cc/mZ3KknnB/IMG_20260326_150853.jpg','','','租借,家庭,輕鬆小品',2,6,'簡單',1,1,0,990,100,900,50,1,'少6張故事卡',207,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(306,'5秒定律好棒棒',replace('\n五秒定律科技大升級！這次推出了聲光特效絕佳的接力棒，玩家只要喊出答案，然後將棒子交給下一位玩家，棒子就會自動感應開始５秒倒數，說出答案交棒或者使用功能卡躲避，誰會是腦力枯竭的最後一棒呢？\n2024 波蘭年度遊戲獎最佳派對遊戲提名\n2024 丹麥年度遊戲獎最佳家庭遊戲','\n',char(10)),'https://i.postimg.cc/tJbfDdsq/IMG_20260326_150727.jpg','','','租借,派對,輕鬆小品',2,8,'簡單',1,1,0,890,100,800,50,1,'',208,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(307,'德國蟑螂',replace('遊戲年齡： 8\n遊戲時間： 少於 30 分鐘\n德國蟑螂是一款非常有趣的遊戲，在遊戲中要不斷的騙人來或得遊戲的勝利。遊戲就好像吹牛一樣，什麼時候是真，什麼時候是假你永遠不清楚。但你可以望穿他的眼神，瞭解他騙人的跡象。\n\n此遊戲適合在歡樂派對中進行，考驗玩家撒謊的功力喔！','\n',char(10)),'https://i.postimg.cc/SND57Mkp/IMG_20260326_151040.jpg','','','租借,派對,家庭,輕鬆小品',2,6,'簡單',1,1,0,590,100,500,50,1,'',209,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(308,'炸彈競技場2',replace('適合年齡：8歲以上\n遊玩時間：20-30分鐘\n西元3012，地球經數次戰爭及汙染，已破壞殆盡。\n玩家將扮演"世界政府軍"與"人民聯軍"，兩大陣營，\n展開搶奪搶奪僅存資源的基地戰爭，最先達成基地連線一方，\n便能稱霸地球！\n而科學之子-米翁，需在激烈戰火下將通往生存的最後希望，\n太空飛船ZERO注滿能量。在分秒必爭的末世戰爭中，誰能成為最存活的一方？','\n',char(10)),'https://i.postimg.cc/BQqkKgWN/IMG_20260326_151010.jpg','','','租借,陣營,派對,輕鬆小品',2,9,'簡單',1,1,0,650,100,600,50,1,'',210,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(309,'龍龍公園',replace('你在經營一座龍龍公園！你將如何設置？\n\n你會把某些恐龍放在一起還是分開？根據你所擁有的種類和放置條件，決定該怎麼做能吸引最多遊客的目光。\n\n遊戲規則非常簡單，擲骰子決定放恐龍的條件＞從手中選一隻恐龍放進去＞把恐龍傳給左手邊玩家，然後重新開始！\n\n簡易的規則、超可愛吸睛的恐龍米寶，一款不論大小朋友都喜歡的遊戲，快一起來體驗看看吧～～～','\n',char(10)),'https://i.postimg.cc/9XGnDhk3/image.png','','','租借,家庭',2,5,'簡單',1,1,0,750,100,700,50,1,'',211,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(310,'忍者之夜',replace('忍者之夜 Night of The Ninja 夜幕降臨...一場新的風暴，即將展開!\n咻咻我來了~ 咻咻我背刺你~~! — 忍者之夜\n『揉合了諜戰、詭計、暗殺的陣營推理遊戲！』\n這是一款超快節奏的遊戲，在簡短的對話中你要找到敵人，想出與自己隊友配合的方法，精準的打擊對手，在這邊收集訊息與暗殺另個敵人一樣重要！\n一局忍者之夜可能在電光石火中就結束了，但爭雄尚未完結，所以趕緊將牌洗勻，再投入下一場挑戰吧。\n忍者的進攻需要快狠準，太陽西下，忍者之夜即將來臨，為了流派的榮譽，你必須找到敵人，且先發制人幹掉他們。發揮忍者優越的隱蔽和狡猾來混淆視聽，克敵制勝。','\n',char(10)),'https://i.postimg.cc/vBsqyDnn/LINE_ALBUM_販售區桌遊_251023_59.jpg','','','租借,陣營,策略燒腦,派對',4,11,'普通',1,1,0,750,100,700,50,1,'',212,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(311,'傳情畫意',replace('風靡各間桌遊店的派對遊戲。\n玩家必須手腦並用，手負責畫畫、腦袋負責開洞；畫技與猜技並用，畫給別人猜、猜給別人畫，當答案揭曉時，才發現大家是否都搞錯了什麼！\n\n輸贏不是重點，笑果最重要。','\n',char(10)),'https://i.postimg.cc/5NgMRdZS/IMG-20251014-205630.jpg','','','販售,租借,派對,家庭',4,8,'簡單',2,1,2,1390,150,1300,50,1,'',4,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(312,'地產大亨-七龍珠Z版',replace('在本集《七龍珠Z》當中，Z戰士加入買賣房地產的戰爭，透過擲骰子掀起一場史詩式混戰！\n\n招攬悟空、達爾和悟飯等傳奇戰士，一同在《Monopoly:七龍珠Z特別版》展開冒險吧！\n你遇上紅帶軍和膠囊集團時，記得把握機會成為世界上最富有的戰士。\n布瑪和龜先人等盟友，僵住你取得偉大成就！你能收集所有地契，成為天下第一嗎？\n\n內含精緻特殊造型配件！讓遊戲體驗更上層樓！','\n',char(10)),'https://i.postimg.cc/50V7Jjzv/LINE_ALBUM_販售區桌遊_251023_60.jpg','','','販售,家庭',2,6,'簡單',0,0,0,1299,0,0,50,0,'',213,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(313,'爆炸貓桌遊','歡慶爆炸貓10 週年！出版社隆重鉅獻《 爆炸貓桌遊》 ☆承襲爆炸貓的簡單有趣及陷害元素，絕對熟悉的爆炸貓卡牌和超有趣的圖板翻面設計','https://i.postimg.cc/7hNjd0Qv/IMG-20251015-111807.jpg','','','販賣,派對,輕鬆小品',2,6,'簡單',0,0,0,950,0,0,50,0,'',214,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(314,'古墓謎蹤',replace('一款探險家 vs. 僵屍，驚險追逐遊戲，潛入詭異古墓，尋找珍貴寶藏！\n\n玩家分為探險家與僵屍，探險家要躲避僵屍的追擊，也要與其他探險家互相競爭，成為最先收集完寶物的勝利者。\n而僵屍則是要阻止入侵者，將他們逐一消滅！\n\n遊戲進行時，探險家及僵屍分別坐在遊戲版圖兩側，角色棋子內含磁鐵可吸在版圖上，\n僵屍看不到探險家的所在位置，因此探險家移動時千萬要小心，不要被僵屍看出端倪唷～～\n探險家回合可以投擲數顆骰子，並從中選一顆當作此回合移動步數，但是！如果骰到僵屍面，此顆骰子將會被僵屍沒收\n若想贖回骰子，僵屍會馬上移動與骰子顆數相同的步數，何時贖回也是關鍵之一！\n這是一款獨特的不對稱競爭遊戲，僵屍會根據你找到的寶藏、移動的格數，來推敲探險家的位置。\n看著僵屍的棋子一步步朝自己接近....那種緊張的感覺，體驗一次就知道！\n驚險刺激、充滿變數，每一回合都是腦力與運氣的較量，與家人、朋友們玩一場吧！','\n',char(10)),'https://i.postimg.cc/C1svxYC1/LINE_ALBUM_販售區桌遊_251023_62.jpg','','','販售,兒童,家庭',2,5,'簡單',1,0,1,1250,0,0,50,1,'',215,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(315,'圖騰快手',replace('遊戲適合7歲以上，2至10名玩家一同遊玩，遊戲時間15分鐘\n這是一款經典派對遊戲；適合與家人好友同樂的最佳的陪伴性桌遊。\n競速記憶的刺激遊戲，訓練孩子的反應與記憶。\n與朋友玩樂的同時，亦能學習，是你的桌遊寶庫中不可或缺的喔！\n最新版本來囉！不但環保還便於攜帶，\n適合在旅途中進行的快速遊戲 快一起來試試吧！','\n',char(10)),'https://i.postimg.cc/cCNNVsxX/IMG-20251014-205450.jpg','','','販售,輕鬆小品',2,10,'簡單',1,0,1,500,0,0,50,1,'',240,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(316,'傳情畫意:6人行',replace('遊戲人數：4-6人\n遊戲時間：20分鐘\n適合年齡：6歲以上\n風靡各間桌遊店的派對遊戲 ─ 可以帶出門玩了！\n玩家必須手腦並用，手負責畫畫、腦袋負責開洞；畫技與猜技並用，畫給別人猜、猜給別人畫，當答案揭曉時，才發現大家是否都搞錯了什麼！\n\n輸贏不是重點，笑果最重要。','\n',char(10)),'https://i.postimg.cc/VLm8gLZp/IMG-20251014-205526.jpg','','','販售,家庭,派對',4,6,'簡單',1,0,1,790,0,0,50,1,'',2,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(317,'時間到家庭版',replace('我們要在有限的時間內，盡可能多猜一點卡片上的單字或短句，出題者請盡量發揮你的表達能力，讓猜題者能盡快猜出答案！\n但是請趕快，就要沒時間了！','\n',char(10)),'https://i.postimg.cc/x8ySQW8y/IMG-20251014-205508.jpg','','','販售,家庭,兒童',4,12,'簡單',1,0,1,550,0,0,50,1,'',216,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(318,'腦洞量表:沒有下限(18+)',replace('適合18+以上歲數人士遊玩\n知名 Youtuber 超愛的遊戲，多部影片累積觀看數直逼300萬，各種腦洞大開的絕妙應答、突破想像的爆笑表演，娛樂效果沒有極限的派對遊戲王者！\n如今推出「沒有下限」的版本，除了各種恥度大開的題目與表演、還有滿滿的地獄梗玩笑以及引戰的爭議話題，遊玩前，請確保你們的遊戲成員都滿17歲，而遊戲過程中引發的任何意外，請自行處理調解。','\n',char(10)),'https://i.postimg.cc/4NsgPNFs/IMG-20251014-205535.jpg','','','販售,派對',4,9,'簡單',0,0,0,790,0,0,50,0,'',218,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(319,'籤籤入扣',replace('兒時回憶中，難忘的刺激遊戲有兩種：\n玩疊疊樂、老師上課抽籤，不要倒下來不要倒下來…不要抽到我不要抽到我… 好刺激啊！\n現在把兩種刺激的感覺融合在一起，不可掌握的命運、抓到平衡的成就感，刺激感加倍！興奮感加倍！\n\n歡樂的氣氛更是隨著籤支增加而蔓延開來！','\n',char(10)),'https://i.postimg.cc/DynT6yYh/IMG-20251014-205544.jpg','','','販售,派對,家庭',2,99,'簡單',1,0,1,890,0,0,50,1,'',217,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(320,'鬥魚俱樂部',replace('兩群魚兒正面交鋒，試圖在新魚缸裡找到最佳的落腳處！率先將自己的5隻魚組成一個魚群的玩家獲勝。注意，其他海洋生物可能會阻擋魚兒的集結！\n1. 選擇你的一隻海洋生物\n2. 將牠投入魚缸\n3. 率先將你的5隻魚集結成一個魚群便獲勝！','\n',char(10)),'https://i.postimg.cc/0yH19GkB/IMG-20251014-211001.jpg','','','販售,兒童',1,2,'簡單',0,0,0,690,0,0,50,0,'',219,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(321,'未來造鎮',replace('★Phil Walker-Harding繼「可可亞」、「熊熊公園」後的又一輕策略遊戲力作\n★打造一個人居與自然世界相結合的城市\n★遊戲適合10歲以上，遊戲時間30-45分鐘','\n',char(10)),'https://i.postimg.cc/7ZQrq1Hd/IMG-20251014-211009.jpg','','','販售,家庭,策略燒腦',2,4,'普通',1,0,1,1050,0,0,50,1,'',229,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(322,'魔法秘笈',replace('★知名桌遊設計師Phil Walker-Harding的全新巫師作品！\n★玩家聚集於此參與一年一度的盛大魔法儀式！學習最酷炫的法術！\n★遊戲適合12+歲以上，遊戲時間45分鐘','\n',char(10)),'https://i.postimg.cc/6Q2Jq7Tn/IMG-20251014-211037.jpg','','','販售,家庭,輕鬆小品',1,4,'普通',0,0,0,1350,0,0,50,0,'',244,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(323,'拉密:城市版:台北版',replace('人數：2~4人遊玩\n2個珍珠奶茶特別牌贈品\n拉密遊戲是一個能激發您思考神經的遊戲，因為它不太靠運氣，卻需要您運用很多的策略。因此除了娛樂性外，尚具有以下極高的教育目標：\n\n1. 排列組合能力 — 學習數字和顏色的最佳排列組合\n\n2. 創新規劃能力 — 培養能不受限於所面對的現有牌局，重新規劃新的牌局組合\n\n3. 決斷分析能力 — 訓練在短時間內，做出正確的出牌和操作牌的能力','\n',char(10)),'https://i.postimg.cc/MGCkQWj3/IMG-20251014-211056.jpg','','','販售,租借,家庭,策略燒腦',2,4,'普通',1,1,0,850,0,0,50,1,'',226,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(324,'絢爛寶石山 ',replace('在世界的一個遙遠角落，矗立著一座充滿神秘和傳說的山脈。\n\n傳說中，深入山脈下方的礦井具有神奇的性質：無論你從其中的隧道中獲得多少袋寶貴的寶石，礦井總是充滿寶藏。\n\n這個國家裡最優秀的珠寶匠決定利用這個神奇的來源製作出最驚人的珠寶作品。他們競相競爭，以證明自己配得上最高獎勵，那就是魔法鐵砧。\n\n《寶石鍛造》是一款多功能的家庭遊戲，擁有獨特的3D立體遊戲棋盤和神奇的插圖。\n\n從神奇的礦井中獲得稀有寶石，並將它們存放在你的寶石盒中。然後，用收集到的寶石來製作精美的珠寶作品。\n\n最後，為完成的作品和珠寶套裝獲得勝利點數！','\n',char(10)),'https://i.postimg.cc/bv7Xtz24/IMG-20251014-211217.jpg','','','販售,家庭',2,4,'簡單',1,0,1,1040,0,0,50,1,'',237,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(325,'數字9乘塔',replace('「2」適合這樣放嗎？「9」待會在更高層好不好放呢？在玩數字9乘塔時，大家的目標都會很「高」。為了打好下一層的基礎，聰明的放置數字板塊吧！將數字越大的板塊放到越高的層級，你就會得到越多的分數。注意！如果放至時留下了太多的空隙，有可能會阻礙到你之後的行動。\n\n適合8歲以上，1~4人遊玩，時間約20分鐘。第一層完成數字x1，第二層x2......越高層次的分數越高！利用空間邏輯推理、手牌控制以及最佳化管理，來獲得最高的分數吧！','\n',char(10)),'https://i.postimg.cc/3wsMvKvQ/IMG-20251014-211225.jpg','','','販售,輕鬆小品,家庭',1,4,'簡單',1,0,1,990,0,0,50,1,'',228,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(326,'拉密:六人版',replace('拉密(Rummikub)遊戲是由以色列人Ephraim Hertzano 於1930年初於羅馬尼亞所研發設計。 第一個拉密遊戲是在自家後院子用手工製作的。在1950年初，拉密遊戲是挨家挨戶沿街叫賣，或者去說服小商店拿一兩個遊戲在店裡寄賣。因著此遊戲與眾不同的遊戲規則和娛樂性，靠著口耳相傳，拉密遊戲就在穩健中不斷的成長。\n\n時至今日，拉密遊戲已成為全世界第三大最佳銷售遊戲和全世界第一大最佳銷售的數字磚塊牌。同時拉密遊戲也是以色列第一大外銷遊戲。\n超過50,000,000個拉密遊戲，用26種不同的語言發行，橫跨五大洲，風行於全世界56個國家和地區。\n\n拉密遊戲是一個能激發您思考神經的遊戲，因為它不太靠運氣，卻需要您運用很多的策略。因此除了娛樂性外，尚具有以下極高的教育目標：\n1. 排列組合能力 — 學習數字和顏色的最佳排列組合\n2. 創新規劃能力 — 培養能不受限於所面對的現有牌局，重新規劃新的牌局組合\n3. 決斷分析能力 — 訓練在短時間內，做出正確的出牌和操作牌的能力','\n',char(10)),'https://i.postimg.cc/XJdRKTfS/IMG-20251014-211234.jpg','','','販售,家庭,策略燒腦',2,6,'普通',1,0,1,1280,0,0,50,1,'',225,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(327,'馬爾喀什(搶地毯、地毯商人)',replace('市場上人們熙來攘往，這是地毯市集的大日子！最佳的銷售人員即將誕生！\n\n每個玩家都是銷售人員，試圖智取他人。每個玩家輪流擲骰子，\n然後移動市場經理阿三。如果阿三停在對手的地毯上，\n銷售人員必須付錢給地毯主人之後，才可以在相鄰空間放一張自己的地毯。\n\n當最後一張地毯鋪上時，每位玩家加總自己在市集上可看見的地毯總數和金錢，\n最富有的玩家獲勝！','\n',char(10)),'https://i.postimg.cc/XJdRKTfj/IMG-20251014-211242.jpg','','','販售,家庭',2,4,'簡單',1,0,1,1190,0,0,50,1,'',243,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(328,'非洲之旅(波札那之旅)',replace('在這趟「非洲之旅」中，你會窺見獅子、犀牛、大象、花豹和斑馬的風采。\n\n你能猜到在旅程終了時，誰會成為最有價值的動物嗎？\n在適當的時機打出正確的紙牌，並收集最有價值的動物，讓你在遊戲結束時獲得高分，可惜，動物的價值會隨著打出的紙牌而改變哦！\n\n規則簡單，易學易教，但是變化迅速，對全家大小來說都是款緊張刺激、富有挑戰性的遊戲！','\n',char(10)),'https://i.postimg.cc/SsCBLw62/IMG-20251015-111638.jpg','','','販售,租借,家庭',2,5,'簡單',2,1,1,990,0,0,50,1,'',245,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(329,'博物館尋蹤',replace('知名設計師Phil Walker-Harding繼《熊熊公園》、《可可亞》、《羊駝山谷》後的家庭遊戲最新力作，中文版獨家獻上！\n\n警鈴大響，快點把出口關閉！某件博物館珍藏品已經被偷走了！\n博物館館長就靠身為名偵探你來揭發躲藏在16個嫌疑犯中的竊賊（或者是竊賊們）。\n找到線索\n\n並解決謎團，除非竊賊在出口關閉前就已經逃走了！\n遊戲目標：調查博物館內的線索，並從16個嫌疑犯裡找到竊賊(們)。\n在6個回合中你要將提示標記在你的筆記內以協助調查；在真正的竊賊(們)身上押注最多的玩家將贏得遊戲。\n1. 從博物館珍藏品上找尋線索。 2. 隱藏你的蹤跡不讓對手察覺。 3. 善用推理技巧來質疑嫌疑犯！','\n',char(10)),'https://i.postimg.cc/zBKsw9Ch/IMG-20251015-111705.jpg','','','販售,家庭',2,4,'簡單',1,1,0,800,0,0,50,1,'',221,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(330,'神來之筆','利用美術行業的規則來擊敗你的競爭對手！在你面前，有一幅畫作需要完成，想要搶到訂單，你必須成為添上最後一筆的那個畫家。如果你沒有需要的色彩，你至少能毀掉這張畫......適合8歲以上，2-4位玩家，遊戲時間15-30分鐘。','https://i.postimg.cc/hvnH2ps6/IMG-20251015-111732.jpg','','','販售,家庭',2,4,'簡單',1,0,1,735,0,0,50,1,'',236,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(331,'幸運轉! 轉! 轉!',replace('你有看過彈珠飛出去，旁邊人先尖叫的遊戲嗎？\n這就是《幸運轉！轉！轉！》！一場靠手感、運氣、算計和一點點報復心的彈射混戰。\n遊戲中的輪盤有兩面，共有兩種截然不同的玩法～\n\n一般模式：新手也能上手，笑著哭著都能玩！\n這裡是訓練場，也是陷阱場。玩家輪流彈出骰子到不同區域——金幣、資源、事件、空白區還有那個超煩的強盜區。\n每個回合你只能彈一次，準就爽、歪就空，而且還可能幫對手觸發事件、撿資源，瞬間變提款機！\n\n進階者模式：這不是彈彈珠，是資源戰爭！\n覺得一般模式太單純？歡迎來到進階者模式，戰略腦開機、心臟掛外面！\n這裡不只要彈準，還得規劃資源、管理牧場、搶佔購買時機，誰先擁有牧場誰就稱王！\n幸運轉！轉！轉！》是一款融合彈射技巧與歡樂競賽的派對桌遊。\n無論是比拼準度還是搏命衝刺高分區，只要一彈上場，誰都有機會逆轉勝！\n小小轉盤充滿大驚喜，快來看看誰是真正的彈射王者吧！','\n',char(10)),'https://i.postimg.cc/yxT2tcp2/IMG-20251015-111755.jpg','','','販售,派對,家庭',2,5,'簡單',1,0,1,990,0,0,50,1,'',224,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(332,'決勝巧力環','力大不一定無窮的角力遊戲。玩家們各握盤子的一邊，借力使力讓球進洞，不比蠻力只比巧勁！集競爭、刺激、挑戰、組隊、對抗等炒熱氣氛要素，巧力環將是最給力的派對神器！','https://i.postimg.cc/4y1jqVFf/IMG-20251015-111840.jpg','','','販售,輕鬆小品,派對',2,4,'簡單',1,0,1,590,0,0,50,1,'',233,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(333,'機獸骰戰Pikit',replace('★投擲骰子拿取怪獸或機甲卡\n★發動卡牌功能獲得優勢或陷害對手\n★遊戲適合8歲以上，2至4名玩家一同遊玩，遊戲時間20分鐘','\n',char(10)),'https://i.postimg.cc/sxJbq70g/IMG-20251015-111847.jpg','','','販售,輕鬆小品,家庭',2,4,'簡單',1,0,1,590,0,0,50,1,'',231,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(334,'三麗鷗翻翻樂','廣受歡迎的卡通人物齊聚一堂，進行考驗記性和運氣的地盤爭奪戰！出牌放入遊戲板，將箭頭所指的牌翻面，試著讓您的人物露臉，越多越好！Hello Kitty 是王牌，可以幫您移除對手的人物。遊戲結束，遊戲板有最多人物露臉的玩家獲勝。','https://i.postimg.cc/BZcWjfZd/IMG-20251015-111857.jpg','','','販售,家庭,兒童',2,4,'簡單',0,0,0,390,0,0,50,0,'',220,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(335,'話立積群',replace('在《話立積群》中，多個隊伍會競賽建造由樂高®積木組成的模型。在六個回合結束後，最多分數的隊伍獲得遊戲勝利！\n\n每個隊伍有兩位玩家：指導師描述如何建造形狀卡上的模型；而建築師如其描述來建造模型。\n每一隊會選擇各自所覺得可以達成的卡牌，需要的樂高®積木數量越多就越難、分數也越高，最先完成的隊伍還會翻轉沙漏，讓其他隊伍陷入時間壓力！考驗玩家們對空間分析的概念，讓我們一起動手建造、快樂學習！','\n',char(10)),'https://i.postimg.cc/4NJDt2nM/IMG-20251015-111904.jpg','','','販售,家庭,合作闖關',2,8,'簡單',0,0,0,700,0,0,50,0,'',242,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(336,'拉密XXL大字版',replace('★經過時間考驗的遊戲：由以色列人Ephraim Hertzano 於1930年初於羅馬尼亞所研發設計。 因遊戲與眾不同的遊戲規則和娛樂性，靠著口耳相傳，拉密遊戲就在穩健中不斷的成長。\n★最受玩家歡迎的遊戲：成為全世界第三大最佳銷售遊戲和全世界第一大最佳銷售的數字磚塊牌。\n★打破語言隔閡的遊戲：超過50,000,000個拉密遊戲，用28種不同的語言發行，橫跨五大洲，風行於全世界70多個國家和地區。但是此遊戲所包含的106個磚塊牌所代表的意義是全球共同了解的\n★激發思考神經的遊戲：因為它不太靠運氣，卻需要您運用很多的策略。\n◎排列組合能力 — 學習數字和顏色的最佳排列組合\n◎創新規劃能力 — 培養能不受限於所面對的現有牌局，重新規劃新的牌局組合\n◎決斷分析能力 — 訓練在短時間內，做出正確的出牌和操作牌的能力。','\n',char(10)),'https://i.postimg.cc/bNkWGD7c/IMG_20260106_203003.jpg','','','販售,租借,家庭,策略燒腦',2,4,'普通',3,1,2,1180,150,1200,50,1,'',227,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(337,'泛亞天鵝數字牌 旅行版',replace('天天鵝一家拜訪蘭陽平原的大姑媽，這裡的蔬果香脆可口，蟲蟲肥滋滋。天天鵝希望永遠不要離開。大姑媽說：「如果你可以率先將手上的蟲蟲，在院子裡排成一隊一隊，就可以搬來這裏住！蟲蟲有四種顏色，長度從1到13，每隊至少要有3條蟲，顏色一樣的蟲排成一隊就要長短不同並且是連號，長度一樣的蟲排在一起就要每條蟲的顏色不同。」天天鵝能否贏過大姑媽，並移居蟲肥果香的蘭陽天堂呢？\n\n★ 牌架組成收納盒，精巧好攜帶！走到哪，玩到哪！','\n',char(10)),'https://i.postimg.cc/VLYxMZds/IMG-20251015-111951.jpg','','','販售,租借,家庭,策略燒腦',2,4,'簡單',2,1,1,590,100,500,50,1,'',235,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(338,'歪星訪客',replace('一場80年代的外星人科幻冒險！\n一艘太空船墜毀在黑森林中，但它的防禦力場仍在運作。\n為何有些物品可以穿越力場，有些物品會被反彈呢？外星人制訂了防禦力場的穿越規則，與小朋友一起對抗所有探員。\n探員觀察哪些物品可以穿越防禦力場，哪些會被反彈，蒐集線索，隨時準備破解穿越規則。\n小朋友必須猜對哪些物品可以穿越防禦力場，哪些會被反彈，贏得外星人的信任，盡早破解穿越規則。\n把握時間，破解穿越規則！','\n',char(10)),'https://i.postimg.cc/3JnPZjvx/IMG-20251015-112037.jpg','','','販售,陣營,輕鬆小品',3,6,'簡單',1,0,1,990,0,0,50,1,'',230,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(339,'海格力士的12試煉',replace('《海格力士的12試煉》是一款合作/陣營類型的遊戲，講述的是海格力士完成12試煉的過程\n可以 4-7 人玩，遊戲中依照人數使用特定的角色，\n例如六人玩的時候，反派赫拉一開始就會登場！\n每個角色會有自己的一次性能力，整場遊戲可以使用一次。\n試煉卡是遊戲的核心，只要海格力士和同伴能完成 12 道試煉就能贏得勝利，\n然而如果海格力士耗盡勇氣標記前都還沒完成，那麼赫拉以及同夥們會贏得勝利。\n試煉卡有三種類型，從試煉卡數字編號的底色可以做分辨，\n其中橘色就是海格力士的 12 試煉：地獄犬、九頭蛇，以及亞馬遜女王的腰帶等，\n一個比一個還艱難！有的試煉完成的條件很簡單，有的則是需要道具卡，\n透過特定道具，試煉將能解開。但是究竟試煉卡需要的道具在哪裡？\n有時候就得透過線索以及同伴的動作來推敲','\n',char(10)),'https://i.postimg.cc/Gmt6gBFM/IMG-20251015-112044.jpg','','','販售,策略,陣營',4,7,'普通',1,0,1,790,0,0,50,1,'',234,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(340,'暗影奇襲',replace('邪魔與正念對決之陣營遊戲\n\n19世紀末，極度繁榮的「霧之都」，成為世界的中心，快速的發展，帶來無窮的財富，也拉大了貧富的差距，造成治安的惡化，邪氣和怨念更是與日俱增。\n\n《暗影奇襲》便是以這個光榮與邪惡並存的「霧之都」作為舞台的「生存系陣營遊戲」，描寫了從黑暗中誕生的邪惡存在「暗影」、討伐暗影的國家秘密機關「獵人」，以及休戚與共的霧之都「市民」間的戰鬥。\n遊戲開始時，沒有人知道你的真實身分，使用特殊能力以及紙牌效果在地區間移動，盡速找到與你相同陣營的伙伴，打倒對手，共享勝利！','\n',char(10)),'https://i.postimg.cc/8zY921w8/IMG-20251015-112050.jpg','','','販售,陣營,策略燒腦',4,8,'普通',0,0,0,890,0,0,50,0,'',232,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(341,'迴轉壽司(壽司走走) Sushi Go!','在這個快速的紙牌遊戲中，我們的目標是當壽司呼嘯而過時，要搶到壽司料理的最佳組合。分數是得到最多卷壽司或者蒐集到全套的生魚片。將你最喜歡的握壽司蘸芥末可以得到三倍的分數，但記得別吃太飽，一定要保留一點空間給甜點，否則很有可能會扣分，收集最多分數即能成為壽司達人！','https://i.postimg.cc/VNbp13HC/IMG-20251015-112111.jpg','','','販售,家庭,派對,輕鬆小品',2,5,'簡單',2,0,2,390,0,0,50,1,'',241,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(342,'寶石商人豪華版',replace('古今中外，珍貴的寶石都是王族、工藝大師及情侶們的收藏品，現在，富甲一方的買家派出他們的珠寶經紀，涉足世界各地搜羅最完美無瑕的寶石以豐富自己的收藏；在祕魯聖艾斯度 Club Hotel 的密室內，你面對其他寶石收購集團的競爭，故此你必須運用聰明的腦袋，甚至實則虛之地嚇唬對手，務求在競投過程中投得珍貴的寶石，讓你背後的老闆獲得心頭好，又或者為自己大賺一筆。\n\n\n\n這款經典的 Knizia 遊戲最初於1993年發行，當時名為Attacke，經多年沉寂後，終於千呼萬喚、改頭換臉再出來，肯定必受到桌遊愛好者及一般玩家的歡迎！再版不僅加添了美麗的元素（5種不同顏色、璀璨奪目的假寶石），還有更清晰簡易的規則說明書，令這款重新改良的經典遊戲猶如ReinerKnizia的最新傑作。\n遊戲適合8歲以上3至5人玩樂，需時約30至45分鐘，故可作為輕鬆的消閒娛樂或桌遊愛好者進一步的入門版。遊戲的精美配件令玩家愛不釋手，相信他們再難找到比 寶石商人 更教人入迷的遊戲。','\n',char(10)),'https://i.postimg.cc/cHRztfW6/IMG-20251015-112125.jpg','','','販售,家庭,輕鬆小品',3,5,'簡單',1,0,1,690,0,0,50,1,'',223,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(343,'哞哞穿新衣',replace('我們有大麻煩了！乳牛們醒來發現自己的花紋消失了一大半，但沒有人知道為什麼。難道是膽小的牛仔在夜裡偷走了？或是昨天的雨水沖走牠們的花紋？\n無論是什麼原因，盡快幫牠們穿上新的衣裳，讓牠們可以自在徜徉在草原上！','\n',char(10)),'https://i.postimg.cc/PJdRWNfM/IMG-20251015-112133.jpg','','','販售,家庭,兒童',1,4,'簡單',1,0,1,990,0,0,50,1,'',222,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(344,'蜜雅蘭登',replace('每位玩家打開各自的偵探調查冊，並展開他們所認為的搗蛋鬼肖像。調查總掌從呵子取出屬於搗蛋鬼的4張特徵卡。\n\n先翻開帽子卡片，接著每位玩家檢查自己的答案。然後，調查總長依次翻開眼鏡、小鬍子、最後是領結卡片。','\n',char(10)),'https://i.postimg.cc/0jZHcxbP/IMG-20251015-112145.jpg','','','販售,兒童,輕鬆小品',2,4,'簡單',1,0,1,690,0,0,50,1,'',239,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(345,'艾亞-生命之源',replace('《艾亞—生命之源》是一款以骨牌為主的合作游戲。\n通過骨牌的方式連接路線，拍攝沿路的風景與動物，成為世界第一的攝影師。\n\n作為一流的攝影師，玩家們的目的是合力探索未知的道路，\n拍攝沿途的風景，罕見的動物，讓自己成為世界最棒的攝影團隊。\n\n在游戲過程中每位玩家在自己的回合要做的事就是隨機抽取一張骨牌，之後放到場上或者是保存在手裡，\n但是每個人手裡只能保存一塊骨牌哦。\n當你抽到一塊帶有相機標志的板塊時，恭喜你！你們找到了一個絕佳的拍攝地點。\n當然，這個游戲可不是簡單的讓你把骨牌放完就行了，它可是有時間限制的哦！\n也就是說，如果你一不小心碰倒了骨牌，重新把它扶起來可是會讓你們痛苦不堪的。','\n',char(10)),'https://i.postimg.cc/gj4BNdnc/IMG-20251015-112152.jpg','','','販售,家庭,合作闖關',2,5,'簡單',1,0,1,990,0,0,50,1,'',238,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(346,'造陸計畫',replace('8歲以上｜約30-40分鐘\n人類最後的一線生機！\n地球因持續暖化導致海平面不停升高，能居住的陸地已經所剩無幾，全球最頂尖的科學家爭相提出搶救計畫，但多數終告失敗。\n直到2165年啟動的造陸計畫，利用喚醒海底火山的方式讓火山緩爆發，流出的熔岩接觸海洋冷卻並硬化成為新陸地。此計畫雖有成效，但在火山爆發時卻會危及四周海洋及人類，並引爆附近潛藏的火山。\n\n被喚醒火山的爆發時機難以預測，引動連爆效應所及地區廣泛，如何帶領族人登上安全的陸地與高原，來獲得延續族群的機會，就需要領袖睿智的策略與應變能力！','\n',char(10)),'https://i.postimg.cc/8kb31dww/IMG_20251015_112203.jpg','','','販售,租借,家庭',2,4,'普通',1,1,0,990,100,900,50,1,'',250,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(347,'跑跑蛙',replace('7歲以上｜20分鐘\n跳到池塘中，找到最佳路徑，消滅對手的青蛙女王。文字能讓你的青蛙更活躍。雄青蛙？女王很快就來找你啦！產下寶寶能讓你們蛙丁興旺。不過要小心池塘裡的梭魚，牠們可是狠角色！\n新版本：新增不同的板塊圖案讓玩家可以運用更多重的策略！\n\n','\n',char(10)),'https://i.postimg.cc/HWtKp03K/IMG_20251015_112209.jpg','','','販售,家庭,兒童',2,4,'簡單',1,0,1,890,100,800,50,1,'',249,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(348,'飛塔巫師',replace('成為第一個將所有巫師都聚集到烏鴉城堡的玩家，並在道路上裝填你的魔藥瓶。巫師可以在遊走的高塔外或塔頂進行移動。如果你使用會飛的塔關住其他的巫師，魔藥瓶將會神奇地裝滿。巧妙運用魔藥，並設法讓自己成為第一個將所有巫師都放入烏鴉城堡的玩家，將贏得勝利。\n\n\n\n從起始玩家開始，玩家輪流進行回合，逐一按照順時針順序進行。當輪到某人進行回合時，他視為當前玩家。在他的回合時可以執行2次行動。 第一次行動：從你的手牌中打出一張移動牌，面朝上放入棄牌堆。根據你打出卡牌進行移動。 第二次行動：你打出你的第二張移動牌，並也根據你打出的卡牌進行移動。','\n',char(10)),'https://i.postimg.cc/sfJ8VPws/IMG_20251015_112230.jpg','','','販售,家庭',2,6,'簡單',1,0,1,1200,0,0,50,0,'',246,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(349,'拼布對決: 臺灣意象',replace('遊戲適合8歲以上，2名玩家一同遊玩，遊戲時間30分鐘。\n此款可租借的品項為拼布藝術(非台灣版)\n\n台灣特別版！四周堆滿形色不同的拼布和皮革－運用這色彩繽紛的布塊製作百衲被吧！要一針一線縫出精美的被子，需要大量的時間和極度的專心，也需確保有足夠的鈕扣可以縫製。挑選最適合的拼布，並展現高超技巧的玩家，就能成為最佳的編織者！','\n',char(10)),'https://i.postimg.cc/fWvFw7Bn/LINE_ALBUM_販售區桌遊_251023_1.jpg','','','販售,輕鬆小品',2,2,'簡單',1,0,1,850,100,800,50,0,'',247,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(350,'提戈梅公會',replace('*僅供現場遊玩*\n在迷人的永恆幽谷裡面，下面是如高塔矗立的樹木枝葉，\n在蜿蜒的河流和苔癬遍布的洞穴之間，一個森林動物的文明世界正在繁衍擴張。\n從長寒地到鈴歌地，一年年過去永恆不變，但是現在，尋找新領土來建立新城市的時候到了。\n你會是一隊動物的領袖來執行這個任務。有建築物要建造，和其他角色見面，事件要處理 - 你將要面對忙碌的一年。\n你能夠在寒冬之月升起前，讓明亮的陽光照耀在你的城市上嗎？','\n',char(10)),'https://i.postimg.cc/7hJwqFK7/IMG-20260105-124143.jpg','','','僅供現場玩,策略燒腦,家庭',1,4,'困難',1,1,0,3000,150,1600,50,1,'',248,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(351,'飆速8連線',replace('以光速在街道中穿梭！\n拿起你的面板，讓電子在科技城市中馳騁，用最快的速度重現組合，並讓對手迷失在乙太網路的漩渦中吧！','\n',char(10)),'https://i.postimg.cc/5NNrjHRF/LINE_ALBUM_販售區桌遊_251023_12.jpg','','','販售,輕鬆小品',1,4,'簡單',1,0,1,750,0,0,50,1,'',266,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(352,'馭風之王',replace('在飛毯王國中，四支隊伍正準備參加一年一度由蘇丹親自舉辦的「馭風之王」競速大賽，玩家們要引導自己的團隊穿過雲層，這些雲朵由蘇丹的燈神所操控，不但如迷宮般複雜而且變幻不停！\n如果技術夠好，抓住在雲層中飛翔的燈神，便可以獲得一個願望！\n最先引導自己的飛毯平安穿過雲層，降落在圖板對面宮殿的玩家獲得遊戲勝利。\n運用你的智慧超越對手成為馭風之王！','\n',char(10)),'https://i.postimg.cc/fTTPk3rc/LINE_ALBUM_販售區桌遊_251023_14.jpg','','','販售,家庭',2,4,'普通',1,0,1,1290,0,0,50,1,'',267,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(353,'頭等艙列車',replace('頭等艙列車裡，玩家要建立的不是複雜的鐵道路線，\n也不需要設定各種貨物運送、股票投資(都是鐵路遊戲常設定之目標)等，\n玩家專注在與19世紀至20世紀最著名的歐洲長途火車「東方特快車」競爭，\n所以除了路線外，最重要的目標便是設立富麗堂皇奢華無比的列車箱，\n吸引名流富豪享受你提供的極上服務。','\n',char(10)),'https://i.postimg.cc/J462X1fZ/LINE_ALBUM_販售區桌遊_251023_16.jpg','','','販售,策略燒腦',2,4,'普通',1,0,1,1490,0,0,50,1,'',265,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(354,'天下鳴動豪華版',replace('『天下鳴動』是一款以日本戰國為背景的區域控制類型的遊戲\n不同於一般的區域控制\n『天下鳴動』的規則非常簡單，一分鐘就能學會\n但是遊戲內含絕對不簡單\n流暢而且快速的遊戲流程\n把戰爭中爾虞我詐 心機算盡的拉力\n濃縮成30分鐘的縮影','\n',char(10)),'https://i.postimg.cc/MKPFBWCy/LINE_ALBUM_販售區桌遊_251023_17.jpg','','','販售,租借,輕鬆小品,策略燒腦',2,4,'簡單',1,1,0,1180,150,1100,50,1,'',257,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(355,'木靈幻境',replace('《木林幻境》的前身是由Sato Familie開發的 《8bit MockUp》。\n在木林幻境中，你扮演一位象徵森林靈魂的樹精靈。你的目標是在星球上孕育出最美的萬物之森。\n試著創造最出色的森林來贏過對手吧！用森林板塊來拓展你的星球。每一輪，所有玩家都會拿取相同數量的板塊，並且放置在自己的星球上，某些板塊還可以讓玩家放置樹木指示物。把每個板塊放在最佳的位置，接著巧妙地放置樹木指示物，獲得高分，並贏得遊戲勝利！','\n',char(10)),'https://i.postimg.cc/sD6NWVkP/LINE_ALBUM_販售區桌遊_251023_18.jpg','','','販售,家庭,輕鬆小品',2,5,'簡單',1,1,0,690,0,0,50,1,'',260,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(356,'狂飆單車牌',replace('在激烈的登山賽事中勝出，以獲得所有動物車手都夢寐以求的豌豆蘿蔔冠軍衫！\n一局遊戲會進行 5 個輪次。每個輪次都代表了一段登山賽程。\n玩家必須率先將自己手中所有卡牌打出，以獲得一輪遊戲的勝利。如果已經有玩家將自己所有手牌打出，則其他玩家繼續進行遊戲，直到僅剩一位玩家擁有手牌為止。\n未能率先打出所有手牌的玩家仍可在一輪遊戲中獲得分數。\n在每一輪遊戲結束時，豌豆蘿蔔冠軍衫會由當前總分最多的玩家獲得。\n在最後一輪結束時，玩家們統計最終得分，總分最高的玩家將會榮獲豌豆蘿蔔冠軍衫，成為整局遊戲的勝利者！\n\n玩家也可以自由調整一局遊戲中輪次的數量與每一輪的難度，以調整遊戲時間的長短。\n玩家甚至可以模擬某個真實單車/自行車賽的路線難度進行遊戲！\n與親朋好友進行一場自行車賽吧～～～～','\n',char(10)),'https://i.postimg.cc/ZK7MNTGs/LINE_ALBUM_販售區桌遊_251023_21.jpg','','','販售,輕鬆小品',1,5,'簡單',1,0,1,450,0,0,50,1,'',261,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(357,'作弊飛蛾',replace('7歲以上｜3-5人｜15-25分鐘\n\n作弊不是禁止的嗎？\n在這款無恥的紙牌遊戲中不是！在這裡，藉由聰明地棄牌以及有技巧地作弊，你努力成為首位擺脫全部紙牌的玩家。\n這個任務其實相當簡單，如果守衛蟲不在的話⋯⋯','\n',char(10)),'https://i.postimg.cc/c49b3sp5/LINE_ALBUM_販售區桌遊_251023_22.jpg','','','販售,輕鬆小品',3,5,'簡單',1,0,1,590,0,0,50,1,'',255,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(358,'蟑螂沙拉',replace('6歲以上｜2-6人｜15分鐘\n玩家輪流打出蔬菜牌，一起製作繽紛的沙拉，越快越好。當你打出蔬菜牌時，必須說出「正確的」蔬菜名稱，但有很多的例外，只有能快速並準確地在實話和謊言中切換的玩家，才能獲勝！舌頭快要打結啦！\n若有任何錯字、結巴或遲疑，你就得吞下整盤沙拉！','\n',char(10)),'https://i.postimg.cc/c49b3sp5/LINE_ALBUM_販售區桌遊_251023_22.jpg','','','販售,輕鬆小品',2,6,'簡單',1,0,1,590,0,0,50,1,'',262,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(359,'鐵道任務:紐約篇',replace('這是鐵道任務城市系列的第一款！\n\n你可以在短時間體驗遊戲的魅力，也可以同時感受紐約的風景～\n\n\n\n讓我們一同回到60年代吧！\n\n欣賞世界第一摩天大樓帝國大廈的壯觀景色，或者去美麗的纽約中央公園遊覽盛世美景。\n\n從時代廣場一路逛到布魯克林……盡享沿途風光！','\n',char(10)),'https://i.postimg.cc/8z7nB2GK/LINE_ALBUM_販售區桌遊_251023_25.jpg','','','販售,家庭',2,4,'簡單',1,0,1,850,0,0,50,1,'',264,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(360,'金錢本色','「金錢本色(Money！)」遊戲為1999年由Reiner Knizia所設計的家庭遊戲，並獲得1999年德國年度遊戲獎項推薦。遊戲中玩家們扮演著理財專家，透過國際貨幣的交換及認購，想辦法讓自家手上的貨幣組合價值愈來愈高。遊戲將進行3個回合，各回合將進行若干輪。各輪進行時，由所有玩家們同時參與競標，並根據競標結果決定執行順序。玩家在執行行動時，可從與公區放置牌列交換、與其他玩家競標牌組交換及不進行交換等三種行動中擇一進行。各回合當卡牌堆耗盡時即告結束，玩家們根據所持有的貨幣卡計算分數。在經過3個回合後，玩家們分別加總最後所獲得的分數，分數最高者即為遊戲贏家。','https://i.postimg.cc/g2xBqCpC/LINE_ALBUM_販售區桌遊_251023_27.jpg','','','販售,輕鬆小品',2,5,'簡單',1,1,0,199,0,0,50,1,'',263,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(361,'抓月亮','登梯直入天，穿雲且攬月。你是否有一個飛天夢？在這裡需要成為一個梯子高手，再加上一點平衡感和一點想像力就能離月亮越來越近。但登月路上總有一些挫折，每當你不小心滑落梯子，月亮就會流下一滴難過的眼淚。有時候，我們需要有面對冒險的勇氣，但也請記得使用你的智慧，才能抵達月之彼岸。','https://i.postimg.cc/FHYngMmX/LINE_ALBUM_販售區桌遊_251023_28.jpg','','','販售,家庭,兒童',2,6,'簡單',1,0,1,790,0,0,50,1,'',259,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(362,'UNO馬力歐賽車版','知名經典遊戲，越玩越上癮','https://i.postimg.cc/2S1XFsm8/LINE_ALBUM_販售區桌遊_251023_30.jpg','','','販售,輕鬆小品',1,4,'簡單',1,0,1,329,0,0,50,1,'',254,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(363,'BANG!砰!',replace('歹徒獵殺警長，警長緝捕歹徒，叛徒則是正在偷偷策劃著準備對付其中一方。\n在這個子彈滿天飛的世界裡，哪一位西部槍手是準備犧牲自己保護警長的副警長？\n而誰又是冷酷無情的歹徒？\n','\n',char(10)),'https://i.postimg.cc/jSB38Mdx/LINE_ALBUM_販售區桌遊_251023_32.jpg','','','販售,陣營',4,7,'普通',1,0,1,990,0,0,50,1,'',252,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(364,'叮！ DING! ',replace('★派對救星！易攜帶、易學會、易嗨翻全場！\n★在遊戲中搶先其他人打出所有的手牌！\n★遊戲適合2-7人遊玩；8+歲以上；遊戲時長約10分鐘。','\n',char(10)),'https://i.postimg.cc/fR1qH8T0/LINE_ALBUM_販售區桌遊_251023_34.jpg','','','販售,輕鬆小品,派對',2,7,'簡單',1,0,1,450,0,0,50,1,'',256,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(365,'屁者先知',replace('玩家拿取了各種有趣的角色乘坐電梯，其中混入了屁者，他會在固定的樓層放屁！聞到屁的玩家則會受到傷害！\n當你和一群陌生人處在幽閉空間，此時有人放屁，那殺傷力足以勘比密室殺人，懸疑的程度好似暴風雪山莊，所以玩家需要在每一個樓層，提前押出行動牌來應對！\n\n更需要看清場上局勢，發起投票，淘汰屁者！\n\n \n\n每個人都滿滿參與感，一旦上手就欲罷不能，笑爛你的朋友，讓他們都多吸一點屁吧！\n人們常用『放屁』比喻『謊言』，當人群中出現屁時，謊言也隨之出現，有人栽贓陷害，有人自證清白，有人屁者先知。\n如何瞞天過海？如何清者自清？如何戳破謊言？\n一個屁就能引發一場人性的較量。當危險就在身邊，是解決危險，是解決人，或者你就是製造危險的那個人？！','\n',char(10)),'https://i.postimg.cc/Y2xVpNbq/LINE_ALBUM_販售區桌遊_251023_4.jpg','','','販售,派對,陣營',5,10,'簡單',0,0,0,590,0,0,50,0,'',258,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(366,'驚艷蘭花園','蒐集各式種子培育多樣植物，讓自己的花園成為最令人驚嘆的園藝奇景！','https://i.postimg.cc/cJY9PfrB/LINE_ALBUM_販售區桌遊_251023_40.jpg','','','販售,家庭,輕鬆小品',2,5,'簡單',0,0,0,490,0,0,50,0,'',251,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(367,'SEVEN!',replace('在找新奇好玩的遊戲嗎？Seven! 是兩位紐西蘭人發明的遊戲，在紐西蘭和澳洲大受歡迎！現在正式登陸亞洲！\n\nSeven! 是一款收集紙牌組的遊戲。玩家輪流開口向其他人要牌，對手無法拒絕。大家為了保護手中既有的紙牌，假動作不斷，以求誤導對手。這是一款在遊戲即將結束時，可能會大翻盤的刺激遊戲！\n除了七組不同類別的紙牌外，還有4張小丑牌、14張金星好牌、3張黑星壞牌和1張備用牌，讓遊戲峰迴路轉、高潮迭起。\n你能敗部復活、起死回生嗎？','\n',char(10)),'https://i.postimg.cc/s2S6b5vt/LINE_ALBUM_販售區桌遊_251023_44.jpg','','','販售,輕鬆小品',3,5,'簡單',1,0,1,490,0,0,50,1,'',253,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(368,'穿越歷史','你即將踏上為時三天的時間之旅，在時光機器中旅行，追溯數千年的歷史，體驗過去歷史上的偉大時刻。每天你都會拜訪一系列的歷史事件，在每個事件上停留數個小時，停留時間的長短將有所不同。在遊戲過程中，遵守你的行程表並按照年份順序拜訪歷史事件，這將讓你獲得分數。','https://i.postimg.cc/B60Y3tKz/LINE_ALBUM_販售區桌遊_251023_48.jpg','','','販售,家庭',2,4,'簡單',1,0,1,1400,0,0,50,1,'',275,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(369,'托爾圖加.烏龜島',replace('在《托爾圖加》中，你是一名勇猛的海盜，試圖在其他海盜玩家從你手中奪走寶藏之前，安全地將其運送到傳說中的海盜天堂托爾圖加。 玩家同時擲骰子並分配它們，以便將船隻放入水中、發射大炮、集結更多船員、近距離與敵人交戰或不斷將財寶移近安全地帶。 玩家因其適應能力和快速決策能力而受到獎勵——一點點運氣和一點貪婪也不會傷害到海盜！\n覺得你能比桌上的其他海狗更好地指揮你的船員嗎？ 如果是這樣的話，拿起短劍，在托爾圖加的滾滾海面上揚帆起航——這是一款適合2-4名海盜（8歲及以上）玩的快速家庭骰子游戲，大約需要30分鐘！ 嘿呵呵！','\n',char(10)),'https://i.postimg.cc/hjBynhdN/LINE_ALBUM_販售區桌遊_251023_49.jpg','','','販售,家庭',2,4,'普通',1,0,1,1890,0,0,50,1,'',273,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(370,'麥田圈尋寶',replace('米諾和多瑞是兩個來自克萊頓星球的厚臉皮外星人，又再一次畫著麥田怪圈，但他們的太空船不小心墜落其中。在墜落的時候，他們弄丟了十二樣特殊的物件，必須找到它們才可以回家。\n現在該你上場了！移動有磁力的外星人，讓他們在迷宮裡穿梭，幫米諾和多瑞找到需要的東西。保持密切的互動，因為通常只有一個人知道正確的道路，一起合作，你們一定能辦得到。但是動作要快！因為時間不多了......','\n',char(10)),'https://i.postimg.cc/DZTjhmGV/LINE_ALBUM_販售區桌遊_251023_50.jpg','','','販售,租借,兒童,家庭',2,4,'簡單',2,1,1,990,100,900,50,1,'',268,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(371,'埃及人:流沙',replace('陽光照射在尼羅河平靜的水面上，空氣在午後的熱浪中搖曳，法老對其最好的建築師降下旨意，要求以他名字建造壯麗輝煌的紀念碑，使其能被後世永遠銘記，令他最為滿意的建築師將得到豐厚的財富、聲望及榮譽。\n遊戲一共進行5輪，每一輪玩家將沿著尼羅河放置船隻，提升建築工人的力量，增加新的田地或採石場，獲得尼羅河和獅身人面像卡牌，玩家在遊戲過程建造柱廊、方尖碑、金字塔以及雕像，最終分數最多的玩家贏得遊戲。','\n',char(10)),'https://i.postimg.cc/wvpfz3Np/LINE_ALBUM_販售區桌遊_251023_53.jpg','','','販售,策略燒腦',2,4,'困難',1,0,1,1700,0,0,50,1,'',270,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(372,'泛亞天鵝數字牌經典版',replace('天天鵝一家人首次來到肥沃的蘭陽平原拜訪大姑媽，發現這裡不只蔬菜水果香脆可口，連土壤裡的蟲蟲都個個肥滋滋。\n飽餐之餘，天天鵝多麼希望永遠都能過著這種天堂般的生活，白日夢還盤旋在腦中，大姑媽就看出了他的心思，便說：「我們來做個小比賽，如果你可以先將手上的蟲蟲，在院子裡排成一隊一隊，就可以搬來這裏住！\n蟲蟲有四種顏色，長度從1到13，每隊至少要有3條蟲，顏色一樣的蟲排成一隊就要長短不同並且是連號，長度一樣的蟲排在一起就要每條蟲的顏色不同。」\n到底天天鵝能否贏過大姑媽，並移居蟲肥果香的蘭陽天堂呢？','\n',char(10)),'https://i.postimg.cc/DZTjhmGv/LINE_ALBUM_販售區桌遊_251023_54.jpg','','','販售,家庭,策略燒腦',2,4,'普通',1,0,1,790,0,0,50,1,'',274,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(373,'底比斯的遠方','玩家是環遊歐洲的考古學家，為了挖掘古物而學習各種知識。在助手的協助下，玩家們整裝往埃及、克里特島（位於希臘）、美索不達米亞等地挖掘各式各樣的古物。這些古物不但能夠為玩家贏得名譽，也能夠帶來獲勝所需的分數。能夠拜訪考古協會或是舉辦展覽會的玩家也能夠獲得名聲與分數。當然，玩家必須妥善規劃有限的時間規劃挖掘工作與展覽會，才能夠得到最高分以贏得這場考古競賽！','https://i.postimg.cc/Tw67xhbP/LINE_ALBUM_販售區桌遊_251023_55.jpg','','','販售,租借,策略燒腦,家庭',2,4,'普通',1,1,0,1700,200,1700,50,1,'',271,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(374,'仙丹妙搖',replace('在混亂中『搖出』秩序的大挑戰！\n\n搖動你的燒瓶，混合五種不同的成分，製作難度破表的仙丹妙藥！小心，你的對手也在緊鑼密鼓地煉丹中。你能完成這個絕世配方嗎？隨時調整你搖晃燒瓶的角度，好讓仙丹現世！\n\n這款老少咸宜的遊戲在任何場合都能帶來歡樂、緊張的氣氛。','\n',char(10)),'https://i.postimg.cc/rmknTz4s/LINE_ALBUM_販售區桌遊_251023_56.jpg','','','販售,派對,家庭,輕鬆小品,兒童',2,4,'簡單',1,0,1,1160,0,0,50,1,'',269,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(375,'紐約1901',replace('為紐約進行都市更新，開啟下一階段的輝煌歷史。\n在曼哈頓下城區一些最具標誌性街道上建設更高更大的摩天大樓。\n建造出四大傳奇摩天大樓之一：公園街大樓、勝家大樓、曼哈頓人壽保險大樓、伍爾沃斯大樓，使其成為你房地產帝國王冠上一顆璀璨的寶石。','\n',char(10)),'https://i.postimg.cc/Pxj3HNDx/LINE_ALBUM_販售區桌遊_251023_57.jpg','','','販售,家庭,策略燒腦',2,4,'普通',1,0,1,1490,0,0,50,1,'',278,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(376,'魔幻森林',replace('你能引導主角走上正確的道路嗎？\n在四則精彩的故事中，你必須快速又睿智，在森林中開創一條突破萬難、邁向成功的道路。\n小紅帽能逃離大野狼的魔掌嗎？羅賓漢會打敗萬惡諾丁漢警長嗎？亞瑟王能夠拔出石中劍，創造不列顛的黃金時代嗎？德古拉伯爵的陰謀會被拆穿嗎？\n透過20張豐富無比的故事板來探索經典童話與傳奇，發揮空間邏輯，巧妙安排樹叢與道路，運用睿智的策略帶領主角趨吉避兇、完成目標，讓他們從此過著幸福快樂的生活！','\n',char(10)),'https://i.postimg.cc/sDDL1BN3/LINE_ALBUM_販售區桌遊_251023_7.jpg','','','販售,家庭,兒童',2,4,'簡單',1,0,1,1390,0,0,50,1,'',272,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(377,'神奈川學院','《神奈川學院》是一款策略卡牌遊戲，玩家在遊戲中扮演畫家，努力在神奈川學院裡學習繪畫技法，並創作出最出色的作品。玩家需透過選擇畫布卡片，來擴充自己的畫室並完成畫作，創作出富有美感的畫卷。遊戲富有策略性且充滿藝術氛圍。','https://i.postimg.cc/xTTZqk4T/LINE_ALBUM_販售區桌遊_251023_8.jpg','','','販售,家庭',2,4,'普通',1,0,1,750,0,0,50,1,'',277,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(378,'水啦',replace('溝通是拯救人類的關鍵！ 水啦！ 是一款派對遊戲，安美特藍教授是一個有點瘋狂的科學家，他開發了一個實驗，用來提升彼此相互了解的能力;\n\n\n\n他的門徒必將兩張照片連結起來，翻譯成一個單一概念的字詞，且必須讓其他人理解。 你可以成為教授最傑出的門徒嗎？YESSS！\n\n','\n',char(10)),'https://i.postimg.cc/HssNjJhk/LINE_ALBUM_販售區桌遊_251023_9.jpg','','','販售,家庭,派對,輕鬆小品',2,7,'簡單',1,0,1,490,0,0,50,0,'',276,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(379,'嗒寶航海王',replace('★嗒寶最新合作IP－【航海王】！\n在航海王版中，除了魯夫、索隆、娜美、喬巴等草帽一行人，還會看到超酷的經典元素──橡膠果實、千陽號、歷史本文！每張卡上都有草帽一夥與偉大航道上的冒險元素，找出重複出現的圖案並喊出他的名字！簡單到連拉布都會玩~','\n',char(10)),'https://i.postimg.cc/fR5gMSrM/192ff348_e3ab_498e_85c6_cac508701278.jpg','','','販售,家庭,兒童,輕鬆小品',2,8,'簡單',0,0,0,500,0,0,50,0,'',281,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(380,'嗒寶多啦A夢版',replace('大家最熟悉的好朋友們與各式各樣的祕密道具，都變成嗒寶上可愛的圖樣囉～\n任意兩張牌上都會有剛好一個圖案重複出現，你需要在其他玩家找出來前喊出圖案的名字，然後就可以替換卡片，尋找下一組相同的圖案！\n在哆啦Ａ夢版中，我們會看到各個經典人物──哆啦Ａ夢、大雄、靜香、胖虎、小夫等好朋友，也會看到千奇百怪的祕密道具──任意門、竹蜻蜓、記憶麵包….甚至還有空地的水泥水管？！','\n',char(10)),'https://i.postimg.cc/K8Qsm3H8/30241c49_9454_47ef_90d0_54e5c468d2bb.jpg','','','販售,家庭,兒童,輕鬆小品',2,8,'簡單',1,0,1,500,0,0,50,1,'',280,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(381,'御木屋',replace('御木屋──藝伎之家，為了得到天皇的恩寵，你必須讓旗下的藝伎在花園裡排列出最動人的隊形，或是阻擋競爭對手，讓他無法加派人手！\n\n一款簡單、機智又充滿詩意的遊戲。','\n',char(10)),'https://i.postimg.cc/zGpPqHc5/1b1a3e08_e8a9_4127_b110_830e3a27c05f.jpg','','','販售,輕鬆小品',2,2,'簡單',1,0,1,590,0,0,50,1,'',282,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(382,'謝謝招待',replace('在這座燈火通明、不夜城般的城市中，你與朋友們相約在一家深夜小食堂聚餐，為了慶祝重逢，大家決定大快朵頤、暢飲一番。\n但單純吃飯怎麼會有趣呢？於是，你們決定要來場「飯局遊戲」。究竟誰能巧妙規避買單，讓別人請客，笑著吃到最後？','\n',char(10)),'https://i.postimg.cc/Hk3PT8hp/d0bce4d8_0a3a_44fc_9ecb_4a739ed310d8.jpg','','','販售,輕鬆小品',2,5,'簡單',1,0,1,490,0,0,50,1,'',279,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(383,'海底探險',replace('一群貪心的探險家共乘一艘老舊潛水艇，一起前往深海尋找寶藏。穿上潛水服，搭配全新的「加速裝置」，他們滿心期待地展開這趟冒險。然而，這艘破舊潛水艇只有一個供大家共用的氧氣瓶。只要有一位探險家太過貪婪，就可能讓全員陷入危險之中！\n\n探險家們究竟能否在寶藏與生命之間取得平衡，平安返回潛水艇呢？','\n',char(10)),'https://i.postimg.cc/nzBgvSh8/IMG_20260326_150632.jpg','','','租借,輕鬆小品',2,6,'簡單',1,1,0,750,100,700,50,1,'',284,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(384,'待宵之花',replace('*此遊戲僅供現場玩*\n身為滿是魔物的酒館老闆，邀請一位魔物娘作為你的夜店之花。在滿是各種各樣的魔物們的環境，完美的應對可是會有不錯的豐厚報酬。\n但VIP顧客實在是給的太多了！😨要盡可能滿足他們獲取鉅額的好處💰\n隨著不斷招待客人，你的手下魔物娘的專業技能也會變得越來越熟練，但也可以將壓力轉為怪癖，調教的好說不定反而是種益處。為了盡力俘獲這些癖好古怪的客人們，你必須大展手腳、妥善運用資源，招攬服務生，盡可能滿足客人需求，成為這城市的頭號夜店吧！','\n',char(10)),'https://i.postimg.cc/BnDp2j1j/IMG-20260105-115736.jpg','','','僅供現場玩,策略燒腦',1,4,'困難',1,0,1,3380,0,0,50,1,'',287,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(385,'沙丘魔堡: 帝國+擴充',replace('*此遊戲僅供現場玩*\n沙丘行星厄拉科斯，無數人想要在這廣大的荒原上舉起自己的旗幟。當蘭茲拉德中的各大氏族都在這裡集結兵力、派出間諜時，你會選擇何人成為盟友？\n又會偷偷背叛何人—殘暴的皇帝、隱秘的女修會、唯利是圖的宇航公會，還是在沙漠中堅韌的弗瑞曼人？帝國中最強大的力量正等待你擷取，但要記著，戰爭並不是獲得力量的唯一途徑。\n\n《沙丘帝國》成功將牌庫構築與工人放置兩大機制有機結合，不但提供具深度的全新策略遊戲體驗，也讓玩家能親手決定帝國的命運。\n是要通過外交手段還是要使用武力征服？要發展經濟，還是要密謀取勝？\n議會的席位與暗影中的尖刀，有時能出人意料地達到目的。\n卡牌已全面揭露，選擇權在你手中，帝國正拭目以待！','\n',char(10)),'https://i.postimg.cc/J4KP1sBH/IMG_20260105_122823.jpg','','','僅供現場玩,策略燒腦',1,4,'困難',1,1,0,3500,300,3500,50,1,'',290,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(386,'戰鬥吧!表情包!',replace('*僅供店內現場遊玩使用*\n是一款以表情包為主題的輕鬆搞笑快節奏桌遊，\n設計者的腦洞大概有半人馬星座那麼大，遊戲簡單到不需\n要兩分鐘就可以上手的桌遊，開局每位玩家三張手牌，然\n後由第一位玩家開始執行按“摸牌-出牌-執行卡牌效果\n再輪到下一位玩家開始','\n',char(10)),'https://i.postimg.cc/gk14wVrx/IMG-20260105-115726.jpg','','','僅供現場玩,派對,輕鬆小品',2,15,'簡單',1,1,0,840,0,0,50,1,'',289,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(387,'海鹽折紙 (Sea Salt & Paper)',replace('緊張刺激的小品遊戲!!小小規則有大大樂趣，另有擴充可以購買哦!\n在你的回合中，你會組合你的手牌，也許放置卡片發揮效果，然後決定是否要結束這一輪。\n但你認為你手中的分數最高嗎？ 你必須做出選擇：立即結束這一輪還是讓其他人多一次機會試圖拉大差距？\n冒這個風險值得嗎？ 當你達到30/35/40分（4/3/2名玩家）時，遊戲結束。\n結束回合時讓對手措手不及的刺激感\n使用效果卡片進行組合的樂趣','\n',char(10)),'https://i.postimg.cc/qMWQtsgr/IMG-20260105-115645.jpg','','','販售,輕鬆小品',2,4,'簡單',2,0,2,550,0,0,50,1,'',291,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(388,'Shadows over Camelot (圓桌武士)',replace('*僅供店內遊玩使用*\n卡美洛的暗影 (圓桌武士) 是一款融合了心機的特殊合作型遊戲！身為一名圓桌武士，你必需和遊戲設定對抗並保護嘉美洛。\n\n你的勝利決定於傳奇任務的達成率，像是尋找神劍、聖杯、或是藍斯洛的鎧甲；和黑武士的馬上競技；以及無數對抗薩克遜人和野蠻人的戰爭。\n\n但是，你要小心，並不是所有的騎士都像他表面那樣高尚，你們中間很有可能有一個人會倒戈成為叛徒，正慢慢布下陷阱並等待著最佳的出手時機，他要幫助黑暗的勢力降臨大地。\n\n\n\n這遊戲是以亞瑟王的圓桌武士為背景，卡米洛將面對不同的威脅，七位圓桌武士為保衛卡米洛而戰。他們要面對黑騎士、惡龍的挑戰、蠻族皮克特人Pict和撒克遜人Saxon的入侵，更甚的是他們之中可能有背叛者！\n這個遊戲是一個合作的遊戲。真心保衛卡米洛的騎士，必須趕赴各地處理不同的危機，尋回聖杯、獲取聖劍、擊敗蘭斯洛、打敗黑騎士、抵抗皮克特人Pict和撒克遜人Saxon的入侵。背叛者則需裝模作樣，不盡全力之餘還可落井下石。但圓桌武士中是否真的有背叛者，也是個未知之數。\n這是個卡牌搜集遊戲。圓桌武士逗留在卡米洛，即可補充卡牌。當集齊卡牌组合後，即可前往面對挑戰。部份挑戰只容一名騎士擔當，部份挑戰則可容多名騎士協力完成。克服挑戰，玩家們即獲白色的劍；任務失敗，則獲黑色的劍。\n遊戲期間，卡米洛的形勢可能會不斷惡化。騎士們必須小心穩定卡米洛的形勢，才分出人手完成任務。否則卡米洛一旦淪陷，各人即作失敗論，獨背叛者一人勝出遊戲。卡米洛幸存下來，遊戲完結時，圓桌上的白色的劍多於黑劍時，各玩家一同勝出遊戲，否則落敗。當然背叛者例外。','\n',char(10)),'https://i.postimg.cc/FswGfy19/IMG-20260105-115302.jpg','','','僅供現場玩,陣營,策略燒腦',3,7,'普通',1,0,1,2400,0,0,50,1,'',283,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(389,'瘟疫危機：浪潮洶湧',replace('*僅供現場遊玩*\n知名遊戲瘟疫危機的潮水版!! \n現在是荷蘭工業時代的開始，幾個世紀以來，\n這個國家都仰賴一系列的堤防和風力驅動的幫浦，\n來抵禦北海長期的淹水危機，但是現在光靠這套系統已經不夠了。\n            \n在Pandemic: Rising Tide裡面，\n你的目標就是在戰略要地建造四座現在化的水力設施，\n來防止這個國家被海水淹沒的悲劇發生。\n風暴即將來臨，而潮水永不止息。\n你要花費全副精力控制水流來保障荷蘭的未來。\n是時候開始工作了。\n             \n控制威脅肆虐這個國家的水流是你最大的挑戰。\n區域的水位由方塊表示，\n當某地的水流控制系統開始失靈，\n就要增加更多水方塊到圖板上。\n當水位持續上升，\n無法維持控制系統會導致更多水溢入圖板。\n           \n要成功建造四座水力設施來獲勝的話，\n你必須先預測並利用水流。\n無法在這個國家維持安全水位會讓你陷入任務失敗的危機。\n幸運的是，水流可以被戰略放置的堤防或幫浦慢慢抽走。\n正確辨識並且干預危險區域會讓你離勝利更進一步。','\n',char(10)),'https://i.postimg.cc/vH43HqYS/IMG-20260105-115250.jpg','','','僅供現場玩,策略燒腦,合作闖關',2,5,'困難',1,0,1,2400,0,0,50,1,'',292,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(390,'萊柏特利亞海盜(LIBERTALIA)',replace('乘風起航！開始冒險、尋找寶藏和榮耀！\n玩家將指揮眾多船員，然而你的對手也是！\n每天船艦將停靠不同島嶼，玩家要派遣船員收集戰利品，\n用以不斷壯大自己的勢力！','\n',char(10)),'https://i.postimg.cc/hPXpPyDp/IMG-20260105-115236.jpg','','','僅供現場玩,策略燒腦,派對',2,6,'普通',1,0,1,2000,0,0,50,1,'',293,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(391,'城邦開拓',replace('蒐集!扣牌!小小的盒子確有大大的策略在\n比想像更豐富的遊戲內容\n玩家扮演古希臘人擴大自身領域範圍。航行到伊比利亞半島建立永久交易點。同時，還要交易物品，探索新區域，各式各樣的事情等著你去完成~','\n',char(10)),'https://i.postimg.cc/BQjMQYS2/IMG-20260105-115226.jpg','','','租借,家庭,策略燒腦',2,4,'普通',1,1,0,950,100,900,50,1,'',285,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(392,'炸彈狂魔',replace('《炸彈狂魔 Catch the Bomber》是一款隱藏陣營對抗遊戲，玩家將分為兩大陣營：「炸彈客」與「警察」。\n\n炸彈客的勝利條件（達成任一條件即可獲勝）：\n\n引爆炸彈，造成平民傷亡。\n\n成功逃出城市。\n\n限制市民行動，擾亂經濟運作。\n\n警察的目標：\n\n找出炸彈客的真實身份，並在其得逞前加以阻止！\n\n遊戲機制\n\n輪流行動：玩家在回合中選擇「移動」或「出牌」來執行計畫。\n\n隱藏資訊：炸彈客的身份秘密，警察必須靠觀察與推理來揪出可疑分子。\n\n最後一刻揭曉勝負：遊戲結束時，若炸彈客仍未被抓住，則需確認所有條件是否達成，才能決定最終勝者！\n\n這是一場刺激的心理博弈，你是潛伏於城市中的危險份子，還是維護和平的守護者？ ','\n',char(10)),'https://i.postimg.cc/sDKwVMZW/IMG_20260105_122828.jpg','','','租借,陣營,輕鬆小品',2,5,'簡單',1,1,0,640,100,600,50,1,'',294,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(393,'重塑火星.殖民火星',replace('*僅供現場遊玩使用*\n人類已經開始擴展到太陽系。在火星上已經建立了少數殖民地。\n這些殖民地提供了環境防護，因為這顆星球是如此的酷寒與乾燥，幾乎沒有大氣層。\n為了要增加地球的移民，火星需要地球化來改變環境，\n直到人類可以在那裏生存而不需要昂貴的防護裝備，\n並且不會因為小小的意外而演變成致命危機。\n因此世界政府已經決定支持任何參與這項龐大工程的組織。\n優渥的資金吸引了競相擴展事業的龐大企業，\n並且演變成地球化幕後最具影響力的力量。','\n',char(10)),'https://i.postimg.cc/qMNjMbJ8/IMG-20260105-115216.jpg','','','僅供現場玩,策略燒腦',2,5,'困難',1,1,0,2480,0,0,50,1,'',295,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(394,'大白鯊',replace('*僅供現場遊玩*\n在大白鯊(JAWS)中，一位玩家扮演艾米蒂島的食人鯊，\n其他1~3位玩家則分別擔任警長布羅迪、海洋生物學家胡伯與鯊魚獵手昆特，要合力獵殺鯊魚。\n\n角色卡與事件卡在遊戲中會提供玩家能力，並提供人鯊兩方執行行動。\n\n遊戲分為兩幕場景 - 艾米蒂島和虎鯨號 - ，分別使用雙面圖板的其中一面來遊玩，重現電影的情節：\n\n在第一幕艾米蒂島中，鯊魚要盡量獵食游客並避免被發現，其他玩家則要設法標記鯊魚的位置並從鯊口中拯救游客。\n在第二幕虎鯨號中，使用圖板的另一面遊玩。布羅迪、胡伯和昆特要登上漁船與大白鯊展開如電影一般的對決，使用額外的行動與策略卡來防衛虎鯨號，避免鯊魚破壞。\n若人類殺死鯊魚，人類獲勝；若鯊魚成功破壞虎鯨號，則為大白鯊獲勝。','\n',char(10)),'https://i.postimg.cc/fytg3Dnh/IMG-20260105-115039.jpg','','','僅供現場遊玩,陣營,合作闖關',2,4,'普通',1,1,0,1600,200,1600,50,1,'',286,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(395,'瘟疫危機',replace('遊戲適合8歲以上，2-4名玩家一同遊玩，遊戲時間45分鐘。\n這是以全球症疫爆發作為題材的遊戲。全球多處區域爆發出大規模的感染，感染者迅速出現病徵。每位玩家在團隊中都扮演著重要的角色，必須有效的制定策略，各自發揮自己的長處，以消滅病毒。\n','\n',char(10)),'https://i.postimg.cc/CKzTWfD9/IMG_20260106_192828.jpg','','','販售,家庭,策略燒腦',2,4,'普通',1,1,0,1450,0,0,50,1,'',308,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(396,'開心滑水梯樂園',replace('開心滑水梯樂園中，換上泳裝的玩家在滑水梯上滑動，努力成為最佳滑水梯員！\n遊戲人數：2-6人\n適合年齡：7+\n遊戲時間：15分鐘左右\n在回合中，延長你的滑水梯，嘗試進行連續行動。拼出最長滑水梯的玩家勝出。\n開心滑水梯樂園是一個節奏明快，規則簡單的闔家歡遊戲。\n與朋友一起盡情享受世上最長，最蜿蜒曲折的滑水梯所帶來的歡樂派對吧！\n ','\n',char(10)),'https://i.postimg.cc/jjm0Kd4Y/IMG_20260106_192945.jpg','','','販售,家庭,兒童',2,6,'簡單',1,0,1,850,0,0,50,1,'',288,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(397,'瘟疫危機:魔獸世界-巫妖王之怒',replace('★當瘟疫危機系統碰上巫妖王\n★合作扮演英雄討伐巫妖王\n★電玩遊戲史上最大IP合作《魔獸世界》\n★遊戲適合14歲以上，1至5名玩家一同遊玩，遊戲時間45分鐘','\n',char(10)),'https://i.postimg.cc/Zq2tZKF7/IMG_20260106_192934.jpg','','','販售,租借,家庭,策略燒腦',1,5,'普通',1,1,0,2100,250,2000,50,1,'',309,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(398,'超級無敵幸運星',replace('這是一款極度趣味且好玩的遊戲！\n一張一張地翻開數字卡並劃掉你的卡片上相應的數字，以獲得三連勝來解鎖獎勵，這獎勵有助於劃掉更多的數字，甚至是獲得更高的獎勵，同時也會大大提高你的分數。\n快來加入遊戲吧，「超級無敵幸運星」讓你永不嫌無聊。\n獲勝需要一點策略和超級的運氣哦！','\n',char(10)),'https://i.postimg.cc/zf6Z5XFV/IMG_20260106_193001.jpg','','','販售,家庭',1,6,'簡單',0,0,0,680,0,0,50,0,'',311,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(399,'搖擺快找王',replace('遊戲人數：2人以上\n遊戲年齡：4歲以上\n遊戲時間：5分鐘~10分鐘\n搖擺快找王？一款在巨型搖搖柱上的超有趣捉迷藏遊戲！','\n',char(10)),'https://i.postimg.cc/gkVYDRqz/IMG_20260106_193015.jpg','','','販售,家庭,兒童',2,99,'簡單',1,0,1,690,0,0,50,1,'',303,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(400,'彩球瘋爆',replace('8歲以上｜1-4人｜30分鐘\n選擇一張彩球牌，將牌上所示的彩球，直向或橫向滾入自己的球盤。\n若有三顆或更多同色的彩球相鄰，立即爆炸並得分。\n在進階規則中，若同一回合內有多組彩球爆炸，還能獲得額外獎勵！\n您能超前部署讓每回合都連環爆炸並搶得高分嗎？\n一旦彩球牌庫用完，遊戲立刻結束，您會是總分最高的彩球爆爆王嗎？！','\n',char(10)),'https://i.postimg.cc/rF18JWCs/IMG_20260106_193025.jpg','','','販售,家庭',1,4,'簡單',1,0,1,890,0,0,50,1,'',302,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(401,'問非所答',replace('遊戲人數：3-8人\n遊戲時間：依照遊玩人數而定\n適合年齡：10+\n🤪跟朋友聚在一起，\n最危險的時刻往往出現在你沒心理準備的瞬間：\n桌面突然翻出一個超詭異的題目卡，\n下一秒大家開始丟出各種離奇答案，\n整桌就像是社會的大染缸。','\n',char(10)),'https://i.postimg.cc/c4yxwTYv/IMG_20260106_193052.jpg','','','租借,派對',3,8,'簡單',2,2,0,790,100,700,50,1,'',300,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(402,'喵電感應',replace('遊戲人數：3-6人\n遊戲時間：依遊玩人數而定\n適合年齡：12+\n多人聚會必備！需要大家喵感最強的時刻～～～\n透過正確猜中詞語及用特定數量的線索詞讓其他玩家成功猜中自己的詞語，成為得分最高的玩家。\n遊戲中每個人都會輪流出題，盡可能在限定數量的提示中讓其他人猜對你的詞語。\n但是！如果你不小心想太久，或是提供的關鍵詞沒有關聯，詛咒貓貓可能就會拜訪你～遊戲結束時會扣分唷！\n抓住關鍵時機，找到正確的詞語，遊戲時間可以自由決定，最適合多人出遊或聚會時遊玩～～～','\n',char(10)),'https://i.postimg.cc/bNxzTbHJ/IMG_20260106_193101.jpg','','','販售,派對',2,6,'簡單',1,0,1,550,0,0,50,1,'',301,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(403,'爆炸貓 狂歡派對包',replace('遊戲人數：2-10人\n遊戲時間：15分鐘\n適合年齡：7歲以上\n遊戲介紹\n最新版的爆炸貓來囉！\n多達120張牌，是原本的兩倍！\n遊戲人數增加到10人\n帶給你更多的歡樂！\n','\n',char(10)),'https://i.postimg.cc/zGpqmrQY/IMG_20260106_193113.jpg','','','販售,派對',2,10,'簡單',0,0,0,950,0,0,50,1,'',306,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(404,'叮！ DING! CNT',replace('★派對救星！易攜帶、易學會、易嗨翻全場！\n★在遊戲中搶先其他人打出所有的手牌！\n★遊戲適合2-7人遊玩；8+歲以上；遊戲時長約10分鐘。','\n',char(10)),'https://i.postimg.cc/mrDBBnxM/IMG_20260106_193122.jpg','','','販售,派對',2,7,'簡單',1,1,0,450,0,0,50,1,'',298,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(405,'咒咒咒!',replace('10歲以上｜1-5人｜15分鐘\n所有玩家被困在一座受到詛咒、滿是鬼怪的豪宅裡，你們翻開的每張牌，不是鬼怪就是聖物：在鬼怪進行襲擊之前，使用聖物來驅趕牠們。\n所有玩家必須相互協調並合作出牌，以確保你們能平安地渡過這個夜晚！','\n',char(10)),'https://i.postimg.cc/T186jYKr/IMG_20260106_193129.jpg','','','販售,租借,家庭,合作闖關',1,5,'簡單',2,1,1,390,50,300,50,1,'',299,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(406,'爆炸貓旅行版',replace('★小小一盒，大大爆炸！\n★原汁原味保留爆炸貓傳統，魅力不減更加快速！\n★遊戲適合7歲以上，2-4名玩家一同遊玩，遊戲時間10分鐘。','\n',char(10)),'https://i.postimg.cc/j2zrM0f8/IMG_20260106_193135.jpg','','','販售,派對',2,4,'簡單',0,0,0,390,0,0,50,1,'',307,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(407,'利曼24小時耐力賽 ',replace('機會與風險並存!\n在6輪激烈的比賽中，玩家們通過抽牌和打牌來獲取分數。\n這些分數代表你在比賽中的領先位置。\n如果你選擇抽一張牌，那麼你就必須從手中打出一張牌。\n留意你的引擎!\n如果你在一輪中得到了3個或者更多過熱點，你就會觸發引擎過熱，並且在這一輪得分為0。\n有時進站維修是更好的選擇!\n進站會使你失去所有過熱點。儘管你的分數會降為0，你仍然可以在這一輪結束前重新獲得一些分數。\n這是一場24小時的耐力賽!\n在能夠維持引擎運行到終點的玩家中，總分最高的玩家獲勝。','\n',char(10)),'https://i.postimg.cc/ryWcVWHh/IMG_20260106_193141.jpg','','','販售,輕鬆小品',2,5,'簡單',1,0,1,450,0,0,50,1,'',297,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(408,'全軍出雞',replace('遊戲人數：2~4人\n遊戲年齡：8歲以上\n遊戲時間：20分鐘~30分鐘\n上阿！小雞們！！咕咕戰爭開戰囉 — 全軍出雞\n《全軍出雞》是一款輕快的卡牌疊放戰鬥遊戲！組織你的雞戰士或是雞法師往前衝吧！這些好笑的雞看起來超有趣的啦。\n你即將化身為雞群領袖，將帶領著小雞集結成軍，在永無止境的戰鬥中與其他玩家勢力交鋒，這就是《全軍出雞》啊！\n超簡單的規則，只要輪到你，從中間牌堆，選擇一張回去疊放你的牌，放你的牌盡可能連在一起吧，這樣就可以帶著你的小雞去攻擊敵人啦！\n簡單的玩法，卻讓大人們歡樂不斷，小朋友更是輕鬆上手！預計七歲左右就可以一起同樂啦。\n玩熟悉後還可使用變體規則，『各有千雞』規則以及『絕地翻雞』規則讓你的咕咕大亂鬥更加混亂拉！','\n',char(10)),'https://i.postimg.cc/HkWC9NLs/IMG_20260106_193154.jpg','','','販售,家庭,輕鬆小品',2,4,'簡單',0,0,0,450,0,0,50,0,'',296,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(409,'角力棋旅行版',replace('遊戲適合7歲以上，2名玩家一同遊玩，遊戲時間20分鐘。\n一款鬥智鬥心的腦力激盪桌遊，是聰慧的你絕不可錯過的！\n你必須運用你的智慧，在六個方向中，洞察對手的下一步並且提早防範。\n在緊張刺激中，培養你的觀察力及思考力。\n此款桌遊簡約且時尚的設計，讓你方便攜帶，不管是戶外出遊，還是居家玩樂，都可一起同歡。','\n',char(10)),'https://i.postimg.cc/8zygKbFv/IMG_20260106_193202.jpg','','','販售,輕鬆小品',2,2,'簡單',1,0,1,450,0,0,50,1,'',310,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(410,'無限手套：情書系列遊戲',replace('適合１０歲以上，２-６人遊玩，遊戲時間２０分鐘。\n整個宇宙都在你的掌握之中！\n在這場充滿冒險和推理的快速紙牌遊戲中，為全宇宙的命運而戰！扮演薩諾斯\n尋找無限寶石，或扮演英雄奮力阻止他。你能幫忙扭轉戰局嗎？','\n',char(10)),'https://i.postimg.cc/CxvpP4Zb/IMG_20260106_193207.jpg','','','販售,輕鬆小品',2,6,'簡單',1,0,1,500,0,0,50,1,'',305,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(411,'星際大戰：賈霸的宮殿 情書系列',replace('★遊戲適合10歲以上，2至6名玩家一同遊玩，遊戲時間20分鐘\n★以星際大戰為背景的紙牌遊戲情書\n★保留了原版有趣的機制，還可用《星際大戰六部曲：絕地大反攻》中標誌性人物的才能\n★加入了目標卡效果，讓玩家獲勝的方式豐富化\n★遊戲適合10歲以上，2至6名玩家一同遊玩，遊戲時間20分鐘','\n',char(10)),'https://i.postimg.cc/43mkrht1/IMG_20260106_193217.jpg','','','販售,輕鬆小品',2,6,'簡單',1,0,1,500,0,0,50,1,'',304,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(412,'貨運帝國',replace('#只有一個行動，學規則比泡麵還快！#\n長久以來，桌遊玩家揪團時都得面對一個巨大的問題--「蛤，太麻煩我不想玩」。\n「難教」、「難學」和「很久」總是阻擋在開團的道路上。\n但《貨運帝國》 克服了以往的種種障礙，清晰易懂的規則加上明快的遊戲節奏，無論新手老手都能快速學會，體驗策略遊戲的樂趣！ \n\n#選擇你的家族，一同走向勝利#\n在遊戲中，你所化身的家族領袖不只承襲前作伊塔利亞系列的背景設定，還各自擁有不同的特殊能力，找出和你最搭的那位，共同奪取天下！','\n',char(10)),'https://i.postimg.cc/ht2mMhV5/IMG_20260106_202039.jpg','','','租借,家庭,策略燒腦',1,4,'簡單',1,1,0,1290,150,1200,50,1,'',312,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(413,'南美高原',replace('安地斯山脈東西側之間橫跨著一片高原，\n這片南美高原上的居民需要運用智慧才能利用這裡稀疏的植被和有限資源進行生產生活。\n這裡的居民努力從的的喀喀湖裡打魚，開採礦物，飼養羊駝，\n用這些資源換取其他貨物，慢慢富足了起來。\n人們建造起了新的生產設施、完成各類訂單、儲藏貨物以備災荒。\n同時，他們也不能忽視道路的建設，因為這是加速發展的關鍵。\n只有最有能力的居民才能最終贏來大豐收！','\n',char(10)),'https://i.postimg.cc/GpNywNgw/IMG_20260106_202332.jpg','','','租借,策略燒腦,家庭',2,5,'普通',1,1,0,1780,200,1700,50,1,'',313,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(414,'法老密碼',replace('遊戲人數：2-5人\n遊戲時間：20-30分鐘\n適合年齡：6歲以上\n一款老少咸宜的數學腦筋急轉彎遊戲，玩家扮演進入法老密室的考古學家，發現骰子與石碑數字的關聯。玩家可以運用任何所知的數學運算方法，加減乘除甚至平方開根號，來破解法老石碑上的秘密。\n當你靠自己的力量解出一次謎題時，你會發現，原來數學沒想像中那麼可怕！','\n',char(10)),'https://i.postimg.cc/RhxJqtz6/IMG_20260106_202509.jpg','','','租借,家庭,兒童',2,5,'簡單',1,1,0,750,100,700,50,1,'',315,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(415,'生態圈',replace('遊戲人數：2-12+人\n遊戲時間：15-30分鐘\n適合年齡：8+\n一款智者生存的生態遊戲。生態圈存在著生產者、消費者與分解者，他們之間有著密不可分的鏈結法則；身為生態圈管理者的你，必須審慎安排他們的生活區域，確保生態平衡外，並讓物種多樣性極大化─你的每一個決定都將關係到他們的未來！\n\n遊戲機制可以應用在108課綱方針中的「系統思考與解決問題」與「規劃執行與創新應變」等面向，透過遊戲訓練思考應變的靈活度，以及規劃自己能掌握的局面。','\n',char(10)),'https://i.postimg.cc/g0wxDszt/IMG_20260106_203117.jpg','','','租借,家庭,兒童',2,12,'簡單',1,1,0,490,50,400,50,1,'',317,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(416,'向日葵物語',replace('向日葵物語是一個有創意的策略遊戲，遊戲裏玩家可以創造自己的山谷。你將繪製可愛的房子，用羊群填滿牧場，在丘陵上種植向日葵，還可以開通鐵路來讓這個地方更加舒適。\n遊戲人數：2-5 遊戲時間：45-60分鐘 年齡：8+','\n',char(10)),'https://i.postimg.cc/fRvPC4Wj/IMG_20260106_202546.jpg','','','租借,家庭',2,5,'簡單',1,1,0,990,100,900,50,1,'',314,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(417,'洛可可 : 豪華版',replace('*僅供現場玩-*\n歡迎來到洛可可時代。路易十五統治法國，盛裝出席他豪華的舞會是當時的時尚巔峰，重要的名流們都穿著華麗的禮服和時髦的長外套，彼此競相展現優雅和風采。在幾個星期後，路易十五將舉辦本季度的終極大舞會，每個人都希望你能提供他們優雅的長外套、華麗的禮服，甚至提供一些款項來資助盛大的煙火表演。你很快意識到這已經不僅僅關乎你的裁縫事業，而是關乎在這個時代最負盛名的舞會上建立存在感，並有機會獲得永恆的名譽和威望。','\n',char(10)),'https://i.postimg.cc/jST9yqTC/IMG_20260106_203017.jpg','','','僅供現場玩,策略燒腦',1,5,'困難',1,0,1,5200,0,0,50,1,'',316,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(418,'阿納克遺跡',replace('探索失落的遺跡，踏上未知的冒險\nBGG高分好評 8.1 #2021年度大獎得主\n令人嚮往的探險旅程＋吸睛的漂亮美術\n完美結合了主題情境和策略度\n規則好上手又有代入感，回饋感滿分\n遊戲玩法結合了工人擺放、牌庫構築\n玩家的每個行動都將更深入阿納克\n升級裝備 擊敗怪獸探索遺跡蒐集神器','\n',char(10)),'https://i.postimg.cc/13SKVCRx/c254a307_1900_4147_aca3_9df351ccd95f.jpg','','','租借,策略燒腦,家庭',1,4,'普通',1,0,1,2200,250,2200,50,1,'',328,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(419,'斯凱島','根據每回合得分方式的改變，調整交易步調，擅用地形特性與排列方式，滿足特定得分條件，讓部落的榮耀在斯凱島上閃耀！ 適合年齡：8歲以上建議人數：2-5人遊戲時間：60分鐘','https://i.postimg.cc/3xZFXXWM/d26322f5_f097_4ab7_a602_2c141c467af8.jpg','','','租借,家庭',2,5,'普通',1,1,0,1100,150,1100,50,1,'',323,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(420,'馬可波羅',replace('▲你將扮演馬可波羅與他的快樂夥伴們一同邁向偉大的旅程！\n■從威尼斯出發後因為選擇而將各自的旅程導往不同的方向。\n■直往北京？或是繞經蘇門答臘？並於途中完成受委託的合約。\n■玩家們會面臨各種重要的決策是一場挑戰十足的旅程！','\n',char(10)),'https://i.postimg.cc/pLBJffyM/a9fbb02c_6fcc_460a_8d05_bc5a6b008b4d.jpg','','','租借,家庭,策略燒腦',2,4,'普通',1,1,0,1980,200,1900,50,1,'',318,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(421,'得分沙拉',replace('在一款遊戲中，有一種以上的得分方式並不稀奇，就算三五種也不罕見，由於這種「多路線取分」的遊戲獲勝方式太過自由，因此桌遊玩家戲稱這種機制叫做「分數沙拉」，意思就是要什麼就拿什麼，跟做份沙拉一樣。\n\n一位遊戲設計師非常故意的，不僅設計了一款「分數沙拉」機制的遊戲，還把這機制放大十幾二十倍，變成「108種得分方式」，它就是《得分沙拉Point Salad》！遊戲共108張遊戲卡牌，每張卡牌的背面各代表一種計算分數的方式，正面就是各種蔬菜，玩家可以自行選擇計分方式，並且蒐集用來計分的蔬菜。\n\n自己的沙拉盤自己夾菜，每局都是獨一無二的設計！','\n',char(10)),'https://i.postimg.cc/dVF9ZHsp/71cbf6a2_be71_4e95_8584_b83abe7e5401.jpg','','','租借,家庭,輕鬆小品',2,6,'簡單',1,1,0,650,100,600,50,1,'',320,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(422,'盜夢都市',replace('盜夢都市是一款不對等陣營的桌遊，一開始會由夢主對抗其他盜夢者，夢主有強大的角色能力來一打多。\n盜夢者則是要猜測夢主的秘密在哪一層夢境，並且揭開它，才能獲得勝利，而夢主則是要保護好自己的秘密不被發現。\n到了遊戲中後期，其他玩家的手牌會漸漸強大起來，足以和夢主抗衡。但夢主金庫被開啟後，又會多了夢魘牌能力和賄賂牌來平衡不對等陣營之間的角力。\n賄賂牌的效果可以讓盜夢者玩家轉移陣營到夢主陣營，讓整個遊戲出現非常有趣的變化。','\n',char(10)),'https://i.postimg.cc/K8b53qcb/715306b7_f918_450a_86bc_62b9b9f6ce5e.jpg','','','租借,陣營',4,10,'普通',1,1,0,660,100,600,50,1,'',325,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(423,'獨家暗語','Just One是一款合作遊戲，您可以和朋友一起玩耍，發現盡可能越多越好的神秘單字。找到最好的線索來幫助您的隊友。記得要盡量想出獨一無二的單字，因為所有相同的線索都會被刪掉！','https://i.postimg.cc/bwPRSCY8/42ede3c1_e586_425c_bb41_f0eec608c728.jpg','','','租借,家庭,輕鬆小品,派對',3,7,'簡單',1,1,0,850,100,800,50,1,'',324,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(424,'輝煌的羅倫佐',replace('羅倫佐·德·麥迪奇是古今中外最具影響力的人物之一。在文藝復興時代，他不僅是義大利著名的外交官和政治家，同時也大力贊助將國家帶到極度繁榮的藝術家和詩人。在本遊戲中，玩家們將化身為佛羅倫斯最有權勢和聲望的歷史名人。\n\n \n\n12歲以上｜2-4人｜60-120分鐘\n《輝煌的羅倫佐》是一款複雜的策略遊戲，運氣在這裡派不上用場。玩家派遣家族成員到各個城市的行動格中來執行行動，家族成員的行動點數每輪都會變化，讓遊戲更具挑戰性。玩家們將征服新的領地、資助雄偉的建築、贊助冒險的投資，並供養門客以得到他們的簇擁與愛戴。如果玩家的智慧夠高、勢力夠大，便能吸引更多當代著名的有力人士，並且得到他們的一臂之力。','\n',char(10)),'https://i.postimg.cc/2SYxLcks/387de17f_f798_405b_9332_797c03c4c37c.jpg','','','租借,策略燒腦',2,4,'困難',2,2,0,1890,200,1800,50,1,'',326,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(425,'收納小能手','收納小能手這款桌遊鼓勵玩家運用創意與觀察力，透過拼湊物件完成挑戰，訓練專注力與空間思考能力。','https://i.postimg.cc/nh1G44Mb/321b04a0_9b9d_4979_aaba_9a8bd211c35b.jpg','','','租借,家庭,輕鬆小品',1,4,'簡單',1,1,0,1400,150,1400,50,1,'',322,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(426,'閱讀空氣 究極二選一',replace('閱讀空氣是日語中形容”察言觀色”的經典表達方式，字面意思為”讀空氣”，實際上是通過觀察現場氛圍或情境，推測自身言行分寸及他人需求的能力。\n\n《閱讀空氣》系列以荒誕風格和獨特玩法引起玩家關注，原作電子版在實況圈中非常紅，也很多Vtuber有遊玩剪輯。\n\n','\n',char(10)),'https://i.postimg.cc/13SKVCRs/24d9f64c_8d5b_4396_86f1_b06c94e5865d.jpg','','','租借,派對,輕鬆小品',3,8,'簡單',1,1,0,590,100,500,50,1,'',327,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(427,'BANG!砰!子彈版',replace('遊戲一開始，歹徒要謀殺警長，警長要捕殺歹徒，而叛徒在暗處秘密籌畫他的陰謀，隨時在兩方陣營中變換立場。但誰是殺人不眨眼的歹徒？你願意開第一槍嗎？要找出每個人的身份你就必須拔搶！沒錯！就是你手中的紙牌！\n在《日正當中》的烈陽下，無預警的事件讓槍手們在鬼鎮中四處逃竄尋求掩護。\n在《道奇市》裡，新槍手挑戰著老槍手，他們帶來許多新的殺人技巧和未知的科技。\n當情況越來越危急，在面對這艱苦環境時，你呼叫《一大票幫手》孤注一擲賭一把。如果這還不夠，呼叫更多槍手從他們的避難所出來吧！\n現在，警長想要用他自己的方式把事情一次解決，他將一個名字寫在一顆子彈上，這個名字就是⋯⋯砰!','\n',char(10)),'https://i.postimg.cc/QdDqK48v/14cec8d1_46b7_45c5_a256_d0e1b50feba9.jpg','','','販售,租借,陣營',3,8,'普通',1,1,0,1690,200,1700,50,1,'',319,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(428,'情書',replace('▲在風險、運氣與邏輯推演間斡旋的經典遊戲。\n■將你的情書送到安妮塔公主手上，同時攔截其他人的情書。\n■強力的卡牌有驚人的效果，但同時也讓你暴露於危險當中。','\n',char(10)),'https://i.postimg.cc/vZvtrrTj/1793daff_5e96_48ab_9acd_306e61944a70.jpg','','','租借,輕鬆小品',2,4,'簡單',1,1,0,490,50,400,50,1,'',321,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(429,'星靈王座:星靈爭霸',replace('我要成為「星靈王」！ — 星靈王座 星靈爭霸\n《星靈王座 星靈爭霸》是由台灣桌遊設計師「AG」以及台灣繪師「MING」雙強聯手合力製作的台灣原創桌遊！！\n為了爭奪「星靈王」的王座，來自四面八方的英雄齊聚於此，展開一場爭奪碎片的冒險。旅程中，他們不僅要面對其他競爭者的算計，也要承受聖地的試煉與反噬。\n唯有善用團隊力量的英雄隊伍，才能征服聖地，獲得寶石碎片的認可，最終加冕為新的星靈王。','\n',char(10)),'https://i.postimg.cc/brF9n29X/IMG_20260212_170820.jpg','','','租借,策略燒腦,輕鬆小品',3,5,'普通',1,1,0,590,100,500,50,1,'',331,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(430,'幻化魔石',replace('祭司們正在為盛大的競賽做準備。競賽的目的是重新恢復土、水、火、空氣和魔法力量的流動秩序。\n能否以最快速重整元素的秩序，並成功通過魔法眼的測試，就能勝出慶典競賽。\n‍\n一款圖形觀察眼明手快的卡牌遊戲。','\n',char(10)),'https://i.postimg.cc/2yX7WBFs/IMG_20260212_170827.jpg','','','租借,輕鬆小品',2,4,'簡單',1,1,0,490,50,400,50,1,'',330,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(431,'富饒之城2',replace('國王駕崩了，但沒有任何後裔，王國內各權貴家族為了奪取政權，使出各種陰謀、詭計⋯⋯甚至不惜用鮮血交換利益。究竟誰能帶領自己的家族，在這場戰役中脫穎而出，取得王位？\n\n1. 面朝下出牌以密謀奪位大業。\n2. 運用牌疊來保護利益或組織系列行動。\n3. 在適當的時機揭露計劃。\n4. 獲得最多的影響力以爭取政權！','\n',char(10)),'https://i.postimg.cc/brF9n2H4/IMG_20260212_170902.jpg','','','租借,策略燒腦,輕鬆小品',3,5,'普通',1,1,0,690,100,600,50,1,'',329,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(432,'矮人礦坑 礦洞逃生','金塊到手的那一刻，地面突然開始搖晃，洞穴崩塌、大水漫灌⋯⋯快！找到出口逃出礦坑！在這緊要關頭，你才發現，部落中並非所有矮人都團結一心，有些傢伙竟是敵方的臥底！如何判別敵我、帶著盡可能多的金塊離開礦坑？錯信他人，可能終將一無所獲！','https://i.postimg.cc/bY6TWKc0/IMG_20260212_170908.jpg','','','租借,家庭,陣營',2,8,'簡單',1,1,0,790,100,700,50,1,'',335,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(433,'演化論:物種起源','在遊戲中，玩家扮演物種演化的推手，培養自己的生物族群，發展各樣的性狀。玩家將在遊戲中體驗到真實的自然生態，而這個世界會是生意昂然，抑或殺機四伏？歡迎體驗適者生存的世界！','https://i.postimg.cc/PrP4j2TS/IMG_20260212_170915.jpg','','','租借,策略燒腦',2,4,'普通',1,1,0,490,50,400,50,1,'',333,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(434,'狐作非為 Outfoxed',replace('波朗特太太的派不見了！是哪個壞蛋把它偷走了呢？讓我們一起跟著偵探雞去破解這棘手的案件吧！\n你們必須在遊戲板上蒐集線索，運用線索解碼器找出嫌犯，你們必須同心協力盡速找出罪大惡極的狐狸，否則狐狸就要從出口溜走了！你能夠成功制止這個飢餓的壞蛋逃過一劫嗎？還是你會被壞蛋反將一軍呢？\n\n\n\n我們一直很喜歡推理及合作型遊戲，無庸置疑的，我們愛死了這款Outfoxed！\n\n遊戲部門巧妙地將這兩個元素融合在一起，精心設計出這款有著迷人場景、需要團隊合作的偵探推理遊戲。\n\n在你們同心協力捉拿那罪大惡極的狐狸之際，將會學到一些寶貴的技能，像是估算機率、留意細節和重要角色，並且合作以破解案件！\n讓我們一起享受破案的成就吧','\n',char(10)),'https://i.postimg.cc/vHkvHfmM/IMG_20260212_170936.jpg','','','租借,家庭,兒童',2,4,'簡單',1,1,0,980,100,900,50,1,'',334,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(435,'三步成堡 Burger Master ',replace('對很大一部份人來說，漢堡可是相當吸引人的美食，繽紛的食材與誘人的美味讓人食指大動。\n\n想要快速製作符合每個人口味的漢堡可沒這麼容易！#不然你以為那個小海綿是怎麼當上廚神的\n\n🚐速食餐車的作業台很小，你得在有限的空間裡組出訂單上的漢堡，疊上生菜加番茄，再從隔壁的盤子裡拿上肉和麵包，順序反了？沒事～翻轉一 下就行。\n\n遊戲中玩家必須將四個盤子中的食材左右交換，試著組出訂單卡上的圖案，誰能使用最少動作堆出指定的組合就能得分。','\n',char(10)),'https://i.postimg.cc/WbC7bg4r/IMG_20260212_171057.jpg','','','販售,家庭',1,6,'簡單',1,0,1,790,0,0,50,1,'',338,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(436,'消失的主角',replace('「消失的主角」是一款考驗想像力的遊戲。遊戲中，你必須畫圖，讓其他玩家看圖猜謎，但並不是要畫出「主角」讓大家猜，而是畫出主角周圍的環境、情境，讓其他人猜出你的「主角」是什麼！\n若想贏得勝利，聰明構圖和盡情猜測比做個稱職的畫家來得更重要！','\n',char(10)),'https://i.postimg.cc/DwGPW0Wg/IMG_20260212_171104.jpg','','','租借,家庭',3,6,'簡單',1,1,0,890,100,800,50,1,'',332,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(437,'雙城爭霸',replace('「雙城爭霸」是一款板塊輪抽類型的遊戲。\n每個板塊都是一個城市的一部分。\n你和你的左手邊玩家一起合作建造一個城市中心，\n同時也和你的右手邊玩家打造另一個城市中心。\n輪到你的回合時，你從手上挑選兩個板塊並把它們翻開，\n然後與你的夥伴一起合作，把你挑選的這兩個板塊分別放到你的兩個城市中。\n遊戲結束時，每個城市會依據建築的宏偉程度計分，\n你協助規劃的兩個城市中，分數較低的城市將會是你的最終分數，最終分數最高的玩家獲勝。\n為了獲勝，你對兩個城市之間的關注以及投入程度必須均等。','\n',char(10)),'https://i.postimg.cc/6pZf7q7z/IMG_20260212_171359.jpg','','','販售,家庭,策略燒腦',1,7,'普通',1,0,1,890,0,0,50,1,'',336,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(438,'大頭娃娃',replace('可憐的大頭娃娃！\n這12個可愛有善的角色，雖然沒有甚麼特別的意義，但有著歡樂的大頭臉，而且常常忘記自己的名字。\n用你天馬行空的想像力，幫大頭娃娃取名字，注意喔！用自己的方式記得幫牠取了甚麼名字。\n大頭娃娃是一個有趣和互動式的牌卡遊戲，透過桌遊可以發揮想像力及促進記憶力。大人和小孩都適合一起參與玩樂。\n▶適用年齡：5歲以上\n▶遊戲人數：2~6人\n▶遊戲時間：約15分鐘','\n',char(10)),'','','','租借,派對,家庭',2,6,'簡單',1,1,0,550,100,100,50,1,'',337,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(439,'水果雞尾酒',replace('8歲以上｜2-4人｜20分鐘\n酒吧即將打烊，趕快為自己的雞尾酒配搭最棒的水果！\n收集各種水果來獲得分數，但每種水果的分數隨著遊戲進行，才會逐漸確定。\n運用策略並憑藉運氣，讓自己享用一杯價值滿滿、果香四溢的雞尾酒！','\n',char(10)),'https://i.postimg.cc/Jz7GNGtz/IMG_20260320_103413.jpg','','','販售,家庭,輕鬆小品',2,4,'簡單',1,0,1,190,0,0,50,1,'',353,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(440,'傻傻玩:土狗隊+黑熊隊',replace('內含6種台灣特有種動物！\n\n上古大洪水來襲，動物爭相為僅存的人類找尋並護送火苗！\n極具速度感的歡樂桌遊，即時換牌、節奏明快，讓您成為團康與破冰高手！\n收集到4張相同動物的人大喊：「火！」搶拿燃燒的柴火，勝利終將屬於反應敏捷和頭腦清楚的玩家！\n\n加上《傻傻玩 黑熊隊》就能12人同樂！','\n',char(10)),'https://i.postimg.cc/XYNpfpXj/IMG_20260320_103433.jpg','','','販售,輕鬆小品',4,12,'簡單',2,0,2,380,0,0,50,1,'',340,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(441,'瘋探長',replace('8歲以上｜3-5人｜20分鐘\n剛發生了一起離奇的命案，分身乏術的福爾摩斯探長派您出馬解開謎團。\n您必須仔細查看，排除無關的線索，搶先找出真相。','\n',char(10)),'https://i.postimg.cc/mgZtYthG/IMG_20260320_103442.jpg','','','販售,輕鬆小品',3,5,'簡單',1,0,1,190,0,0,50,1,'',357,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(442,'炫富雪怪',replace('8歲以上｜2-4人｜20分鐘\n你們是一群雪怪，生吞活剝登山客後，用他們的裝備來裝飾洞穴。\n誰能成為喜馬拉雅山上擁有最炫洞穴的雪怪？','\n',char(10)),'https://i.postimg.cc/Z5YC8C0J/IMG_20260320_103449.jpg','','','販售,輕鬆小品',2,4,'簡單',1,0,1,190,0,0,50,1,'',354,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(443,'101塊起司',replace('8歲以上｜3-5人｜20分鐘\n老鼠家族搬運大量起司回家，但該如何分配？\n您要根據有限的資訊，掌握機率並管控風險，猜中紙牌編號來獲得起司，再運用紙牌行動獲得更多起司，成為今晚的起司霸主！','\n',char(10)),'https://i.postimg.cc/kgMBQBD6/IMG_20260320_103457.jpg','','','販售,輕鬆小品',3,5,'簡單',1,0,1,290,0,0,50,1,'',339,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(444,'與貓的距離',replace('接近貓咪，抓好對的距離，讓貓咪靠近你吧😻 — 與貓的距離\n\n\n\n試著增加手上物品的吸引力，用毛線球和貓薄荷等道具，吸引可愛的貓咪更靠近你，拉近你與貓的距離！\n\n一起來體驗與貓咪互動，又愛又恨的有趣體驗吧！\n\n\n\n🐈《與貓的距離》是Sky Huang 新作品，與《猜心俱樂部》、《貓的名字》、《巧克力對決》同樣精采。\n\n小小一盒可以支援到六個人，半小時一場的派對桌遊，帶上它，不管是朋友聚會還是一起吸貓咪，都能帶來笑聲與樂趣！\n\n一卡兩用，手上的牌同時是「數值」也是「物品」！\n\n想要招來貓咪，可以透過卡牌為場上物品加上吸引力，留下的物品加乘場上的吸引力，對手會提供你「巨大的助力」！','\n',char(10)),'https://i.postimg.cc/jSqLHLC7/IMG_20260320_103515.jpg','','','販售,輕鬆小品',2,6,'簡單',0,0,0,400,0,0,50,0,'',359,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(445,'午茶之戰','玩了一個上午，熊熊們決定來個下午茶派對。阿極找出家裡僅有的食物，為大大與胖達準備了美味的甜點，只是份量不太夠，動作太慢就吃不到啦！','https://i.postimg.cc/t4RY3Y7P/IMG_20260320_103527.jpg','','','販售,輕鬆小品',2,2,'簡單',1,0,1,390,0,0,50,1,'',341,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(446,'跑跑蛙',replace('一款適合家庭娛樂的小遊戲。 \n移動池塘中的青蛙贏得有利位置並運用資源，與雄青蛙繁殖寶寶。 \n利用蚊子和睡蓮加快行動部署或是休息。 \n注意危險的梭魚，這可不是好玩的禮物！','\n',char(10)),'https://i.postimg.cc/jS8CZtJj/IMG_20260320_103535.jpg','','','販售,家庭',2,4,'簡單',1,1,0,990,0,0,50,1,'',361,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(447,' 情書系列:詭鎮奇談:克蘇魯',replace('在《詭鎮奇談：克蘇魯情書》這款遊戲中，你將扮演一位調查員，追蹤一連串明顯是在引誘你來發現的線索；然而，你需要謹慎行事，因為某些線索隱含著禁忌的秘密，而另一些則被兇猛的超自然生物守護著。\n\n\n\n隨著經典克蘇魯情書卡牌遊戲踏入阿卡姆市的詭異城鎮，帶來不寒而慄的轉變。鑽研克蘇魯神話的謎團，在這場扣人心弦的智力戰鬥中，你面臨遠古的恐懼、發掘瀕臨瘋狂的盟友。你能維持你的神智並躲避克蘇魯，或你會屈服於潛伏於其中的蔓延黑暗？\n適合14歲以上，2-6人遊玩，遊戲時間30-45分鐘。','\n',char(10)),'https://i.postimg.cc/4x8nBshY/IMG_20260320_103543.jpg','','','販售,輕鬆小品',2,6,'普通',1,0,1,500,0,0,50,1,'',343,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(448,'故事小Q(故事骰)','這是一款非常有趣的遊戲，可以提升玩家的智慧並磨練想像力。投擲9顆骰子，用擲出的圖案講述一個故事。《故事小Q 》提供了無限創作可能性。故事沒有對錯，誰都能寫出自己的故事。適合家庭、旅行、娛樂、派對！《故事小Q 》為所有人帶來來歡樂！唯一的規則: 就是沒有錯誤的答案。','https://i.postimg.cc/K894Jxg3/IMG_20260320_103554.jpg','','','販售,租借,輕鬆小品',1,99,'簡單',4,1,3,420,50,400,50,1,'',351,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(449,'幾隻羊','遊戲人數:2-4人遊戲時間:15分鐘推薦年齡:5歲以上遊戲簡介:小羊牧場養了好多的黑羊與白羊，羊群在農場主人細心照顧下，每一隻都胖嘟嘟而且羊毛濃密。但是，在大野狼的眼中，牠們可是美味可口呢！驅趕野狼、清點羊隻數量，可是農場主人最重要的工作，你能勝任嗎？遊戲目的:最快清點出正確羊隻數量者獲勝。','https://i.postimg.cc/52PjnbFC/IMG_20260320_103602.jpg','','','販售,輕鬆小品',2,4,'簡單',1,0,1,250,0,0,50,1,'',348,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(450,'爆炸貓原始版',replace('炸貓是一款非常簡單的小品遊戲，曾在Kickstarter募資網站上達到219,382位支持者，而且募到超過870萬美金。它的超高人氣也跟遊戲的繪師Matthew Inmanu有關，魔性又可愛的畫風，大量的黑色幽默，深深抓住不少人的心。不過不需要擔心，我們這次的爆炸貓是闔家歡樂版，保證每張圖都很「正常」，適合年齡從七歲到七七七歲都OK！\n遊戲適合7歲以上，2-5名玩家一同遊玩，遊戲時間15分鐘。','\n',char(10)),'https://i.postimg.cc/nhdM0pQB/IMG_20260320_103608.jpg','','','販售,輕鬆小品',2,5,'簡單',1,0,1,720,0,0,50,1,'',356,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(451,'骨董拍賣王',replace('玩家可以透過競標手段買進、賣出各種古董商品來賺取利潤，\n\n並運用自身的策略與口才主持拍賣會，影響拍賣的結果。\n\n玩家也可以活用店鋪的技能，搭配各種物品牌的獨特效果，組織出變化多端的賺錢連續技，甚至干預其他玩家的買賣計畫。\n\n在七個回合內誰能賺取最多金錢獲得勝利呢？','\n',char(10)),'https://i.postimg.cc/htChpc78/IMG_20260320_103616.jpg','','','販售,策略燒腦',3,5,'困難',1,1,0,1790,0,0,50,1,'',367,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(452,'小小村莊',replace('一群辛勤的工人在一塊肥沃的大地上，辛勤的耕作、收穫與蓋新建築，一起發展村莊。家庭遊戲中，玩家們用心建造自己的家園，耕作與收穫自己的成果，思考策略的同時兼具收穫的成就感，如果你想成為最有天分和野心的建築師，此款桌遊是你不容錯過的喔！\n\n合10歲以上，2-4位玩家，時間60分鐘。','\n',char(10)),'https://i.postimg.cc/6pHTYtGh/IMG_20260320_103624.jpg','','','販售,家庭',2,4,'普通',1,0,1,690,0,0,50,1,'',347,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(453,'熱帶椰林雞尾酒',replace('《熱帶椰林雞尾酒》是一款適合全家同樂的派對遊戲。玩家最多可以擲骰三次，來達成杯墊上可用的組合。\n在對手之前，巧妙地擺放你的雞尾酒標記，占據有利位置。\n你將獲得珍貴的分數，一步步邁向勝利……\n\n但最快的獲勝方式，是將 4 個你的雞尾酒標記排成一直線，完成著名的「熱帶椰林雞尾酒」，立即贏得比賽！','\n',char(10)),'https://i.postimg.cc/fRHkBD05/IMG_20260320_103639.jpg','','','販售,租借,輕鬆小品,派對,家庭',2,4,'簡單',11,1,10,650,100,600,50,1,'',355,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(454,'拉斯維加斯豪華版',replace('歡迎來到炫目夢幻的拉斯維加斯，到底你們的運氣能帶來巨額財富嗎？\n在六間賭場試試你的手氣。決定把你的骰子放在哪裡，嘗試取得最大利益，\n巧妙地勝過你的對手，你才沒有想過要空手而回吧！\nLas Vegas Royale包括基本遊戲，同時加入更多新的規則，\n帶給全新且刺激的內容，保證你們欲罷不能！','\n',char(10)),'https://i.postimg.cc/2SH32rB2/IMG_20260320_103800.jpg','','','租借,派對',2,5,'簡單',1,1,0,1800,200,1800,50,1,'',350,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(455,'回想血戰',replace('《Blood Recall 回想血戰》是由日本桌遊社ThyellaGames所發行的卡牌對戰遊戲。\n發售後，憑借著優秀的遊戲性以及精美的立繪而獲得了玩家的好評。\n在本作品中，玩家將體驗到得殊定 "極限瀕死邊緣" 卡牌對戰。\n玩家所受到的傷害將全部轉化為資源，用來強化自己的牌組。\n通過自傷或是承受敵人攻擊後構築強烈的牌庫，在鮮血僨張的戰鬥中贏得勝利。','\n',char(10)),'https://i.postimg.cc/7ZBbmwTt/IMG_20260320_103815.jpg','','','租借,策略燒腦',1,2,'普通',1,1,0,1900,200,1900,50,1,'',344,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(456,'方格都市',replace('你能接受挑戰，成為史上最負盛名的市長嗎？\n你需要根據市民的工作、能源需求至定都市規劃，\n分派建築師在城市中建造各類建築，從而超越你的對手。\n每幢建築都能讓你獲得勝利點數，\n通過組合可以讓它們獲得更高的效益榮獲2016金極客獎年度遊戲提名、\n2016國際玩家大獎多人策略遊戲獎提名。','\n',char(10)),'https://i.postimg.cc/dVWD4wTS/IMG_20260320_103850.jpg','','','租借,家庭',2,4,'普通',1,1,0,1400,150,1400,50,1,'',352,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(457,'城主(大王:西班牙版)',replace('遊戲人數：2-5人\n適合年齡：13歲以上\n遊戲時間：約90分\n中世紀晚期的西班牙，國王的地位和他的王國十分穩固，但是身為高階貴族的城主亟欲擴展他們的影響力。玩家化身城主，派遣忠心的騎士到各個領地，以鞏固自己在西班牙的地位。城主並非靠著刀劍在權力鬥爭中勝出，而是施展各種奸詐狡猾的詭計，讓爭權奪利的陰謀得逞。\n★基本版榮獲1996德國年度遊戲獎冠軍★','\n',char(10)),'https://i.postimg.cc/8CjcY9hm/IMG_20260320_103913.jpg','','','僅供現場玩,策略燒腦',2,5,'普通',1,0,1,3000,0,0,50,1,'',345,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(458,'軍鬥牌','簡單快速、刺激耐玩！《軍鬥牌》是一款「心理博弈」遊戲，你要用運氣、策略、還是嘴遁來獲勝？任何人都能享受樂趣!','https://i.postimg.cc/8CjcY9h4/IMG_20260320_103932.jpg','','','租借,輕鬆小品',2,4,'簡單',1,1,0,1400,150,1400,50,1,'',363,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(459,'芋頭天堂',replace('又到了「芋頭」最美味的季節！「芋頭」可是瘋狂島上最好吃的美食之一呢！\n今年在螺旋山上特別舉辦了一場種芋頭大賽，成為種植冠軍的農夫，將會獲得一年份的美食招待券！','\n',char(10)),'https://i.postimg.cc/d0L3fp85/IMG_20260320_103944.jpg','','','販售,家庭',2,6,'普通',1,1,0,1080,150,1000,50,1,'',360,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(460,'我是大老闆! 紙牌版',replace('9歲以上｜3-6人｜30-60分鐘\n這是一款需要你用盡心機來操縱交易，以獲取最大利益的遊戲，如果你拿到一手爛牌（如同真實人生⋯⋯），就設法破壞這場交易，讓它由盈轉虧來擊潰你的對手。\n透過狡詐的交易手段（設計一些陷阱和使用背後捅刀的伎倆）、或讓「表兄妹」插股，賺取最多的財富來證明你是當之無愧的「大老闆」。','\n',char(10)),'https://i.postimg.cc/9fr0kKGx/IMG_20260320_104211.jpg','','','租借,派對,家庭',1,4,'簡單',1,1,0,690,100,600,50,1,'',349,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(461,'卡斯卡迪亞之旅',replace('在《卡斯卡迪亞之旅》中，玩家們通過輪抽棲息地板塊、野生動物標記來鑲嵌成一幅華麗景觀，在太平洋西北地區競相創建最多樣化的生態區。穿越卡斯卡迪亞的自然景觀，成為一名當地的生物學家，同時研究\n這裡的棲息地和野生動物以獲得成就！單人或多人模式下皆可獲得並記錄你的成就。每一場《卡斯卡迪亞之旅》遊戲的得分目標都會有不同的組合，這些組合與五種野生動物有關。在將野生動物排列成得分圖案的同時，玩家們還會競相創建最大的連續棲息地廊道。玩家建造生態區時，必須特別注意自己創建的棲息地和居住其中的野生動物，目的是在《卡斯卡迪亞之旅》建立最和諧的生態系統。','\n',char(10)),'https://i.postimg.cc/BvXbzkxw/IMG_20260320_104228.jpg','','','租借,策略燒腦,家庭',1,4,'普通',1,1,0,1800,200,2000,50,1,'',342,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(462,'大師畫廊',replace('遊戲人數：2~5人\n推薦年齡：10歲以上\n遊戲時間：約30~45分鐘\n在“大師畫廊”這款遊戲中，玩家們扮演藝術評論家和畫廊擁有人。\n在這個偉大藝術家的殿堂裡，各玩家都能欣賞到自己所喜愛的繪畫大師名作 \n—或許，至少遊戲開始後你就能體驗了。在早期西方的藝術世界中，人們對於每位大師藝術價值的品味與評價都一直在不斷變化著。不過，在這款遊戲裡，還數玩家們對於各位大師名作價值的影響力最大。\n究竟哪一位玩家能施加最大的影響力呢？誰能預測這些不斷變化的藝術品味和評價，並收集價值最高的經典名作呢？','\n',char(10)),'https://i.postimg.cc/JhG0FvbF/IMG_20260320_104309.jpg','','','租借,家庭',2,5,'簡單',1,1,0,650,100,600,50,1,'',346,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(463,'職場地下城',replace('這是一款輕鬆的吹牛遊戲，玩家扮演在地下城工作的職員，解決案子才能賺取報酬。\n俗話說職場如戰場，利己才是王道！把握時機收割結案成果，成為顧人怨的勝利者！\n遊戲人數：3-5人\n遊戲時間：20-30分鐘\n適合年齡：8+','\n',char(10)),'https://i.postimg.cc/YSh0PZ1V/IMG_20260320_104313.jpg','','','租借,派對',3,5,'普通',1,1,0,490,50,500,50,1,'',358,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(464,'我的村莊',replace('12歲以上｜2-4人｜60-90分鐘\n村莊的歷史又翻開了新的篇章，每位玩家將帶領自己的村莊，為了榮譽和財富而奮鬥。你在遊戲開始時只有一小塊田地，以及5位不同職業的村民：修道院長、議員、旅行家、工匠和商人。你將通過增加建築和農田來改善村莊，還要發展你的旅遊業，來吸引顧客和僧侶，與此同時，時間一刻不停地往前走。不時會有村民過世，他的職業將成為空缺。即使你可以培訓新人來填補他的位置，很快，你就不得不做出取捨，將精力專注於其它地方。\n\n‍我的村莊是一款獨立遊戲，它的背景設定與著名的獲獎遊戲村莊相同。\n它將熟悉的元素與新鮮的機制融合在一起，無論是新手玩家還是村莊的粉絲都將深受其吸引。','\n',char(10)),'https://i.postimg.cc/cCTDmpqF/IMG_20260326_151555.jpg','','','販售、策略燒腦',2,4,'困難',1,0,1,1890,0,0,50,1,'',362,'90分鐘以上');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(465,'我是牛頭王',replace('玩家輪流出牌，所出的牌不能比棄牌堆頂的牌大11以上，否則就要拿走一個棄牌堆全數的牌，放入手牌中。\n8歲以上｜2-7人｜30分鐘\n試著在每輪中率先出清手牌，其他玩家尚餘的手牌都是扣分。\n遊戲結束時，扣分最少的玩家獲勝！\n\n熱銷桌遊《誰是牛頭王》系列作品，延續無限歡樂！','\n',char(10)),'https://i.postimg.cc/cJykmMgQ/wo-shi-niu-tou-wang.png','','','租借,輕鬆小品',2,7,'普通',1,1,0,490,50,400,50,1,'',364,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(466,'驢橋(外文版)',replace('如何輕易地記住多個不相關的東西呢？‍\n很簡單！只要藉由一小段故事的幫助，加上一點巧思與創意，\n把這段故事變得趣意橫生，就可以讓其他人很容易地記住。\n本遊戲內含180張有趣可愛的全彩圖片，\n讓你可以盡情發揮天馬行空的想像力，\n你創造的故事若能讓人朗朗上口，\n就越容易讓人記住裡面提到的關鍵字。\n   \n驢橋是一款超好玩的瞎說話記憶遊戲，\n只要善用故事記憶法以及圖片記憶法，\n你將發現你的記憶力正在突飛猛進⋯\n原來記東西也可以這麼有趣！','\n',char(10)),'https://i.postimg.cc/brnj60H0/IMG_20260326_151221.jpg','','','租借,派對,家庭',3,12,'普通',1,1,0,1490,150,1400,50,1,'',365,'30~90分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(467,'密弒派對',replace('！大逃殺開始！誰有辦法活到最後？\n一場歡樂的變裝派對，殺手們已經混在其中!!\n玩家要隱藏好自己的身分，邊伺機剷除其他人\n\n透過每次的移動以及殺人事件，玩家都有機會推理彼此的隱藏身分\n\n心機又刺激，派對聚會必備\n\n內附不同造型米寶，非常值得收藏！ \n\n\n\n建議年齡｜10歲以上\n遊玩人數｜4-10人\n遊戲時間｜20-30分鐘','\n',char(10)),'https://i.postimg.cc/fyXStbq8/351a2a52-1d86-4c1b-bd35-1c02602f771e.jpg','','','販售,派對',2,6,'簡單',1,0,1,880,0,0,50,1,'',366,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(468,'小小賽車手',replace('在《小小賽車手》中，每回合擲出所有的骰子，\n根據骰子的結果，玩家可以自由選擇前進或者是切換賽道，\n最後由最先抵達終點的玩家獲勝。\n         \n六台賽車在起跑線上蓄勢待發，準備開始一場刺激的競賽。\n只有骰出完美骰子組合的選手才能全速前進！','\n',char(10)),'https://i.postimg.cc/Mp7qzr0c/562a12aa_e378_44c2_aa79_b25972ee3650.jpg','','','租借,兒童',2,6,'簡單',1,1,0,990,100,1000,50,1,'',368,'30分鐘');
INSERT INTO "BoardGames" ("game_id","name","description","image_url","image_url_2","image_url_3","tags","min_players","max_players","difficulty","total_stock","for_rent_stock","for_sale_stock","sale_price","rent_price","deposit","late_fee_per_day","is_visible","supplementary_info","display_order","play_time") VALUES(469,'地產大亨瑪利歐賽車',replace('來自與任天堂合作的地產大亨遊戲，\n每個角色在遊戲中都有自己的特殊能力。\n玩家們在賽道上比賽，躲避香蕉皮 ，並收集硬幣以獲得勝利的點數。','\n',char(10)),'https://i.postimg.cc/T3VfTHjK/c357c029_a100_470a_b2b4_7121baa71257.jpg','','','租借,家庭,派對',2,4,'簡單',1,1,0,1299,150,1300,50,1,'',369,'30~90分鐘');
